INSERT INTO books VALUES('',0,'','WesselenyiUtinaplo-FD.jpg','','',1,0,15,6,'',0,'','','','','',NULL,NULL,'','',0,NULL,0,7,2008,18,'Wesselényi Miklós','Útinapló, 1821-1822','978-963-87741-1-8',2,'','1','A4',191,'1',1990,3,'#LA4#','http://adlibrum.hu/Wesselenyi/','http://www.konyvesbolt.online/spd/978-963-87741-1-8/Wesselenyi-Miklos-Utinaplo-1821-1822-Ad-Librum-200','http://bookline.hu/product/home!execute.action?id=73344&type=22&_v=Wesselenyi_Miklos_Utinaplo_1821_1822','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/terkepek_utikonyvek/utinaplo_1821_1822_regi_utazasok_','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-7-0','','','Wesselényi naplója Széchenyivel tett híres nyugat-európai útjáról. 1925 óta az első teljes kiadás!','Párizs este igazán tündérvároshoz hasonló, s első látásra meglepő és elvakító. A remek világítás, az ízléses fényes boltok, a széles, szabad utcák két oldalán meseszerű, ragyogó látványt nyújtanak. L`Hotel des Princes-be szállottunk meg. Széchenyi nagyon szép lakosztályban, én egy kis szobácskában.

Mindjárt útiruháinkban a Palais Royalba menénk. Itt az első pillantás a velencei Márkus-térre emlékeztet, de több fénnyel, ízléssel és élettel. A legnemesebb szellemi termékektől s a legszükségesebb használati cikkektől, a leghiúbb élvek s a legkeresettebb divatárukig minden található itt. Tudományos egyletek, olvasótermek, kávéházak, melyekben kizárólag politizálnak, játékbarlangok, kéteshírű korcsmák, a legelőkelőbb emberek s a legaljasabb csőcselék rikító ellentétben vannak itt együtt.','2009.ZKI:58+1=59',1205925785,1467194341,0);
