INSERT INTO books VALUES('',0,'','MillerAdrienn--FD.jpg','','',1,0,0,34,'',0,'',10,40,'','',NULL,NULL,'',50,0,NULL,0,7,2008,34,'Miller Adrienn','A budapesti Le Meridien Hotel és a párizsi Ambassador Hotel Front Office részlegének komplex elemzése','978-963-87830-3-5',1,'','1','A5',84,'3',1490,1,'#LA5#','Miller-Adrienn','http://www.konyvesbolt.online/spd/978-963-87830-3-5/Miller-Adrienn-A-budapesti-Le-Meridien-Hotel-es-a-','http://bookline.hu/product/home!execute.action?id=2100431449&type=10&_v=Miller_Adrienn_a_budapesti_Le_Meridien_Hotel_es_a_parizsin_Ambassador_Hotel_','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-7-0','Miller Adrienn, 06 70 221 0080, 1157 Budapest, Zsókavár utca 63.','adrienn.miller@gmail.com','','Budapest és Párizs két európai főváros, két hasonló és mégis eltérő kultúrával. Az egyik az otthonom, ahol főiskolai éveimet töltöttem, a másikban pedig többek között elsajátítottam a szakmám alapjait.

A párizsi luxusszállodában töltött hónapok adták az ötletet, hogy két ilyen nagy múltú francia hotel példáján mutassam meg, milyen különböző is az egyformának tűnő. Véleményem szerint mindkét szállodának lenne mit tanulnia a másiktól.

Bár a Front Office tevékenység komplexitásáról szól ez a könyv, a többi részleg – így például az étterem – munkája is nagy befolyással van rá. Étteremvezetőként azóta megtanultam ezt. Hogy miért van így és hogyan működik? Leírtam ebben a könyvben. 2007. januárban nívó-díjat kaptam érte.

Elsőként Laurent Carasconak ajánlom ezt a könyvet – nélküle nem születhetett volna meg, szerzője pedig ma sem szakmai, sem emberi téren nem lehetne az, aki.
','2009.ZKI:5+1=6',1206629913,1461226594,0);
