INSERT INTO books VALUES('',0,'','NyirfasDedi-FD.jpg','','',1,0,0,8,'',0,'',10,40,'','',NULL,NULL,'',100,0,NULL,0,6,2008,40,'Nyírfás Pyrker Dezső','A dédi öröksége','978-963-87830-9-7',1,'','1','A5',404,'0',2590,1,'#LB4#','Nyirfas-Dezso','http://www.konyvesbolt.online/spd/978-963-87830-9-7/Nyirfas-Pyrker-Dezso-A-dedi-oroksege-2008','http://bookline.hu/product/home!execute.action?id=73366&type=22&_v=Nyirfas_Dezso_A_dedi_oroksege','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-6-0','1172 Budapest, Algír u. 58.','nyird@t-online.hu','A dédi ládája és a háborús menekülés.','"A szekér nem volt nagy, amolyan közönséges parasztszekér volt, amilyen szinte minden portán akadt, amíg el nem rekvirálták a katonák. Ezt már, jól látszott, annyira kikezdte szú, hogy talán azért maradt meg a gazdának. Édesapám mégis bátran felpakolt mindent, amit édesanyám mondott, így hát senkinek sem volt kényelmes ülőhelye a kosarakon, batyukon és ládákon, csak annak a szigorú embernek, aki a lovakat hajtotta. Arra emlékszem, hogy akkora kezei voltak, mint egy szénázó favilla. A jobbikban a gyeplőt tartotta, a másikban az ostort. Nem kímélte a lovakat. Lépten-nyomon megcsapta, hol az egyiket, hol a másikat. Néha úgy éreztem, hogy nekem is fáj, mikor végighúzott a lovak tomporán. Közben megvolt a saját bajom. Az a kis vaspántos láda, amin kucorogtam, alaposan belenyomódott a fenekembe, és lábaimat sem tudtam jól mozgatni, hol az egyik zsibbadt el, hol a másik. Mindenféle holmik voltak körülöttem, és csak egy arasznyi résen láthattam előre, különben pedig csak az eget és a hajnali fényben fürdő felhőket láthattam. A szekéren hátul, a saroglyában Dédinek alakított ki helyet édesapám, körül is rakta dunyhával, még a nagy csergét is aláterítette, mert Dédi már öreg is volt, beteg is volt, járni meg alig tudott, így hát egy kicsit kényeztetni kellett."','2012nov: 3 pld.

Bemutatópl.:1db',1207646079,1475168318,0);
INSERT INTO books VALUES('',0,'','MeszarosAdam-FD.jpg','',0,1,0,0,38,'http://books.google.hu/books?printsec=frontcover&id=aIDfJ5kl5iAC#v=onepage&q=&f=false',0,'',10,40,'','',NULL,NULL,'','',0,NULL,0,7,2008,41,'Mészáros Ádám','A bűncselekmény elkövetői. Elméleti és gyakorlati alapkérdések','978-963-9888-02-9',2,'','1','140x200 mm',332,'2',2990,1,'#LA4#','http://adlibrum.hu/MeszarosAdam/','http://www.konyvesbolt.online/spd/978-963-9888-02-9/Meszaros-Adam-A-buncselekmeny-elkovetoi--Elmeleti-','http://bookline.hu/product/home!execute.action?id=77330&type=22&_v=Meszaros_Adam_A_buncselekmeny_elkovetoi_Elmeleti_es_gyakorlati_alapkerdesek','','','http://www.konyvesbolt.online/spd/978-963-9888-02-9/Meszaros-Adam-A-buncselekmeny-elkovetoi--Elmeleti-','','','',3,3,0,0,0,0,0,'Array-0-0','2008-7-0','','meszaros@okri.hu','','A szerző az anyagi büntetőjog egy fontos területét tekintélyes szakirodalmi anyag alapján és önálló szempontok szerint dolgozta fel.‭
A tárgy körvonalazása és az elméleti alapok felvázolása után a hatályos jog alapján a tettesség és részesség általános fogalomrendszerét,‭ ‬majd a tettesség alakzatait és a részesség általános jellemzőit tárgyalja,‭ ‬kitérve a bírói gyakorlatra is.‭ ‬Ezt az egyes problematikus területek részletesebb elemzése követi‭; ‬ennek keretében fejti ki az‭ „‬in dubio mitius‭” ‬elvet,‭ ‬majd sorra veszi a személyes tulajdonságok jogi hatókörét,‭ ‬a részesség járulékosságának problematikáját és az elkövetői alakzatoknak a gondatlanságból elkövetett bűncselekmények körében mutatkozó sajátos vonásait.‭ ‬Itt foglalkozik az‭ „‬actio libera in causa‭” ‬kérdésével és az ittas,‭ ‬vagy bódult állapotban elkövetett bűncselekmények megítélésével,‭ ‬továbbá az‭ „‬agent provocateur‭” ‬problematikájával.‭ ‬Fejtegetéseit a közvetett tettesség intézményének elemzésével folytatja,‭ ‬kitérve a folyamatban lévő anyagi büntetőjogi kodifikáció munkálatainak keretében felszínre került különböző elgondolások bemutatására és értékelésére is,‭ ‬végül foglalkozik a függőben lévő szabályozási alternatívákkal és összegezi saját javaslatait.

Reményeim szerint ebből a‭ – ‬szükségképpen vázlatos‭ – ‬áttekintésből is megítélhető,‭ ‬hogy a szerző gondolatgazdag művet alkotott.‭

Hozzá kell tennem:‭ ‬a szerteágazó kérdések útvesztőjében otthonosan mozog,‭ ‬a különféle vitatott pontokat biztos kézzel emeli ki,‭ ‬az eltérő nézeteket aprólékosan és lényegre törően mutatja be és saját álláspontját világosan megfogalmazva,‭ ‬egyszersmind logikusan indokolva fejti ki.‭

Aki az anyagi büntetőjog elméleti kérdései iránt érdeklődik,‭ ‬bizonyára nem várt reveláció erejével ható,‭ ‬mellbevágó új felismeréseket.‭ ‬Kellemes meglepetésben lesz tehát része,‭ ‬amikor majd azt tapasztalja,‭ ‬hogy a szerzőnek sikerült az igazságosság és az‭ „‬in dubio mitius‭” ‬elvet következetesen alkalmazva egy olyan viszonyítási rendszert kialakítania,‭ ‬amelynek tükrében a megszokott‭ – ‬s így mintegy magától értetendőnek tekintett‭ – ‬fogalomrendszer gyenge pontjait,‭ ‬hiányosságait,‭ ‬esetenként következetlenségeit és belső ellentmondásait szokatlanul éles megvilágításba helyezheti.‭ ‬Kiváló példáit nyújtják ennek a sajátképi bűncselekményben való társtettesi és bűnrészesi közreműködés kérdéseit,‭ ‬a bűnrészesség járulékosságát,‭ ‬illetőleg a közvetett tettesség szabályozatlanságából adódó elvi következményeket tárgyaló részek.‭

Abban a meggyőződésben ajánlom minden érdeklődőnek,‎ ‏hogy egy olyan könyvet olvashat,‭ ‬amely időszerű hozzájárulás az anyagi büntetőjog tudományához,‭ ‬s amelynek értékét a benne olvasható,‭ ‬gondosan megfogalmazott és megindokolt szövegjavaslatok‭ – ‬a folyamatban lévő kodifikációra tekintettel‭ – ‬csak növelik.‭
Budapest,‭ ‬2008.‭ ‬május‭ ‬29.

dr.‎ ‏Bócz Endre

','2009.ZKI:3+1=4',1211282235,1451383057,0);
INSERT INTO books VALUES('',0,'','Tolnai--Tanitsatak--FD.jpg','','',1,0,0,2,'',0,'',40,80,'','',NULL,NULL,'',50,0,NULL,0,7,2008,42,'Tolnai Tamás','Tanítsátok meg az embereket szeretni','978-963-9888-03-6',1,'','1','A5',64,'0',1490,1,'','Tolnai-Tamas','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-7-0','','','','Tolnai Tamásnak hívnak. 1972. április 11-én születtem Budapesten.
Azóta megtapasztaltam, hogy rengeteg probléma van szerte a világon, amelyeknek legfőbb forrása a szeretethiány.
Elsősorban nem a párkapcsolati szeretetre gondolok, hanem úgy nagy összességében mindenféle szeretetre. Sajnos ennek a hiányát megszenvedi a valódi lét.
Gyermeteg bájjal támad az emberre gyarlósága, eltemetve a jó reményét, a szépség vágyát. Már alig vagyunk képesek észrevenni ezeket, mert a hibák annyira elfedik előlünk. Úgy gondolom, a verseimmel pont ezekre a hibákra mutatok rá. Ha néhány ember hallgat rám, már megérte. 
Kérek mindenkit, aki olvassa ezt a kötetet, gondolkodjon el a verseimen és próbáljon meg emberhez méltón élni. 
Remélem, mindenkinek kellemes olvasmány lesz!
','',1211962624,1461146463,0);
INSERT INTO books VALUES('',0,'','BendaszPeter-FD.jpg','','',1,0,0,3,'',0,'',40,80,'','',NULL,NULL,'',50,0,NULL,0,6,2008,43,'Bendász Péter','A fogadás','978-963-9888-04-3',1,'','1','A5',148,'0',1490,1,'#A3','Bendasz-Peter','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-6-0','','bendasz@enternet.hu','','Na, áll a fogadás?
Miféle fogadás?
Cserélünk, te elmész Kingával, én meg Judittal próbálkozok.
Ezt komolyan gondolod?
Komolyan. Itt a mobilszáma – elővett egy darab papírt és ráfirkantott néhány számot – Juditét tudom.
Gábor hitetlenkedve nézett rá, eddig abban a hitben volt, hogy Tamás szereti Kingát, hiszen együtt éltek már majdnem egy éve, de most rájött valamire, a barátjának valójában Judit tetszik. Esztelen boldogság töltötte el a lelkét, itt a lehetőség, kapott egy esélyt!
…………………………………………………………………..

Álltak egymással szemben és haragosan méregették egymást.
Kard, vagy pisztoly? – kérdezte hirtelen Gábor. A lány elnevette magát.
Én a partvist választom.
Tudtad, hogy én utálok porszívózni?
Én meg szeretek.
És még mit szeretsz?
Veled veszekedni!','2009.ZKI: 9',1211962772,1463732676,0);
