INSERT INTO books VALUES('',0,'','Soki_Peter--FD.jpg','','',1,0,0,2,'',0,'',40,80,'','',NULL,NULL,'',100,0,NULL,0,7,2008,47,'Sóki Péter','Fényben szomorkodni','978-963-9888-06-7',1,'','1','A5',28,'0',990,1,'#LA3','Soki-Peter','http://www.konyvesbolt.online/spd/978-963-9888-06-7B/Soki-Peter-Fenyben-szomorkodni-2008','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-7-0','Sóki Péter, 7626 Pécs, Kiss Ernő utca 55., 70/4083556','soki.peter@freemail.hu','','Kanálisban

                 Sötétben vagyok
             Szeretném feltépni bőröm                                
        S kiszakadni szánalmas testemből,
