INSERT INTO books VALUES('',0,'','Bota_Gabriella--Lelek,_test,_kotodes--FD.jpg','','',1,0,26,36,'',1,'',40,80,'','','','',100,110,0,NULL,17,4,2009,54,'Bóta Gabriella Sarolta','Lélek, test, kötődés - A méhen belüli állapot és a szülés-születés pszichológiája és élettana','978-963-9888-17-3',1,'','2','B5',267,'2',2490,1,'#A4','Bota-Gabriella','','','','','','','','',3,3,1,7,4,0,0,'2009-2-0','2009-4-17','Tóthné Bóta Gabriella, 3535 Bükk utca 18., 20/323-5444, botagabi6@freemail.hu','botagabi6@gmail.com','A kezdetek, a méhen belüli állapot és ezt követő élettér lelki-élettani feladatai.','„Az út, nem az út.
