INSERT INTO books VALUES('',0,'','Mester_Gyorgyi-FD.jpg','','',1,0,0,3,'',1,'',40,80,'','',NULL,NULL,'',50,0,NULL,0,8,2008,55,'Mester Györgyi','A LEGJAVÁBÓL - válogatott novellák','978-963-9888-15-9',1,'','1','A5',200,'0',1990,1,'#LB5#','Mester-Gyorgyi','http://www.konyvesbolt.online/spd/978-963-9888-15-9/Mester-Gyorgyi-A-LEGJAVABOL---valogatott-novellak-','http://bookline.hu/product/home!execute.action?id=2100261196&type=10&_v=Mester_Gyorgyi_A_legjavabol_valogatott_novellak','','','','','','',3,3,0,0,0,5,0,'Array-0-0','2008-8-0','','mestergyorgyi@freemail.hu','','Szerette a tengert. Olyan fájdalmasan szép volt a látvány. Szemében visszatükröződött a lenyugvó nap tüze, mely lángoló vörösre festette a tenger azúr fényét, majd a hanyatló nap belebukott a végtelenbe, és a nagy víz kioltotta a tüzet. Ezt csodálta minden este, s a csendet, mely telítve volt a nászukat ülő kabócák örökös cirpelésével, a tenger mormogásával, a partra csapódó hullámok halk, egyenletes neszével, s a szelídülő langy fuvallat érzéki susogásával.

Napszálltával a tenger fölé mélyfekete lepel borult, elfedve minden rosszat, minden csúfságát a keserves életnek, s betakarta őt is.

…a tenger minden éjjel kiszökött a medréből. Ő is szerette a fiút. A napcserzett fiatal arcot, a fekete, szomorú szemeket, a rakoncátlan hajat, mely olyan hullámokat vetett, mint maga a haragvó tenger. Hol a szülöttének érezte az apátlan-anyátlant, hol szeretőjének, kivel szakadatlan kívánt együtt lenni, együtt érezni, lélegzeni… A kalyibához igyekezett hát unos-untalan, de hullámai nem bírták erővel, s előbb haltak el a kagylótörmelékes parton, minthogy elérték volna azt…','2009.ZKI:3+21=24+1=25',1215078224,1480409847,0);
INSERT INTO books VALUES('',0,'','MezoFerenc-FD.jpg','','',1,0,2,3,'',1,'',40,80,'','',NULL,NULL,'','',0,NULL,0,9,2008,56,'dr. Mező Ferenc','Legyenek-e az ellenségeink a politikusok (Töredékek Jób elfelejtett naplójából)','978-963-87753-0-6',3,'Fit-Plan Bt.','1','A5',176,'0',1990,1,'#LB4#','Mezo-Ferenc','http://www.konyvesbolt.online/dr--Mezo-Ferenc-Legyenek-e-az-ellensegeink-a-polit','http://bookline.hu/product/home!execute.action?id=73356&type=22&_v=dr_Mezo_Ferenc_Legyenek_e_az_ellensegeink_a_politikusok_','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tortenelem_politika/legyenek_e_az_ellensegeink_a_politikusok','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-9-0','','fitplan@chello.hu','','A könyv Mező Ferenc őszinte vallomása, rendhagyó formában. Hol versben, hol prózában, hol verses prózában, hol meg teljesen másban. Nemcsak a politikában csalódott nézeteit fejti ki nekünk, hanem az életről alkotott szokatlan gondolatait is. A könyv megszámlálhatatlan kis darabból, papírfecnikből áll, de mégis valami láthatatlan szál felejthetetlen egésszé szövi össze.


„A mindennapok esztétikája”
(Eszerik Márton esztéta)

„Vágatlan gondolatok szokatlan formában”
(László Erik irodalomtörténész)

„Aki szeret borzongani a közéleten, az megkapja, amit vár”
(Másik Péter politológus)','2009.ZKI:310+1=311

fitplan@chello.hu, 20/569-5398, 70/931-5403

216 g/pld',1216197998,1467198049,0);
INSERT INTO books VALUES('',0,'','Tunisz-FD.jpg',77,0,1,0,0,3,'',1,'',40,70,'','',NULL,NULL,'',550,0,NULL,0,10,2008,57,'TUNISZ','21/12 (ROCK`N`ROLL)','978-963-9888-20-3',1,'','1','A5',100,'0',1490,1,'#LA4,LGII#  Kiss Sándor','Tunisz','http://www.konyvesbolt.online/spd/978-963-9888-20-3/TUNISZ-21-12-ROCK039N039ROLL-2008','http://bookline.hu/product/home!execute.action?id=74617&type=22&_v=Tunisz_21_12_ROCK_N_ROLL','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/tunisz_2112_rocknroll','http://www.konyvesbolt.online/spd/978-963-9888-20-3/TUNISZ-21-12-ROCK039N039ROLL-2008','','','',3,3,4,9,4,5,5,'2008-0-0','2008-10-0','nincs stabil címe, a telefonja is csak Mo-on él: 06-70 265-7265','kss_sandor@yahoo.com','Nem szépirodalom. Underground-karcolatok.','Magyar író vagyok. Amit írok: rock`n`roll. Nem több, nem kevesebb.
Nem szépirodalom. Underground-karcolatok.

Kinek írok?

Elsősorban a rohanó embernek. Annak, akinek nincs ideje egyáltalán.
Sem magára, sem a szeretteire. Egy alkotásomat elolvasni csak annyi idő, mint egy dal.
Mint amennyi idő alatt lepereg egy rock`n`roll.

Másodsorban ajánlom mindenkinek sör helyett, fű helyett...
Talán túlóra helyett is.

Remélem, megtalál az élmény.

Tunisz','2009.ZKI:170+1=171; ROSSZ adat: 340+1 (mivel 331-nek kellene lenni, talán visszáru volt valamikor)
',1216637227,1451298491,0);
