INSERT INTO books VALUES('',2,'','Kerekes_Gabor--Ungarnbild--FD.jpg',414,'',1,0,0,41,'http://books.google.hu/books?printsec=frontcover&id=uXKZ1lfXtgsC#v=onepage&q=&f=false',1,'',10,40,'','','','',50,100,0,NULL,2,4,2009,59,'Gábor Kerekes','Prag liegt zwischen Galizien und Wien - Das Ungarnbild in der österreichischen Literatur 1890-1945','978-963-9888-19-7',2,'','1','140x200 mm',344,'0',2990,1,'#LB5#  T:Szerző,B:V','Gabor-Kerekes','http://www.konyvesbolt.online/spd/978-963-9888-19-7/Gabor-Kerekes-Prag-liegt-zwischen-Galizien-und-Wie','','','','','','','',3,3,0,7,4,0,0,'Array-0-0','2009-4-2','06-26-331-695','kegahu@yahoo.de','','A könyv az osztrák irodalom magyarságképét vizsgálja interdiszciplináris megközelítésben, a szorosabban vett irodalmi (imagológiai) vizsgálódások keretein túllépve. Összesen 18 osztrák író (Arthur Schnitzler, Karl Schönherr, Hugo von Hofmannsthal, Rainer Maria Rilke, Robert Musil, Stefa Zweig, Franz Kafka, Hermann Broch, Georg Trakl, Franz Werfel, Joseph Roth, Felix Salten, Erwin Guido Kolbenheyer, Theodor Herzl, Andreas Latzko, Arthur Holitscher, Arthur Koestler és Emil Szittya) eddig hozzáférhető életműve alapján felvázolja a Magyarországgal szembeni attitűdök skáláját az osztrák irodalmon belül. Arra a kérdésre is választ nyújt, hogy mi szerint, mely faktorok és mentalitástörténeti folyamatok alapján alakultak ki a szimpátiák illetve antipátiák Magyarországgal és a magyarokkal szemben.','2009.ZKI:24+1=25


50 pld (ebből nálunk 23)',1216716226,1476870412,0);
INSERT INTO books VALUES('',0,'','Untener1-FD.jpg','','',1,0,0,31,'',0,'','','','','',NULL,NULL,'',50,0,NULL,0,10,2008,60,'Untener Erika','Kiadjuk magunkat I. Tehetségek mundérban','978-963-06-5796-9',1,'','1','A5',110,'0',2490,1,'','Untener-Erika','http://www.konyvesbolt.online/spd/978-963-06-5796-9/Untener-Erika-Kiadjuk-magunkat-I--Tehetsegek-munde','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-10-0','','','','Első elismert írásmunkám az általános iskola nyolcadik osztályának irodalom órájához kötődik, amikor is Nyilas Misi szemszögéből kellett a „Légy jó mindhalálig” egy tetszőleges részletét adaptálni. A következő órán Koncz tanár úr teátrális hangsúllyal jelentette be, hogy az egyetlen kitűnő tanuló csillagos ötös dolgozatán kívül van egy kétcsillagos is, az enyém… Azt hittem, ott süllyedek el! Nem kényeztettem el ugyanis a tanáraimat – sem magamat – jó jegyekkel egyéb tantárgyakból. Csak az irodalom érdekelt, még a nyelvtan sem, hiszen megelégedtem azzal, hogy a rengeteg olvasás következtében lefényképeződött bennem a helyesírás.
Aztán jöttek a bökversek, építőtábori szerelmes dalszövegek, tanár-utánzó jelenetek, lakodalmas strófák, végül a gyerekversek, mesék.
Az újságírói pályára a véletlen sodort, és kis kirándulásokat leszámítva nagyrészt a Pénzügyőrbe írtam. Elégedett vagyok e tekintetben. E válogatás szerkesztésekor ismét átéltem a kellemes órákat, amivel beszélgetőtársaim megajándékoztak. Kívánom, hogy szerezzen Önöknek is hasonló élményt az írások újraolvasása, esetleg messzire szakadt rokon, barát, ismerős részére szolgáljon ajándékul ez a könnyed kötet. 
S ha vannak még tehetségek mundérban – adjuk ki magunkat ismét!

A szerző','Nem terjesztjük.',1217239661,1460716596,0);
