INSERT INTO books VALUES('',0,'','Klicsu_Anna-FD.jpg','',0,1,0,0,11,'',1,'',40,80,'','',NULL,NULL,'',50,0,NULL,0,9,2008,62,'Klicsu Anna','Érdekes forgatókönyv','978-963-9888-25-8',1,'','1','A5',184,'0',1990,1,'#LB6','Klicsu-Anna','http://www.konyvesbolt.online/spd/978-963-9888-25-8/Klicsu-Anna-Erdekes-forgatokonyv-2008','','','','http://www.konyvesbolt.online/spd/978-963-9888-25-8/Klicsu-Anna-Erdekes-forgatokonyv-2008','','','',3,3,0,0,0,0,0,'Array-0-0','2008-9-0','Klicsu Anna, 1222 Budapest, Promontor utca 20., 20/480-6936','klicsua@citromail.hu','','- Nem értem, miért olyan hatalmas probléma számodra az, hogy itt kell lennünk a rendező parancsára. Szerintem kifejezetten jó helyre kerültünk.
- Jó helyre? Hogy jó helyre kerültünk? Te nem vagy normális! Egy börtön hogyan lehetne már jó hely?
- Ne siránkozz már annyit! 
- Hogy mi van? Annyit siránkozom, amennyit akarok! És nekem ne mondd meg, hogy mit tehetek és mit nem! Azt teszek, amit akarok!
- Jó, csak kicsit halkabban. Jön valaki.
- Teszek rá, hogy jön valaki! Nem érdekel!
- Toni!
- Mi van?
- Ne felejtsd el, rabok vagyunk! Szóval egy kicsit fogd vissza magad! Te is gyilkos vagy, ne felejtsd!
- Gyilkos?! Gyilkos?


Toni úgy tette fel a kérdést másodszorra, mintha elismerné, hogy valóban az. Persze ez lehetetlen… Hiszen akkor nem színészként, hanem gyilkosként csücsülne a dutyiban. Fel a folytatásra!
','2009.ZKI:4+1=5',1217330351,1451377143,0);
INSERT INTO books VALUES('',0,'','Huszarok-FD.jpg','','',1,0,0,5,'',0,'',10,10,'','',NULL,NULL,'',300,0,NULL,0,9,2008,63,'Szentgyörgyvölgyi Péter','A magyar huszár a magyar irodalomban','978-963-9888-26-5',3,'Huszár Múzeum Baráti Kör','1','A5',282,'0',3990,1,'#LB4#','Magyar-huszar','http://www.konyvesbolt.online/spd/978-963-9888-26-5/Szentgyorgyvolgyi-Peter-A-magyar-huszar-a-magyar-i','http://bookline.hu/product/home!execute.action?id=76856&type=22&_v=Szentgyorgyvolgyi_Peter_szerk_A_magyar_huszar_a_magyar_irodalomban','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/irodalomtortenet/a_magyar_huszar_a_magyar_irodalomban','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-9-0','','','','A zengő kürtszó régen elviharzott...

S legendák őrzik már a hősi harcot

Amelynek híre szájról szájra jár,

Hogy tűzben, vérben, virtusában égbe

Ezer csatából egyenest az égbe

Száguldott egykor a magyar huszár!
Manno Miltiadész
