INSERT INTO books VALUES(490,0,'','David_Jou-FD.jpg',98,3,1,0,0,2,'',0,'',37.5,75,'','',NULL,NULL,'',300,0,NULL,0,10,2008,65,'David Jou','Az univerzum írásai - versek a tudományról','978-963-9888-27-2',2,'','1','A5',100,'0',1490,1,'#LA3,LGI#','http://adlibrum.hu/David-Jou/','http://www.konyvesbolt.online/spd/978-963-9888-27-2/David-Jou-Az-univerzum-irasai---versek-a-tudomanyr','http://bookline.hu/product/home!execute.action?id=75529&type=22&_v=Jou_David_Az_univerzum_irasai_versek_a_tudomanyrol','','http://www.fo.hu/hu/reszletes_kereso?kButton=1&h_gyorskereso=david+jou','http://www.konyvesbolt.online/spd/978-963-9888-27-2/David-Jou-Az-univerzum-irasai---versek-a-tudomanyr','','','',3,2,0,0,0,0,0,'Array-0-0','2008-10-0','','','Katalán szerző versei a matematikáról és természettudományokról.','A nyelvek és a versek rengetegében vándorolva egyszer rábukkantam egy spanyol nyelvű versre, amit a π-számról írtak.

Egyrészt nagyon meglepett a dolog, hogy egy költő arra vetemedett, hogy matematikáról írjon verset, hiszen általában az irodalmat, s különösen a költészetet kedvelők számára a matematika teljesen idegen, rideg valami. Később sikerült megszereznem a vers szerzőjének a címét.
Kiderült, hogy ő katalán, a verseit katalánul írja. Mindjárt az első leveléből arra is magyarázatot kaptam, miért a matematika – és mint később megtudtam, a fizika is – a verseinek egyik (de nem egyedüli) témája. David Jou a barcelónai egyetem Kondenzált Anyagok Fizikája tanszékének a professzora. Szakterülete a visszafordíthatatlan folyamatok termodinamikája. Tudományos munkássága mellett igen termékeny költő. Tudományos művein túl számos verseskötete megjelent, mindkét területen elismerik, kitüntetésekkel, díjakkal jutalmazzák (többek között Spanyolország királya, János Károly kezéből is vett át magas rangú állami kitüntetést). Művei közül több megjelent fordításban is. Magyarul azonban ez az első kötete, amelyet katalán eredetiből fordítottam, azzal a reménnyel, hogy e verseket olvasva a költészet kedvelői kedvet kapnak, hogy a fizikát és a matematikát is jobban megismerjék; ugyanakkor talán a matematikusok, fizikusok is ezentúl több verset fognak olvasni, látva, hogy az ő szakterületeiket is ki lehet fejezni költői eszközökkel.

                                                                      Dabi István
									fordító','Itthoni képviselője: Dabi István
Bemutatópl.: 1db',1218008828,1451298096,0);
INSERT INTO books VALUES('',0,'','Christine_Fawkes-FD.jpg',413,'',1,0,0,13,'',1,'',40,75,'','',NULL,NULL,'',300,0,NULL,0,9,2008,66,'Christine Fawkes','Világok közt','978-963-06-5798-3',1,'','1','A5',358,'0',1980,1,'#LA2#','Christine-Fawkes','http://www.konyvesbolt.online/spd/978-963-06-5798-3/Christine-Fawkes-Vilagok-kozt-2008','http://bookline.hu/product/home!execute.action?id=75534&type=22&_v=Fawkes_Christine_Vilagok_kozt','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/vilagok_kozt','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-9-0','06-20-527-8409','zso.almadi@t-online.hu','Priscilla Scotch nem hős, nem harcos, nem vezér, de a tudás, amelynek birtokába jut, megköveteli, hogy azzá váljék.','Senki nem születik hősnek. De születhet olyan emberként, aki magában hordozza a megmagyarázhatatlant; a képességet arra, hogy átlépje a saját árnyékát.
Senki nem születik harcosnak, de az élet megtaníthatja rá, hogyan küzdjön meg mindazért, ami fontos számára.
Senki nem születik vezérnek sem, de ha csak így viheti véghez a lehetetlent, van ember, aki képes magára venni a felelősség terhét.
Priscilla Scotch nem hős, nem harcos, nem vezér, de a tudás, amelynek birtokába jut, megköveteli, hogy azzá váljék. A szerencsétlen véletlen, amely derékba töri életét ebben a világban, a halál utáni következőben egy kettéhasadt birodalom régen várt reménységévé teszi. De hogyan vehetné fel a harcot az új, ismeretlen lét árnyaival, amíg saját démonai ellen küzd?','2009.ZKI:6+1=7


Megbízó polgári neve: Almádi Zsófi',1218104148,1468234254,0);
