INSERT INTO books VALUES('',0,'','Meszlenyi-FD.jpg',150,'',1,0,27,26,'',1,'',40,70,'','',NULL,NULL,'',1000,0,NULL,0,10,2008,73,'Meszlényi Attila','A világvége illemtana (Túlélőkönyv)','978-963-87769-5-2',2,'','1','130x200 mm',104,'0',1790,1,'#LB6#','http://adlibrum.hu/Meszlenyi-Attila/','http://www.konyvesbolt.online/spd/978-963-87769-5-2/Meszlenyi-Attila-A-vilagvege-illemtana-Tulelokonyv','http://bookline.hu/product/home!execute.action?id=75115&type=22&_v=Meszlenyi_Attila_A_vilagvege_illemtana_Tulelokonyv','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tarsadalomtudomany/a_vilagvege_illemtana_tulelokonyv','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-10-0','','valamint@freemail.hu','','Izgató botránykönyv. Ámde nem mások botrányos tetteiről szól, amin élvezettel felháborodhatnánk, hanem a sajátjainkról. Hogyan kéne dolgoznunk, szórakoznunk, ünnepelnünk, ajándékoznunk – egyszóval élnünk, hogy az ökológiai válságból kilábalhassunk, s a világvége folyamatát megfordíthassuk?','2009.ZKI:33+200=233+1=234
A nyomdai szállítólevél sz. csak 950 db jött!',1221722405,1476870584,0);
INSERT INTO books VALUES('',0,'','Kovacs_Viktoria-FD.jpg','','',1,0,20,17,'',1,'',40,70,'','',NULL,NULL,'',1000,0,NULL,0,11,2008,74,'Kovács Viktória','Nicsak! Mi  beszélünk!','978-963-06-5849-2',1,'','1','140x200 mm',104,'0',1190,1,'#LB6,dobozban a raklapon# T:G,B:V','Nicsak','http://www.konyvesbolt.online/spd/978-963-06-5849-2/Kovacs-Viktoria-Nicsak-Mi-beszelunk-2008','http://bookline.hu/product/home!execute.action?id=75830&type=22&_v=Kovacs_Viktoria_Nicsak_Mi_beszelunk_','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/nicsak_mi_beszelunk','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','06-30-488-4164, 1022 Budapest, Ruszti u 10. 2/4.','Viktoria.kovacs@t-online.hu','','Kedves Olvasóink!

Ezt a könyvet - zsenge korunk ellenére - saját kútfőből, mi írtuk nektek!
Na jó, visszaveszünk az „arcoskodásból” és pontosítunk: alvás közben diktáltuk anyának, aki teleportálás útján magához vette a gondolatainkat és megosztotta veletek.

Fény derül többek között arra, miért teljesen fölösleges hivatalos nevet adni egy gyereknek, vagy arra, hogyan lesz egy hosszúnadrágból pár hónap alatt tangabugyi. Tanácsot adunk, hogyan kell otthon felépíteni egy igazi rabszolgatartó társadalmat, vagy hogyan kell észrevenni a víz alatt leselkedő paparazzót. Megismerkedhettek egy gyógyüdülés és több rekreációs nyaralás részleteivel, és elmeséljük, miért van az útlevélképünkön az arcunk belecsúszva a tokánkba. Pénzügyi tréningünk során eláruljuk, hol számít helyi valutának a sör. Bemutatkozik egy Vírus is, amelyik nálunk járt és demót tartott, hogyan fog ezentúl minden feltűnésekor végigvonulni a családon. Bemutatunk túlélési technikákat, amelyekkel a világ és a felnőttek által ránk mért megpróbáltatásokon lehet túljutni, és olvashattok azokról a gyenge próbálkozásokról is, amivel a felnőttek minket akarnak megszelídíteni.

Reméljük, hogy eddigi életünk bölcsességeit ti is hasznosnak találjátok!
Üdv!

Julcsi (2 éves) & Ádám (6 hónapos)','2009.ZKI:13+346=359+1=360

1000 pld-ból 800 pld marad nálunk',1222243599,1460715567,0);
