INSERT INTO books VALUES('',0,'','Polgar_Andras-FD.jpg','','',1,0,0,4,'',1,'',40,70,'','',NULL,NULL,'',1000,0,NULL,0,10,2008,76,'Polgár András','hüje zsiráf','978-963-9888-42-5',2,'','1','140x200 mm',186,'0',1990,1,'#LB6,LGII,LGraklap#','Polgar-Andras','http://www.konyvesbolt.online/spd/978-963-9888-42-5/Polgar-Andras-huje-zsiraf-Ad-Librum-2008','','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-10-0','06-30-906-0110','polgar.andras@chello.hu','','A hÜje zsiRáf tizenhetedik regényem, az Apuka, a Nyolcvankilenc nap, az Anna, Te vagy?, A didergő nyár, a Csendkúra, a Tolókocsi, a Kéjgyilkos és egyéb könyvek után. Izgalommal várom az Olvasó véleményét hősnőmről, aki született vesztes, és hihetetlen (kilátástalan?) küzdelmet folytat, hogy ezen állapotán változtasson.

Egész életében, megszállottan keresi a szerelmet, amíg álmai lovagja kilép számítógépe monitoráról. Ott áll előtte, egy lakásban él vele, és még sincs közel. Sőt, egyre távolabbra kerül. Mit jelenthet ez a szerelem? Ki ez a férfi? Mi történik Hédivel, ezzel a magas lánnyal, aki sikeres, boldog és győztes szeretne lenni, mint mindannyian.','2009.ZKI:3+669=672+1=673
Örököse: Polgár Lea (Andrea) apolgr@gmail.com, tel: 06-20-233-1911',1223029085,1458818450,0);
