INSERT INTO books VALUES('',0,'','',264,0,0,0,0,9,'',0,'',0,0,'',21,20,257,500,500,1,NULL,0,11,2008,81,'Gáti Vilmos','Fedésben - A terroristák nyomában (politikai krimi)','978-963-9888-37-1',2,'','1','A5',194,'0',2490,2,'#LE3,LGIV#','Gati-Vilmos','http://www.konyvesbolt.online/spd/978-963-9888-37-1/Gati-Vilmos-Fedesben---A-terroristak-nyomaban-poli','http://bookline.hu/product/home!execute.action?id=75825&type=22&_v=Gati_Vilmos_Fedesben_A_terroristak_nyomaban','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/fedesben_a_magyar_katonai_felderites_a_nemzetkozi_alvilag_es_az_al_kaida','http://www.konyvesbolt.online/spd/978-963-9888-37-1/Gati-Vilmos-Fedesben---A-terroristak-nyomaban-poli','','Gati_Vilmos','AdLibrum--Gati_Vilmos--Fedesben--Kulonnyomat.pdf',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','','agenda.alapitvany@t-online.hu','Titkosszolgálati küzdelem az alvilág és az Al-Kaida összefonódása ellen.','Magyarország nem szerepel az al-Kaida közvetlen célpontjai között, de a fordulatos alvilági konfliktus váratlan következményeként tesz szert a magyar szolgálat kulcsszerepre a történetben.

A több szálon futó cselekmény bonyolítása teremt alkalmat a magyar katonai hírszerzés eddig a nyilvánosság előtt nem, vagy csak nagyon kevéssé ismert tevékenységének, jelenjének és valamelyest múltjának felvillantására. A katonai titkosszolgálat működésének hétköznapi módszereit is megismeri az olvasó annyira, amennyire ezek a valaha féltékenyen őrzött titkos módszerek a nemzetközi hírszerzés és elhárítás közös fegyvertárát képezik manapság már.','Eredetileg 40%/10% jogdíj, amiről a forgalom fejében lemondott.

