INSERT INTO books VALUES('',0,'','','','',0,0,0,11,'',0,'',5,20,'',15,5,494,100,107,1,NULL,0,10,2008,82,'Christian Crow','A polip barlangjában','978-963-9888-38-8',2,'','1','A5',286,'0',2990,2,'#A5 Kovács Krisztián Duplikálva mint 396.','http://adlibrum.hu/Christian-Crow/','','http://bookline.hu/product/home!execute.action?id=76069&type=22&_v=Crow_Christian_A_polip_barlangjaban','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_polip_barlangjaban','','','','',5,3,0,0,0,0,0,'Array-0-0','2008-10-0','','christico@freemail.hu','','Gabriel Cromwell nem az emberiség mintapéldánya. Felesége elvált tőle, az apja kitagadta, de szerencsére legalább alkoholizmusából sikerült kigyógyulnia. Mindezek ellenére munkáját tisztességesen végzi, s élete a már lassan megszokott, sanyarú, agglegényi mederben csordogál - egészen egy borús, esős, májusi estéig.
Midőn hazafelé tart könyvtári kutatómunkájából, az őt szüntelenül követő idegenben egykori szerkesztőtársára ismer. Cromwell hezitál ugyan, hogy beengedje-e a lakásába, lévén legutóbbi találkozásuk nem a béke jegyében zajlott, azonban furcsa dolgot észlel a rejtélyes férfin.
Az egykori szerkesztőtárs fél. Retteg, s közben elejt néhány kósza megjegyzést egy mágikus erejű tárgyról, mígnem egy ismeretlen merénylő ki nem oltja az életét.
Az események ekkor felgyorsulnak, s Gabriel Cromwell nyugodt élete egy-kettőre megbolydul. Kutatni kezd, vajon ismerőse kinek állhatott az útjában, s közben egyre képtelenebb dolgok derülnek ki az egykori szerkesztőtársról. Ki volt valójában ez a férfi? Ki küldi a rejtélyes fenyegetéseket Cromwellnek? És vajon mit jelképez az a furcsa szimbólum, amelyet a bejárati ajtóra tűzött levélen talál?
Cromwell, tudtán kívül olyan események kereszttüzébe kerül, amelyekben senki és semmi nem az, aminek látszik, s amelynek megoldási kulcsa az ő kezében van… A probléma azonban csak annyi, hogy ő maga sem tud róla.','2009.ZKI:1+4=5+1=6 - elment OSZK-ba 5 db


szerző polgári neve: Kovács Krisztián
2009.dec.fogy.j.küldtem MK',1223031298,1460711812,0);
INSERT INTO books VALUES('',0,'','OroszTCsaba-FD.jpg','',3,1,0,0,13,'',1,'',10,40,'',21,20,176,300,500,1,NULL,0,11,2008,83,'Orosz T. Csaba','Lehettünk volna Istenek','978-963-9888-40-1',2,'','1','A5',132,'0',2490,2,'#LB6,LGIV,dobozban oldalt LGInél,LGsalgó#     #RB1c','Orosz-T-Csaba','http://www.konyvesbolt.online/spd/978-963-9888-40-1/Orosz-T--Csaba-Lehettunk-volna-Istenek-Ad-Librum-2','http://bookline.hu/product/home!execute.action?id=75828&type=22&_v=Orosz_T_Csaba_Lehettunk_volna_istenek','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/lehettunk_volna_istenek','http://www.konyvesbolt.online/spd/978-963-9888-40-1/Orosz-T--Csaba-Lehettunk-volna-Istenek-Ad-Librum-2','','','',3,0,0,6,0,0,0,'Array-0-0','2008-11-0','','arpadhaz2@freemail.hu','','Ez a könyv egy elképzelt, mégis hiteles múltba kalauzolja olvasóit.

Zoltán, a könyv főhőse napjainkban éli a programozók hajszolt életét. Leszerelt katonatisztként rajong a magyar történelem középkori világáért és annak hőseiért. Egy napon megadatik neki a csoda. Internetes böngészése során egy érdekes fájlra bukkan, amelynek segítségével váratlanul a XIII. századi Magyarországon találja magát. Elmondhatja-e a múlt embereinek a közelgő pusztulást? Megváltoztathatja-e a történelmet, ezzel megóvva az országot a tatárjárás borzalmaitól? Hogyan áll helyt egy korunkbeli ember a középkor forgatagában?','110713: 65 pld. a raktárban

