INSERT INTO books VALUES('',0,'','Avira_Bloemfontein-FD.jpg',434,'',1,0,0,11,'',0,'',10,40,'',21,20,409,300,500,1,NULL,0,11,2008,86,'Avira Bloemfontein','Megpecsételt sorsok','978-963-9888-46-3',2,'','1','140x200 mm',374,'0',3490,2,'#LD,LGI, LGIII# Péterné Oravecz Elvira','Avira-Bloemfontein','http://www.konyvesbolt.online/spd/978-963-9888-46-3/Avira-Bloemfontein-Megpecsetelt-sorsok-Ad-Librum-2','http://bookline.hu/product/home!execute.action?id=75826&type=22&_v=Bloemfontein_Avira_Megpecsetelt_sorsok','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/megpecsetelt_sorsok_pszichothriller','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-11-0','Péterné Oravecz Elvira, (1) 430-8119 vagy 06-70-509-3770, 1038 Budapest Kőbánya u. 80., ','poebp@t-online.hu','Pszichotriller és meghökkentő orvosi krimi Persányi Miklós ajánlásával.','﻿– Max, ha kiderül, hogy itt másról van szó, mint amire szerződtünk, én kiszállok! – fordult Val Maxhez. – Nem fogok tiltott kísérletekben részt venni! 
– Mi van, ha anyámnak igaza van?
– Annak szerény véleményem szerint egyre kisebb a valószínűsége. Ne haragudj, kezdem azt hinni, hogy épp ő áll a dolgok mögött.
– Mi oka lenne rá, hogy olyan kísérleteket végeztessen velünk, amelyeket világszerte tiltanak?! – kérdezte Max ingerülten. – Hippokratészi esküt tett, Val! Miért irányítana olyan kutatásokat, amelyeknek az eredményeit nem viheti ki a nagyvilágba?! Nem látod, mi a végső célja ennek az egésznek? Idáig a disznó xenográfokkal küzdött mindenki. Amit mi csinálunk, ha beválik az elképzelés, forradalmasítja az egész szervátültetést. Nem lesz semmilyen beépülési gond. Mert nincs szervméretbeli különbség, vagy legalábbis csekély, nincs kilökődési veszély, és minimálisra csökken a várakozási idő.
– Hát ez az! Óriási a tét! Itt most nem lehet hibázni! Lily Preston éppen ezért semmit nem bíz a véletlenre… Ugyan, Max! Ne gyere nekem azzal, hogy őt nem vakíthatja el egy őrült ötlet megvalósításának a lehetősége!


Egy rejtélyes múltú fiatal újságírónő, aki megpróbálja elfogadni vőlegénye váratlan halálát, rájön, hogy egy helyi kórházban a szervátültetésekhez olyan génmanipulált szerveket használnak fel, amelyeket illegálisan előállított humán klónokból nyer egy Indonéziában működő kutatóintézet. Vajon a cél mindig szentesíti az eszközt?','11-08-07: #RF 193 pld.

