INSERT INTO books VALUES('',0,'','Szabo_Daniel-FD.jpg','','',1,2,0,11,'',0,'','',30,'',15,5,356,100,107,1,NULL,0,11,2008,91,'Szabó Dániel','A halál üdvözletét küldi','978-963-9888-47-0',2,'','1','A5',150,'0',2390,2,'','Szabo-Daniel','','','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','06 70/3983237','szada2006@citromail.hu','','Cris Daniels magánnyomozó hullák között kel és fekszik, ám ez még neki is megfekszi a gyomrát. Hívatlan látogatók nézik az ablakot leszállópályának, felrobban a chicagói panellakás, elrabolják Barbara apját, olyan lányokba botlik, akikből kibotlani is nehéz, titokzatos halálesetek történnek, amerre jár, és mindenhol ott van a vészjósló ezüst hajszál.
És mi köze lehet mindehhez Eldorádó legendájának? Szörnyű válaszokat suttognak a Kígyó-halmot körülölelő fák...','091202: Kifogytunk, nem kell neki semmit küldeni. (G)

Csak webboltos terjesztés',1224146676,1461232509,0);
INSERT INTO books VALUES('',0,'','Szots_Balazs-FD.jpg','',0,1,0,0,2,'',1,'',10,40,'',21,20,234,300,310,2,NULL,0,12,2008,92,'Szőts Balázs','esemesszerelem','978-963-9888-49-4',2,'','1','106x147 mm',120,'0',1990,2,'#LB4, LGI#  T:G B:szerző','Szots-Balazs','http://www.konyvesbolt.online/spd/978-963-9888-49-4/Szots-Balazs-esemesszerelem-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77179&type=22&_v=Szots_Balazs_esemesszerelem','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/esemesszerelem','http://www.konyvesbolt.online/spd/978-963-9888-49-4/Szots-Balazs-esemesszerelem-Ad-Librum-2008','','','',3,3,0,0,0,0,0,'Array-0-0','2008-12-0','06208289110','szots.balazs@enternet.hu','Versek az új kommunikációhoz - Havas Henrik ajánlásával.','Pontosan tíz esztendővel ezelőtt kezdődött, hogy álnév alatt irodalmi
talentumát, tehetségét szomjasan nyitogató fiúként, szemérmesen
rímekbe kezdtem folyatni lelkem már megolvadt aranyát. Ékszereshez
sohasem vittem, csak egy-két műgyűjtőnek mutattam meg, na és persze
ami (aki) a legfontosabb:
Sok szeretettel ajánlom ezt a kis könyvet minden szívből érző kedves
új és régi barátomnak!

***

Birtokló korunk jelszava: ``Enyém vagy!``
Balázs kötetéé pedig: ``Tiéd vagyok!``
Ez nekem tetszik. És neked, kedves Olvasó?

(Ördögh Ottó, író)


Az ``esemesversek``-et olvasva meglepődtem. Műfajilag izgalmas kísérletről van szó, kíváncsi vagyok, lesz-e folytatása. A kísérleteket és a vállalkozószellemű költőket mindig is tiszteltem.

(Havas Henrik)','2009.ZKI:200+1=201

091214: Nem kell neki decemberben fogyási. (G)

091202: kiszámlázva.

A6-os: vagyis a kötet vágott mérete 105x148, a gerinc 7 mm-es, a teljes borítóméret pedig 217x148 mm (+kifutó)',1224489329,1451295810,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,41,'',1,'','','','',15,5,794,100,110,1,NULL,2,4,2009,93,'Böhm Edit','A magyar versszavalás története','978-963-9888-93-7',2,'','2','A5',428,'0',3990,2,'#A4','Bohm-Edit','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','http://bookline.hu/product/home!execute.action?id=79731&type=22&_v=Bohm_Edit_A_magyar_versszavalas_tortenete','','','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','','','',3,3,1,9,4,5,1,'2009-2-0','2009-4-2','Némethné Dr. Böhm Edit 70/37-47-282,23/379-564, 2030 Érd, Betonozó u. 15.','edi05@t-online.hu','','Ez a könyv a magyar verselőadás (versszavalás) gyökereit, hagyományait, fejlődésének küzdelmes útját, fontosabb állomásait tárja fel, amivel hozzájárul e művészeti ág vitatott kérdéseinek megválaszolásához. Egyben emléket állít azoknak a képviselőinek, akik a különböző korszakokban hittel és odaadással vállalták fel a költészet élőszóbeli közvetítését, de mert művészetük –a színészethez hasonlóan- a pillanat művészete, alakjuk gyorsan eltűnik az emlékezetből. Bemutatja a versek szavalásával kapcsolatos nézetek, elméletek alakulásának folyamatát és utal az egyes korszakok előadóművészeti közegére, sajátos elvárásaira, az irodalmi- és a színházi élettel való összefüggésekre.
A szerző avatott szakértője a versszavalás elméleti és történeti kérdéseinek, neve ismerősen csenghet a versmondással foglalkozók számára. Előadóművészként, szavalóversenyek zsüritagjaként, tanárként egyaránt találkozhattak vele. 1989-ben A vers szószólói címmel jelent meg a verselőadás művészeti kérdéseit tárgyaló szöveggyűjteménye, majd a Magyar Színháztörténet köteteinek egy-egy fejezetében foglalta össze a művészeti ág történetének szakaszait.
Ajánljuk a könyvet mindazok figyelmébe, akik művelik, tanulják, tanítják, vagy csak kedvelik az előadóművészetnek ezt az ágát, s akiket érdekel a magyar művelődéstörténetnek ez az eddig feldolgozatlan, izgalmas szelete.','2009.ZKI:2+29=31+2=33
tudomány


2009.dec. fogyj. kiküldve MK',1224497704,1451380812,0);
INSERT INTO books VALUES('',0,'','','','',0,0,18,15,'',1,'',10,40,'',21,20,259,300,400,2,NULL,0,11,2008,94,'Arany Emmi','Ti, kínaiak','978-963-9888-50-0',2,'','1','140x200 mm',106,'0',1990,2,'#LA6,LGIII,IV#  Vincze Edit T&B:szerző','Arany-Emmi','http://www.konyvesbolt.online/spd/978-963-9888-50-0/Arany-Emmi-Ti-kinaiak-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77513&type=22&_v=Arany_Emmi_Ti_kinaiak','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','Vincze Edit, 20/94-29-037, ideiglenes: megszünt, állandó: 1137 Budapest Szent István krt. 30.','vincze@emimail.com','Egy magyar diáklány kalandjai Kínában.','﻿„A változás, az, hogy semmi nem állandó, erre az országra egyértelműen jellemző. Tulajdonképpen ez volt az egyik fő oka, amiért ezt a könyvet megírtam. Szeretném, ha minél többen megismernék az itt élő emberek igazi arcát. A boldogságukat, a könnyeiket, örömüket, bánatukat. Kicsit bepillantanának a mindennapi életükbe, és ezzel közelebb kerülnének ehhez a túlmisztifikált világhoz. Én megszerettem őket. A hibáikkal, rossz tulajdonságaikkal együtt.  Mégis, szívemből szólnak ők, az első perctől fogva. Mert adtak nekem valamit, valamit önmagukból, abból a szemléletből, ahogy ők látják a világot. Sok mindenre tanítottak, és remélem én is hagytam magamból valamit az ő számukra.
(...)
Ja, neve is volt az új barátomnak. Idehaza már az óvodában ráragasztották a János (Jancsika) nevet, a későbbiekben is ezt használta, mivel az eredeti, Dong Hong Fang kiejtése és megjegyzése némi nehézséget okozott a magyar pedagógusoknak. Nekem is ez volt az egyszerűbb, még örült is neki, hogy végre valaki ezen a néven szólítja. 
Ekkor már több mint egy hete Kínában tartózkodtam, és eddig a napig úgy gondoltam, csendben, szerényen élem le az itteni tíz hónapomat. De Jánosommal való találkozás után egyre nyilvánvalóbbá vált, hogy most sem kerülhet el a kalandok sora.”','2009.ZKI:7+355=362+1=363

091214: Csak fogyási, számlázás januárban.
2009.dec.fogy.j.kiküldve MK

091202: Két számlával is tartozik.

szerző polgári neve: Vincze Edit
2009.12.8. beszéltem vele, szlákat újra kipostáztam,
megígérte h azonnal fizet. MK',1224573659,1467281220,1);
INSERT INTO books VALUES('',0,'','',124,0,0,0,12,4,'',0,'',10,30,'',21,5,275,300,300,1,NULL,30,11,2008,95,'Németh György Gábor','Ophelia virágai','978-963-9888-51-7',2,'','1','A5',96,'0',1990,2,'#L §372-n folytatva','Nemeth-Gyorgy','','http://bookline.hu/product/home!execute.action?id=77329&type=22&_v=Nemeth_Gyorgy_Gabor_Ophelia_viragai','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/ophelia_viragai','','','','',5,0,0,0,0,0,0,'Array-0-0','2008-11-30','Dr. Németh György Gábor, 06-30-5023-222, ideiglenes: 1072 Budapest, Dob u. 46/a., állandó: 1121 Budapest, Árnyas út 14.','nemethgyo@freemail.hu','','„Az álmod éjjel játszódik, s te egyedül vagy a gyerekkori otthonodban. Az ágyban fekve arra riadsz fel, hogy valaki odakint járkál a kertben. Leszaladsz a földszintre, és kinézel az ablakon. Eleinte semmit nem látsz, csak a vaksötétet, majd hirtelen egy arc jelenik meg az üveg túloldalán. Egy szőrös férfiarc. A vonásai durvák, a képe sebhelyes, a tekintetéből kegyetlenség árad. Megpróbálja kinyitni az ablakot, de nem jár sikerrel, így hát továbbsiet, hogy keressen egy titkos helyet, ahol bejuthat. Megpróbálod megelőzni. Minden ajtót és ablakot be kell zárnod, mielőtt odaérne. Versenyt futtok egymással. 
De a konyhaajtó mindig utoljára marad, s mire odajutnál, ő már a házban van.” ','2012. február: 40 példány megvásárlásával lezárás, a maradék példányok a cégé.

2009.ZKI:181+1=182

091214: Várjuk meg a Fok-ta jelentését, aztán kapjon fogyásit.

Szerződésmódosítás kiküldve 2010.02.23.
',1224574565,1332706416,0);
