INSERT INTO books VALUES('',0,'','','',0,0,0,0,1,'http://books.google.hu/books?printsec=frontcover&id=fRv5fQfs8A8C#v=onepage&q=&f=false',1,'',10,40,'',100,20,350,1000,1000,2,NULL,0,11,2008,97,'Pozsgai Zsolt','Szeretlek, fény - történelmi játékok, társadalmi drámák, bohózatok','978-963-9888-53-1',2,'','1','140x200 mm',368,'0',2990,2,'#LC3,LGVI,LGraklap#   T:G,B:V','http://adlibrum.hu/Pozsgai-Zsolt/','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','http://bookline.hu/product/home!execute.action?id=76861&type=22&_v=Pozsgai_Zsolt_Szeretlek_feny','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/szeretlek_feny_tortenelmi_jatekok_tarsadalmi_dramak_boh','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','','','',3,0,0,0,0,0,0,'2008-10-0','2008-11-0','ideiglenes: 1021 Budapest, Hüvösvölgyi u. 6. 30-279-1324','pozsgaizsolt@vipmail.hu','','Vak Béla, Mátyás király, Janus Pannonius, Balog úr a nyolcadik kerületből, egy tucat közép-amerikai prostituált, nagyhangú olasz család, klasszikus francia bohózati alakok mind megférnek ebben a kötetben. Pozsgai Zsolt /1960/ legújabb drámakötete a műfaji sokféleség jegyében született. Megtalálható itt érzékeny történelmi színmű, abszurd komédia, társadalmi dráma, bűnügyi játék, és két, álnéven írt bohózat. A szerző egész eddigi életműve a műfaji sokrétűséget képviseli. Eredeti darabjaival, musical-szövegkönyveivel, vagy színpadi átdolgozásaival gyakran találkozhatunk a színházakban. Nem csak itthon, egyre gyakrabban külföldön is. A kötetben található művek egy kivételével már kiállták a színpad próbáját, nagy sikerrel mutatták be, és játszották, vagy játsszák ma is őket. Olvasva is élvezetes  és kitűnő szórakozást nyújtanak.','2009.ZKI:2+236=238+1=239


091214: Nem kell neki decemberben fogyási. (G)',1225098412,1451300848,1);
INSERT INTO books VALUES('',0,'','Sary_Gyula-FD.jpg',424,'',1,0,3,21,'http://books.google.hu/books?printsec=frontcover&id=CTCELfyuNAIC#v=onepage&q=&f=false',0,'',0,0,'',0,5,368,0,503,0,NULL,5,3,2009,98,'Dr. Sáry Gyula','Üres helyek trófeái','978-963-9888-54-8',2,'','1','A5',320,'0',2990,3,'#LB2, LGV#  T:G,B:V','Sary-Gyula','http://www.konyvesbolt.online/spd/978-963-9888-54-8/Dr--Sary-Gyula-Ures-helyek-trofeai-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=78788&type=22&_v=Sary_Gyula_dr_Ures_helyek_trofeai_Vadasztortenetek_kicsit_maskepp_','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/ures_helyek_trofeai','','','','',3,3,1,6,4,5,1,'Array-0-0','2009-3-5','','','Filozófikus eszmefuttatások erdőről, madarakról, fegyverekről, vadászírókról és veszendő értékekről.','Csak szenvedélyes erdőjáróknak!

Filozófikus eszmefuttatások erdőről, madarakról, fegyverekről, vadászírókról és veszendő értékekről.

Harmincegy állatmese a mátyásmadárról, a ravasz nyúlról, az Apró Vadászok Egyesületéről - és persze az erdőről.

A népszerű vadászíró (Az időről és az erdőről, Az erdőről és az eltűnt időről,  Az elveszett erdőről és a megtalált időről) újabb párbeszéde a természettel.

Az „Üres helyek trófeái” című könyvet talán a magyar vadászirodalom megújításának kísérleteként is jellemezhetném. Sok-sok évtized folyóirataiban olvasható elbeszélések és a könyvpiacon fellelhető vadászszerzők műveinek olvasása után alakult ki bennem az a meggyőződés, ellaposodás fenyegeti ezt a témát. Egyrészt csupa hurrá kimentem és a nagy kant meglőttem, miután hetekig űztem, kerestem. Másrészt kétségbeejtő fogalmazások végigkínlódása után félretett elbeszélések mondatják, hogy minden sületlenség megjelenhet. Ezek egyetlen célja az önfényezés. (E kiváló megfogalmazását e jelenségnek Csekő Sándor barátomtól tanultam.) Nincs kellő szigorú szakmai és kellő felkészültségű irodalmi kritikusi munka. Ezért néhány hagyományos elbeszélést, néhány vadászati tárgyú esszét, vadászattal  összefüggő etikai gondolatsort,  esztétikai meglátást igyekeztem becsempészni kifejezetten vadászi elbeszélésekbe. Úgy, hogy vér is folyjék. Azután travesztáltam egy jó barátom megtörtént kalandjait, jóváhagyásával, hogy a bársonyi vidámságot jelen idejű keretekben is láttassam.
Talán legnehezebb lesz elfogadtatnom azokat az írásokat, amelyek vadászszociológiai megfontolásokkal közelítenek meg nagyon szép trófeagyűjteményeket, talán túl szépeket. Amelyek jól mutatnak a falakon, de mutatva árulkodnak sok külsőség mögötti tömeglövészi teljesítményekről, és nem egyéni vadászi kvalitásokról. Sok igaz vadász ismerősöm megerősítette, nem a legmutatósabb trófeák jelentették számára a legnagyobb megszerzési nehézséget. Nem mindig az érmes trófeák elejtésének a története „aranyérmes” vadásztörténet. Sajnos az élmény nem mutatkozik a falakon, csak a mennyiség és a minőség. Az pedig ma pénzzel mérhető. Élményszerzésre modern puskásnak nincs ideje és nincs természetismerete. Igénye? Ezt nem tudom! Ebben az utolsó néhány mondatban tetten érhető az a folyamat, amelynek a vége a vadászati etika elhalása.','2009.ZKI:29+1=30

A5 lesz. A vadászkönyv gerince 17 mm, a teljes borítómérete pedig (148+17+148)x210 mm lesz (+kifutó).

Üres helyek trófeái
Vadásztörténetek – kicsit másképp

egyéb, szórakoztató irodalom, novellák',1225098533,1473762576,0);
