INSERT INTO books VALUES('',0,'','Furj_Kata-FD.jpg','','',1,0,0,16,'',0,'',10,40,'',50,5,500,500,499,2,NULL,4,3,2009,107,'Fürj Katalin','Az elefánt és a repülő szőnyegek','978-963-9888-58-6',2,'','2','A5',60,'0',1990,2,'#LB6#','Furj-Katalin','http://www.konyvesbolt.online/spd/978-963-9888-58-6/Furj-Katalin-Az-elefant-es-a-repulo-szonyegek-Ad-L','http://bookline.hu/product/home!execute.action?id=78793&type=22&_v=Furj_Katalin_Az_elefant_es_a_repulo_szonyegek','','http://www.fo.hu/hu/konyv/szepirodalom/gyerekirodalom/versek/az_elefant_es_a_repulo_szonyegek','','','','',3,3,1,7,4,5,5,'2009-1-0','2009-3-4','','bogarka7605@gmail.com','','Jött a cápa, nagy dühöngve
Támadt a medúzákra,
De arra már nem számított,
Hogy őt a páncél várja.
Így sikerült Töhinek a
Medúzákat megóvni,
A cápa egy árva kukkot
Sem mert többé már szólni. 
Egész tenger Töhötömöt
Áldotta és szerette,
Úgy gondolták, jó, hogy Isten
Páncélosnak megtette.

Azt mondom én erre nektek
Édes, kicsi gyerekek,
Ha valaki bajba kerül,
Nyújtsátok ki kezetek.','229 gr.(egy 20 kilós csomagban max. 85)

