INSERT INTO books VALUES('',0,'','',336,0,0,0,0,8,'',0,'',10,40,'',50,5,370,500,500,2,NULL,29,5,2009,110,'Gáti Vilmos','Az elfelejtett légió','978-963-9888-62-3',2,'','2','A5',278,'0',2990,2,'#C T:G Duplikálva §375.','Gati-Vilmos','','http://bookline.hu/product/home!execute.action?id=81295&type=22&_v=Gati_Vilmos_Az_elfelejtett_legio','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/az_elfelejtett_legio','','','','',3,0,0,7,4,0,0,'Array-0-0','2009-5-29','','agenda.alapitvany@t-online.hu','','Sem sarat dobálni, sem fényezni nem állt szándékomban, amikor elhatároztam, hogy leporolom annak a bizonyos régi hadseregnek az emlékét, amelyről ma még sokan őriznek személyes emlékeket, gyakran fájdalmasakat. Még többen vannak, akik csak mások tapasztalatai s véleménye alapján ítélkeznek, többnyire sommásan. Ez a sereg nem volt különleges. Jellemzői, tulajdonságai nem különböztethetők meg a kor társadalmának tulajdonságaitól és jellemvonásaitól. Ezt a sereget, még nem olyan régen, kevés kivétellel az egész magyar férfitársadalom megjárta.

A tisztek, tiszthelyettesek és a mindenkori besorozott és behívott nemzedékek a kettészakadt világban álltak fegyverben. Abban a világban, amelyben a vezérkarok térképeit befedték az atombombák és rakéták ellipszis alakú hatókörzetei,  azok a halálos ellipszisek, amelyek jelzik a területet, ahol a bomba vagy rakéta rombol és öl. A mi kis országunk térképén nem sok ilyen ábra fért el. Ezek a magyar fiatalok olyan seregben szolgáltak, amelyről szakszerűen kiszámították, hogy egy összecsapás első üteme során, vagyis napok alatt – ahogy a vezérkarban mondják – élőerőben hetven százalékos veszteséget fog szenvedni tisztekből, tiszthelyettesekből, sorkatonákból.

A kép, amit az elmúltakról alkotunk, mindig nagyon egyéni és minél bonyolultabb eseményekre emlékeztet, annál nehezebben ragadja meg a képzelet. A megélt történelmet is képesek vagyunk félreérteni. Ezért ne kárhoztassuk az utóbb születetteket, ha a járható utat keresve, elfogadják a történtekről a leegyszerűsített képet, különösen akkor, ha az a kor számukra már valóban távoli. A hősi korszakok nemzedéke, kivéve egy pár bitang árulót, csupa hősökből állt. Míg a szomorú időkre emlékezve csak gazembereket és szenvedő áldozatokat vélnek felismerni. 

Pedig a később kárhoztatott, sötétnek tartott korszakokban is az élvezték emberek a napsütést, átéltek örömöket, ismerték a barátságot, a szerelmet, az orgazmust. Mindez vonatkozik e könyv témájára és szereplőire egyaránt.  Ne taszítsuk el, és főként ne vessük meg őket, amiért rossz korban születtek.
                                                                  *****

Megkérdeztük a szerzőt, mennyiben tekintendő a regény életrajzi ihletésűnek?
 
„Ez a könyv a fantáziaterméke, nem életrajz, nem egyfajta emlékirat. Felhasználtam viszont tapasztalataimat és élményeimet, ahogy  másokét is, – amiért elnézést kérek tőlük – és szétosztottam mindezt a regény erre alkalmas, vagy alkalmas helyzetben lévő szereplői között. Így azután, noha valóban olvashatunk valahol másutt megesett történeteket, valahonnan ismerős figurákról, de azonosítható személyt nem találunk.','2009.ZKI:4+304=308+1=309
G: 4 hiányzik (313 kellene)


regény, szórakoztató

borító kész!
2009.dec.fogy.j. kiküldve MK',1225885804,1382893426,1);
INSERT INTO books VALUES('',0,'','Zeus_Bratis-FD.jpg','','',1,0,0,28,'',1,'',10,40,'',21,20,342,300,300,2,NULL,7,1,2009,111,'Zeus Bratis','A Nagy Piramis egy világtérkép','978-963-9888-63-0',2,'','2','A5',168,'0',2490,2,'#LB3,LG6#   Pozsonyi Zénó','Zeus-Bratis','http://www.konyvesbolt.online/spd/978-963-9888-63-0/Zeus-Bratis-A-Nagy-Piramis-egy-vilagterkep-Ad-Libr','http://bookline.hu/product/home!execute.action?id=78156&type=22&_v=Bratis_Zeus_A_Nagy_Piramis_egy_vilagterkep','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tarsadalomtudomany/a_nagy_piramis_egy_vilagterkep','','','','',3,3,1,8,4,5,1,'2008-12-0','2009-1-7','Pozsonyi Zénó, 70-578-2176, Állandó: 3527 Miskolc, Soltész N.K. 1 2/5, Ideiglenes: 3529 Miskolc, Középszer u. 32 3/2;','pozsonyi.zeno@freemail.hu','','A Nagy Piramis maga a földgolyó négyszögesített mása. Az ősök akarták, hogy így legyen. Egy izgalmas utazásra hívja az embert a bolygónkon, a Földön, és olyan tájakra kalauzol el, amelyek fontos szerepet töltöttek be az emberi civilizáció kialakulásának hajnalán.
 A könyv részletesen magyarázza el, mily módon lehet a piramis belsejében lévő kamrákat földrajzi helyszíneknek megfeleltetni. A felvázolt elméletben nincsenek fiktív vagy bizonytalan tényezők. Kizárólag a piramisban megtalálható jelekből olvasva épül fel egy tökéletes összefüggésrendszer. Mindig is ott volt a szemünk előtt, de csak most vált világossá! A gigászi épület által szolgáltatott pontok a térképen jelölik a kincs helyét. És hogy mi is ez a KINCS? A legnagyobb, amire ember áhítozhat: TUDÁS AZ EMBERISÉG MÚLTJÁRÓL. 
','2009.ZKI:74+1=75
ingyenes kiadású akcióban

szerző polgári neve: Pozsonyi Zénó
2009.dec. fogyj. kiküldve MK',1226317853,1461231758,0);
INSERT INTO books VALUES('',0,'','Toth_Attila-FD.jpg','',0,1,0,0,18,'',1,'',40,65,'','',NULL,NULL,'',100,0,NULL,0,12,2008,112,'Tóth Attila','A vasfüggönytől Schengenig - Hatvan év emlékezete','978-963-9888-64-7',2,'','1','A5',120,'0',1990,1,'#LA2','Toth-Attila','http://www.konyvesbolt.online/spd/978-963-9888-64-7/Toth-Attila-A-vasfuggonytol-Schengenig---Hatvan-ev','http://bookline.hu/product/home!execute.action?id=77458&type=22&_v=Toth_Attila_A_vasfuggonytol_Schengenig_Hatvan_ev_emlekezete','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tortenelem_politika/a_vasfuggonytol_schengenig_hatvan_ev_emlekezete','http://www.konyvesbolt.online/spd/978-963-9888-64-7/Toth-Attila-A-vasfuggonytol-Schengenig---Hatvan-ev','','','',3,0,0,0,0,0,0,'Array-0-0','2008-12-0','06-20-310-8332','muangthai@freemail.hu','Szarkasztikus korrajz az 50-es évektől máig.','A szerző apró kis epizódok révén igyekszik érzékeltetni a kort, amelybe beleszületett és élt, a múlt század ötvenes éveinek elejétől napjainkig. A könyv helyenként enyhén szarkasztikus formában fejti ki mondanivalóját, főleg tényszerű adatok, konkrét helyszínek és nevek megadása nélkül. A leírt élmények, érzetek nemcsak a magyar valóságra terjednek ki, olvashatunk a szerző visszaemlékezéseiről a volt Szovjetunió és a nyugati világ kapcsán is.
Mivel az írás egyfajta korrajz is akar lenni, nem szerepelnek benne olyan jellegű személyes momentumok, amelyek nem illeszkednek a múlt és jelen társadalmi valóságához. Nem kizárt azonban, hogy az Olvasó ráismer bizonyos helyszínekre, esetleg konkrét személyekre is.','20 példány kipostázása, amint visszaér a Lírától.

2009.ZKI:4+1=5,ebből 3 db írónak átadva

Adásvétel 091228-án: 12 db = 13834 Ft',1226324112,1451387302,0);
INSERT INTO books VALUES('',0,'','Kiss-Gyorgy-FD.jpg','',2,1,0,0,26,'',1,'',5,30,'',30,20,200,300,300,2,NULL,0,12,2008,113,'Kiss-György Rita, Kiss-György László','Jegyesség, házasság, gyermeknevelés - Praktikus tanácsok házasságra készülők számára','978-963-9888-65-4',2,'','1','A5',132,'0',1990,2,'#LA4#','Tanacsok-hazassagkoteshez','http://www.konyvesbolt.online/spd/978-963-9888-65-4/Kiss-Gyorgy-Rita-Kiss-Gyorgy-Laszlo-Jegyesseg-haza','http://bookline.hu/product/home!execute.action?id=77461&type=22&_v=Kiss_Gyorgy_Rita_Kiss_Gyorgy_Laszlo_Jegyesseg_hazassag_gyermekneveles','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/jegyesseg_hazassag_gyermekneveles_praktikus_tanacsok_hazzassagra_keszul','http://www.konyvesbolt.online/spd/978-963-9888-65-4/Kiss-Gyorgy-Rita-Kiss-Gyorgy-Laszlo-Jegyesseg-haza','','','',3,3,1,8,4,5,1,'Array-0-0','2008-12-0','Kiss-György Rita, 06-70/530-57-57, 8000 Székesfehérvár, Erzsébet út 2.; László: 30/605-06-21','kgyrita@freemail.hu','','Amikor a fiatalok felfedezik magukban, hogy szerelmesek, egyre jobban meg akarják ismerni választottjukat.

Az udvarlás, együtt járás és főként a jegyesség időszakának a célja, hogy egymást minél korrektebben és józanabbul megismerjék, kedvesük családján keresztül és a különböző élethelyzetekben való reagálásuk alapján. A jegyesség időt ad arra is, hogy tervezgessük közös életünket, egyeztessük elképzeléseinket és kiderüljön, valóban összeillünk-e.

A házassággal megkezdődik a közös élet, amely nem lesz zökkenő- és konfliktusmentes, bármennyire is úgy gondolja a fiatal pár, de megfelelő előzetes felkészüléssel, türelemmel, egymásra figyeléssel, szeretettel, együttes erővel sok probléma elkerülhető, megoldható.

Könyvünkben összefoglaljuk a jegyességgel, a házassággal, gyermekvállalással és gyermekneveléssel kapcsolatos legfontosabb tudnivalókat, hogy a leendő házasok, szülők, akik házasság vagy gyermekvállalás előtt állnak, teljesebbé tehessék családi életre való felkészülésüket.','2009.ZKI:25+1=26

ingyenes kiadású akcióban
2009.dec. fogyj. kiküldve MK

',1226483925,1451385098,0);
INSERT INTO books VALUES('',0,'','Csaky_Istvan-FD.jpg','','',1,0,0,27,'',0,'',10,40,'',50,20,324,500,500,2,NULL,0,12,2008,114,'Csáky István','Elhitelezett Magyarország - A magyar nemesek és taksások emlékének','978-963-9888-67-8',2,'','1','A5',170,'0',2490,2,'#LB2# 230 g','Csaky-Istvan','http://www.konyvesbolt.online/spd/978-963-9888-67-8/Csaky-Istvan-Elhitelezett-Magyarorszag---A-magyar-','http://bookline.hu/product/home!execute.action?id=77558&type=22&_v=Csaky_Istvan_Elhitelezett_Magyarorszag_A_magyar_nemesek_es_taksasok_emlekenek','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/elhitelezett_magyarorszag_a_magyar_nemesek_es_taksasok_eml','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-12-0','Coware Kft., 1035 Ágoston u.1.','cowarekft@gmail.com','','Felbomlik az Egyesült Államok. Nem lesz meglepő, mert Magyarország hasonló hitelbűnözés következtében - igaz lassabban - de felbomlott. A bomlást a reformkórokozók: Széchenyi, Kossuth, Deák és Andrássy azonos sablont követve oltották az ország testébe. A sötét magyar értelmiségnek, amikor Széchenyi Hiteléből gépel ki egymondatos idézeteket, fogalma sincs, hogy Széchenyi egy szót nem írt a hitelről. Könyvecskéje a váltót isteníti (ezt ma derivatívnak hívják), ami kivonja a pénzt a gazdaságból. Magyarország folyamatos lezüllését a nyugati vámdiszkrimináció és az uzsorahitelekkel társított váltókereskedelem okozta, amit a fenti névsor tagjai erőltettek az országra.
Aki elolvassa a könyvet maga döntheti el, hogy a jelenlegi globális pénzügyi válság, amit egyenes adásban közvetít a televízió, mennyiben hasonló ahhoz, amit Magyarországon a reformkorral indítottak el. A könyv a magyar nemességnek és parasztságnak állít emléket, akik együtt voltak áldozatai ennek a pénzügyi terrorizmusnak, és akiknek utódai most is ennek a túszai. Szomorú tény, hogy az egész folyamatot sokan és világosan látták, de szavuk pusztába (könyvbe) kiáltott szó maradt. Szeretnénk az olvasó emlékezetét felfrissíteni.','2009.ZKI:1+354=355+1=356

091214: Nem kell neki számlázni decemberben, csak fogyási jelentés. De a tartozását ki kell belőle hajtani. (G)
