INSERT INTO books VALUES('',0,'','Mester_Gyorgyi_II-FD.jpg','','',1,0,0,3,'',1,'',40,80,'','',NULL,NULL,'',100,0,NULL,0,12,2008,115,'Mester Györgyi','Fehéren, feketén - válogatott novellák','978-963-9888-68-5',2,'','1','A5',206,'0',1990,1,'#LB5#','Mester-Gyorgyi','http://www.konyvesbolt.online/spd/978-963-9888-68-5/Mester-Gyorgyi-Feheren-feketen---valogatott-novell','http://bookline.hu/product/home!execute.action?id=77459&type=22&_v=Mester_Gyorgyi_Feheren_feketen_valogatott_novellak','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-12-0','','mestergyorgyi@freemail.hu','','Egészen más ember az, akinek bensőjét örökké a tűz égeti, s mardossa a vágy. És valóban, ő, a Férfi ilyen volt. Égetnivalóan csalárd, csalfa és hűtelen, és ha nem is azért, de annak ellenére, szerették. És sokan szerették, vagy megkapni szerették volna. Tulajdonképpen mindegy is volt az, csak szóba álljon, évődjön velük, hozzájuk érjen azzal a hosszú ujjú, férfiasan elegáns kezével. Simítsa a karjukat, karolja a vállukat, futólag, mintegy véletlenül érintse derekukat, hajoljon a nyakuk felé, elhitetve velük, hogy akár egy leheletnyi csók is megeshet…jobb híján elegendő volt egy átható, jelentőségteljes pillantás, vagy egy mély meghajlással kísért találó, érzékletes, olykor csupán csipkelődő bók. Odavoltak érte a nők, és ő tudta ezt. Tudatosan, vagy tudattalanul, de vissza is élt vele. Udvarolt és potyázott, ahol csak tudott. Alig akadt nő a kisvárosban, akinek ne lett volna valamiféle élménye vele. De ezen túl is, az elszegényedett, de magára még sokat adó... fiatal férfi feltűnő jelenség lévén, gyakran szerepelt a helyi lapok címoldalán, és nem csak a nőügyei miatt. 
Ha valahol bált rendeztek, ott bizton lehetett számítani az ő megjelenésére, és várható volt cirkusz is. Túlzás lett volna őt botrányhősként emlegetni, ugyanakkor valóban dolgozott benne valamiféle tudatos, vagy tudattalan, egészséges szereplési vágy... 
És hogy milyen volt a külseje? Hát amilyennek elképzeljük a nők bálványát. Sármos, délcegen magas, csinos arcú, jókötésű, izmos férfiállat, szép barna szemekkel, fekete hullámos hajjal, és hová is lenne egy tüzes amorózó a hetyke bajusz, s az ápolt szakáll nélkül? Íme, a hiteles kép róla.','2009.ZKI:3+29=32+1=33

fizetős',1227695150,1467279682,0);
INSERT INTO books VALUES('',0,'','Srychy--Reiki--FD.jpg','','',1,0,0,22,'',1,'',10,40,'',50,5,160,500,500,2,NULL,20,4,2009,116,'Srychy','REIKI a természet ereje','978-963-9888-69-2',2,'','2','140x200 mm',96,'0',1990,2,'#LA6,LGsalgó# T:G B:V Tóth Gábor','Reiki','http://www.konyvesbolt.online/spd/978-963-9888-69-2/Srychy-REIKI-a-termeszet-ereje-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=79968&type=22&_v=Srychy_Reiki_a_termeszet_ereje','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/reiki_a_termeszet_ereje','','','','',3,0,0,7,0,0,0,'2008-11-0','2009-4-20','Tóth Gábor, ...303029239','srychy@citromail.hu','','Tóth Gábor
(Srychy)
Tradicionális Reiki Mester


Ezt a könyvet azért írtam meg, mert mint minden, a Reiki is fejlődik. Fejlődik, bár nem mindig jó irányba. A tradíciókat fenn kell tartani, ha azok jók, helyesek. Ami téves az úgyis lemorzsolódik. Azt látom, hogy a Reikis társadalom létszámának növekedésével, kezd elveszni az a tanítás, amiről igazából a Reiki szól. Azt vettem észre, hogy a gyógyítás tanítását tették előtérbe mestertársaim. Ez nem helyes, mert a Reikinek ettől magasztosabb célja van. 
Számtalan módszer létezik a különböző betegségek kezelésére, az ezoterikus és a hagyományos orvoslás terén. Mindig annak a híve voltam és vagyok, hogy előzzük meg a betegséget. Éljünk úgy, hogy a betegség elkerüljön. Ha már bekövetkezett a baj, akkor sem az ellenséget, hanem inkább a barátot, a tanítást ismerjük fel benne.

Srychy','2009.ZKI:4+302=306

091214: Nem kell számlázni, csak fogyási.
2009.dec.fogy.j.kikülve MK

szerző polgári neve: Tóth Gábor

