INSERT INTO books VALUES('',0,'','Zsiros_Andras--Hobbinyultenyesztes--FD.jpg',273,'',1,0,0,43,'http://books.google.hu/books?printsec=frontcover&id=XY_6Rca5UgwC#v=onepage&q=&f=false',1,'',10,40,'',50,5,348,500,510,2,NULL,26,2,2009,117,'Zsiros András','Hobbinyúltenyésztés - a tervezéstől a kiállításokig','978-963-9888-70-8',2,'','2','148x210 mm','188+8','0',2990,2,'#LD;LG régi salgó#','Hobbinyul','http://www.konyvesbolt.online/Hobbinyultenyesztes','http://bookline.hu/product/home!execute.action?id=78809&type=22&_v=Zsiros_Andras_Hobbinyultenyesztes_A_tervezestol_a_kiallitasokig','','','','','Zsiros_Andras--Hobbinyultenyesztes','Zsiros_Andras--Hobbinyultenyesztes',3,3,0,6,4,0,1,'2008-11-0','2009-2-26','30/256-7046, 2200 Monor Munkácsy u 16;','amon29@citromail.hu','Fajták kiválasztása, elhelyezés, takarmányozás, betegségek és kezelésük,  párosítás és még sok más. 8 oldal színes kép.','﻿Amennyiben ön vagy gyermeke nyúltartáson, illetve tenyésztésen gondolkodik, először is el kell döntenie, milyen fajtát szeretne, 
mekkora helye van az állatok számára, és hogy mennyi időt tud fordítani a majdani kedvenceire. Ezekben és még néhány kérdésben
szeretne segíteni ez a könyv: pl. a fajták kiválasztása, elhelyezés, takarmányozás, betegségek és kezelésük,  párosítás.
Ezeken felül pedig a kiállítások felépítéséről, a bírálatról, a nyúltenyésztő szervezetekről, is olvashat a kedves olvasó.

Remélem, mindenkinek jó szórakozás és segítség lesz ez a könyv.
Eredményes állattartást és kellemes kikapcsolódást kívánok minden leendő és gyakorlott nyúltartónak!','2009.ZKI:275+1=276
-15 db szerzőnek jan. végén


2009.dec.fogy.j.kiküldve MK',1227695903,1472545327,0);
INSERT INTO books VALUES('',0,'','Bender_Mate-FD.jpg','','',1,0,0,2,'',1,'',40,70,'','',NULL,NULL,'',100,0,NULL,0,12,2008,118,'Bender Máté (A.Sz.)','Hintázó körökben','978-963-9888-71-5',2,'','1','A5',106,'0',1990,1,'#LB6#','Bender-Mate','http://www.konyvesbolt.online/spd/978-963-9888-71-5/Bender-Mate-A-Sz--Hintazo-korokben-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77460&type=22&_v=Bender_Mate_A_Sz_Hintazo_korokben','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/hintazo_korokben','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-12-0','','mtbender1@gmail.com','','A szerző már 2001-ben részesült a Gyermek-, Ifjúsági és Sportminisztérium, valamint a Diák- és Ifjúsági Újságírók Országos Egyesületével közös szakmai elismerésében, az Arany Titán díjban (Az Év Ifjú Írója), költői pályája tehát nem új keletű. Sejtelmes, gyakran kérdőjelszerű verseiben - melyek fő témái a halál, a szerelem, a transzcendenssel való kapcsolat - a vissza-visszatérő önvizsgálat a világban való lét értelmének keresésére irányul, kontemplatív művei pedig a teremtés apró csodáiról szólnak.
Bender Máté a klasszikus poétikai hagyományhoz nyúl vissza, s azok elemeiből építkezik.  Alkalmaz ugyan manapság divatos eljárásokat - pl. az intertextusok direkt  írása (József Attila vagy Hermann Hesse művének megidézésével) -, versei mégis leginkább az ezerkilencszázhúszas-harmincas évek klasszicizáló hagyományával rokoníthatók. Bármilyen poétikai eljárással is él, kötetének versei szintetikus egésszé, zárt, átgondolt kompozícióvá állnak össze, alkotásmódjukban letisztult, egységes képet mutatva.


Rózsafalvi Zsuzsanna

irodalomtörténész','',1227696127,1460714998,0);
INSERT INTO books VALUES('',0,'','Arany_Janos--John_Arany--Utazas_a_jovobe-FD.jpg',272,'',1,0,0,18,'',0,'',10,40,'',0,5,302,0,510,0,NULL,6,2,2009,119,'Arany János','Utazás a jövőbe - Egy kivándorlás története','978-963-9888-73-9',2,'','2','A5',204,'0',1990,1,'#LB6,LGIV#','Arany-Janos','http://www.konyvesbolt.online/spd/978-963-9888-73-9/Arany-Janos-Utazas-a-jovobe---Egy-kivandorlas-tort','http://bookline.hu/product/home!execute.action?id=80116&type=22&_v=Arany_Janos_Utazas_a_jovobe_Egy_kivandorlas_tortenete','','','','','','',3,3,4,7,4,0,5,'Array-0-0','2009-2-6','Arany János Canada/szerződésben','john.arany@gmail.com','Pozsonyból Jugoszlávián Kanadába, ahol emigránsként kell helyt állni.','Arany János, a szerző Pozsonyban született és nevelkedett, a Duna utcai magyar gimnáziumban érettségizett 1964-ben. Apai oldalról az elődjei Tamásházáról származnak, több száz évre visszamenően igazolható, hogy az elődök a csallóközi község lakosai voltak.

1969-ben kapta meg a mérnöki diplomáját a Pozsonyi Közgazdasági Egyetemen. A következő évben egy festői cseh kisvárosban, Český Krumlovban volt katona. 1970 szeptemberében munkába állt az ENSZ fejlesztési programja keretében működő Számító Kutató Központban, Pozsonyban. 1973-ban megnősült, felesége Zsuzsanna, kozmetikus, a szenci magyar iskola tanulója volt. 

1977 nyarán aztán nekivágtak a nagyvilágnak. Magyarországon keresztül Jugoszláviába utaztak szabadságra, ahonnan kalandos körülmények között mentek át Ausztriába. Bécsben három hónapig dolgozott a szakmájában, majd karácsonyra megérkeztek Torontóba.

Mindmáig Torontóban élnek és János egy nagy bankban a személyi számítógéprendszerek teljesítményének a felmérésével foglalkozó kis munkacsoport vezetője.','2009.ZKI:5+1=6


önéletrajz',1228815439,1472722092,0);
INSERT INTO books VALUES('',0,'','',332,0,0,0,0,13,'',1,'',5,30,'',18,5,543,200,210,1,NULL,9,2,2009,120,'Eric Asvak','Vér/vonal - Harc a létezésért','978-963-9888-72-2',2,'','2','140x200 mm',269,'0',2700,2,'#LD,LGII,LGV#  Sepsikné Erika','Eric-Asvak','http://www.konyvesbolt.online/spd/978-963-9888-72-2/Eric-Asvak-Ver-vonal---Harc-a-letezesert-Ad-Librum','','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/vervonal_harc_a_letezesert','http://www.konyvesbolt.online/spd/978-963-9888-72-2/Eric-Asvak-Ver-vonal---Harc-a-letezesert-Ad-Librum','','','',3,3,1,8,4,5,0,'2008-12-6','2009-2-9','Sepsik Istvánné, 06–48/411–515; 06–30/502–4994, 3700 Kazincbarcika, Rózsa út 10/b.','furafiu@citromail.hu','','Évszázadokkal ezelőtt egy puccskísérlet után a vagyonától megfosztott Collins-dinasztia megmaradt harcosai a Birodalom határán kívül lévő, független bolygóra menekültek. Utódaik alapították meg a Vadászok Rendjét, és az idő múlásával békésebb módszerrel hozzájutottak a császári trónhoz is. 
A legbefolyásosabb Nagy Ház azonban történetünk kezdetén már csak három emberből áll...

Ronald Parker, a vadászok Vezére vágyai nyomán és Rendje érdekében kizsarol a Birodalom uralkodónőjétől egy trónörököst. Egy peremvidéki származású vadászát társítja a nagy múltú dinasztia leszármazottjához, s ezzel akaratlanul is az események olyan láncolatát indítja el, amelybe beleremeg a Vadászok Rendje.

Ideiglenes szövetségek, érdekbarátságok, titkok, csapdák, szerelmek kusza hálója – kegyetlen játszma két kíméletlen és kiszámíthatatlan ember között.
Harc egymással - egymásért.
Az életük a tét.
Az ellenfél a jutalom.','2009.ZKI:1+101=102+1=103

fantasy
2009.dec.fogyj.kiküldve MK',1228815755,1451302282,1);
INSERT INTO books VALUES('',1,'','Balogne--Dialectology--FD.jpg','',0,1,0,0,35,'http://books.google.hu/books?printsec=frontcover&id=UGpth2xTx_sC#v=onepage&q=&f=false',0,'',5,20,'',50,5,176,500,500,2,NULL,29,1,2009,121,'Balogné Bérces Katalin','Beginner`s English Dialectology: An Introduction to the Accents and Dialects of English','978-963-9888-44-9',2,'','1','148x210 mm',129,'0',1990,2,'#LB5# T:szerző B:V','Dialectology','','','','http://www.fo.hu/hu/konyv/tankonyv/nyelvkonyvek/beginners_english_dialectology','','','Balogne--Dialectology','',5,3,1,8,4,5,1,'Array-0-0','2009-1-29','06-30-4053950, Állandó: 3023 Petőfibánya Puskin köz 4., Ideiglenes: 1154 Budapest Pöltenberg u. 46.','bbkati@yahoo.com','﻿This textbook provides an overview of the accents and dialects of the English language.','﻿This book provides an overview of the accents and dialects of the English language. Its primary target audience is advanced (especially BA) students of English, who have a pretty good command of (standard) English and some background knowledge of English pronunciation and grammatical terminology. The first half of the book surveys the major regional dialects of English, in comparison to the standard varieties, concentrating on pronunciation differences. Then the book takes the differences between Standard British English and Standard American English under scrutiny: besides pronunciation, vocabulary, grammar and spelling differences are also discussed. Each chapter concludes with questions and exercises for revision and practice, followed by lists of recommended further reading and electronic links, all meant to motivate the students to do further browsing and research.


Katalin Balogné Bérces is a Lecturer in English Linguistics at Pázmány Péter Catholic University (PPKE) and teaches various courses on English phonology, syntax and dialectology.
','MEK-be került 2016-02-22.

Lezárva 2015-12-22. 1 referencia példány maradt.

2009.ZKI:2+240=242+1=243


tudomány
2009.dec. fogyj. kiküldve MK',1228816314,1456139558,1);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,3,'',0,'',0,30,'',50,5,317,300,305,2,NULL,12,3,2009,122,'Kovács Gergő','Frö(c)csögés - Fröccs mellett fogyasztható történetek','978-963-06-6421-9',3,'SzolidArt Vizuális Műhely Egyesület','2','A5',104,'0',1990,2,'LEZÁRVA #B7 SzolidArt Vizuális Műhely Egyesület','Kovacs-Gergo','','http://bookline.hu/product/home!execute.action?id=79711&type=22&_v=Kovacs_Gergo_Fro_c_csoges','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/froccsoges','','','','',5,3,0,0,4,0,0,'2009-1-0','2009-3-12','2084 Pilisszentiván, Táncsics M. u. 7.','info@szolidart.hu','','„A rend a sarokban cigarettázott és lenéző vigyorral követte az eseményeket.`` 

Kovács Gergő bármelyik novellájának végére odabiggyeszthette volna ezt a kis fricskát. A történetek mindennapiak, tálalásuk a szokatlan. Bárki magára ismerhet a kisszerű drámák mélységeiben és magasságaiban, ha ugyan vannak. Konvencionális értelemben véve ritkán bírnak mondanivalóval, rendszerint a jófajta humorral fűszerezett fordulatokban az is elrejtőzik. Mégis magával ragadóan szórakoztató az impulzivitás, heherésző gőg, irigyelhetően megvalósított, lazába váltott félszegség, amelyek mögött valódi élményeket sejtünk. Ez a kötet szemüveg, amelyen keresztül a vidéki srác pesti egyetemistaként majd dolgozó fiatalként értelmezi újra a valóságot és szembesül saját jelentéktelenségével.  Szemlélő pózban ír, megfigyel, mint egy néző, leül a kedvenc asztalához, kikéri a következőt, a többi csak megtörténik.  Cselekedetei legtöbbször mellőzik az idilli és elvárt viselkedésnormákat, kocsmaszagú esték, éjszakák és hajnalok mámorába torkollanak. A történetekben félhomályos italkimérések kétes szereplői, régi cimborák, szép lányok és kevésbé szépek sorjáznak és koccintgatnak nagy egyetértésben.','Lezárva 2010.12.15-én.

2010.12.03.: 70 pld. a #B7-en

2009 ZKI:76+1=77
novellás
2009.dec. fogyj. kiküldve MK',1228816545,1301056199,0);
INSERT INTO books VALUES('',0,'','E-BOK-FD.jpg','','',1,0,0,19,'',0,'',10,20,'',50,5,554,300,310,2,NULL,5,3,2009,123,'Bialkó-Hermán László Gergő','e-BOK avagy Válogatás a kortárs naplóírók munkáiból','978-963-9888-74-6',2,'','2','B5',366,'0',2990,2,'#LG régi salgó,doboz# LEZÁRVA->§449','e-BOK','','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/e_bok_avagy_valogatas_a_kortars_naploirok_munkaibol','','','','',5,3,1,9,4,5,1,'2009-1-0','2009-3-5','','bialko.laszlo@gmail.com','','Ezt a könyvet mintegy nyolcvanan írták. Legtöbbjük nem ismeri a másikat, soha nem is találkozott a többi szerzővel. Nyolcvan történet, amely Magyarországon, Franciaországban, Angliában és az Egyesült Államokban játszódik – többek között. Nyolcvan egyedi hang és legalább ennyi, ha nem több személyiség. A szerzőkben egyetlen dolog közös: bloggerek. Az interneten vezetik naplójukat. Közkinccsé teszik titkos gondolataikat, vágyaikat. Írnak boldogságról, depresszióról, szerelemről, gyűlöletről, erotikáról, apátiáról.
Ha Önnel valamely város, valamely utcáján szembejönne egy szerző, nem ismerné fel. A neve sem csengne ismerősen. E könyv nyolcvan szerzőjének többsége elbújik a világhálón egy fantázianév, egy előre megtervezett (vagy hirtelen felindulásból kitalált) virtuális entitás mögé.
A könyvben olvasható történetekbe nem nyúltunk bele, ezért előfordulhat, hogy az olvasó olyan szöveggel is találkozik, amelyben nincsenek ékezetek vagy éppen a mondatok kisbetűvel kezdődnek. Ez nem a lustaság, vagy a hozzá nem értés következménye. Így írnak ők.
Ez a könyv, bár vaskos, csak nagyon kicsi szelete a magyar blogkultúrának. Mégis tanulságos, szórakoztató és talán még tanít is. 

Bialkó László Gergő – szerkesztő

A bevételből a Peter Cerny Alapítványt támogatjuk.  ','2009.ZKI:1+156==157+1=158


091202: 80 pld.-t számláztunk szerz. szerint, nem fizette ki, nem lehetett megtalálni. Októberben megígérte, hogy fizet, és két tételben 40e Ft-ot kifizetett. Tartozik 45.500 Ft-tal. (G)
2009.12.8.megigérte hogy 2 részletbe fizet, a mai nap és dec.16 körül. Ez évben rendezi a szláját.MK
