INSERT INTO books VALUES('',0,'','Kuklai_Katalin--90_napos_dieta--FD.jpg',148,0,1,0,0,29,'',0,'',10,40,'',50,5,'121,2',500,500,2,NULL,20,3,2009,124,'Kuklai Katalin','A 90 napos diéta','978-963-9888-75-3',2,'','2','148x210 mm',100,'0',1990,2,'#LA2# T:G B:V illusztrációkkal','Kuklai-Katalin','http://www.konyvesbolt.online/spd/978-963-9888-75-3/Kuklai-Katalin-A-90-napos-dieta-Ad-Librum-2009','','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/a_90_napos_dieta_receptek_mozgasprogram_meditacio','http://www.konyvesbolt.online/spd/978-963-9888-75-3/Kuklai-Katalin-A-90-napos-dieta-Ad-Librum-2009','','','',3,0,0,7,3,0,0,'2009-2-0','2009-3-20','30/422-0476; 1144 Budapest, Ond vezér útja 39. VII./29.','kuklaikata@freemail.hu','Tanácsok és receptek a 90 napos diéta sikeréhez.','Létezik egy módszer, amelynek segítségével éhezés, kalóriaszámlálgatás és szenvedés nélkül lehet megszabadulni a súlyfeleslegtől. 90 nap alatt akár 15-20 kg-ot is fogyhat, ha ezt a diétát választja.

A módszer részletes leírásán túl ízletes, változatos, könnyen elkészíthető ételek receptjeit tartalmazza a könyv.

Bár a 90 napos diéta akkor is hatásos, ha egész idő alatt a fotelban üldögél, javítja a kúra hatásfokát, ha sportolni is kezd. Ehhez szintén talál tippeket a könyv lapjain.

Ami pedig egyedülálló a fogyókúrás kötetek között: meditációs programra és „lelki mankókra`` támaszkodhat, ha segítségre van szüksége az életmódváltáshoz.


Vágjon bele! Ezreknek már sikerült!','2009.ZKI:9+1=10
egészség, egyéb


2009.dec. fogyj. kiküldve MK',1229337109,1451384811,0);
INSERT INTO books VALUES('',0,'','',317,0,0,0,0,30,'http://books.google.hu/books?printsec=frontcover&id=m1PxXkCoN50C#v=onepage&q=&f=false',0,'',10,40,'',50,5,282,500,500,2,NULL,20,3,2009,125,'Dr. Szabó Erika','Házi tünetmagyarázó - Fejfájás, hasi fájdalom, láz, lapozza fel, mi okozhatja','978-963-9888-76-0',2,'','2','A5',232,'0',2490,2,'#LA2#','Dr-Szabo-Erika','http://www.konyvesbolt.online/spd/978-963-9888-76-0/Dr--Szabo-Erika-Hazi-tunetmagyarazo---Fejfajas-has','http://bookline.hu/product/home!execute.action?id=79712&type=22&_v=Szabo_Erika_dr_Hazi_tunetmagyarazo','','http://www.fo.hu/hu/konyv/szakkonyv/orvosi/hazi_tunetmagyarazo_fejfajas_hasi_fajdalom_laz_lapozza_fel_mi_okozh','http://www.konyvesbolt.online/spd/978-963-9888-76-0/Dr--Szabo-Erika-Hazi-tunetmagyarazo---Fejfajas-has','','','',3,0,0,7,4,0,0,'Array-0-0','2009-3-20','','drszabo@mhcable.com','','Tüneteket, szervezetünk jelzéseit minden nap tapasztaljuk valamilyen formában. A tünetek, bár sok esetben kellemetlenek, nagyon fontos információk  szervezetünk működéséről. A fájdalom különböző testrészekben, izgatottság, kézremegés, étvágytalanság, memóriazavarok, zsibbadás, emésztési zavarok, ájulásérzés, szaglás, ízérzet csökkenése, mind fontos jelzések, amikkel a szervezet tudtunkra adja, hogy valamilyen szervi vagy működési hiba történt. Mivel a betegség meghatározása nem egyszerű a tünetekből, kezdő nővér koromban elkezdtem egy gyorsan átlátható diagnosztikai szerszám összeállítását, amit az egyetemi évek során bővítettem, és most megosztok önnel. A tünetek, tünetcsoportok listája gyors áttekintést ad például a lázat okozó betegségek okaira, mik okozzák, ha kísérő tünetként  fejfájás, köhögés, hányinger, szédülés, duzzadt nyirokcsomó, bőrkiütés társul hozzá. Milyen betegségek okozhatnak hasi fájdalmat, mik lehetnek a kiváltó okok amikor a hasi fájdalmakat láz, fejfájás, hányinger kíséri. Célom nem a laikus öndiagnosztika elősegítése, hanem az ön és orvosa közreműködésének megkönnyítése. Minél tájékozottabb a páciens, annál pontosabban képes tüneteit elmondani, aminek következménye a tünetet kiváltó okok gyorsabb megállapítása és kezelése. A könyvben szintén talál információt számos betegség tüneteinek rövid ismertetéséről, a betegellátásban, gyógyszer és gyógynövényhasználatban előforduló hibákról és betegségek kialakulásának megelőzéséről, valamint kevésbé ismert tünetekről, az öregedés folyamatának lassításáról. ','2009.ZKI:18+1=19

egészség/életmód

2009.dec. fogyj. kiküldve MK',1229337902,1451384281,0);
INSERT INTO books VALUES('',0,'','','','',0,0,8,4,'http://books.google.hu/books?printsec=frontcover&id=nRoMNghIsZcC#v=onepage&q=&f=false',1,'',10,40,'',50,5,210,500,500,2,NULL,4,6,2009,126,'Kamocsay Ildikó','Bovary kisasszony','978-963-9888-77-7',2,'','2','148x210 mm',152,'0',2290,2,'#LB5,LGI,LGVI# C T:G B:V','Kamocsay-Ildiko','http://www.konyvesbolt.online/spd/978-963-9888-77-7/Kamocsay-Ildiko-Bovary-kisasszony-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81296&type=22&_v=Kamocsay_Ildiko_Bovary_kisasszony','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/bovary_kisasszony','','','Kamocsay_Ildiko','',3,3,1,7,4,0,0,'Array-0-0','2009-6-4','','racka@monornet.hu','','Kamaszkoromban olvastam először a Bovaryné-t, s azóta nem hagy nyugodni, vajon mi lett a sorsa a Bovary-házaspár ötévesen árván maradt kislányának, Berthe-nek. Flaubert néhány ecsetvonása is elég volt hozzá, hogy megelevenedjék, s képes legyen megszólítani az embertársadalom tagjait. Kezdeti, még gyermekded kíváncsiságom az évek során egyre kínzóbbá vált: vajon mi lett vele? Mindinkább úgy éreztem, hogy a vérrokonságnál is szorosabb szálak fűznek hozzá, s  végül rádöbbentem: én tudom, mi lett vele!
Engedjék hát meg, hogy bemutassam önöknek a már felnőtt leányt, embertársaságunk új vendégét:
– Hölgyeim és uraim, Berthe Bovary!','2009.ZKI:246+1=247


