INSERT INTO books VALUES('',0,'','','',0,0,0,0,4,'http://books.google.hu/books?printsec=frontcover&id=cybQV7QZ2UUC',0,'',10,40,'',50,5,210,500,500,2,NULL,4,2,2009,127,'Ivánfy Jaksity György','A nagymenő','978-963-9888-78-4',2,'','2','A5',170,'0',2490,2,'#LB6  nem áruljuk a maradék példányokat','Ivanfy-Jaksity-Gyorgy','','http://bookline.hu/product/home!execute.action?id=78159&type=22&_v=Ivanfy_Jaksity_Gyorgy_A_nagymeno','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/a_nagymeno','','','Ivanfy_Jaksity_Gyorgy-A_nagymeno','',5,0,0,6,4,1,0,'2008-12-0','2009-2-4','1113 Budapest, Tarcai u. 17.',' dr.jaksity@bszsz.hu ','','Ivánfy Jaksity György gazdag és sokszínű élettapasztalata alapján írta meg legújabb, immáron negyedik regényét, mely a fővárosban munkát kereső vidéki fiatalokról szól, akik megszokott környezetükből kiszakadva, szüleiktől, családjuktól távol, gyökértelenül hányódnak, s szeretetre éhesen keresik egymást a házibulikon, az üzemi mulatságokon… és az éjszakában.
Két fiatal nem mindennapi szerelmi története bontakozik ki a regényben.
A fiú az ismételten sikertelen egyetemi felvétel kilátástalanságától megkeseredve hozzácsapódik az éjszakai élet örömeit gátlástalanul habzsoló „nagymenők”-höz. Megszédíti a nagyváros bűnös élete, elvakítja a talmi csillogás, a mindenre kapható lányok odaadása, a könnyen jött pénz.
A lány értetlenül áll ezzel a változással szemben. Sokáig nem tudja levetkőzni a falu szigorú erkölcsi normáin alapuló gátlásait, és amikor megteszi, bár ne tette volna, mert ebből erednek a tragédiához vezető bonyodalmak.
A szerző arra keres választ, hogy tud-e győzni az emberség egy hazugságra épülő, igazságtalan világban. Elég lesz-e a lány fegyvertára, aki „csak” a szerelmét, egy családi otthon szegényes és bizonytalan jövőjét kínálhatja cserébe. Lesz-e erejük jól, rosszul megkötni kompromisszumaikat, vagy az önpusztító csalóka vidámság embert próbáló kísértése győz az otthonról hozott kötelességtudat, a szerény, de emberibb élet reménye fölött?','2009.ZKI:291+2=293


091214: Nem kell neki számlázni decemberben, csak fogyási jelentés. (G)
2009.dec.fogy.j.kiküldve MK

szépirodalom, regény',1229340392,1413273104,0);
INSERT INTO books VALUES('',0,'','Toth_Jozsef--Tudomanyos_elorehaladas--FD.jpg','','',1,0,0,43,'',1,'',40,65,'','','','','',100,0,NULL,19,2,2009,128,'Dr. Tóth József','A gyorsabb tudományos előrehaladás útjai és buktatói','978-963-9888-80-7',2,'','2','A5',80,'0',1990,1,'#LB2#','Dr-Toth-Jozsef','http://www.konyvesbolt.online/spd/978-963-9888-80-7/Dr--Toth-Jozsef-A-gyorsabb-tudomanyos-elorehaladas','','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/a_gyorsabb_tudomanyos_elorehaladas_utjai_es_buktatoi','','','','',3,3,1,6,4,0,3,'Array-0-0','2009-2-19','','cadmas@upcmail.hu','Plagizáljunk a sikerért? De mi is az a plagizálás, és hol vannak a határai?
A kötet áttekinti a tudományos előrejutás elérésnek helyes és helytelen útjait mind szerzői jogi, mind etikai szempontból.','A könyv hosszú évek egyetemi oktatói, tudományos kutatói, valamint gyakorlati szaktanácsadási és publikálási tevékenység alapján kíséreli meg segítséget nyújtani diákoknak, kezdő és nem kezdő oktatóknak és kutatóknak, a tudományos munkában történő gyorsabb előrehaladáshoz.

Most kivételesen nem tudományos munkát kíván közreadni, hanem saját tapasztalatok alapján tett megállapításokat, következtetéseket.

Segítséget szeretne nyújtani a buktatók elkerüléséhez is, ahhoz, hogy bárki a gyorsabb előrehaladás érdekében szerzői jogok megsértésével jusson tudományos érdemekhez. Éppen ezért jelentős teret szentel a szerzői jogi törvénynek, a jogsértő technikák ismertetésének, s a jogsértés ellen való védekezések lehetőségének és hatékonyságának, vagy hatástalanságának az ismertetésére. Konkrét eseteket is felvillant a szerzői jogsértések eseteiről.

Csupán rövid összefoglalást ad, hogy a szerző tapasztalatai szerint melyek a tudományos kutató legfontosabb jellemvonásai, s kikből, hogyan lehetnek egyetemi oktatók, illetve tudományos kutatók. Végül nagyobb teret szentel annak, hogy általános és konkrét segítséget nyújtson a gyorsabb tudományos előrehaladáshoz.

A célul kitűzött feladat nem könnyű, s biztosan nem sikerül maradéktalanul megoldani. Annál inkább nem, mert a könyv igen röviden, könnyen olvasható formában kíséreli meg a célul kitűzött problémakör tárgyalását.  ','2009.ZKI:9+1=10


borító ``akadémikus``, azaz kép nélküli lesz, mint az Online-os könyv

borító megrendelve jan. 20-án',1229595211,1461144760,0);
INSERT INTO books VALUES('',2,'','Kerekes_Gabor--Zwei_Jahrhunderte--FD.jpg','',0,1,0,0,41,'http://books.google.hu/books?printsec=frontcover&id=vD1O6DFl4F0C#v=onepage&q=&f=false',1,'',10,10,'','','','',50,100,0,NULL,10,4,2009,129,'Gábor Kerekes','Zwei Jahrhunderte der deutsch-ungarischen literarischen Kontakte. Interkulturelle Studien','978-963-9888-79-1',2,'','1','140x200 mm',140,'0',2490,1,'#LB5#',' Gábor Kerekes','http://www.konyvesbolt.online/spd/978-963-9888-79-1/Gabor-Kerekes-Zwei-Jahrhunderte-der-deutsch-ungari','','','','http://www.konyvesbolt.online/spd/978-963-9888-79-1/Gabor-Kerekes-Zwei-Jahrhunderte-der-deutsch-ungari','','Gabor-Kerekes','',3,2,1,7,4,1,0,'2008-11-0','2009-4-10','06-26-331-695','kegahu@yahoo.de','','','2009.ZKI:21+1=22',1230021087,1451380689,0);
INSERT INTO books VALUES('',0,'','Nemeth_Dezso--Uj_Minotaurusz--FD.jpg','','',1,0,13,3,'',1,'',40,65,'','','','','','',0,NULL,20,3,2009,130,'Németh Dezső','Új Minótaurosz','978-963-9888-81-4',2,'','2','A5',78,'0',1990,1,'#LA4+#LG10','Nemeth-Dezso','http://www.konyvesbolt.online/spd/978-963-9888-81-4/Nemeth-Dezso-Uj-Minotaurosz-Ad-Librum-2009','','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/egyeb_felnottirodalom/uj_minotaurosz','','','Nemeth_Dezso','',3,3,0,7,4,5,5,'Array-0-0','2009-3-20','(30)431-7837; 1211 Bp. Ady E. út 5. 3/10.','nemethdezso@windowslive.com','','Az „Új Minótaurosz” című kisregényemben feltaláltam azt a módszert, amellyel elkerülhetjük a halált. Feltaláltam az űrhajó nélküli űrutazást, és egy új elméletet világunk keletkezésére. A halál leküzdése: ez az elérhetetlennek tűnő vágy, talán a legszebb és legértékesebb értelme az ember életének. Életérzéseink tárolásával örökké élhetünk, de az ember mesterséges biológiai tenyésztése konfliktusokhoz vezet. Óriási dilemma elé kerülnek a kutatók, amikor az Isten tulajdonának tekintett életet teremtenek. Különösen akkor, amikor az esendő ember szexuális vágyainak kielégítésére használják a mesterséges lányokat, vagy katonai célokra hoznak létre biológiai lényeket.
De a föld alá zárt Minótaurosz, aki tenyésztett és igazi sejtekből áll, fellázad bezártsága ellen. 
Apjával, a biológia professzorával, kemény vitát folytat.
Az ember a legnagyobb ragadozó. Öröklött gyarlóságai miatt – hatalomvágy, gazdagság, élvezet – zsarolásra, kínzásra, gyilkolásra lesz képes. A Földön, a fajok fennmaradásának alapja, a gyengébb elpusztítása. De felcsillan a remény, mert létrejön a Pontész, a hatalmas tudású, szintézist teremteni képes agy, akár egy Isten. De addig is a terroristákkal kell harcolnunk, és ebben segítenek bennünket egy másik bolygóról idetévedt hullámemberek.','2009.ZKI:34+1=35

sci-fi

borítórendelés febr. 9-én
szerzőhöz márc. 4-én
',1230027685,1460714551,0);
INSERT INTO books VALUES('',0,'','Kovacs_Laszlo--Az_ehes_ornagy--FD.jpg','',0,1,0,0,3,'',1,'',40,65,'','',NULL,NULL,'',50,0,NULL,6,2,2009,131,'Kovács László','Az éhes őrnagy','978-963-9888-82-1',2,'','2','140x200 mm',60,'0',2100,1,'#LB2','Kovacs-Laszlo','http://www.konyvesbolt.online/spd/978-963-9888-82-1/Kovacs-Laszlo-Az-ehes-ornagy-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=78529&type=22&_v=Kovacs_Laszlo_Az_ehes_ornagy','','','http://www.konyvesbolt.online/spd/978-963-9888-82-1/Kovacs-Laszlo-Az-ehes-ornagy-Ad-Librum-2009','','Kovacs_Laszlo','',3,3,3,6,4,3,3,'2008-12-21','2009-2-6','1/220-1413, 1144 Budapest, Tihany út 42-44. fsz. 12.','laszlone.kovacs@chello.hu','','Kovács László 
Sárváron született 1944-ben. Szülővárosa gimnáziumában tett érettségije után az ELTE bölcsészettudományi karán és a Szombathelyi Tanárképző Főiskolán tanult. Évtizedekig állt a katedrán, pályafutása a budapesti Hajnik Károly Közgazdasági Szakközépiskolában töltött tizenöt év könyvtáros tanári és némettanári működéssel zárult. 
Novellái, kis karcolatai a KLÁRIS irodalmi-kulturális folyóirat és a Magyar Fórum hasábjain jelentek meg. Ez első kötete. A címadó novella első változatát a www.regenytar.hu 2005. évi Novellapályázat rovata publikálta.','2009.ZKI:1+1=2',1230027923,1451299138,0);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,13,11,'http://books.google.hu/books?printsec=frontcover&id=aN_vOwbdSTIC#v=onepage&q=&f=false',0,'',10,40,'',50,5,274,500,500,2,NULL,4,2,2009,132,'Nácsa János','A Csontváry-kód, avagy nem esik messze a macska a fájától','978-963-9888-84-5',2,'','2','140x200 mm',240,'0',2490,2,'#A6 B:V LEZÁRT','Nacsa-Janos','','http://bookline.hu/product/home!execute.action?id=78155&type=22&_v=Nacsa_Janos_A_Csontvary_kod_avagy_nem_esik_messze_a_macska_a_fajatol','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_csontvary_kod_avagy_nem_esik_messze_a_macska_a_fajatol','','','Nacsa_Janos','',5,3,0,0,4,0,1,'2009-1-15','2009-2-4','Nácsa János, 30/292-4233, 7623 Pécs, Csend u. 20.','nacsajanos@freemail.hu','','Zseni vagy őrült? Csontváry Kosztka Tivadarral kapcsolatban nehéz ezt a kérdést megválaszolni, de talán kiegyezhetünk döntetlenben. Röpiratai, újságcikkei, valamint az önéletrajza legalább olyan rejtélyes, mint bármelyik festménye. Önmagát Raffaellónál sokkal többre tartotta, és volt annyira talányos, hogy Leonardo is elbújhatna mögötte Mona Lisástól, Utolsó vacsorástól, Sion-rendestől együtt. 
Ez a szatirikus krimi észbontó szituációkba kergeti hőseit, és zseniálisan tárja fel Csontváry titkait. Kiderül, hogy a festő pécsi kiállítását olyanok is látogatják, akik nemcsak a művészetében szeretnének gyönyörködni. Sötét céljaik megvalósítása érdekében nem riadnak vissza a képhamisítástól, az emberrablástól, valamint a gyilkosságtól sem. Ahogy a botcsinálta magánnyomozó egyre jobban belegabalyodik a szövevényes ügybe, úgy válik nyilvánvalóvá számára, hogy nem csupán néhány vagyont érő festmény tulajdonjoga a tét. Mindezek tetejébe még maga a mester is tiszteletét teszi a helyszínen, segítve saját kódja megfejtését.','2011.11.01. Az utolsó példányok visszarendelésével és elküldésével zártuk a kiadást. A Líra 5 példányos utolsó eladását még fel kell vezetni.

2010.10.27: Ajánlat cégeknek:
5 példány felett ingyenes postázás, 10 példány felett 30% engedmény, 20 példány felett 40%, 30 példánytól pedig 50% kedvezmény. A weblapon nem lesz meghirdetve, az Ön exkluzív ajánlata. Ön felé ezeket viszonteladós kategóriával számoljuk el.

2009.ZKI:2+214=216+1=217

2009.dec. fogyj. kiküldve MK',NULL,1323530037,0);
INSERT INTO books VALUES('',0,'','Boronkai_Dora--Tarsalgaselemzes--FD.jpg',254,'',1,0,37,35,'http://books.google.hu/books?printsec=frontcover&id=n8zPv3yFFfcC#v=onepage&q=&f=false',0,'',10,40,'',40,5,300,400,400,2,NULL,6,10,2009,133,'Boronkai Dóra','Bevezetés a társalgáselemzésbe','978-963-9888-89-0',2,'','2','A5',200,'0',2990,2,'#LB4, LGII#','http://adlibrum.hu/Boronkai-Dora/','http://www.konyvesbolt.online/spd/978-963-9888-89-0/Boronkai-Dora-Bevezetes-a-tarsalgaselemzesbe-Ad-Li','http://bookline.hu/product/home!execute.action?id=83695&type=22&_v=Boronkai_Dora_Bevezetes_a_tarsalgaselemzesbe','','http://www.fo.hu/hu/reszletes_kereso?kButton=1&h_gyorskereso=Boronkai&x=0&y=0&=Keresd','','','Boronkai-Dora','',3,3,0,7,4,5,0,'2009-8-31','2009-10-6','30/848-6445 (régi: 70/279-9889) Új cím: 7030 Paks, Tolnai u. 6/b.','boronkaidori@freemail.hu','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai?','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai? Miért nem akadályozzák meg a hibák és hibajavítások a spontán beszélgetések megértését, és hogyan segítik szerveződésüket? Milyen mentális folyamatok és interakciós szabályok lépnek működésbe a hétköznapi nyelvi tevékenység során? A fentiekhez hasonló kérdésekre választ keresve a szerző egy olyan tudományág bemutatására tesz kísérletet, amelynek átfogó ismertetése magyar nyelven eddig még nem jelent meg. Az első fejezetekben számba veszi a társalgáselemzés előzményeit, alapfogalmait, főbb kutatási területeit, majd bemutatja az elemzés módszertani lépéseit és alkalmazási lehetőségeit. A könyv a külföldi szakirodalom és a hazai empirikus kutatások eredményeit ötvözi, megállapításait saját gyűjtésű, beszélt nyelvi szövegkorpuszból származó példák segítségével támasztja alá. A szerző a Pécsi Tudományegyetem Illyés Gyula Főiskolai Karának adjunktusa, számos spontán nyelvhasználattal foglalkozó publikáció szerzője. Doktori disszertációját a társalgások szövegtani jellemzőiről írta kognitív nyelvészetből. A gazdag nyelvi példaanyaggal illusztrált könyv a témához kapcsolódó kutatómunkájának szintézise, amely hasznos módszertani segítséget nyújthat a spontán nyelvhasználat további empirikus vizsgálatához, hiánypótló összefoglaló és oktatási segédanyag lehet a felsőoktatásban, és ajánlható mindazoknak, akik többet szeretnének tudni a hétköznapi, spontán helyzetekben történő kommunikációról.','2011.11.02. Új cím: 7030 Paks, Tolnai u. 6/b.

2011.03.23. - 30 példány egyelőre elszámolás nélkül postázva.

