INSERT INTO books VALUES('',0,'','Olomlabu_Tonya--Allj_vagy_elaslak--FD.jpg','','',1,0,20,18,'',1,'',40,65,'','','','','',1000,0,NULL,19,2,2009,139,'Ólomlábú Tonya','Állj vagy eláslak! - szemelvények a lapátos alakulatok életéből','978-963-9888-85-2',2,'','2','148x200 mm',206,'0',2190,1,'#LD#  RB1c Ferwagner Antal T:G,B:V Ny:Mondat','Olomlabu-Tonya','http://www.konyvesbolt.online/spd/978-963-9888-85-2/Olomlabu-Tonya-Allj-vagy-elaslak---szemelvenyek-a-','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/allj_vagy_elaslak_szemelvenyek_a_lapatos_alakulatok_eletebol','','','Olomlabu_Tonya--Allj_vagy_elaslak','Olomlabu_Tonya--Allj_vagy_elaslak',3,3,3,6,4,1,3,'2009-1-6','2009-2-19','Ferwagner Antal','antal.ferwagner@t-online.hu','','Te is ott voltál? Ha igen, akkor tudod, hogy mi az a lapátos alakulat; ha pedig nem volt benne részed, akkor most egy „élménnyel`` gazdagabb lehetsz. Ja! – nem is voltál katona? Csórikám, nem is tudod, mit vesztettél. Mi, akik részt vettünk ebben az állami pénzen szponzorált kalandban, mi tudjuk – két (gyengébbek másfél) évet pazaroltunk el az életünkből. Igaz, ezt nem vettük észre, mert a 70-es és a 80-as években még nem volt ilyen gyors a világ, a Czinege-korszak lassan csordogált a csámpásan kitaposott medrében. Két évet vesztegettünk el, de nem feleslegesen. Hihetetlen kalandokban volt részünk, amely felkészített minket az élet árnyas oldalának derűs elviselésére.

Nem ajánlom továbbá ezt a könyvet feleségemnek, mert piszkosul kiakad tőle, ha elolvassa. Remélem, ennél tovább nem jut, és bevágja a sarokba.','A borítóelképzelések és illusztrációk a CD-n.

szórakoztató irodalom, egyéb',NULL,1466762093,0);
INSERT INTO books VALUES('',0,'','Kun_Attila--A_multinacionalis_vallalatok_szocialis_felelossege--FD.jpg',550,0,1,0,43,34,'',1,'',40,65,'','',5,351,'',500,0,NULL,16,6,2009,140,'Kun Attila','A multinacionális vállalatok szociális felelőssége - CSR-alapú önszabályozás kontra (munka)jogi szabályozás','978-963-9888-86-9',2,'','2','A5',312,'0',4500,1,'#LB2,LGIII-IV#   RG','Kun-Attila','http://www.konyvesbolt.online/spd/978-963-9888-86-9/Kun-Attila-A-multinacionalis-vallalatok-szocialis-','http://bookline.hu/product/home!execute.action?id=81677&type=22&_v=Kun_Attila_A_multinacionalis_vallalatok_szocialis_felelossege','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/a_multinacionalis_vallalatok_szocialis_felelossege_csr_alapu_onszabalyoza','http://www.konyvesbolt.online/spd/978-963-9888-86-9/Kun-Attila-A-multinacionalis-vallalatok-szocialis-','','','',3,3,0,7,2,0,0,'2009-4-1','2009-6-16','30/345-8032 - 2235 Mende, Dózsa Gy. út 77.','kunattila@freemail.hu','A piacelvű elváráson túli szociális felelősség taglalása a multik, a világszervezetek (ENSZ, OECD, EU) és a közpolitika szemszögéből.','``CSR - ugyanaz a fogalom sorsa, mint a demokrácia vagy a civilizáció kifejezéseké? Minél többet használjuk, annál kevesebbet tudunk róla, egyben annál többféle értelmezése létezik. Mi a CSR? A vállalatok jótékonykodása, mely valódi arcukat fedi el? Avagy a közjóért elkötelezett felelős vállalatvezetés? Aki ezt a könyvet elolvassa már nem ugyanúgy fog gondolkodni a világról, mint korábban.`` (Ligeti György, CSR szakértő, Kurt Lewin Alapítvány).

„Hiányzott idehaza egy ilyen könyv, amely a CSR elterjedésének több tudományban, munkajogban, szociológiában, szociálpolitikában, politikatudományban felhalmozott nemzetközi tapasztalatait összegzi. A 2008-ban megindult pénzügyi, gazdasági válsággal való küzdelmek közepette különösen izgalmas a gazdálkodók társadalmi felelősségéről és az ezt erősíteni hivatott közpolitikákról folyó tudományos, ideológiai, közpolitikai vitákba belelátni.” (Simonyi Ágnes, szociológus, c. egyetemi tanár, Szociálpolitikai és Munkaügyi Intézet − Főigazgató)

 „A munka kísérletet tesz arra, hogy meghatározza és elemezze a CSR és a munkajog, munkaügyi szabályozás viszonyrendszerét. E tekintetben a munka hiánypótló a magyar munkajogi szakirodalomban. Érdekes és tanulságos olvasmány lesz minden munkaügyi kapcsolatokkal, munkajoggal és menedzsmenttel foglalkozó kolléga számára.” (Prof. Hajdú József egyetemi tanár, Szegedi Tudományegyetem) 

„Kun Attila munkája az első magyar jogászi megközelítésű könyv erről a témáról. Mi is a CSR Kun Attila könyvében? A nemzetközi munkajog félig optimista, félig realista válasza a globalizálódó munkaerőpiac által generált problémákra.” (Gyulavári Tamás)


A könyv megjelenését a Kurt Lewin Alapítvány támogatta. ','2011-08-05: #RG 159 pld.

2009.ZKI:32+80=112+1=113
',NULL,1451381485,0);
INSERT INTO books VALUES('',0,'','Atrox_Teuton--Az_elatkozott_grofsag--FD.jpg',526,'',1,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=ZppUG9MtvxgC#v=onepage&q=&f=false',1,'',10,40,'',50,5,500,500,500,2,NULL,28,7,2009,141,'Atrox N. Teuton','Az elátkozott grófság','978-963-9888-97-5',2,'','2','148x210 mm',400,'0',3290,2,'#LB4,LGVI,LG23# #RB1 T:G B:V Szeder Norbert Attila','Atrox','http://www.konyvesbolt.online/spd/978-963-9888-97-5/Atrox-N--Teuton-Az-elatkozott-grofsag-Ad-Librum-20','http://bookline.hu/product/home!execute.action?id=82274&type=22&_v=Teuton_Atrox_N_Az_elatkozott_grofsag','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/az_elatkozott_grofsag','','','','',3,3,1,7,4,0,0,'2008-12-0','2009-7-28','Szeder Norbert Attila, 1203 Budapest, Ősz utca 20., 06-30-904-3465','atrox@inf.elte.hu','Nagyszabású fantasy regény.','Atanar a civilizációtól távol, egy gyors folyású, hegyi patak partján tér magához. Megdöbbenve tapasztalja, hogy emlékeit elvesztette, eddigi életéből semmire nem emlékszik. Ki ő? Honnan jött? Hová tart? A múlt felderítésére egyetlen esélye egy rövid levél, mely átázva kerül elő mellénye zsebéből. Ennek nyomán elindul, hogy felderítse múltját, ám hamarosan megtapasztalja, hogy ez nem olyan egyszerű dolog. Útja során számtalan ellenséget, akadályt kell leküzdenie, mert ez a világ veszélyes, és a gyengék nem sokáig élnek. Azonban értékes barátokra is szert tesz kalandozásai során. És közben egy percre sem felejti el célját: felkutatni elveszett múltját. A nyomok végül egy távoli grófságba vezetnek, ahol furcsa dolgok történnek…','2009.ZKI:10+220=230
fantasy

2009.dec.kiküldve MK',NULL,1467197604,0);
INSERT INTO books VALUES('',0,'','Mary_Morgan--Selina--FD.jpg','',0,1,0,0,14,'',1,'',10,40,'',50,5,350,500,500,2,NULL,31,3,2009,142,'Mary Morgan','Selina, a vámpírboszorkány','978-963-9888-87-6',2,'','2','A5',320,'0',2990,2,'#LA4 425 gr. Balogh Orsolya','Mary-Morgan','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','','http://www.fo.hu/hu/konyv/szepirodalom/ifjusagi_irodalom/regenyek/selina_a_vampirboszorkany','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','Mary_Morgan--Selina','Mary_Morgan--Selina',3,3,1,7,4,1,1,'2008-12-0','2009-3-31','BALOGH ORSOLYA, 30/522-53-21, állandó: 1221 Budapest, Leányka u. 32. IX/58.; ideiglenes: 1225 BUDAPEST AKÓ U. 26.','morgan333@freemail.hu','Egy lány, aki tizennyolc éves koráig csak ember volt... majd egyszerre lett vámpír és boszorkány.','Biztos hogy csak ember vagy? 
Egy lány, aki tizennyolc éves koráig csak ember volt... majd egyszerre lett vámpír és boszorkány. Soha vissza nem térő alkalom a Mágiába és a Vámpírok a Birodalmába való belépéshez. Ahol megismerkedik a szerelem és a vér ízével. Démonok és Angyalok szüntelen harca. 
De a kettős életnek ára van. Nem lehet egyszerre két oldalon állni. A Halál örökké elkíséri.
Döntsd el, Te melyik oldalon állsz?
','2009.ZKI:17+1=18 G:OK 100106

