INSERT INTO books VALUES('',0,'','Jade_Dorado--Erinthetetlen--FD.jpg',447,'',1,0,11,12,'',1,'',10,40,'',25,5,783,100,100,3,NULL,28,5,2009,145,'Jade Dorado','Érinthetetlen','978-963-9888-96-8',2,'','2','A5',390,'0',3490,2,'#LB2+LG27# Péter Anita','Jade-Dorado','http://www.konyvesbolt.online/spd/978-963-9888-96-8/Jade-Dorado-Erinthetetlen-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81298&type=22&_v=Dorado_Jade_Erinthetetlen','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/erinthetetlen','','','Jade_Dorado--Erinthetetlen','',3,3,1,7,4,5,1,'2009-1-16','2009-5-28','Péter Anita, 8132 Lepsény, Zengő  Dülő 1429/2. 06 70 317 2134','flycomp@gmail.com','Fordulatos kalandregény egzotikus helyszíneken.','Zsarad elnevette magát, és elengedte a kezét. Titó ebben a pillanatban már nagyon féltette az életét, nem is tudott figyelni a férfira, akire ha ránézett volna, látta volna, hogy nem akarja bántani és kényszeríteni semmire. Futtában leráncigálta magáról a csadort, mert zavarta a kilátásban és minden lépésében. Ekkor közvetlen mellette egy motoros állt meg, készült kitámasztani a motort a teret keretező vaskorlátnak. Titó azonnal átugrotta a korlátot, ezzel fellökve a fiatal fiút, aki a motor tulajdonosa volt, és döbbenten állt a jelenet előtt. Gyorsan berúgta és végigsöpört vele egy hosszú, keskeny utcán, ahol a köveket fényesre járták az emberek, és faltól-falig csupán két méter széles. Túl sokat kellett kerülgetnie az elélépőket, és félt, hogy Zsarad karja eléri. A sarokról egy pillanatra visszanézett, hogy Zsarad hol jár a nyomában, de az nem mozdult, hanem a kávézó teraszán állt zsebre tett kézzel, és őt nézte. Elengedte? Meg mert volna esküdni rá, hogy mosolyog.','2009.ZKI:42+1=43

kaland

2009.dec.fogy.j.kiküldve MK',NULL,1478511135,0);
INSERT INTO books VALUES('',0,'','Redenczki_Maria--Turelemfa--FD.jpg','','',1,0,20,17,'',1,'',40,65,'','','','',100,110,0,NULL,10,4,2009,146,'Redenczki Mária','Türelemfa - avagy nevel, vagy nevelem a családom?','978-963-9888-98-2',2,'','2','A5',52,'0',1990,1,'Minden saját példányt visszakapott a szerző. Tóth Miklósné','Redenczki-Maria','','http://bookline.hu/product/home!execute.action?id=79975&type=22&_v=Redenczki_Maria_Turelemfa_avagy_nevel_vagy_nevelem_a_csaladom_','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/turelemfa_avagy_nevel_vagy_nevelem_a_csaladom','','','','',5,3,0,7,4,0,0,'Array-0-0','2009-4-10','Tóth Miklósné 20/440-8700 Cím: 6000 Kecskemét. Kodolányi János utca 15. II/4.','tejbegriz@vipmail.hu','﻿Azoknak, akik okulni szeretnének egy fiatal, lelkes családanya nehézségeiből. Azoknak, akik röhögni szeretnének egy fiatal, lelkes családanya nehézségein.','﻿Azoknak, akik okulni szeretnének egy fiatal, lelkes családanya nehézségeiből.
Azoknak, akik röhögni szeretnének egy fiatal, lelkes családanya nehézségein.

Hozzávalók:

- Egy szerető, türelmes, melegszívű anyuka.
- Egy dolgos, ötletekből soha ki nem fogyó apuka.
- Egy öcsi, aki partner volt minden csínyben. 
- Egy húgi, akinek jó testvér módjára kitapostuk a biztos utat.
- Még egy öcsi, aki még évekig gondoskodik arról, hogy idős szüleit sokáig emlékeztesse arra: gyerek van a háznál!
- Végül a szerző, a legidősebb és legkisebb gyerek, aki mindezt elmondja és leírja.

S mivel az ember otthonról hozza az alapokat, így senki ne csodálkozzon a végeredményen.

Ehhez persze szükség volt:

- Egy apukára, aki mindig dolgozik, de a hosszú évek munkája nyomán (ami nekem köszönhető) mindig kapható a „mulatságra”.
- Egy elsőszülött fiúra, aki soha nem sietett el semmit, és mindig rácsodálkozott mindenre (akár többször is!).
- Egy lányra, akit nagyon annak vártunk, és akinek nem kívánok semmi rosszat, csak annyit, hogy neki is legyen egy éppilyen leánya.

Egyszóval:

Vidám családi történeteken való ámokfutás sok nevetéssel.

','Új cím: Kodolányi János utca 15. 2/4.
Cím 2015 előtt: 6000 Kecskemét, Szövetség u. 42.

2009.ZKI:1+1=2


végleges borító',NULL,1482138366,0);
INSERT INTO books VALUES('',0,'','Fust_Antal--Koronas_hegyek--FD.jpg',216,'',1,0,0,8,'',1,'',40,60,'','',NULL,NULL,'','',0,NULL,3,11,2010,147,'Füst Antal','Koronás hegyek – A Zagyva-völgyi várak regénye','978-615-5014-61-1',2,'','3','130x200 mm',192,'0',2490,1,'#LC3,LGV#  §362 folytatása, K:K,B:V,T:G','Fust-Antal','http://www.konyvesbolt.online/spd/978-615-5014-61-1/Fust-Antal-Koronas-hegyek-A-Zagyva-volgyi-varak-re','','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2010-11-3','Dr. Füst Antal, 30/353-2766, 1142 Budapest, Nezsider park 2.','antalfust@gmail.com','Történelmi rege a török idők várairól.','A Zagyva-völgyi várak megmaradt kövei ma is valami különleges erőt sugároznak. Ostromágyúk által szaggatott falaikkal, felhőkbe törő csonka lakótornyaikkal a magyarság nagy próbatételeit idézik, példát mutatnak az utókornak, vitézségből és helytállásból. A késői utódok borzongva mesélik a védők hőstetteit, menekülő alagutakról, nagy szerelmekről és még nagyobb tragédiákról suttognak. A kövek pedig továbbra is féltékenyen őrzik a titkokat.

A salgótarjáni születésű szerző a regényben olyan stílusban fűzi egybe a történelmet és a várak legendáit, mint amikor a nagyapó mesél az unokáinak.','',NULL,1460713892,0);
INSERT INTO books VALUES('',0,'','Szabo_Szilard--Asztrologia--FD.jpg','',0,1,0,0,28,'',1,'',46,70,'','',5,194,550,560,0,NULL,30,3,2009,148,'Dr. Szabó Szilárd','Mi az igazság az asztrológiáról? Amit a magyar adatok mutatnak','978-963-06-6776-0',1,'','2','',150,'0',2490,1,'#LD1,LG30# RA1','asztrologiakutatas','http://www.konyvesbolt.online/spd/978-963-06-6776-0/Dr--Szabo-Szilard-Mi-az-igazsag-az-asztrologiarol-','http://bookline.hu/product/home!execute.action?id=82006&type=22&_v=Szabo_Szilard_dr_Mi_az_igazsag_az_asztrologiarol_','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/ezoterikus_irodalom/mi_az_igazsag_az_asztrologiarol','http://www.konyvesbolt.online/spd/978-963-06-6776-0/Dr--Szabo-Szilard-Mi-az-igazsag-az-asztrologiarol-','','Szabo-Szilard--Asztrologia','Szabo-Szilard--Asztrologia',3,2,1,7,4,5,3,'2009-2-0','2009-3-30','','terinformatika@t-online.hu','','Vágó István néhány évvel ezelőtt az Origo internetes portál látogatóinak kérdéseire az alábbiakat válaszolta: 

Miért nem hisz a horoszkópban? [Dyfish.]
- Azért, mert az egész téma humbugra épül, minden állításuk légből kapott, és semmit soha nem bizonyítanak. Szívem szerint bizonyítási eljárást rendelnék el egy asztrológus ellen, hogy igazolja, honnan veszi az adatait.

Utánaolvasott a témának? Nem gondolja, hogy olyan dolgokról nyilatkozik, amit nem ismer? [zaszlorud]
- Én nyitott vagyok ezeknek a munkáknak a megismerésére, de miközben már évek óta várom, hogy asztrológus ellenfeleim bemutassanak egy ilyen tanulmányt, erre ők még nem kerítettek sort. Mindig annak kell bizonyítania, aki állít valamit, nem annak, aki kételkedik.

Nos, ez a könyv pontosan azt vizsgálja, amit az ismert műsorvezető hiányolt. A kötet első felében részletes áttekintés található az asztrológia társadalmi elfogadottságáról, valamint az elmúlt ötven évben végzett asztrológia tárgyú kutatásokról.  A második részben a szerző közel tíz éves kutatásainak első eredményei olvashatók.

Ez a munka az első, szigorúan tudományos szempontok alapján felépített kutatás Magyarországon az asztrológia tárgyában. A vizsgálat 4850 emberre terjedt ki. A kutatás teljes anyaga dokumentált, s az bármely komoly kutató számára hozzáférhető. Az adatokat a szerző a leggondosabban gyűjtötte össze, a kutatást előre lefektetett szempontok alapján végezte. 

Semmilyen előzetes hipotézist nem alkalmazott, és kifejezetten került minden spekulatív vagy irracionális elemet. Arra törekedett, hogy kizárólag csak a tényeket fogadja el. Meglepve tapasztalta, hogy a minta bármilyen vonatkozását nézte, mindenhol valami markáns jellegzetességeket tapasztalt.

Ebben a könyvben olyan tények és eredmények szerepelnek, melyeket különböző szakértők bevonásával meg kell vitatni, és a helyükre kell tenni. Újabb, komplexebb vizsgálatok serege kell. A szerző meggyőződése, hogy nem állítható szembe a hagyományos tudomány és az ezotéria. Azt vallja, hogy minden olyan jelenséget, amely bármely okból az érdeklődés homlokterébe kerül, lehet és kell is vizsgálni. A tudomány története azt bizonyítja, hogy lehetnek olyan területek, melyek kezdetben abszurdnak, „légből kapottnak” látszanak, valójában a világról alkotott ismeretünk egy másik dimenzióját nyitják meg.

A higgadt és szakszerű kutatásnak pontosan az a célja, hogy megvizsgáljon minden lehetséges állítást, és segítséget nyújtson abban, hogy a világról alkotott képünk mennél teljesebb legyen.     
','2009.ZKI:53+166=219


Határidő: Március 13 + a szerzői korrektúra ideje


',NULL,1451385008,0);
INSERT INTO books VALUES('',0,'','Jenei_Andras--Konstantin-kereszt--FD.jpg',129,0,1,0,0,4,'',1,'',40,65,'','','','',100,110,0,NULL,23,4,2009,149,'Jenei András','Nyeregben a Konstantin-kereszt','978-963-9934-01-6',2,'','2','A5',100,'0',1990,1,'#LA6','Jenei-Andras','http://www.konyvesbolt.online/spd/978-963-9934-01-6/Jenei-Andras-Nyeregben-a-Konstantin-kereszt-Ad-Lib','http://bookline.hu/product/home!execute.action?id=80376&type=22&_v=Jenei_Andras_Nyeregben_a_Konstantin_kereszt','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/nyeregben_a_konstantin_kereszt','http://www.konyvesbolt.online/spd/978-963-9934-01-6/Jenei-Andras-Nyeregben-a-Konstantin-kereszt-Ad-Lib','','','',3,3,4,7,4,1,3,'2009-4-3','2009-4-23','2040 Budaörs, Zombori u. 42., 06/30 478-7801','kispartizan@gmail.com ','Biciklis mentők.','Gyerekként mindig arra vágytam, hogy legyen egy saját biciklim. Tinédzser koromban azért tanultam tovább, hogy mentős lehessek.
Gyorsan  kikerültem az életbe, a beteg emberekkel való munka lett a hivatásom, majd az első fizetésemből megvettem az első kerékpáromat is.
Aztán elvégeztem a mentőszakápolói iskolát és a második álmom is valóra vált.
Már sok éve dolgoztam, amikor jött egy ötlet, mi lenne, ha a hobbim összekötném a hivatásommal?
Na nem találtam fel a spanyolviaszt, de jó volt elkalandozni a gondolataimban és látni, ahogy megszületik a terv, majd felépül valami…
Ebből született meg ez a történet, ami akár lehetne maga a valóság is.','2009.ZKI:22+1=23

Adásvétel 091228-án: 5 db = 4263 Ft',NULL,1451300419,0);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,2,'',1,'',5,20,'',50,5,249,200,210,2,NULL,10,4,2009,150,'Garay Zsuzsanna','Színek','978-963-9934-02-3',2,'','2','A5',60,'0',1990,2,'LEZÁRT a szerző felé','Garay-Zsuzsanna','','','','','','','','',5,3,1,7,4,1,1,'2009-2-20','2009-4-10','Bödőné Garay Zsuzsanna 1046 Bp., Megyeri út 210. 6/23. 30/4501227','otello@t-online.hu','','Néha egyetlen pillanatban, egyetlen színben, egyetlen mondatban benne van a körülöttünk zajló élet, minden ellentmondásosságával és szépségével együtt. Érzéseket, gondolatokat, színeket ragad meg rövid verseiben Garay Zsuzsanna, amit Rápolthy Ingrid illusztrációi tesznek még érzékletesebbeké.','2010. augusztusában lezárva, a maradék példányok más könyvszámon.
2009.dec. fogyj. kiküldve MK',NULL,1322639799,0);
