INSERT INTO books VALUES('',0,'','Gathy_Vera--FD.jpg',258,3,1,0,0,18,'',0,'',0,0,'','','','','',500,0,NULL,23,2,2009,152,'Gáthy Vera','Egy dinoszaurusz (nőstény) történetei','978-963-9934-00-9',2,'','2','A5',184,'0',1990,3,'#LC3, LGI#','Gáthy-Vera','http://www.konyvesbolt.online/spd/978-963-9934-00-9/Gathy-Vera-Egy-dinoszaurusz-nosteny-tortenetei-Ad-','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/egy_dinoszaurusz_nosteny_tortenetei','http://www.konyvesbolt.online/spd/978-963-9934-00-9/Gathy-Vera-Egy-dinoszaurusz-nosteny-tortenetei-Ad-','','','',3,2,0,0,0,0,0,'Array-0-0','2009-2-23','','','A neves indológus története családjáról és indiai élményeiről.','Gáthy Ve­ra 1941-ben szü­le­tett Bu­da­pes­ten. Szo­ci­o­ló­gus, for­dí­tó, az új­ko­ri In­dia tör­té­nel­mé­nek és tár­sa­dal­má­nak ku­ta­tó­ja, a tör­té­ne­lem sze­rel­me­se.
El­be­szé­lé­se­iben ro­ko­na­i­ról, ma­gyar és a vi­lág kü­lön­bö­zõ tá­ja­i­ról szár­ma­zó ba­rá­ta­i­ról ír, akik fon­tos sze­re­pet ját­szot­tak az éle­té­ben. Be­szá­mol né­hány kü­lö­nös él­mé­nyé­rõl, és idõ­rõl idõ­re szót ejt In­di­á­ról is.
Kis cso­kor­ba szed­te ös­­sze ta­lál­ko­zá­sa­it az in­di­ai ál­lat­vi­lág­gal. Hos­­szú­nak ne­vez­he­tõ pá­lyá­ja so­rán szer­zett ta­pasz­ta­la­tai alap­ján szól az öre­ge­dés­rõl, a ba­rátság­ról, a mai élet visszásságairól, bos­­szú­sá­ga­ink­ról, és ar­ról, hogy min­den tet­tünk, sza­vunk és gon­do­la­tunk a tör­té­ne­lem­ben gyö­ke­re­zik. Egyik-má­sik sze­rep­lõ­jé­nek meg­rá­zó tör­té­ne­te egye­dül­ál­ló, má­sok éle­te pe­dig olyan volt, mint bárkinek, aki a Kár­pát-me­den­cé­ben szü­le­tett és vagy ott ma­radt, vagy el­szár­ma­zott. Nincs ben­nük sem­mi kü­lö­nös, ép­pen csak olya­nok, mint mi ma­gunk, mint bár­ki­nek a fel­me­nõi, hoz­zá­tar­to­zói, sor­suk­ban fel­is­mer­he­tõ a küszködõ, ver­gõ­dõ, de tisz­tes­ség­gel vál­lalt, még­is egye­di és megismételhetetlen élet a ma­gyar tör­té­ne­lem ese­mény­te­len­nek alig­ha te­kint­he­tõ hu­sza­dik szá­zad­ában.','2009.ZKI:10+1=11',NULL,1451303176,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Ne_hagyjatok_beken--FD.jpg','','',1,1,12,4,'',0,0,0,0,'',120,5,300,90,90,0,NULL,18,8,2009,153,'P. Dobrossy Rita','Ne hagyjatok békén!','978-963-9934-09-2',2,'','2','A5',160,'0',1490,5,'#A3','Dobrossy-Rita','http://www.konyvesbolt.online/spd/978-963-9934-09-2/P--Dobrossy-Rita-Ne-hagyjatok-beken-Ad-Librum','','','','','','','',3,3,0,7,4,5,0,'2009-2-0','2009-8-18','Pásztorné Dobrozsi Rita, 45/421-051, 4600 Kisvárda, Rétalja út 1.','dobrozsirita@freemail.hu','','Szeretném megismerni az IGAZI szerelmet.

Egy nevelőintézetből kikerült csinos, fiatal lány pincérnőként helyezkedik el egy night-clubban. Az éjszakai élet szexuális kihívásairól semmit sem tud. Egyedül van. Megismerkedik egy dúsgazdag vállalkozóval, aki rengeteg pénzt kínál föl, ha vele tölt egy éjszakát. A lánynak nagyon megtetszik a fiatal, jóképű férfi. Szerelmes lesz belé. A férfit is mélyen megérinti a lány szépsége, bája. Ám kiderül, hogy a férfi AIDS betegségben szenved, ezért számára ez az utolsó szerelem lehetősége…','2009.ZKI:9+1=10

Eredetileg ingyenes kiadás, szerződés újrakötve POD-ra. A szerzői jogdíjáról a megjelenésért cserében lemondott.

A könyvmegrendelő 90 példányra a dossziéjában.

Borítórendelés 0727

borító kész! 0731

',NULL,1460368697,0);
INSERT INTO books VALUES('',0,'','Alexander_Wolf--Solo_trilogia_I--FD.jpg',296,'',1,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=wUlEjbcea70C#v=onepage&q=&f=false',0,'','','','',75,5,380,300,500,4,NULL,4,6,2009,154,'Alexander Wolf','Vámpírkard','978-963-9934-03-0',2,'','2','148x210 mm',212,'0',1990,2,'#LC1#','Alexander-Wolf','http://www.konyvesbolt.online/spd/978-963-9934-03-0/Alexander-Wolf-Vampirkard-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81303&type=22&_v=Wolf_Alexander_Vampirkard','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/vampirkard_solo_trilogia_1','','','','',3,3,0,7,4,0,0,'2009-3-10','2009-6-4','Kuklin Alekszandr lev.cím:1211.Bp.II.Rákóczi F.út 107-115. D.ép.II.12. 1118 Bp., Tűzkő u. 4. 20/992-0007','soloicewind@yahoo.com','','Te mit tennél akkor, ha rádöbbennél, hogy fokozatosan elveszíted emberi mivoltodat? És amikor rájössz, hogy nem is voltál ember soha?
Milyen örökkévaló entitásként létezni, amely meghal újra és újra, és mindig más alakban jelenik meg ismét?
Milyen érzés soha nem emlékezni az előző életeidre? A hűséges párodra sem, aki végigkísér az örökkévalóságon át, és akinél nem szeretsz jobban senkit? És aki meg sem tud szólítani, amíg megint rá nem jössz a varázsszóra, amelyet elfelejtettél, mint mindig?
Milyen az, amikor ellenfeleid között találsz nagy hatalmú istenségeket, és egész világokkal szórakozásból játszó mágusokat is, a barátaid pedig nem azok, akiknek gondoltad őket?
Milyen, amikor viszonylagossá válik a Fény és a Sötét?

Csak sodródsz, vagy megragadod a kardot, vállalva ezzel az átkot?

Milyennek látod az emberiséget kívülről, ha megtetted?
Milyen lesz vándorolni a világok között?

Akarod tudni?

A Solo Trilógia erről szól, annak az első kötetét tartod a kezedben.

Ha kinyitod, veszélyes utazásba kezdesz.
De a döntés a tiéd, hiszen Solo a Korlátlan Szabadság.

Ítéld meg te, mennyire valóságos a történet, az én szerepem csak annyi volt, hogy lejegyzeteltem.

Alexander Wolf','2014. november: A szerző lemondott a példányairól és a bevételről.


