INSERT INTO books VALUES('',0,'','Sebestyen_Adam--Marika_mesel_I--FD.jpg',695,'',1,0,0,37,'',0,'','','','','',NULL,NULL,'',210,0,NULL,25,5,2009,160,'Sebestyén Ádám','Bukovinai székely népmesék I. - Márika meséi','978-963-9934-12-2',2,'','2','B5',608,'0',2990,3,'#LC#','Sebestyen-Adam','http://www.konyvesbolt.online/spd/978-963-9934-12-2/Sebestyen-Adam-Bukovinai-szekely-nepmesek-I----Mar','','','','','','','',3,3,1,9,4,0,0,'2009-3-0','2009-5-25','Sebestyén Imre Dezső, 74/674-994,7100 Szekszárd, Csalogány u. 18., ','','Sebestyén Ádám, a bukovinai székelyek néprajzkutatója ebben a kötetben 90 gyöngyszemet gyűjtött össze.','Sebestyén Ádám a bukovinai székely telepesek története, népdalai és földművelése után népmeséik összegyűjtéséhez és a ma élő, illetve a kö­zelmúltban elhunyt kiemelkedő mese­mondók bemutatásához fogott. A bukovinai székelyektől gyűjtött népmeséket összesen 1782 oldalon négy kötetben Bukovinai székely népmesék I–IV. címmel a Tolna megyei Könyvtár adta ki 23–30 évvel ezelőtt. 
Most az I. kötet meséit ismét megjelentetjük. Ebben a kötetben a meséknek 90 gyöngyszemét ajánljuk olvasásra. A meséket  Fábián Ágostonné Márika néni mondta el, aki a mesemondó teljesítményével elnyerte a Népművészet mestere címet.
Már Sebestyén Ádámban felmerült a kétség, tudnak-e a ma élő bukovinai szé­kely mesemondók újat mondani a korábban gyűjtött mesekincs gazdag előzménye után.
Fábián Ágostonné meséinek olvastán feltétlenül igennel kell vála­szolnunk, bár hiányzik a mesék mögül a kiváló mesemondó előadói va­rázsa, mert hiszen meséit nem tőle magától halljuk, hanem kinyomtatva olvassuk. Meséi azonban még így, olvasva is igaz gyönyörűségére fognak szolgálni felnőtt- és gyermek­olvasónak egyaránt, s tanulságos nyersanyagot biztosítanak a me­sekutatónak.','11-08-07: #RA1b 20 pld. (stimmel)

Eredetileg a megrendelőnek készült 100 példány előfinanszírozásban, de később további példányokat nyomtunk saját finanszírozásban.

Bemutató pl:1 db
borítóterv szerzőhöz 04.22.',NULL,1468318336,0);
