INSERT INTO books VALUES('',0,'','Ferenczi_Krisztina--Tunodes_egy_gondolatsoron--FD.jpg','','',1,0,0,2,'',1,'',8,30,'',125,5,230,500,500,4,NULL,20,4,2009,162,'Ferenczi Krisztina','Tűnődés egy gondolatsoron - versek','978-963-9934-07-8',2,'','2','A5',126,'0',2390,2,'#LA3,LG32,LGrégi polc#','Ferenczi-Krisztina','http://www.konyvesbolt.online/spd/978-963-9934-07-8/Ferenczi-Krisztina-Tunodes-egy-gondolatsoron---ver','http://bookline.hu/product/home!execute.action?id=79974&type=22&_v=Ferenczi_Krisztina_Tunodes_egy_gondolatsoron_versek','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/tunodes_egy_gondolatsoron_versek','','','','',3,3,0,7,4,1,1,'2009-3-0','2009-4-20','Ferenczy Krisztina; 30/751-0495; Tardona, Dózya Gy. út 4.','jfkrisztina@citromail.hu','','Sok magányos éji óra szülöttei ezek a versek. Csillagokat számlálva kémleltem az éjszakai eget, mint aki keres valamit. Mit kerestem? Önmagam... Vágyakból, álmokból, káoszból igyekeztem csillagképeket építeni;  megfejteni a bennem áradó lét minden atomját; kiismerni a szelet, mi arcomhoz ér; az éji csendből dallamot szűrni; csillagfényeket olvasztani homlokom mögé... 
Szürke percek színes virágai ezek a versek. Számtalanszor álltam egyedül a tömegben, figyeltem a rohanó embereket, kik a gondjaiktól fásultan elfelejtenek élni, érezni, hinni... Sokszor éreztem vágyat, hogy csak egy szót szóljak, csak annyit: állj! Állj meg, ember; állj meg, idő!  Csak egy pillanatra, nézz fel az égre, nézz mélyen magadba: micsoda titkokat láthatsz...!

A szerző


„Mikor az éj leszáll s a csillagok feljőnek, mikor a világ szavai elhalnak, elkezd beszélni a természet, akkor a végtelen mindenség megnyílik s az ember lelke lát.”
                                                                              /Jókai Mór/ ','Bemutatópl.: 1 db
