INSERT INTO books VALUES('',0,'','',186,0,0,0,26,34,'http://books.google.hu/books?printsec=frontcover&id=4-P_YKwFY7YC#v=onepage&q=&f=false',0,'',10,40,'Hasznos ismeretek és tanácsok ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről.',250,5,160,1000,1000,4,NULL,30,4,2009,163,'Varga Géza','Menj biztosra! (Olvasókönyv biztosítósoknak és ügyfeleiknek)','978-963-9888-30-2',2,'','2','A5',128,'0',2490,2,'LEZÁRT ->§440','Menj-biztosra','','http://bookline.hu/product/home!execute.action?id=80373&type=22&_v=Varga_Geza_Menj_biztosra_Olvasokonyv_biztositosoknak_es_ugyfeleiknek','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/menj_biztosra_olvasokonyv_biztositosoknak_es_ugyfeleiknek','','','Varga-Geza--Menj_biztosra','',5,3,1,7,4,0,1,'2009-4-24','2009-4-30','Dr. Varga Géza, 70/454-7741, 3580 Tiszaújváros, Babits M. u. 2.','menjbiztosra@gmail.com','','A könyv szerzője - közgazdász képzettségű biztosítási üzletkötő - átvilágította a biztosítások világát, és bemutatja, hogy hogyan látja azt egyszerre belülről és kívülről is. Hasznos ismereteket és tanácsokat ad ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről. Rávilágít néhány, a biztosítók működésével és a biztosítások értékesítésével kapcsolatos hatékonysági problémára, és megértő empátiával firtatja a potenciális ügyfelek különböző attitűdjeit és annak okait. A szakmailag igényes tartalmat néhány színes, érzelemben gazdag olvasmány egészíti ki.

A tartalomból:

    * az élet mint szerencsejáték;
    * a biztosítások fajtái és jellegzetességei;
    * kapitalizmus és marketizmus;
    * a befektetések időzítése;
      a biztosítások értékesítésének módjai;
    * az öngondoskodás filozófiája.
','2009.ZKI:38+1=39

