INSERT INTO books VALUES('',0,'','Vasi_Szabo_Janos--Csillagpuszta--FD.jpg','',0,1,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=-fSxn4GFeWIC#v=onepage&q=&f=false',1,'',45,65,'','',NULL,NULL,'',100,0,NULL,28,5,2009,166,'Vasi Szabó János','Csillagpuszta','978-963-9888-10-4',2,'','2','A5',72,'0',1690,1,'#LB5,LG7#','Vasi-Szabo-Janos','http://www.konyvesbolt.online/spd/978-963-9888-10-4/Vasi-Szabo-Janos-Csillagpuszta-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81297&type=22&_v=Vasi_Szabo_Janos_Csillagpuszta','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/csillagpuszta','http://www.konyvesbolt.online/spd/978-963-9888-10-4/Vasi-Szabo-Janos-Csillagpuszta-Ad-Librum-2009','','','',3,3,0,7,4,0,0,'2009-3-0','2009-5-28','Vasi Szabó János, 94/711-108, 9762 Tanakajd, Kossuth L. u. 26.','vasi.szabo.janos@gmail.com','A Világállamban játszódó disztópiák és egyéb történetek.','Az első két történet a Világállamban játszódó disztópia. A  Haszontalan mágia főszereplője a szürke kishivatalnokként élő Jim Scone: kezébe kerül egy ősrégi recept. A vegyület felszabadítja az ember mentális képességeit. Scone képes lett a múltba pillantani. Így kiderítette, hogy ki erőszakolta meg brutálisan a komputerosztály csinos, fiatal alkalmazottját, aki emiatt öngyilkos lett. Ám hiába a különleges képesség, a nyomozók őt tartják tettesnek és elmegyógyintézetbe csukják.

A Kőfolyam egyrészt a Spear űrhajó parancsnokának, Estellnek és a különös planéta lakójának, Ellteának története, másrészt a Világállam nevű diktatúra utolsó éveiről, a változásról szóló novella.

A szürke ország című hosszabb elbeszélés átmenet a valós történelmi korrajz és egy fantázia szülötte jövő között. A közelmúlt eseményei: a kilencvenes évek közepe, a főhős egy pályakezdő újságíró hölgy; a jövőbeni események legyenek meglepetés...','2009.ZKI:51+2=53

borítóanyagot kértem 03.17.

borítórendelés 04.10.

szerzőhöz 04.27.

borító kész!',NULL,1451301705,0);
INSERT INTO books VALUES('',0,'','Kormendi_Janos--Utolso_figyelmeztetes--FD.jpg',252,'',1,0,3,20,'',0,'',0,0,'','',NULL,NULL,'',5000,0,NULL,20,5,2009,167,'Körmendi János','Utolsó figyelmeztetés','978-963-9888-11-1',2,'','2','148x210 mm',168,'0',1990,3,'#LC3,LGI,LGV, LGrégi salgó,LG 27,27/a#','','http://www.konyvesbolt.online/spd/978-963-9888-11-1/Kormendi-Janos-Utolso-figyelmeztetes-Ad-Librum-200','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/utolso_figyelmeztetes','','','','',3,3,3,7,0,0,1,'2009-3-0','2009-5-20','Körmendi Gabriella, 1022 Budapest, Alsótörökvész út 8., 30/9924-955, ','kgabcsi@chello.hu','A híres komikus halála előtt saját kezűleg összeállított könyve teli szórakoztató történetekkel színészekről és az élet furcsaságairól.','„A bohóc, ha meg is hal: azonnal föltámad. Elterül – és máris játszik tovább. (…) Körmendi János egyszemélyes színház volt. Bölcs és rendkívül vidám színház.”

2008 novemberében, a sírkőavatásnál Müller Péter író méltatta e szavakkal a feledhetetlen komédiást.

Aki máris játszik tovább…

Ezúttal utolsó, még életében összerendezett írásain keresztül nevettet bennünket. Megannyi árnyalattal és nyelvi leleménnyel festi elénk – Noé bárkájától kezdve a több évszázados artistacsaládon át – a közelmúlt eseményeinek történéseit. Kifogyhatatlan a színházadomákból. Nem fukarkodik pályatársainak jellemrajzával sem: Gábor Miklósról, Márkus Lászlóról, Rátonyi Róbertről, Gyenge Árpádról, Sas Józsefről, sőt még a világhírű bűvészről, Rodolfóról is lehullik a lepel…
Ironikus társadalomkritikáinak, ötletgazdag, frappáns párbeszédeinek titka: a humor és a mély emberismeret.

A kötetben szereplő fotók többsége szintén első ízben jelenik meg.

„Jó mulatást!”
','2011-06-05: 461 pld. #RG

2009.ZKI:22+430=452+2=454 G:OK!',NULL,1472716361,0);
INSERT INTO books VALUES('',0,'','Haffner_Orsolya--Ahogy_a_felnottek--FD.jpg',176,0,1,0,0,16,'',1,'',5,20,'',75,5,300,300,300,3,NULL,7,5,2009,168,'Haffner Orsolya','Ahogy a felnőttek mondanák','978-963-9888-29-6',2,'','2','140x200 mm',120,'0',1990,2,'#LB6,LG9#  T:G B:szerző','Haffner-Orsolya','http://www.konyvesbolt.online/spd/978-963-9888-29-6/Haffner-Orsolya-Ahogy-a-felnottek-mondanak-Ad-Libr','','','','http://www.konyvesbolt.online/spd/978-963-9888-29-6/Haffner-Orsolya-Ahogy-a-felnottek-mondanak-Ad-Libr','','','',3,3,0,7,0,0,0,'2009-3-0','2009-5-7','30/875-8130, 1094 Budapest, Liliom u. 34.','haffnero@yahoo.com','Egy 13 éves lány humoros kalandjai.','Vedd meg, ha szereted az olyan könyveket, amin nevetni lehet!

A könyv főszereplője egy 13 éves városi lány, aki néha komoly, néha szeleburdi családjával egy társasház második emeletén él. Bátyja, húga és osztálytársai révén vidám, kacagtató kalandokba keveredik, amelyek gyakran további gondolkodásra késztetik.

Hogyan ismerkedik meg Kitti a titkokat rejtegető fiúval, Viktorral? Hogyan kerül madárpók a pékségbe? Mi lesz Lajos bácsi, a leselkedő közös képviselő sorsa? Mit árul el a színes körmöket viselő és kissé szétszórt angol tanárnő a lánynak?

A könyvből minderre fény derül!','Vonalkódot, isbn-t átküldtem neki 03.18.
2009.dec. fogyj. kiküldve MK',NULL,1451379318,0);
INSERT INTO books VALUES('',0,'','Petrozsenyi_Nagy_Pal.-Turos_puliszka--FD.jpg','','',1,0,0,3,'',1,'',45,65,'','',NULL,NULL,'',100,0,NULL,28,5,2009,169,'Petrozsényi Nagy Pál','Túrós puliszka','978-963-9934-13-9',2,'','2','140x200 mm',334,'0',2990,1,'#LA6,LGIII#','Nagy-Pal','http://www.konyvesbolt.online/spd/978-963-9934-13-9/Petrozsenyi-Nagy-Pal-Turos-puliszka-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81302&type=22&_v=Petrozsenyi_Nagy_Pal_Turos_puliszka','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/turos_puliszka','','','','',3,2,0,7,4,0,0,'2009-3-0','2009-5-28','Nagy Pál, 06/76/41 30 35, Kecskemét, Puskás Tivadar 13.','gyanlap@hotmail.com','Cselekményes, fordulópontokban gazdag meseszövés, reális élethelyzetek, elgondolkodtató csattanók.','Cselekményes, fordulópontokban gazdag meseszövés, reális élethelyzetek, elgondolkodtató csattanók. Íme, néhány lényeges sajátosság, ami az erdélyi származású Petrozsényi Nagy Pál írásait jellemzi. Stílusa egyszerű, teljesen sallangmentes, így persze nincsenek benne sem sziporkázó stílusbravúrok, sem meghökkentő képek, gondolattársítások, melyek jelenkori irodalmunkban oly buján tenyésznek. Hogy emiatt már nem is korszerű? Bizonyos vonatkozásban valóban nem, de olyan fontos ez? Jelen és múlt, Magyarország, Erdély: két kor, két világ. Vajon vannak-e bennük közös érintkező pontok is? Mindezt bárki azonnal megtapasztalhatja, és ki tudja, talán önmagára is rábukkan, amint megízleli a Túrós puliszkát.','Új email: gyanlap@hotmail.com (2012-12-14, Régi: palnagy4@gmail.com)


