INSERT INTO books VALUES('',0,'','Rinyai--Tetrameron--FD.jpg','','',1,0,0,3,'',0,'',40,65,'','',NULL,NULL,'',100,0,NULL,5,6,2009,171,'Rinyai László','Tetrameron I.','978-963-06-7071-5',1,'','2','A5',160,'0',1100,1,'#LB6# Oberding László','Rinyai-Laszlo','http://www.konyvesbolt.online/spd/978-963-06-7071-5/Rinyai-Laszlo-Tetrameron-I--2009','','','','','','','',3,3,0,7,4,0,0,'2009-4-2','2009-6-5','','rinyai@chello.hu','','Rinyai László

TETRAMERON  
I. ÍZELÍTŐ

Írói nevem somogyi származásomra utal. Rinyaszentkirályon nőttem fel, 1967 óta Budapesten lakom. 1973-ban jelent meg első novellám, azóta 200 folyóiratokban, antológiákban, lapokban. Ebben a kötetben a 100 novellára és XL epizódra tervezett TETRAMERON című művem 18 novellája és két epizódja található. Reneszánsz hagyományok − a világszerte ismert Decamerone és Navarrai Margit királyné Heptameronja − nyomán keretes elbeszélés-gyűjtemény, valós történetei a XX. század végén játszódnak.

e-mail: rinyai@chello.hu','2009.ZKI:9+1=10

borítórendelés 04.06.

16-án 11-re jön szerző belívet+borítót nézni

borító kész!',NULL,1460712234,0);
INSERT INTO books VALUES(NULL,0,'','',206,0,0,0,0,20,'',0,'',5,20,'',75,5,250,300,310,4,NULL,10,7,2009,172,'Toldi Nagy Miklós','Humor a petrencén','978-963-9888-32-6',2,'','2','A5',144,'0',2290,2,'LEZÁRVA ->§403','Toldi-Nagy-Miklos','','http://bookline.hu/product/home!execute.action?id=82026&type=22&_v=Toldi_Nagy_Miklos_Humor_a_petrencen','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/egyeb_felnottirodalom/humor_a_petrencen','','','','',5,3,1,7,4,1,2,'2009-6-0','2009-7-10','Toldi Miklós; 2100 Gödöllő, Szarvas u. 10.; (30)972-3017','toldi.miklos@invitel.hu','','1951-ben születtem Budapesten.  A Színművészeti Főiskola zenés színész szakának elvégzése után két évet prózai színészként is dolgoztam. Ezután különböző zenés színházaknál operát énekeltem 24 éven át. A Népszínháztól mentem nyugdíjba. Írással 12 éve foglalkozom. A Rádiókabaré is többször leadott az anyagomból. Könnyen írok, mert nagy nyugalomban és gondtalanul élek. Ha megkérdezik tőlem, hogy vagyok, a válasz: Ember jobban nem lehet! Egy napi problémákkal küszködő ember agyában ennyi marhaság nem születik meg. Nagy kertem van, ahol szőlészkedem is.  Azt tartom, hogy a kert szüli, a bor hizlalja a gondolatot. Hitvallásom: Ha sokáig akarsz élni, ne tartózkodj siránkozó emberek társaságában.

Toldi Nagy Miklós
','2009.ZKI:83+1=84


borító kész!
2009.dec. kiküldve MK

',NULL,1325434365,0);
INSERT INTO books VALUES('',0,'','Kovacs_Laszlo--A_kuldetes--FD.jpg','','',1,2,0,3,'',1,'',40,40,'','',NULL,NULL,'',32,0,NULL,16,4,2012,173,'Kovács László','A küldetés','978-615-5110-49-8',2,'','5','140x200 mm',102,'0',2000,1,'#LB2','',' URL: http://www.konyvesbolt.online/spd/978-615-5110-49-8/Kovacs-Laszlo-A-kuldetes-Ad-Librum','','','','','','','',3,2,1,7,4,5,3,'2012-2-13','2012-4-16','220-1413; 1144 Budapest, Tihany út 42-44. fsz. 12.','laszlone.kovacs@chello.hu','','A képzelt jövőben játszódó regény főhőse iskolái elvégzése után sorsdöntő elhatározásra jut. Hol mulatságos, hol veszélyes helyzetekbe sodródik. Kalandjai, megpróbáltatásai humoros és abszurd elemekkel fűszerezett történetben tárulnak elénk, amely lebilincsel fordulatos cselekményével, remek karaktereivel és – nem utolsó sorban – mondanivalójával.

A művet egy G. A. Bürgertől vett idézettel bocsátjuk útjára: 
„Ez az egyszerű kis könyvecske igazán többet ér, mint egy egész rakás könyv, amely sem meg nem ríkat, sem meg nem nevettet…”','12 pld. utánnyomása 2014.feb..',NULL,1459503812,0);
