INSERT INTO books VALUES('',0,'','Szeifert_Natalia--Gyogyfuresz--FD.jpg','','',1,0,0,19,'',0,'',40,65,'','',NULL,NULL,'',200,0,NULL,3,6,2009,182,'Szeifert Natália','Gyógyfűrész - Soha naplója','978-963-9888-12-8',2,'','2','A5',178,'0',1990,1,'#LB4#','Szeifert-Natalia','http://www.konyvesbolt.online/spd/978-963-9888-12-8/Szeifert-Natalia-Gyogyfuresz---Soha-naploja-Ad-Lib','http://bookline.hu/product/home!execute.action?id=81299&type=22&_v=Szeifert_Natalia_Gyogyfuresz_Soha_naploja','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/gyogyfuresz_soha_naploja','','','','',5,3,0,9,4,0,0,'2009-5-0','2009-6-3','8420 Zirc, Fáy A. u. 4/B. 3. em. 3.','szeifert.natalia@gmail.com','Soha nem derül ki. Vagy pont hogy kiderül. Soha kiderül. Hülye mondat, mi?','„Oldalba bököm magam, hogy menjek már odébb. Jó oldalról,  jó szögben pont szíven találnám magam, de nem. Hiába az a sok anatómia.
Hogy őszinte legyek, te nem vagy teljesen morális.
Hiába, az a sok katatónia.”

Soha. Határozószó. Meghatároz legfőképp időt – illetve annak, mármint az alkalmas időnek a hiányát –, másrészt meghatároz egy embert. Egy nőt. 

Vagy pont hogy az a nő határozza meg a sohát, annak az alkalmas időnek a hiányát. 

Soha nem derül ki. Vagy pont hogy kiderül. Soha kiderül. Hülye mondat, mi?

Pedig kiderül. Ír naplót, internetre. Tudod, bárki elolvashatja. Bárki. Mégis, az egész valahogy szemtelenül intim. Van, hogy irreál (van, hogy ír reál), és van, hogy szürreál. Soha mindent leír maga körül, még azt is, ami nincs. Kegyesen, kegyetlenül, szenvesen, szenvtelenül. Persze, szereti a szójátékokat, de sohasem öncéllal. A szó neki nem játék, illetve nem csak az. Minden valós időben leírt naplóbejegyzés, minden többé vagy éppen kevésbé megszerkesztett mondata egy tökéletlen egész része, félreütésestül, elragadtatásostul, makulásan is. Pont úgy őszinte, ahogyan még nem gejl és már nem obszcén. 

Soha semmit nem ír le csak úgy. Soha. 

(Szaniszló Judit)','Új cím (2012.05.13.):
Budapest, 1048, Külső Szilágyi út 56. 2. em. 6.
Telefonszám: 06 20 264 90 98

2009.ZKI:61

',NULL,1477650500,0);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,4,'',0,'',5,20,'',75,5,160,300,300,4,NULL,10,7,2009,183,'Góczi Noémi','Az élet árnyékában','978-963-9934-16-0',2,'','2','A5',60,'0',1990,2,'LEZÁRVA ->§429','Goczi-Noemi','','http://bookline.hu/product/home!execute.action?id=82023&type=22&_v=Goczi_Noemi_Az_elet_arnyekaban','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/az_elet_arnyekaban','','','','',5,3,0,7,4,0,0,'2009-6-0','2009-7-10','7145 Sárpilis, Dózsa u. 18. Tel.: 20/389-2201','nonyka90@freemail.hu','','A könyv, amelyet a kedves Olvasó a kezében tart, több nem mindennapi témát dolgoz fel történetszerűen. Ezek: skizofrénia, gyermeki félelmek, kéjgyilkosság – egyre inkább társadalmunk hozadékává válnak. Nem mindannyiunknak alakul ki közvetlen kapcsolata ezekkel a dolgokkal, de egyre többen vagyunk kénytelenek közvetetten találkozni velük újságok, TV-s közvetítések által, ezért érdemes és kell is foglalkoznunk velük, ha csak addig is, míg ezt a néhány rövid novellát végigolvassuk.
Kiskorában talán mindenki gondolt már hasonlókat, mint a kisfiú a Papa történetében, vagy éppen van egy levelezőpartnere, akiről épp csak annyit tud, amennyit az elárul magáról. De ne áruljunk el előre semmit: mindenkinek kellemes olvasást kívánok!

A Szerző','Ingyenes kiadás lezárva 2010.12.06-n

2009.ZKI:92+1=93

