INSERT INTO books VALUES('',0,'','Szabo_Krisztina--Harmadik_part--FD.jpg','','',1,1,0,2,'',1,1280,10,'','','',NULL,NULL,'','',0,NULL,31,8,2009,195,'Szabó Krisztina','Harmadik part','978-963-06-7636-6',1,'','2','A5',164,'0',2495,5,'#LA4#','Szabo-Krisztina','http://www.konyvesbolt.online/spd/978-963-06-7636-6/Szabo-Krisztina-Harmadik-part','','','','','','','',3,3,0,5,4,0,0,'2009-7-14','2009-8-31','Kalmár György, 1106 Bp., Rákosvölgyi u. 2. T.: 20/983-5531  (email is Kalmár Györgyé)','giogiohu@gmail.com','','Szabó Krisztina vagyok. Túl 35 éven. Budapesten élek, és sokáig Budapest egyik utolsó utcájának rossz kölykeként boldogítottam a családomat.

Kedvenc családtagom a Nagymamám, aki sokat adott, hogy azzá legyek, aki vagyok. Sajnos már nem él. De bennem mindig itt van. Sőt: a járásom, az orrom állása és a makacs, néha kérges viselkedésem is Őt jellemzi.

A világmegváltás a célom. A tetteim, írásaim, megnyilvánulásaim erre irányulnak, és a maradandóság a legfontosabb szempont.

Szeretem, ha figyelnek rám, ha fontos dolgot teszek. Nem szeretek nagyon a háttérben lenni, csak akkor, ha egy jó csapat tagjaként dolgozhatok. Hiszem, hogy ugyanúgy vagyok csapatjátékos, mint az önállóság megalkotója.

Szeretem és tisztelem az embereket. Néha viccesek, okosak, érzelmesek, megfásultak és még ezeregy jelzővel illethetők, de emberek! Ezt sokszor elfelejtjük. Elfelejtjük, hogy együtt élünk, és talán egymásért.','2009.ZKI:1+20=20+1=21


Jogtulaj: Kalmár György

szerzői kiadás!

120 pld. 090831

20 db maradt nálunk',NULL,1460370887,0);
