INSERT INTO books VALUES('',0,'','Beni-Nyerges_Olga--Az_utolsoelott_szo_jogan--FD.jpg','',0,0,0,0,18,'',0,'',40,65,'','',NULL,NULL,300,300,0,NULL,28,9,2009,197,'Béni-Nyerges Olga','Az utolsó előtti szó jogán','978-963-9934-28-3',2,'','2','A5',270,'0',2490,1,'#LA4#','Beni-Nyerges-Olga','','http://bookline.hu/product/home!execute.action?id=83694&type=22&_v=Beni_Nyerges_Olga_Az_utolso_elotti_szo_jogan','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/az_utolso_elotti_szo_jogan','','','','',5,2,4,7,4,5,0,'2009-7-0','2009-9-28','06-1/340-8814 (üzenet), 06-30/321-6553, 36-1/647-435-6892','info@pannonia.ca','','2005-ben találkoztam először a Kanadában élő Béni Olgával, akinek meggyőződése volt, hogy közvetlen leszármazottja vagyok annak a Ragályi Elemérnek, akinek a második világháború előtt híres gyermekszínháza volt, s melynek Ő ifjú és lelkes sztárja volt.
Elemér bácsi nagyon távoli rokonom volt, s egyszer találkoztam vele 1968-ban, mikor első mozifilmemet forgattam, melyben Ő egy pici szerepet játszott. Én protezsáltam be, színházi múltja előtt tisztelegve.
Olga régi színházi előadások féltve őrzött plakátjait hozta el nekem, s rengeteg emlékét, melyek nemcsak a gyermekszínházról szóltak. Találkozásaink során, ha nem is sorjában, de elmesélte egész „regénybe illő” életét. A történetek mozaikját összerakva arra biztattam, rakjon rendet az események sorában, s írja meg, mert a nem mindennapi izgalmas drámai történések sokak számára jelenthetnek tanulságot, s élvezetes olvasmányt. Most 2009-ben jutottunk el ehhez az örömteli pillanathoz. Szívesen ajánlom a könyvet az olvasók figyelmébe.

Ragályi Elemér rendező-operatőr, aki csak távoli rokona a megboldogult Ragályi Elemér színiigazgatónak','2012.08.29.: A szerző telefonutasítása szerint minden példányt visszahívunk, és kiszállítjuk a köv. címre: Kun Péter, 1133 Budapest, Pozsonyi út 48. IV. em. tel: 340-8814

