INSERT INTO books VALUES('',0,'','','','',0,1,16,13,'',1,1400,10,'','','',NULL,NULL,'','',0,NULL,1,10,2009,199,'Gigi Scott','Sárkány születik - A gyermek','978-963-9934-27-6',2,'','2','140x200 mm',200,'0',1990,5,'#LE#>§428 (mint előfinanszírozott); Faragó Ágnes','Gigi-Scott','http://www.konyvesbolt.online/spd/978-963-9934-27-6/Gigi-Scott-Sarkany-szuletik---A-gyermek-Ad-Librum-','','','','','','','',3,3,0,7,4,5,0,'2009-7-0','2009-10-1','Faragó Ágnes Julianna, 20/575-9544','a.j.farago@gmail.com','','A Sárkány születik egy különös kislány, Diana története. Egészen a fogantatásától kezdve szokatlan dolgok történnek körülötte, amiket az idő előrehaladtával a környezete – különösen az édesanyja – egyre rosszabbul visel. Diana azonban egy gyermek őszinte érdeklődésével fordul a szokatlan lények és események felé. Ám ezek a kezdeti szórakoztató kalandok szinte észrevétlenül fordulnak egyre komolyabbra, mindaddig, amíg már a kislány élete is veszélybe kerül. Diana kalandjai során a személyisége is sokat változik, és csakhamar rájön, hogy az események egy távoli világban történtekkel állnak kapcsolatban, amelyekhez neki is köze van valamiféleképp.

A Sárkány születik kellemes kikapcsolódást nyújthat mindazoknak, akik idegennek érzik magukat ebben a világban, akik nem értik a különcöket, akik szeretik a mesét, vagy egyszerűen csak egy könnyű olvasmányra vágynak.','2009.ZKI:35+1=36

borító kész! 0825

(webre csak linket kért)',NULL,1474541863,0);
INSERT INTO books VALUES('',0,'<a href=\"http://adlibrum.hu/csandi\" target=\"_blank\"><img src=\"http://csandi.net/csacsik.jpg\" width=\"392\" height=\"72\" border=\"0\" alt=\"Cserepes Andrea, azaz Csandi könyvei\"></a>','Cserepes_Andrea--Algaringa--FD.jpg','',0,1,1,0,16,'',1,1178,10,'','','',NULL,NULL,'','',0,NULL,6,10,2009,200,'Cserepes Andrea','Algaringa-tó','978-963-9934-29-0',2,'','2','140x200 mm',126,'0',1800,5,'#LB6,LG5#','Csandi','http://www.konyvesbolt.online/spd/978-963-9934-29-0/Cserepes-Andrea-Algaringa-to-Ad-Librum-2009','','','','http://www.konyvesbolt.online/spd/978-963-9934-29-0/Cserepes-Andrea-Algaringa-to-Ad-Librum-2009','','','',3,2,0,3,4,5,0,'Array-0-0','2009-10-6','7632 Pécs, Viktória u. 1. T.: 20/976-1053','cserepes.andrea@gmail.com','','``Tegnap éjjel Tiloltlen átrepült az egész város felett. Álmában lépésről lépésre odasétált a háztető pereméhez, és belenézett a végtelen Világba. Sokáig szemlélte az embereket, ahogy forgolódnak, zajonganak, sírt is, nevetett is miattuk. Egyszer csak feltámadt a szél, arcára borította a kavalkád illatait, és ekkor elhatározta, beleveti magát az emberek sűrűjébe. Átugrotta a háztető peremét. Zuhant lefelé, ahogy minden súlyos test tenné ebben a helyzetben. Igen, zuhant. Zuhant, ámde különös zuhanása volt, mert nem közeledett növekvő sebességgel a talaj felé, ahogy az elvárható, inkább lassan, kacskaringós úton evickélt egyre lejjebb, és lejjebb, mint egy lehulló, cingár papírdarab. Könnyű volt, olykor egy-egy szellő belekapott, vitte jobbra-balra, így táncolt át a házak, boltok, iskolák felett, vidáman és gondtalanul.
Nézte odalent az embereket, amint felfelé mutatva azt kiáltják: „Nini, ott repül Tiloltlen! Szegényke képtelen leszállni! Gyorsan, segítsünk neki!” Kinyújtották a kezüket, el akarták kapni, ámde ahogy mindkét kezükkel felé kalimpáltak, felkavarodott a levegő, szellő támadt, Tiloltlen számára sodró szélvihar, és ő hirtelen továbbsuhant.
Valahányszor le akart szállni az emberek közé, ők ugrottak máris, hogy segítsenek, de Tiloltlen túl könnyű volt, és nyomban tovaröppent vele egy újabb fuvallat.``','2009.ZKI:86+6=92 - elment OSZK-ba 6 db


',NULL,1451379500,0);
INSERT INTO books VALUES('',0,'<a href=\"http://adlibrum.hu/csandi\" target=\"_blank\"><img src=\"http://csandi.net/csacsik.jpg\" width=\"392\" height=\"72\" border=\"0\" alt=\"Cserepes Andrea, azaz Csandi könyvei\"></a>','Cserepes_Andrea--Orkankedd--FD.jpg','',0,1,1,0,16,'',1,1424,10,'','','',NULL,NULL,'','',0,NULL,1,10,2009,201,'Cserepes Andrea','Orkánkedd','978-963-9934-30-6',2,'','2','140x200 mm',208,'0',2200,5,'#LB6,LG4,LG6#','Csandi','http://www.konyvesbolt.online/spd/978-963-9934-30-6/Cserepes-Andrea-Orkankedd-Ad-Librum-2009','','','','http://www.konyvesbolt.online/spd/978-963-9934-30-6/Cserepes-Andrea-Orkankedd-Ad-Librum-2009','','','',3,2,0,7,4,5,0,'Array-0-0','2009-10-1','7632 Pécs, Viktória u. 1. T.: 20/976-1053','cserepes.andrea@gmail.com','','Cserepes Andrea, azaz Csandi mozgásában korlátozott, ámde fantáziáját tekintve korlátlan író. Első mesekönyve a Nagymama szponzorálásával jelent meg 2005-ben, Katicapettyegető Felicián címmel. A mesekönyv sikerének köszönhetően a szponzorációs alaptőke hamar megújult, így 2006-ban megjelenhetett Csandi első novelláskötete, az Algaringa-tó, majd 2007-ben elkészült Csandi első meselemeze is.

Idén, az Orkánkedd című kötet oldalain Cserepes Andrea sok-sok egykori és új meséjét olvashatja a Kedves Olvasó.','2009.ZKI:82+1=83',NULL,1451379435,0);
