INSERT INTO books VALUES('',0,'','Zeus_Bratis--Alin_Labirintusa--FD.jpg','','',1,1,22,13,'',0,1400,10,'','','',NULL,NULL,'','',0,NULL,1,10,2009,203,'Zeus Bratis','Alin Labirintusa és a sárkánylegyek harcosai','978-963-9934-31-3',2,'','2','140x200 mm',191,'0',2190,5,'#LB3 Pozsonyi Zénó','Zeus-Bratis','http://www.konyvesbolt.online/spd/978-963-9934-31-3/Zeus-Bratis-Alin-Labirintusa-es-a-sarkanylegyek-ha','','','','','','','',3,3,0,8,1,5,2,'2009-8-16','2009-10-1','Pozsonyi Zénó, 70/578-2176','pozsonyi.zeno@gmail.com','','A két világháború között vésett kamrákat fedeznek fel Grönland jege alatt. A hieroglifákkal telerótt termek egyértelműen egy ősi emberi létesítmény részei, de Grönlandon soha nem virágzott semmilyen civilizáció.
A feltárás során kiderül, hogy egy egész labirintusról van szó, mely irdatlan nagy és hihetetlenül régi. A földtörténeti Karbon időszakban kezdték kialakítani, amikor mai tudásunk szerint még szárazföldi gerinces állatok sem léteztek igazán, nemhogy ember. A Karbon időszakot a ROVAROK FÉNYKORA-ként emlegetik.','2009.ZKI:3+1=4


235g',NULL,1463045679,0);
INSERT INTO books VALUES('',0,'','Alim_BR--Gyulolet--FD.jpg','',0,1,1,14,11,'',1,1400,'','','','',NULL,NULL,'',50,0,NULL,15,12,2009,204,'Alim B. R.','Gyűlölet','978-963-88690-0-5',1,'','2','120x200 mm',200,'0',2390,5,'#LB4,LG18# Csavnyiczky Bettina, T:G,B:B','Alim','http://www.konyvesbolt.online/spd/978-963-88690-0-5/Alim-B--R--Gyulolet-2009','','','','http://www.konyvesbolt.online/spd/978-963-88690-0-5/Alim-B--R--Gyulolet-2009','','','',3,3,0,7,4,5,3,'Array-0-0','2009-12-15','Csavnyiczky Bettina, 1152 Bp., Kiss Ernő u. 11. T.: 20/545-9203','csavnyiczkybettina@gmail.com','','Gyűlölet s szeretet között egy hajszál választja el egymástól a két érzést.

John Feoster fiatal, sikeres ügyvéd kiegyensúlyozott és vidámnak tűnő élete, idill sorsfonala egy csapásra elszakad. Attól a naptól kezdve elszabadul a pokol, rémálmok s felfoghatatlan jelenségek sorozata sújt le rá. Hihetetlen és kegyetlen, véget nem érő átváltozáson megy keresztül.

Aki ezt előidézi számára, nem más, mint Joe Brown, aki a féltestvére, s egyben legjobb barátja volt régen.

Joe a túlvilágról tér vissza, hogy bosszút állhasson Johnon – és a gyűlölet úrrá esz. Miért jött vissza Joe? Kit gyűlöl valójában? Miért alakult ki ez a két férfi között?

A múlt elkap, s a gyűlölet uralkodni fog.','2009.ZKI:39

szerzői ár: 1400 Ft



',NULL,1451377351,0);
INSERT INTO books VALUES('',0,'','Zaicsek_Balazs--A_kard_haboruja--FD.jpg','','',1,1,0,13,'',1,1664,10,'','','',NULL,NULL,'','',0,NULL,15,10,2009,205,'Zaicsek Balázs','A Kard Háborúja','978-963-9934-34-4',2,'','2','A5',286,'0',2490,5,'','Zaicsek-Balazs','http://www.konyvesbolt.online/spd/978-963-9934-34-4/Zaicsek-Balazs-A-Kard-Haboruja-Ad-Librum','','','','','','','',3,3,0,9,4,5,0,'2009-8-0','2009-10-15','8500 Pápa, Hold u. 11/A. T.: 70/593-2152','zebalu@gmail.com','Ebben a mesében négy fiatal küzd az életéért és a lelkéért, hogy végül megmenthessék a világot; közben azzal a teherrel is szembe kell nézniük, hogy tudják, a történet végére egyikük meg fog halni.','Meséink tele vannak csodálatos lényekkel, sárkányokkal, törpékkel, nimfákkal, orkokkal, és még rengeteg olyan teremtménnyel, amikhez még csak hasonlókkal sem találkozhatunk életünk során. Honnan van ez a sok mese? Talán az emberiség emlékezetében élnek? Hol találkoztunk velük? Hová lett az a világ?

Réges-régen életünk még közös volt velük. Ott, akkor a Gonosz sereget gyűjtött, hogy leigázzon mindent. Mit tesz erre Isten? Kiválaszt négyet a hívei közül, és elküldi őket, hogy keressék meg a fegyvereket, amiket Mihály arkangyal viselt akkor, amikor legyőzte Lucifert. Mire jó egy több évezredes penge? Miért nem söpri el a Sátánt és minden kompániáját?

Ebben a mesében négy fiatal küzd az életéért és a lelkéért, hogy végül megmenthessék a világot; közben azzal a teherrel is szembe kell nézniük, hogy tudják, a történet végére egyikük meg fog halni.','2009.ZKI:14+1=15

borító kész!

',NULL,1460370219,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,22,11,'',0,'',5,20,'',75,NULL,NULL,300,300,4,NULL,7,12,2009,206,'Vasas Judit','Mah-ree Nok - Misztikus kalandregény','978-963-9934-33-7',2,'','2','A5',280,'0',2990,2,'#LB4 LEZÁRVA ->§437','Vasas-Judit','','http://bookline.hu/product/home!execute.action?id=85509&type=22&_v=Vasas_Judit_Mah_ree_Nok','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/mah_ree_nok','','','Vasas-Judit','',5,3,0,7,4,5,3,'Array-0-0','2009-12-7','6721 Szeged, Füredi u. 9/B. T.: 20/442-7354','szamira15@gmail.com','','A Mah-ree Nok csak egy legenda: történet egy nagyon régi, mágikus könyvről, ami valójában nem is létezik. Vagy mégis? Erre a kérdésre keresi a választ az ifjú Duncan Scott, és meg is találja – legalábbis azt hiszi, mígnem kénytelen lesz rájönni, hogy olyan erőkkel játszadozik, amikre aligha van befolyása. Csakhogy addigra már – hála neki – a barátai is nyakig ülnek a pácban… Vajon képesek lesznek együtt helyrehozni a dolgokat, vagy viselniük kell Duncan kíváncsiságának következményeit egészen életük végéig (ami talán nincs is olyan messze…)?','2009.ZKI:118+1=119

344 g: 90 pld. = 31 kg = 2 csomag

