INSERT INTO books VALUES('',0,'','','','',0,0,4,20,'',1,'',40,70,'','',NULL,NULL,'',200,0,NULL,12,10,2009,209,'Nagy J. Gábor','Dalnoki, a 11. csapás (A hülyeség - szabadság)','978-963-9934-41-2',2,'','2','A5',140,'0',2690,1,'# #RF','Edomer','http://www.konyvesbolt.online/spd/978-963-9934-41-2/Nagy-J--Gabor-Dalnoki-a-11--csapas-A-hulyeseg---sz','http://bookline.hu/product/home!execute.action?id=83696&type=22&_v=Nagy_J_Gabor_Dalnoki_a_11_csapas','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/dalnoki_a_11_csapas_a_hulyeseg_szabadsag','','','','',3,3,0,7,4,5,0,'2009-9-2','2009-10-12','Nagy József Gábor, 1084 Bp., Nagyfuvaros u. 4. II. em. 12. T.: 20/770-5749','ujlevelem@gmail.com      ','regény','…Ekkor mellé lépett egy szigorú kinézetű, kopasz, szemüveges illető, és mérőszalagjával tetőtől talpig méricskélni kezdte.

– Mit méreget engem? – lépett hátrébb Dalnoki mérgesen.

– Az intelligenciaszintjét – válaszolta az idegen.

Dalnoki unottan legyintett egyet.

– Ne fáradjon, teljesen felesleges, ugyanis mérhetetlenül magas.

– Akkor miért nem egy minisztériumban dolgozik? – érdeklődött az illető.

– Azért, mert még nem találták fel a hülyeségügyi miniszteri posztot, az udvari bolondét pedig már régen megszüntették.

Így aztán én is munka nélkül maradtam. És amit körülöttem látok, minden mástól elvette a kedvemet. Tulajdonképpen hihetetlenül okos vagyok, csak hülyének látszom a hülyék között – jelentette ki Dalnoki magabiztosan…

``A valóságos relativitás-elmélet tárul elénk ebben a műben!``
(Einstein)

``Csodálatos pszichológiai tananyag, ehhez még én is kevés lennék``

(S. Freud)

 

„Átütő erejű alkotás! Mindenki meghülyül tőle! Én is!``

(F. Nietzsche)

 

„Fantasztikus! Alapjaiban változtatja meg az evolúciós elméletemet!``

(Ch. Darwin)

 

„Lenyűgöző politikai ötletgazdagság! Ha ezt előbb olvasom...``

(V. Iljics Lenin)

 

„Tiszta bolondság az egész!!!``

(A Szerző)','2009.ZKI:46+1=47

