INSERT INTO books VALUES('',0,'','Racz_Katalin--Foldonkivuliek_a_Penzverem_utcaban--FD.jpg',108,'',1,0,3,16,'',1,'',40,70,'','',NULL,NULL,'',500,0,NULL,25,9,2009,210,'Rácz Katalin','Földönkívüliek a Pénzverem utcában','978-963-9934-37-5',2,'','2','117x160 mm',120,'0',1390,1,'#LB6,LGIII,LG9#   T&B:B','Racz-Katalin','http://www.konyvesbolt.online/spd/978-963-9934-37-5/Racz-Katalin-Foldonkivuliek-a-Penzverem-utcaban-Ad','http://bookline.hu/product/home!execute.action?id=83270&type=22&_v=Racz_Katalin_Foldonkivuliek_a_penzverem_utcaban','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/egyeb_felnottirodalom/foldonkivuliek_a_penzverem_utcaban','','','','',3,2,0,7,4,5,0,'Array-0-0','2009-9-25','Halmosné Rácz Katalin','hrk@kabelnet.hu','Rácz Katalin novelláinak témaválasztása, szarkasztikus, fanyar hangvétele a magyar irodalom gyökereiből táplálkozik. Stílusa hanyag, laza eleganciájú és élvezetes. ','A szerző budapesti születésű, Győrben élő közgazdász. 2006 óta ír novellákat.

Hősei hétköznapi emberek csetlés-botlását, elbizonytalanodását mutatják be kissé elidegenedett világunkban, akik válaszokat keresnek az őket foglalkoztató kérdésekre, mint pl.:

Mit jelent a boldogság?

Van-e az ölelésnek áfa-ja?

Milyen sorrendben folyik a víz, befelé és azután kifelé, vagy fordítva?

Előny-e egy kutyának, ha csak három lába van?

Mi a sikeres fogyókúra titka?

Befolyásolja-e jellemünket a tiroli rétes?

Egyik kritikusa szerint témaválasztása, valamint szarkasztikus, fanyar hangvétele a magyar irodalom gyökereiből táplálkozik. Stílusa hanyag, laza eleganciájú és élvezetes.  Finom humorral átszőtt történetei rendkívül szórakoztatóak.

 Olvasói egy részének Örkény István groteszkjei jutnak eszébe ezekről az írásokról, sokan Rejtő Jenő mai utódját látják benne, de akadnak, akik Douglas Adams fanyar angol iróniáját vélik felfedezni stílusában.

A novelláskötetet különösen ajánljuk mosógépszerelőknek, kozmetikusoknak, alkoholista vagy absztinens fogorvosoknak, levéltárosoknak, rendszergazdáknak, festőknek, íróknak, boldogságkeresőknek és földönkívülieknek, valamint ezek minden rendű és rangú rokonainak, barátainak és hozzátartozóinak. ','2009.ZKI:165+1=166

300 pld. marad terjesztésre + kötelespéldányok

Borka készíti

115x165 mm

Kifizetve 500 db',NULL,1472719176,0);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,2,'',1,'',5,20,'',75,NULL,NULL,300,300,5,NULL,3,11,2009,211,'Liz Bet','Végre az enyém...','978-963-9934-39-9',2,'','2','A5',80,'0',1690,2,'LEZÁRT ->§442 Kiss-Hegyi Erzsébet','Liz-Bet','','http://bookline.hu/product/home!execute.action?id=84491&type=22&_v=Bet_Liz_Vegre_az_enyem_','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/vegre_az_enyem','','','','',5,3,0,7,4,5,1,'2009-9-0','2009-11-3','Kiss-Hegyi Erzsébet, 30/463-5482, 3300 Eger, Vízimolnár u. 8. 3/9.','lisandra@freemail.hu','','Mary, a csinos ingatlanközvetítő mélységesen csalódott férjében. A válás után egyedül él, nem is akar hallani férfiakról. Barátnője unszolására végül mégis felad egy hirdetést egy társkereső irodánál.

Túl sok reményt nem fűz a dologhoz, és úgy látszik, igaza is lesz… De éppen amikor végleg feladni készül, olyan levél érkezik, melynek írója felkelti érdeklődését. A jóképű, titokzatos Ronald, aki, amilyen hirtelen feltűnik, olyan váratlanul el is tűnik…','2009.ZKI:205+1=206

Valójában B6 (125x178 mm)!!

Letét 1 befizetve.

