INSERT INTO books VALUES('',0,'','Vasvari_Zoltan--Emlek_emlek_miert_kisersz--FD.jpg','','',1,1,0,37,'',1,1304,10,'','','',NULL,NULL,'','',0,NULL,12,10,2009,213,'Vasvári Zoltán','Emlék, emlék, miért kísérsz? - Tanulmány a XX. századi emlékkönyvkultúráról','978-963-9934-42-9',2,'','2','140x200 mm',168,'0',1800,5,'#LB4,LG16#  T:B B:szerző','Vasvari-Zoltan','http://www.konyvesbolt.online/spd/978-963-9934-42-9/Vasvari-Zoltan-Emlek-emlek-miert-kisersz---Tanulma','','','','','','','',3,3,0,7,4,5,5,'Array-0-0','2009-10-12','1131 Bp., Madarász V. u. 13. B. 162. T.: 30/280-2807','z.vasvari@index.hu','','Az emlékkönyvek története fél évezredet ölel fel. Jelen tanulmány az utolsó száz év emlékkönyv-kultúrájának bemutatására vállalkozik. Vizsgálati módszere folklorisztikai szemléletű. Kiindulópontja, hogy az emlékkönyvkultúra a XX. században a folklór létmódja szerint egzisztált, ezért vizsgálata a folklorisztika módszereivel releváns eredményeket hozhat.

 

A folklorista szerző két évtizede foglalkozik az emlékkönyvvel és emlékverssel, mint kulturális jelenséggel. A témát épp annak a történeti folyamatnak a végigkísérése teszi a modern folklorisztikai és művelődéstörténeti kutatás számára izgalmassá, ahogyan férfiak (diákok) által írott „magas” kultúra-termékből, az album amicorumból egyre fiatalabb leányok divatos, nem egyszer tréfás szokásává válik. Az emlékkönyvbe írt emléksorok, -versek komoly vagy tréfás „életvezetési tanácsaikkal” azt a korszellemet, morális modellt, normarendszert is tükrözik, azt a nyelvi és stiláris hagyományt is őrzik, amelyben születtek. Az emlékversek témája és tartalma gyakran ellentétbe kerül az illusztrációs (képi) anyaggal, használójának társadalmi helyzetével, életkorával és a megváltozott korszellemmel is. Következésképp még érdekesebb felfejteni és értelmezni azokat a mentális és művelődéstörténeti folyamatokat, amelyek létrehozzák az emlékezésnek és nevelésnek ezt a speciális formáját, illetve visszatükrözik ezek változásait. ','2009.ZKI:6+38=44

Borka készíti

szerzői ár: 1280 Ft',NULL,1463045606,0);
