INSERT INTO books VALUES('',0,'','Ujvari_Akos--A_jogos_vedelem--FD.jpg',298,'',1,0,0,38,'',1,'',40,70,'','',NULL,NULL,'',100,0,NULL,20,11,2009,228,'Dr. Ujvári Ákos','A jogos védelem megítélésének új irányai','978-963-9934-52-8',2,'','2','A5',240,'0',2990,1,'#LA3','Dr-Ujvari-Akos','http://www.konyvesbolt.online/spd/978-963-9934-52-8/Dr--Ujvari-Akos-A-jogos-vedelem-megitelesenek-uj-i','','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/a_jogos_vedelem_megitelesenek_uj_iranyai','','','','',3,2,0,7,4,5,2,'2009-10-21','2009-11-20','1122 Bp., Karap u. 10. I. em. T.: 30/319-1331','ujvariakos@freemail.hu','A munka átfogó képet kíván rajzolni a gyakorlatban legtöbbször hivatkozott büntethetőséget kizáró okról.','A monográfia alapjául a Szerző PhD értekezése szolgál, amelyet a Pázmány Péter Katolikus Egyetem Jog- és Államtudományi Karán, 2009. május 27-én megrendezett nyilvános vitán  sikerrel bemutatott.

A munka átfogó képet kíván rajzolni a gyakorlatban legtöbbször hivatkozott büntethetőséget kizáró okról. A jogintézményhez kapcsolódó elvi és gyakorlati kérdések tematikus egységekben olvashatóak. A vonatkozó szakirodalom kritikai elemzése mellett az elmúlt 30 év valamennyi jogos védelmet érintő legfelsőbb bírósági eseti döntés is elemzett formában szerepel a dolgozatban. 

A Szerző a hazai szabályozásra, a hazai és külföldi jogirodalmi álláspontokra figyelemmel feldolgozza a kontinentális jogrendszerekhez sorolt egyes európai országok Büntető Kódexeinek a jogintézményt érintő rendelkezéseit is.

A monográfia gyakorló jogászok számára kézikönyvként szolgálhat. 
Az elméleti jogászok is haszonnal forgathatják a jogos védelmet övező elméleti problémák felvetése, megoldása során.

Érdekes olvasmány lehet a laikusok számára is, mivel a könyv – szinte – minden állampolgárt érintő büntetőjogi problémát dolgoz fel.


Ujvári Ákos a Pázmány Péter Katolikus Egyetem Jog- és Államtudományi Kara Büntető Anyagi Eljárási és Végrehajtási Jogi Tanszékének egyetemi adjunktusa, a Budai Központi Kerületi Bíróság büntető ügyszakos bírája. Eddig különböző szakfolyóiratokban 14 tudományos közleménye jelent meg.','2009.ZKI:2+33=35+2=37






',NULL,1480933784,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,20,'',0,'',8,30,'',125,NULL,NULL,500,500,5,NULL,27,11,2009,229,'Peter Woodpecker','A hülyeségen túl','978-963-9934-51-1',2,'','2','A5',156,'0',2190,2,'#LB6# A2 (emlékpéldány) lezárt->folytatás->§417 Harkányi Péter, 217 g','Peter-Woodpecker','','http://bookline.hu/product/home!execute.action?id=85241&type=22&_v=Woodpecker_Peter_A_hulyesegen_tul','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/a_hulyesegen_tul','','','','',5,3,0,7,4,5,3,'2009-11-0','2009-11-27','Harkányi Péter 4024 Debrecen, Liszt F. u. 9., T.: 30/9834-514','info@harkanyi.hu','','Mindannyiunk életében már gyermekkorunkban elhangzik egy mondat: Fiam, Te nem vagy normális!
Mivel ezt többnyire saját szülőnk vágja a fejünkhöz, egy percig se kételkedjünk benne, hogy ez így is van! Az idő múlásával a fenti mondatban foglaltak egyre inkább bebizonyosodnak. (Régen rossz, ha mondjuk már kettő van...)
A későbbiek folyamán már akár leletekkel is tudjuk bizonyítani, hogy találó volt a megállapítás. Nem kell ezt szégyellni, titkolni sem érdemes. Úgyis látszik rajtunk. Képzelhetjük, hogy a mi esetünkben nem így lesz, de ez csak önámítás lenne.

A fiatal (-nak még jóindulattal sem nevezhető) elsőkönyves szerző az emberi hülyeség problematikáját feszegeti. (Már amennyiben ez gondot okoz!?) Attól, hogy mások tudják rólunk, hogy agyilag gagyik vagyunk, még élvezhetjük az életet! Sőt...','2009.ZKI:1+6=7+325=332+1=333 - elment OSZK-ba 6 db

letét 2. is kifizetve',NULL,1421406779,0);
INSERT INTO books VALUES('',0,'','Glied_Viktor--Vizkonfliktusok--FD.jpg',473,3,1,1,0,40,'',0,'','','','','',NULL,NULL,'','',0,NULL,0,10,2009,230,'Glied Viktor (szerk.)','Vízkonfliktusok - Küzdelem egy pohár vízért','978-963-88332-9-7',3,'Publikon Kiadó','2','A5',271,'0',2590,4,'#LE#','Glied-Viktor','http://www.konyvesbolt.online/spd/978-963-88332-9-7/Glied-Viktor-szerk--Vizkonfliktusok---Kuzdelem-egy','','','','http://www.konyvesbolt.online/spd/978-963-88332-9-7/Glied-Viktor-szerk--Vizkonfliktusok---Kuzdelem-egy','','','',3,0,0,0,0,5,0,'Array-0-0','2009-10-0','','','A környezeti szűkösség okozta problémák.','A Vízkonfliktusok – Küzdelem egy pohár vízért című tanulmánykötet fókuszában a környezeti szűkösség fogalma áll, kiemelt tekintettel az édesvízhiány és vízszennyezés okozta problémákra, valamint részben a szűkösség következtében kialakuló konfliktusok módjaira, megjelenésük lehetséges földrajzi helyeire, okaira és a várható következményekre.

Napjainkban 1,1 milliárd ember nem jut tiszta ivóvízhez, és ez a szám néhány évtizeden belül hárommilliárdra emelkedhet. A borúlátóbb forgatókönyvek még ennél is messzebbre mennek, ezek szerint 2025-re az emberiség 66%-ának nem lesz elegendő ivóvize.

A mű szerzői főként környezetpolitikával, konfliktuselemzéssel, gazdaság- és társadalomföldrajzi, valamint nemzetközi jogi (elsősorban vízjogi) kérdésekkel foglalkozó fiatal kutatók, környezetvédelmi szakemberek, ezáltal a kötet referenciaként szolgálhat a közép- és felsőoktatásban tanuló hallgatóknak, környezetvédelmi szakembereknek, de jellegénél fogva rengeteg érdekességet tartogat környezetünk védelme iránt fogékony, szerencsére gyarapodó számú olvasóközönség számára is.

A kötet szerzői a „vizes ügyek” különböző aspektusait vizsgálják ugyan, de a tanulmányok célja minden esetben közös: felhívni a figyelmet az emberiséget ér kihívásokra, bemutatni a következő évtizedek várhatóan súlyos környezeti, politikai és társadalmi problémáit, új fogalmak segítségével megoldásokat találni a felmerült gondokra.','2009.ZKI:8+1=9',NULL,1451383234,0);
INSERT INTO books VALUES('',0,'','','',0,0,2,40,39,'',0,1550,10,'','','',NULL,NULL,'','',0,NULL,7,12,2009,231,'Dezse Tivadar','A magyar nyugdíjbiztosítás története','978-963-06-8295-4',1,'','2','B5',220,'0',2700,5,'','Dezse-Tivadar','','','','','','','','',5,3,0,7,4,5,4,'Array-0-0','2009-12-7','6451 Tataháza, Kossuth L. u. 56., T.: 70/555-0110','tivadar.dezse@gmail.com','','A társadalombiztosítás, amelynek egyik kulcseleme a nyugdíjbiztosítás, a szociális ellátórendszerek mára legjelentősebb tényezőjévé vált. A kötet bemutatja a magyarországi nyugdíjbiztosítás öt, időben egymáshoz kapcsolódó korszakát. A szerző célja betölteni a magyar nyelvű szakirodalomban meglévő űrt olyan átfogó, összefoglaló ismereteket adó kötettel, amelyet érdeklődéssel és haszonnal forgathatnak kutatók, felsőoktatási hallgatók, újságírók és a nyugdíjbiztosítás iránt érdeklődő állampolgárok is.','Plágium miatt lezárva.

