INSERT INTO books VALUES('',0,'','Fuleki_Gabor--Zengo_anakronit--FD.jpg','',0,1,0,0,2,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,15,10,2012,244,'Füleki Gábor','Zengő anakronit','978-615-5110-55-9',2,'','5','130x200 mm',103,'0',1490,1,'#LA3,LGII#','Fuleki-Gabor','http://www.konyvesbolt.online/spd/978-615-5110-55-9/Fuleki-Gabor-Zengo-anakronit-Ad-Librum-2012','','','','http://www.konyvesbolt.online/spd/978-615-5110-55-9/Fuleki-Gabor-Zengo-anakronit-Ad-Librum-2012','','','',3,3,1,7,4,5,4,'2012-5-31','2012-10-15','Füleki Gábor, 2370 Dabas, Bartók Béla út 30/A.; 20/943-8258','fulgus@freemail.hu','','Első kötetek megítélésénél gyakran szerepel az ,,ígéretes” jelző. Biztató, de fenntartással buzdító szó. Füleki Gábor debütálásakor nem alkalmaznám ezt a kifejezést. Úgy vélem, hogy türelmesen érlelt, csiszolt, válogatott verseinek gondosan, tudatosan komponált gyűjteménye túl van ezen a küszöbön. Nem ígéret, inkább ígérkezés nélkül a beváltás kezdete.
Széles Klára irodalomtörténész

A kötet hangja találkozókra invitálja olvasóját, találkozóra a nyelvvel, találkozóra egy léttapasztalattal, egy megértésbe vonással és találkozásra önmagával, önmaga itt-létének másával, vélt-remélt perspektívájával.  
Füleki Gábor erős, gazdag, plasztikus képiségű, jó ritmusú, zengő akusztikájú költői nyelvvel ajándékozza meg közönségét, ilyen nyelvbe vonja be olvasó-társát. Ez a nyelv nem ancilla, nem valaminek, valakinek a (ki)szolgálója, eszköze, ez maga az a totális entitás,  amelyre az arc (facies) metaforával mutat rá, „arcod: anyanyelv”.    
A szövegek hangja a szubjektumnak olyan találkozásáról, olyan mély megértéséről, nem át-, hanem megéléséről ad hírt, amelyben a tudat a tér és az idő kreatúráival nem mint mással, nem mint ellenféllel, nem mint legyőzendővel áll szemben, hanem úgy viszonyul hozzájuk, mint a saját bensőségességéhez („hozzád simul tér és idő”). 
A vers hangja ez átfogó találkozáskor nem kényszerül szembesülni a mysterium tremendummal, sem azzal, ami ennek következménye: a szubjektum (átmeneti) kiüresedésével, ürességével - az abszolút transzcendens itt szeretőn fogja át a létezőket, szelíd derűvel tartja kezében őket. 
Az olvasó elfogadhatja a szövegek kínálta kettős tapasztalatot: újraalkotva maga is részesedhet e költői nyelv bőségében, és részesedhet abban az univerzális léttapasztalatban is, amelyet ez a nyelv involvál, átfogni képes - s amelynek olyan gyakran híjával vagyunk.  

Kovács Kristóf András irodalomtörténész','200 példány marad terjesztésre, a többit elviszi a szerző.',NULL,1451296671,0);
INSERT INTO books VALUES('',0,'<p>A <strong>haiku</strong> (jelentése: humoros, szokatlan vers) csak mint egy kavics, a mozdulatlan tóba – az olvasó tudatába – hajítva: finom hullámokat indít, asszociációkat hív elő az emlékezet gazdagságából. Költő s költemény csodálata helyett alkotói részvételre invitálja tehát az Olvasót: a 3 soros, 17 szótagos természet-közeli költemény őáltala avatódhat igazán haikuvá.</p>

<h4>Részlet</h4>

<p>Most, a bálban, férfiasan magamhoz szorítottam tanárnőmet, és formás, illatos kis fülébe dúdoltam reszelős kamasz-hangon:</p>

<p><strong>Így szövődik sok tarka regény<br/>
Mexikóban az éj közepén…</strong></p>

<p>Inkább éreztem, mint láttam, hogy elpirul. „Nagyon nagyosan tangózol… majompofa!” Mire ezt kimondta, már eltartott magától, hogy megmutassa mosolyát, majd felhevült testével visszasimult hozzám.</p>

<p><strong>…s mire feljön a hajnali fény,</strong><br/>
tova suhan a remény – meg a szerelem…</p>

<p>Sok-sok évvel később úgy adódott, hogy belecsöppentem egy váratlan táncórába:</p>

<p><strong>Száz férfi hátrál<br/>
száz nő elől<br/>
tangólépésben</strong></p>

<h4>Világ Haiku Fesztivál - ginko-díj</h4>
<p>Bakos Ferenc meghívott résztvevője volt a pécsi World Haiku Festival-nak, melyet ginko (közös sétát követő haiku-háziverseny) zárt: huszonnégy hazai és külföldi résztvevő egy-egy angolul írt költeménnyel pályázott. A verseny második díját Bakos Ferenc haikuja nyerte:</p>

<p><strong>ginko walk<br/>
unworn shoes of my father<br/>
died a year ago</strong></p>

<p><strong>ginko séta<br/>
egy éve halott apám<br/>
új cipőjében</strong></p>

<p>(a szerző fordítása)</p>
 
<h4>Bakos Ferenc: Sivatagi szél - Hír a Nagyvilágban</h4>
<h4>Magyar szerző haikusikere</h4>

<p>Bakos Ferenc, folyóiratunk munkatársa, szép sikert ért el angol nyelven írt haikujával a japán Ito En Tea Company ez évi rangos „New Haiku” versenyén: az angol szekcióban 31 ország 13 ezer pályázója közül a legjobb 9-be került, és a „Tiszteletre Érdemes” díjban részesült.</p>

<p>A japán zöld teát és teakészítményeket forgalmazó cég évente írja ki pályázatát, a japánul és angolul író szerzők számára, ezúttal a 20. alkalommal. Szép gesztus – s egyúttal bizonyára gyümölcsöző PR-fogás –, hogy a díjazott haikukat rányomtatják a teák címkéjére, csomagolására. A vevő így a tea mellé egy haikut is kap a boltban:</p>

<p><strong>autumn dusk<br/>
in my boots’ depths<br/>
a lone ladybug</strong></p>

<p>(az eredeti díjazott haiku)</p>

<p><strong>őszi homály<br/>
csizmám rejtekében<br/>
magányos katicabogár</strong></p>

<p>(Bakos Ferenc fordítása)</p>

<p>(NAGYVILÁG, 2009/11. szám, 1021.old.)</p>
 
<h4>Mainichi versenyeredmény - A szerző ráduplázott</h4>

<p>A Mainichi Daily News japán országos napilap az újév elején hirdette ki a 2009-es évi nemzetközi haiku versenyének eredményét. A rangos verseny – nevezési díj nélkül – nyitva áll a világszerte angolul vagy franciául haikut „komponáló” költők előtt. A kiírás szerint a klasszikus – évszak szót használó és 5-7-5 szótagú – formától bátran elrugaszkodó pályázatokat vártak, és ezt a várakozást – Toru Haga professzor, a zsűri elnöke szerint – jó néhány kiváló haiku be is váltotta.</p>

<p>Bakos Ferenc a 12 „második díj” egyikében részesült angolul írt haikujával. A Szerző – elmondása szerint – tíz év óta rendszeresen küld pályázatot erre a versenyre is, ám a „Mainichi még egyszer sem jelzett vissza”. Annál nagyobb volt a meglepetése, amikor, épp a kihirdetés napján, a honlapot kinyitva nevével és versével találkozott:</p>

<p><strong>old cherry tree:<br/>
knotty branches embrace<br/>
full-bosomed moon</strong></p>

<p><strong>vén cseresznyefa:<br/>
göcsörtös ágak ölelnek<br/>
teltkeblű holdat</strong></p>

<h4>Terebess Gábor üdvözlete</h4>

<p>Kedves Feri!</p>

<p>Elért a Sivatagi szél haikuművelet, megjött könyved a jövőből (2010). Köszönöm ezt az ünnepi ajándékot. Gyönyörű! Megérdemelted. Gratulálok!</p>

</p>Baráti öleléssel,<br/>
Gábor<p>

<h4>Bakos Ferencről</h4>

<p><img src=\"pics/bakos-ferenc--foto250.jpg\">A Szerző – akkor még: novellaíró – idestova 30 éve kapott egy haiku könyvet a feleségétől karácsonyra; attól fogva munkálkodik a ritka-rövid műfaj honosításán. Fordít és ír, angolul is – költeményei a hazai irodalmi folyóiratokban, európai és tengerentúli (japán és amerikai) antológiákban és internetes honlapokon jelennek meg. Rendszeresen részt vesz a nemzetközi angol nyelvű haiku versenyeken, és begyűjtött már néhány „Tiszteletre Érdemes” oklevelet. Az Ito En japán teacég népes és rangos haiku-versenyének 2009. évi díjazottja.</p>','bakos_sivatagiszel--FD.jpg',133,2,1,0,0,2,'',1,'',40,70,'','',NULL,NULL,'',500,0,NULL,17,12,2009,245,'Bakos Ferenc','Sivatagi szél - haiku','978-963-9934-62-7',2,'','3','120x200 mm',88,'0',1990,1,'#LC2,LGII#  A3 131g','Bakos-Ferenc','http://www.konyvesbolt.online/spd/978-963-9934-62-7/Bakos-Ferenc-Sivatagi-szel---haiku-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=85671&type=22&_v=Bakos_Ferenc_Sivatagi_szel_haiku','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/sivatagi_szel_haiku','http://www.konyvesbolt.online/spd/978-963-9934-62-7/Bakos-Ferenc-Sivatagi-szel---haiku-Ad-Librum-2009','','','',3,3,1,7,4,5,2,'2009-11-20','2009-12-17','84/322-671, 8600 Siófok, Jegenye sor 22.','bakos.ferenc@t-online.hu','A többszörös díjnyertes szerző versei.','Sivatagi szél –
ha embert vágyom látni,
csizmámra nézek.

Vén körtefácskám,
hossz és bessz idusán
csak a pálinkád!','Haikuk

Borka

',NULL,1451297931,0);
INSERT INTO books VALUES('',0,'','Thomas_Forstner--Fata_Morgana--FD.jpg','',0,1,0,0,11,'',1,'',40,70,'','',NULL,NULL,'',500,0,NULL,8,2,2010,246,'Thomas E. Forstner','Fata Morgana','978-963-9934-63-4',2,'','3','130x200 mm',200,'0',1990,1,'#LC1,LGIV#D T:G B:V Egri Tamás','Forstner','http://www.konyvesbolt.online/spd/978-963-9934-63-4/Thomas-E--Forstner-Fata-Morgana-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-63-4/Thomas-E--Forstner-Fata-Morgana-Ad-Librum-2010','','','',3,3,4,7,4,5,5,'2009-11-23','2010-2-8','Egri Tamás 30/904-2961  1132 Bp., Visegrádi u. 82/b.','tomarex@comunique.hu','A titokmorzsák igazi gyűjtői.','A titkok tudói köztünk élnek. Ki meggyőződésből, elkötelezettségből, ki pedig anyagi, vagy karrier ígéretek fejében őrzi a titoknak azt a picinyke morzsáját, amihez a véletlen, vagy a tudása kapcsán jutott.

A titokmorzsák igazi gyűjtői és rendezői, akik odafigyelnek a legbanálisabb történésekre is, behozhatatlan tudáshoz, anyagi és technikai előnyökhöz jutnak. Nem kérkednek vele, nem tolakodnak semmilyen elismerésért, egyszerűen csak használják. 

Közvetve, vagy közvetlenül csak használják.

Thomas E. Forstner','kiajánlva!
',NULL,1451376943,0);
INSERT INTO books VALUES('',0,'','','',0,0,2,43,31,'',1,'','','','','',NULL,NULL,'',300,0,NULL,3,9,2012,247,'Telbisz Márta','Hangról hangra – megtanulok furulyázni','978-615-5110-54-2',2,'','5','140x200 mm',88,'0','',1,'#LB4# Tűzött.','','','','','','','','','',5,3,1,7,4,5,4,'2012-5-0','2012-9-3','Telbiszné Náday Márta, 1114 Budapest, Fadrusz u. 12., (20)356-7539','tnmarta@gmail.com','','','',NULL,1421311081,0);
INSERT INTO books VALUES('',0,'','Nelah_Mored--Sarkanyver--FD.jpg','',0,1,1,0,16,'',1,2000,10,'','','',NULL,NULL,'',28,0,NULL,18,12,2009,248,'Nelah Mored','Sárkányvér','978-963-9934-64-1',2,'','2','',400,'0',3000,5,'#LB2#  Horváth Judit','Nelah-Mored','http://www.konyvesbolt.online/spd/978-963-9934-64-1/Nelah-Mored-Sarkanyver-Ad-Librum-2009','','','','http://www.konyvesbolt.online/spd/978-963-9934-64-1/Nelah-Mored-Sarkanyver-Ad-Librum-2009','','','',3,3,0,7,4,5,0,'Array-0-0','2009-12-18','Horváth Judit, 8000 Székesfehérvár, Vízaknai u. 127. T.: 70/505-0573','horvathjudit@postafiok.hu','A Sárkányvér szomorú meséjét az 1998-ban eltűnt Szathmáry Nikolett, a hazánkban talán legnagyobb erőkkel keresett gyermek sorsa ihlette.','A Sárkányvér szomorú meséjét az 1998-ban eltűnt Szathmáry Nikolett, a hazánkban talán legnagyobb erőkkel keresett gyermek sorsa ihlette. A sárkányok, akik fájó történeteikből összeszőtték a sok éven és életen átívelő történetet, 2001-ben születtek, amikor Nikolett máig magyarázat nélkül maradt halála biztossá vált.

``Lelkesülten folytatták útjukat, érezve, közel már a cél.
Aztán a pillanatnyi remény után hamar megtudták: elkéstek. Látták a megürült ketrecet. Hallották, mi történt, csupán öt nappal előbb. Csak Elanai lehetett a sárkány, akiről beszéltek.
Frofenksz maga is megborzongott, elképzelve a lány életét abban a szörnyű kalitkában. De amikor látta Máktif ökölbe feszülő kezét, a szemét elöntő könnyeket, ő is, mint a többiek, elfordult, hogy ne lássák az apa fájdalmát.
Máktif nem tudott uralkodni magán. Nem kapott levegőt, a szeme a ketrecre tapadt, semmi mást nem látott. Megkapaszkodott a fémrácsokban, és addig szorította őket, míg az ujjai kis híján eltörtek. 
Kislányom! Kislányom! – suttogta merev ajkakkal, kétségbeesetten. 
Jó ideje gépiesen menetelt a sivatagban, többet gondolt a társaira meg az otthoniakra, mint Elanaira. De az a ketrec újra közel hozta őt, túlságosan is közel. Olyan tehetetlen volt, olyan nagy erővel áradt el benne az önvád és a szégyen, amiért engedte, hogy így megalázzák Elanait, aki számított a védelmére, hogy földre lökte a fájdalom.``

A történet főhőse Elanai, az elrabolt sárkánygyerek, akinek nyolc évig tartó keresése körülötte az egész világát megváltoztatja.
Az ő keresői szerencsésebbek, mint akik Nikolett nyomát próbálták megtalálni. Elanai megkerül, bár akkorra már nem ugyanaz, aki volt. Megpróbál újra helyet találni magának a régi életében, de ő is, szerettei is kénytelenek rájönni, hogy hiába hitték a távol töltött évek minden napján, hogy semmi más nem számít, csak újra együtt lehessenek: továbbra is küzdeni kényszerülnek, csak már mással, másért. ','2009.ZKI:7


Szerzői ár: 2000 Ft - 5 db-ot kér

Könyvbemutató 2010. január 14-én, Szathmáry Nikolett éves emléksétáján, Gyulán.',NULL,1451379075,0);
INSERT INTO books VALUES('',0,'','Deak_Csaba--Ordogmalom--FD.jpg',387,'',1,0,0,3,'',1,'',40,70,'','',NULL,NULL,'',1000,0,NULL,5,2,2010,249,'Deák Csaba','Ördögmalom','978-963-9934-67-2',2,'','3','A5',224,'0',2490,1,'#LGV#  RG Közreadó: ifj. Deák Csaba B&T:B','Deak-Csaba','','','','','','','','',3,3,3,7,4,5,3,'2009-11-25','2010-2-5','Deák Csaba, 20-246-4616, Monitor Group Hungary Kft., 1046 Budapest, Farkaserdő utca 19. 4. em. 13.','deakcsaba1@gmail.com','Dráma, novellák és versek.','Két furcsa alak halandzsázása egy földmélyi bunkerben, majd egy odacsalt emberke hátborzongató és mégis komikus vallatása, testi-lelki megtörése az Elhárítás figyelő szemei előtt . Mindez csak egy gyilkos hatalmi játszma része, vagy a végén felbukkanó rejtélyes űrlakók manipulálták a tragikomikus színjátékot...? – Megjelenésük után a szereplők fejei már csak ijesztő halotti maszkok. Szélsőséges terrorista csoportocska akar bosszút állni az őket frusztráló társadalmon. A katonai és polgári elhárítás csetlik-botlik az események nyomában, ám az egymással rivalizáló szervezetek nem bírnak az ördögi véletlen-láncolattal, ami szinte törvényszerűen vezet a főváros szívében egy atombomba felrobbantásához. Klinikai halál állapotából visszatért embertársunk számol be „élményeiről”, ám homályos jelentésű szavain elmondhatatlan borzalmak sejlenek át. Hogyan járhatja meg a legelszántabb állatbarát, ha egyszer a balszerencse üldözőbe veszi? – megtudhatjuk egy másik írásból. Mindezek után talán felüdülést jelentenek majd az Olvasónak a „Tündér-idő” versei.','A megrendelő és kapcsolattartó a szerző fiának a cége, a Monitor Group Hungary.

11-08-07: #RG 75 pld.',NULL,1458820350,0);
INSERT INTO books VALUES('',0,'','Vasi_Szabo_Janos--Vilagallam--FD.jpg','',0,1,1,3,13,'http://books.google.hu/books?printsec=frontcover&id=Jr2VaVuG16AC#v=onepage&q=&f=false',1,1040,10,'','','',NULL,NULL,'',50,0,NULL,18,12,2009,250,'Vasi Szabó János','Világállam','978-963-9934-65-8',2,'','2','A5',73,'0',1690,5,'#LB5#','Vasi-Szabo-Janos','http://www.konyvesbolt.online/spd/978-963-9934-65-8/Vasi-Szabo-Janos-Vilagallam-Ad-Librum-2009','','','','http://www.konyvesbolt.online/spd/978-963-9934-65-8/Vasi-Szabo-Janos-Vilagallam-Ad-Librum-2009','','','',3,3,1,7,4,5,3,'2009-11-0','2009-12-18','9762 Tanakajd, Kossuth L. u. 26. Tel.: 94/711-108','vasi.szabo.janos@gmail.com','','A Világállam helyszínei különbözőek: a Mars rideg homokja, a galaxis mélyén rejtőző civilizáció, klausztrofóbiás fémburok-otthon, zöld planétánk alternatív valósága, a mediterránum hőségtől szenvedő kőtáblái.
  Közös bennük az orwelli elveken szervezett társadalom: félelmetes diktatúra, ahol a magánélet legapróbb részleteibe is beleüti orrát a hatalom. Az írások számos igen érdekes kérdést vetnek fel: hányféle módon torzulhat egy totális diktatúra embereinek élete; hogyan terheli az emberi kapcsolatokat, átláthatunk-e minden ezzel kapcsolatos problémát?
  A Világállam novellái érzékletes leírások ebből az egyszer már megtörtént, nyomasztó „jövőből”.','2009.ZKI:39


A borító Viktornál.
',NULL,1451301623,0);
INSERT INTO books VALUES('',0,'','Hoppe--Demokracia--FD.jpg',437,3,1,1,40,42,'',0,2200,0,0,'','',NULL,NULL,'',300,0,NULL,12,2,2010,251,'Hans-Hermann Hoppe','Demokrácia, a bukott bálvány. A monarchia, a demokrácia és a természetes rend gazdaságtana és politikája','978-963-9934-68-9',2,'','3','170x240 mm',240,'0',2990,5,'#LB2, LGII#   Rraklap','Hoppe','http://www.konyvesbolt.online/spd/978-963-9934-68-9/Hans-Hermann-Hoppe-Demokracia-a-bukott-balvany--A-','http://bookline.hu/product/home!execute.action?id=86450&type=22&_v=Hoppe_Hans_Hermann_Demokracia_a_bukott_balvany','','','http://www.konyvesbolt.online/spd/978-963-9934-68-9/Hans-Hermann-Hoppe-Demokracia-a-bukott-balvany--A-','','','',3,3,0,9,4,5,5,'Array-0-0','2010-2-12','Váradi István, 1174 Bp., Kisfaludy u. 13. T.: 30/334-6892','ivaradi@gmail.com','A híres közgazdász és filozófus javaslatai egy általa  természetes rendnek nevezett, állam nélküli, a magántulajdon teljes tiszteletben tartásán alapuló társadalom kialakítására.','HANS-HERMANN HOPPE 1949-ben született Nyugat-Németországban. Egyetemi tanulmányait ott, és az Egyesült Államokban végezte. 1986-ban az Egyesült Államokba költözött, ahol Murray Rothbard, az osztrák közgazdaságtani iskola anarcho-kapitalista tagja mellett folytatta munkáját.

2006-ban megalapította a Tulajdon és Szabadság Társaságát (Property and Freedom Society), amely a magántulajdon, a szerződési és társulási szabadság, valamint a teljesen szabad kereskedelem védelméért száll síkra.

A könyv alapját a nyugati világban lezajlott, a monarchikus korból a demokráciába való történelmi átmenet felülvizsgálata képezi. A szerző feltárja mindkét társadalmi berendezkedés hibáit, és a ma elterjedt nézettel szemben megállapítja, hogy a monarchia kevésbé káros, mint a demokrácia. Javaslatot tesz egy általa  természetes rendnek nevezett, állam nélküli, a magántulajdon teljes tiszteletben tartásán alapuló társadalom kialakítására.

Módszere logikai következtetéseken alapul, melyek révén a történelmi események (újra)értelmezésére alkalmas gazdasági és társadalmi tételeket állít fel.','10 pld-t kért a fordító.

Eredeti cím:
Democracy: The God that Failed

Borító: Borka',NULL,1451383170,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Elmenni_messze--FD.jpg','',0,1,1,0,4,'',1,2290,0,0,'','',NULL,NULL,'',70,0,NULL,21,8,2012,252,'P. Dobrossy Rita','Elmenni messze...','978-615-5110-56-6',2,'','5','140x200 mm',361,'0',1990,5,'#LB3  T:G B:B','','http://www.konyvesbolt.online/spd/978-615-5110-56-6/P--Dobrossy-Rita-Elmenni-messze----Ad-Librum-2012','','','','http://www.konyvesbolt.online/spd/978-615-5110-56-6/P--Dobrossy-Rita-Elmenni-messze----Ad-Librum-2012','','','',3,3,2,7,4,5,5,'2012-5-0','2012-8-21','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','A könyv négy kisregényt tartalmaz, amelyek címéhez - éppen úgy, mint az első kisregényhez – a Kormorán zenekar dalai adták az ihletet. A „Ha messze méssz…” című kisregény egy művészeti kolónia mindennapjait mutatja be. A két főszereplő egyike a világtól megcsömörlött híres zenész, aki terápiás céllal költözött társaihoz. Közte, és a fájdalmas múltú, szép festőnő között kialakuló, sodró lendületű szerelem vezérfonalán keresztül jutunk el a meglepő befejezésig.

Koltay Gergely csodaszép dalának felidézésével ajánlom még három - másodszorra kiadott - kisregényemet, melyek mindegyikében egy-egy újrakezdett élet nehézségeit, viszontagságát, és tünékeny boldogságát találja meg az olvasó. A dalrészlet - őszintén remélem - megtalálja helyét lelkekben, és szívekben egyaránt...  de tartalma alapján, minden esetben föl kellett adni a biztosat a bizonytalanért, és
 
ELMENNI MESSZE
 
Elmenni messze
magasra felrepülni
csapódni kőhöz
üvegként összetörni.
Veled, mégis egyedül
állni, csak állni szótlan,
végleg összeforrva
az életen túl egy csókban.','Nincs jogdíj.',NULL,1451299941,0);
INSERT INTO books VALUES('',0,'','Vasvari_Gyorgy--Biztonsagi_kultura--FD.jpg','',0,1,1,34,38,'',0,1100,0,0,'','',NULL,NULL,'','',0,NULL,18,12,2009,253,'Vasvári György CISM','A társadalmi és szervezeti (vállalati) biztonsági kultúra','978-963-9934-66-5',2,'','2','',100,'0',1990,5,'#LA5','Vasvari-Gyorgy','http://www.konyvesbolt.online/spd/978-963-9934-66-5/Vasvari-Gyorgy-CISM-A-tarsadalmi-es-szervezeti-val','','','','http://www.konyvesbolt.online/spd/978-963-9934-66-5/Vasvari-Gyorgy-CISM-A-tarsadalmi-es-szervezeti-val','','','',3,3,1,7,4,5,2,'2009-11-25','2009-12-18','Vasvári György, 1157 Budapest, Erdőkerülő u. 21.','gvasvari@tiphaz.hu','A biztonsági kultúrát társadalmunkban és az azt alkotó humán közösségekben a figyelem, a képzés, a védelem központi kérdésévé kell tenni.','A globalizáció, az információs társadalom kialakulása új biztonsági kihívásokat vet fel, amit kegyetlenül bizonyít az USA elleni 2001. szeptember 11-i terroristatámadás. A leküzdendő vagy csökkentendő biztonsági kockázatok közé bekerült a fizikai, számítástechnikai terrorizmus (a cyberterror) is. A katonai információs hadviselés mellett pedig megjelent a társadalmakat, szervezeteket, vállalatokat, egyéneket és a civilszférát egyaránt fenyegető változata is.
A biztonságtechnikában felértékelődik az emberi tényező. A társadalomnak és az azt alkotó közösségeknek (szervezeteknek), ezért a megfelelő védelemhez magas szintű biztonsági kultúrával, biztonsági tudatossággal és etikával rendelkező humán erőforrásokkal kell rendelkeznie.
E kérdések kifejtése a társadalom, a szervezet (vállalat), a kultúra, a biztonság, a biztonsági kultúra és biztonsági tudatosság, az etika, valamint ezek kapcsolatának, egymásra hatásának vizsgálatával történik. Ezt követi a biztonsági kultúrák szerepének kifejtése az emberi tényező biztonsági hatékonyságának növelésében. Majd e kultúrák biztosításában az egyén személyiségjegyeinek szerepéről, annak célirányos fejlesztésről kerül szó. A könyv foglalkozik a biztonsági kultúrák felmérésével, fejlesztésével, napra készen tartásával is.
Végül rámutat arra, hogy ezt az eddig nem megfelelően művelt területet, a biztonsági kultúrát társadalmunkban és az azt alkotó humán közösségekben, a figyelem, a képzés, a védelem központi kérdésévé kell tenni. Szembe kell nézni azzal, hogy nem lehet hatékony önvédelmi intézkedéseket biztosítani, az emberi tényező és közösségek magas szintű biztonsági kultúrája, tudatossága, etikussága nélkül.','2009.ZKI:24+1=25

091202: Viktor tördeli és borítózik.

B6 méretű

A szerző lemondott a jogdíjról, de 25 példányt kap a szerzői ár feléért kiadáskor.
',NULL,1451383090,0);
INSERT INTO books VALUES('',0,'','Mester_Gyorgyi--Zizi_naploja_III--FD.jpg','',0,1,1,0,16,'',1,'',40,60,'','',NULL,NULL,'',100,0,NULL,18,7,2012,254,'Mester Györgyi','Zizi naplója - A Kos jegyében','978-615-5110-57-3',2,'','5','115x165 mm',100,'0',500,1,'#LB4# T&B:B','','http://www.konyvesbolt.online/spd/978-615-5110-57-3/Mester-Gyorgyi-Zizi-naploja---A-Kos-jegyeben-Ad-Li','','','','http://www.konyvesbolt.online/spd/978-615-5110-57-3/Mester-Gyorgyi-Zizi-naploja---A-Kos-jegyeben-Ad-Li','','','',3,3,1,7,4,5,4,'2012-6-1','2012-7-18','2092 Budakeszi, Ifjúság u. 2., 23/451-617','mestergyorgyi@freemail.hu','','Ismét tizenegy tagúra bővült a családunk. Egyszer volt már erre példa, bár akkor négy kutyakölyökkel lettünk gazdagabbak, most viszont egy »kos« került a családunkba.
Nagyinak igaza volt, és nagyinak mégsem lett igaza. Igaza volt, hogy ha férjhez megy az ember, nagyon elfoglalt lesz, szinte megszűnik a szabadideje.
Nagyinak ugyanakkor nem lett igaza, mivel, a családi fekete krónika híresztelései ellenére, négyes ikrek — a már említett kutya leszármazottakon kívül —, még sohasem voltak a családunkban.
És ez most sem így történt, mert március 23-án megszületett a gyermekem, és csak egy fiacskám született, egy igazi vadóc kis »kos«...','',NULL,1451379214,0);
