INSERT INTO books VALUES('',0,'','Wanderer_Janos--Csilimon--FD.jpg','',0,1,0,0,3,'',0,'',40,60,'','',NULL,NULL,'',300,0,NULL,14,11,2012,260,'Wanderer János','Csilimon','978-615-5110-59-7',2,'','5','130x200 mm',142,'0',1990,1,'#LB6,LG10#  6 egész oldalas képpel. K:K T:G B:B','Wanderer-Janos','http://www.konyvesbolt.online/spd/978-615-5110-59-7/Wanderer-Janos-Csilimon-Ad-Librum-2012','','','','http://www.konyvesbolt.online/spd/978-615-5110-59-7/Wanderer-Janos-Csilimon-Ad-Librum-2012','','','',3,3,4,7,4,5,3,'2012-9-17','2012-11-14','Wanderer János, 30/217-1636, 1115 Budapest, Etele út 52/A. VIII/48.','csilimon@gmail.com','Lenyűgöző novellák.','Mi történik azzal, aki hirtelen a csúcsra ér? Miért higgadt a kalauz,
egyáltalán szükség van-e vasútra? Kire vár a kislány az ablak előtt?
Mi rejlik egy pocsolya fenekén? A fenti kérdésekre a választ e kötet
novellái, elbeszélései nyújtják. Megtudjuk belőlük azt is, hogy
mennyit ér a győzelem a pályán, mennyit a vízparton s mit jelent a
kisfiúnak egy pár futballcipő?','',NULL,1451298424,0);
INSERT INTO books VALUES('',0,'','Susy_Cat_Lee--Forro_csoki_es_fekete_kave--FD.jpg','',0,1,0,0,16,'',1,'',40,60,'','',NULL,NULL,'',300,0,NULL,23,11,2012,261,'Susy Cat Lee','Forró csoki kontra fekete kávé','978-615-5110-60-3',2,'','5','120x200 mm',284,'0',1990,1,'#LE4,LGV#K: szerző T:T B:B Ivicsics Mátyásné ','Susy-Cat-Lee','http://www.konyvesbolt.online/spd/978-615-5110-60-3/Susy-Cat-Lee-Forro-csoki-kontra-fekete-kave-Ad-Lib','','','','http://www.konyvesbolt.online/spd/978-615-5110-60-3/Susy-Cat-Lee-Forro-csoki-kontra-fekete-kave-Ad-Lib','','','',3,3,1,7,4,5,4,'2012-9-17','2012-11-23','Ivicsics Mátyásné, 30/3284099, 1163 Budapest, Lándzsa u. 21/C.','ivicsics.zsuzsi@gmail.com','','– Ez nem kínai, hanem irodalmi – vágta rá Kinué.
– Lassan magyarázd el neki – tanácsoltam.
– Szótagoljam vagy rágjam a szájába? – kérdezett
vissza.
– De hölgyeim, kérem!
– Elnézést, Mr. Belgian – szabadkozott barátném.
– Kérem, magyarázza el Mr. Jonesnak e mű értelmét!
Kinué Mikey felé fordult, majd kedvesen, pontosab-
ban tyúkanyó stílusban előadta magát.
– Kedves fiam, Mikey...','+30.000 forint a terjedelem növelése miatt a 2. részletben.',NULL,1451378699,0);
