INSERT INTO books VALUES('',0,'','','',0,0,2,0,10,'',0,'','','','','',NULL,NULL,'',12,0,NULL,23,1,2013,270,'Ellen Adlon','A Csajkovszkij-projekt I. Árnyak az éjszakában','(nincs ISBN)',1,'','6','140x200 mm',200,'0','',1,'Horváth Edit','','','','','','','','','',5,3,4,7,4,5,5,'2012-11-0','2013-1-23','Asszisztens: katalin.kiss71@gmail.com 20/403-6971; Horváth Edit 1071 Damjanich u. 28/A. Fszt. 8.a. 70/201-5871','katalin.kiss71@gmail.com','','Gyönyörű nők és a markukban tartott dörzsölt üzletemberek. Valamelyikük meg akarja kaparintani a hatalmas befektetéseket, amelyeket az oroszok a világraszóló sporteseményükre szántak. Kinek sikerül? Ez csak az első gyilkosság megtörténte után derül ki. A riválisok harca kíméletlen, a gyilkos kézre kerítéséhez pedig szükség van a Scotland Yard, a francia rendőrség és az orosz titkosszolgálat kíméletlen bevetésére is...','',NULL,1366961018,0);
INSERT INTO books VALUES('',0,'','Pataki_Janos--A_vegrehajto_es_az_ados--FD.jpg',414,'',1,0,0,38,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,25,1,2013,271,'dr. Pataki János István','A végrehajtó és az adós. A bírósági végrehajtás a gyakorlatban','978-615-5110-62-7',2,'','6','140x200 mm',224,'0',3990,1,'#LB5,LGV,LGVI#','','http://www.konyvesbolt.online/spd/978-615-5110-62-7/dr--Pataki-Janos-Istvan-A-vegrehajto-es-az-ados--A','','','','','','','',3,3,4,7,4,5,5,'2012-11-18','2013-1-25','dr. Pataki János István, 1046 Budapest, Hárfa u. 34., 30/422-1928','patakijdr@gmail.com','A végrehajtási ügyek manapság magas száma igényel egy ilyen jellegű jogi szakmai és szociológiai összefoglaló munkát, amely iránymutatás keretében igyekszik válaszokat adni minden érdeklődő és érintett fél számára. Keménytáblás.','A bírósági végrehajtási eljárás foganatosítása során gyakran előfordulnak problémák és félreértések a gyakorlati életben. Jelen monográfia ezek magyarázatára törekszik azzal, hogy azon élet- és jogi helyzetekre összpontosít, amelyekben a bírósági végrehajtó és a végrehajtási eljárás foganatosítása által érintett személyek interakciója magában hordozza a konfliktus lehetőségét. Vizsgálat tárgya továbbá az eljárás társadalomra és gazdaságra gyakorolt hatása, a bírósági végrehajtási eljárás elhelyezkedése a jogon mint társadalmi alrendszeren belül.
A végrehajtási ügyek manapság magas száma bizonyosan igényel egy ilyen jellegű jogi szakmai és szociológiai összefoglaló munkát, amely iránymutatás keretében igyekszik válaszokat adni minden érdeklődő és érintett fél számára. A könyv nem csak a jogásztársadalomnak szól, hanem minden, a témában érintett vagy érdekelt résztvevőnek is.
A kötet a legfrissebb információkat tartalmazza, a 2012-ben jelentősen módosult irányadó jogszabályi hátteret is követi.
A könyvet Dr. Krejniker Miklós a Magyar Bírósági Végrehajtói Kamara elnöke lektorálta, az előszót Dr. Schadl György PhD főiskolai docens írta. A borító Szabó Borka tervei alapján készült.','Bankszámlaszám: 11100104-90135118-33000002',NULL,1485945741,0);
INSERT INTO books VALUES('',0,'','Kolcsey_Krisztina--Hajnalhasadas--FD.jpg','','',1,1,0,12,'',1,1694,10,'','','',NULL,NULL,'',70,0,NULL,24,2,2010,272,'Kölcsey Krisztina','Hajnalhasadás','978-963-9934-70-2',2,'','3','',280,'0',2200,5,'#LB3, LG20#','Kolcsey-Krisztina','http://www.konyvesbolt.online/spd/978-963-9934-70-2/Kolcsey-Krisztina-Hajnalhasadas-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,4,'2010-1-17','2010-2-24','Pappné Kölcsei Krisztina, (06-20)290-4339, 2315 Szigethalom, Mű út 264/B.','kolcsei.kriszti@gmail.com','','Az első szerelem jelentős fordulatot hoz minden nő életébe. Ez alól Fonyó Adél sem kivétel, aki tizenöt évesen, egy balatoni nyaralás alkalmával éli át, milyen is az, ha Ámor nyílvesszője szíven találja. Ám a boldog végkifejlet sajnos elmarad, és a fiatal lány keserű csalódottsággal tapasztalja meg az elutasítás fájdalmát.
Tíz év elteltével Hídvéghy Márk ismét keresztezi az útját, immár jelentős vagyonra szert téve, amely azonban – úgy tűnik – végérvényesen megakadályozza sorsuk egybeforrását.
Ám a szív szavának nehéz ellenállni, és miközben hőseink kétségekkel teli érzelmi szálaik kibogozásán fáradoznak, a háttérben egy sikkasztással egybekötött emberrablás zajlik, amelynek kimenetele súlyos tragédiával fenyeget.
Vajon sikerül-e Adélnak és Márknak a – sokszor önhibájukból adódó – problémákat legyőzni, megmentve ezzel szerelmüket? Legyőzhető-e egy olyan ellenség, aki a homályból támad, és akinek az értékrendjében a pénz imádata, meg a hőn áhított hatalom birtoklása mögé szorul az emberi élet?
Ez a lebilincselően izgalmas regény választ kínál a kérdésekre, miközben egyszerre megtapasztalhatjuk az igaz szerelem varázslatos szépségét, és azt a fajta önzést, amely az embert testestül-lelkestül romba dönti, megfosztva őt azoktól az értékektől, amelyek a lélek tisztaságának megőrzéséhez szükségesek.
','50 bizományosi terjesztésre szánt pld. kell az elején + 2 a szerzőnek

Viktor',NULL,1460364334,0);
INSERT INTO books VALUES('',0,'','Bosnyak_Maria--Tureshatarig--FD.jpg','','',1,1,0,12,'',1,1238,10,'','','',NULL,NULL,'',50,0,NULL,26,2,2010,273,'Mária M. Bosnyák','Tűréshatárig','978-963-9934-71-9',2,'','3','140x200 mm',146,'0',2990,5,'#LB3,LG31#  T:G,B:V','Maria-Bosnyak','http://www.konyvesbolt.online/spd/978-963-9934-71-9/Maria-M--Bosnyak-Tureshatarig-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,5,'2010-1-20','2010-2-26','Bosnyák Mária, 20/557-3769, 2800 Tatabánya ,Tatai út 9/1.','bosnyak.maria@freemail.hu','','Amíg az ember fiatal, azt gondolja, hogy csak az ő kiváltsága a szerelem. A középkoron vagy még azon túli korosztály pedig már mentes ettől a világrengető érzéstől. De nem így van!

A szerelem nem válogat. Ugyanolyan elementáris erővel söpör végig a gyanútlan, magát már védettnek hitt szíveken is.

Amíg a fiatalnak van ideje több csalódáson is sikeresen túlesni, addig az érettebb korosztálynak talán ez az utolsó esélye a boldogságra. Nekik már nehezebb, mert meg kell küzdeniük a hátuk mögött, több, rosszul sikerült házasság terhével is. Nem könnyű elfogadni egymás már kialakult szokásait sem. Megkeserítheti a kialakuló kapcsolatukat a régről magukkal hozott sérelmek árnyéka is, amely sokszor igazságtalanul bizalmatlanná teszi a másikkal szemben. És nem egyszer az új partner kapja vissza a múltban kapott pofonokat is.

A szerelem ára és Mint levél a szélben című könyvek folytatása.','A szerző tartozik a plakátok árával.

25 db. kell a szerzőnek kiadás után.',NULL,1460364246,0);
INSERT INTO books VALUES('',1,'','Kontschan_Jeno--Uropodina_mites_from_Korean_Peninsula--FD.jpg','',0,1,1,0,43,'',1,1390,'','','','',NULL,NULL,'',40,0,NULL,23,1,2013,274,'Kontschán Jenő','Uropodina mites from the Korean Peninsula','978-615-5014-66-6',2,'','6','140x200 mm',78,'0',2500,5,'#LB2','','http://www.konyvesbolt.online/spd/978-615-5014-66-6/Kontschan-Jeno-Uropodina-mites-from-the-Korean-Pen','','','','http://www.konyvesbolt.online/spd/978-615-5014-66-6/Kontschan-Jeno-Uropodina-mites-from-the-Korean-Pen','','','',3,3,1,7,4,5,3,'2012-11-28','2013-1-23','Dr. Kontschán Jenő, 30/768-6927, ideiglenes lakcím: 1215 Budapest, Árpád u. 12/C. 2/62.; állandó: 2840 Oroszlány, Takács I. u. 3.','jkontschan@gmail.com','','','25 pld. a szerzőnek

OSZK levél alapján egy régi ISBN újrafelhasználásával.',NULL,1451383488,0);
INSERT INTO books VALUES('',0,'','Fulop_Beata--Dolce--FD.jpg',226,0,1,0,4,12,'',1,'',40,40,'','',NULL,NULL,'',250,0,NULL,8,3,2010,275,'Fülöp Beáta','DOLCE – A megbocsátás ára','978-963-9934-74-0',2,'','3','148x210 mm',220,'0',2490,1,'#LB6# RA1b','Fulop-Beata','http://www.konyvesbolt.online/spd/978-963-9934-74-0/Fulop-Beata-DOLCE-A-megbocsatas-ara-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-74-0/Fulop-Beata-DOLCE-A-megbocsatas-ara-Ad-Librum-2010','','','',3,3,0,7,4,5,3,'2010-1-0','2010-3-8','30/260-1653 1185 Bp., Zilah u. 66.','dolcespiritoso71@yahoo.com','Ez a könyv a szerelemről, az érzelmek erejéről és a megbocsátásról szól.','Ez a könyv a szerelemről, az érzelmek erejéről és a megbocsátásról szól. Egy szárnyait próbálgató írónő és egy trombitaművész megismerkedik a világhálón. Már megismerkedésük elején mélyen és visszavonhatatlanul egymásba szeretnek. Idillinek tűnő kapcsolatukba azonban lassan, de biztosan problémák szűrődnek be a múltból, amelyek megmérgezik a jelent is. Elindul egy érzelmi lavina, amely egyre nagyobb erővel és tömeggel zúdul rájuk, és kezdetét veszi egy könyörtelen, kétségbeesett és végeláthatatlan harc az elveszettnek hitt bizalom helyreállításáért, a becsület visszaszerzéséért. 
   Az érzelmek – amelyek irányítják az egész cselekményt – nem akaratlagos tevékenységei az embernek, mégis olyan hatásokkal bírnak spontán magatartásunkra, amelyek nem várt helyzeteket eredményeznek. 
Feszítő és feloldozó, örökké vibráló, kínzóan fájdalmas és mégis boldog, csábító, érzékeny, a végletekig érzelmes hangulatok ezek, amelyek ott élnek mindnyájunkban. A kínlódás és a tehetetlenség elleni harc ez az igaz szerelem mellett, az igazság és hazugság mezsgyéjén. 
   Vajon sikerül-e a szerelmeseknek kimászniuk az érzelmi csapdából, anélkül, hogy életre szóló sérüléseket szereznének? Sikerül-e győztesen kikerülni a háborúból, amit egymás ellen vívnak, de egymásért? Vagy marad az örök lángok közötti vergődés, a kínzó, beteljesületlen vágyakozás a másik után? A megbocsátás valóban az őszinte szerelem szócsöve, vagy csupán egy emberi érzelmektől mentes tudatos cselekedet?
   Többek között ezekre a kérdésekre is választ ad a könyv.','11-08-07: #RA1b 9 pld. (stimmel)

Előkészítés és terjesztés, a nyomdai munka a szerző szervezésében.

',NULL,1451378252,0);
INSERT INTO books VALUES('',0,'','Alim_BR--Hentes--FD.jpg','',0,1,1,0,14,'',1,1346,10,'','','',NULL,NULL,'','',0,NULL,13,10,2010,276,'Alim B. R.','Hentes','978-963-06-7848-3',1,'','3','120x200 mm',182,'0',2390,5,'#LB4,LG18#  Csavnyiczky Bettina, T:G,B:B','Alim','http://www.konyvesbolt.online/spd/978-963-06-7848-3/Alim-B--R--Hentes-2010','','','','http://www.konyvesbolt.online/spd/978-963-06-7848-3/Alim-B--R--Hentes-2010','','','',3,3,1,7,4,5,5,'2010-1-0','2010-10-13','Csavnyiczky Bettina, 1152 Bp., Kiss Ernő u. 11. T.: 20/545-9203','csavnyiczkybettina@gmail.com','','Jim Little, Duluft város őrzője. Amikor rejtélyesen eltűnt emberek után kutat, hátborzongató felfedezésre lel az Ironheard család háza táján. Jim azt hiszi, hogy lezárhatja a gyilkossági ügyeket, de nagyot téved - a rémálmok még nem értek véget. Végig kell járnia a poklot, hogy a szörnyűségeket felfedezze. Arra pedig végképp nem számít, hogy személyesen is érintett lesz a család végzetében.

Azt hiszed, mindent tudsz? Akkor nagyon tévedsz!','kiadás után 10 db-ot kér',NULL,1451378553,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,35,'',1,'',40,60,'','',NULL,NULL,'',300,0,NULL,26,2,2010,277,'Yasmín Hondar Gómez','Mosolyogva spanyolul','978-963-9934-36-8',2,'','3','A4',212,'0',3990,1,'#LB7  T&B:Szerző','Mosolyogva_spanyolul','http://www.konyvesbolt.online/spd/978-963-9934-36-8/Yasmin-Hondar-Gomez-Mosolyogva-spanyolul-Ad-Librum','','','','http://www.konyvesbolt.online/spd/978-963-9934-36-8/Yasmin-Hondar-Gomez-Mosolyogva-spanyolul-Ad-Librum','','','',3,3,0,9,4,5,3,'2010-1-20','2010-2-26','Jakab Istvánné, 3529 Miskolc, Szentgyörgy u.74. 3/5, 0630/743-79-47,0646/562-268','yasminh@t-online.hu','','Könyvem a magyarul beszélő, 14. életévüket betöltött nyelvtanulók számára készült, hogy a spanyol nyelvet egészen az alapoktól, logikusan felépített módon tanítsa.

     A tapasztalatom az, hogy a spanyol nyelvet elsőnek választóknak a két nyelv eltérő rendszere miatt nehézségeik vannak a nyelvtanulásban. 

     Szeretnék segíteni azoknak, akik még soha nem tanultak idegen nyelvet, hogy könnyen és élvezetes módon sajátítsák el a spanyol nyelvet. Az egyszerű nyelvtannal írt, képekkel illusztrált, vicces történetek, valós szituációkon alapuló érdekes párbeszédek, számtalan gyakorlat, valamint a versek, közmondások segítik a nyelv megtanulását. A nyelvtanulásban jártasak pedig gyorsabban is haladhatnak. 

A könyv 22 egységből áll, az egyes leckék struktúrája a következő:

    * Nyelvtan
    * Példák képes illusztrációk segítségével, a fő kérdések és válaszok magyarra fordítva
    * Nyelvtani gyakorlatok
    * Valós szituációkon alapuló gyakorló párbeszédek
    * Olvasmányok
    * Vicces történetek, közmondások, versek
    * Szószedet
    * Házi feladat

     A fejezetek egymásra épülnek, a következő fejezethez szükséges lexikai és nyelvtani alapot mindegyik fejezetrész megadja, így könnyen és egyszerűen lehet továbbhaladni.

     A témához kapcsolódó érdekes párbeszédek, leckék, viccek és folytatásos mesék könnyen olvashatók anélkül, hogy unalmasnak találnák, emellett közben rendkívül sok szót is megtanulnak.

     Ezzel a könyvvel megismerhetik a kijelentő mód jelen idejét, az egyszerű  jövő időt, továbbá a közel-, a befejezett, a folyamatos és a folyamatos régmúlt idők használatát. Elsajátíthatják a határozói igenév, melléknévi igenév, a tárgy-, a részeshatározó esetek, a felszólító mód és az ir –„menni” ige különleges használatát is.

     Remélem, hogy ezzel a könyvvel a nyelvtanulás élvezetesebb és gyorsabb lesz azoknak is, akik a nyelvet nehezebben tanulják.

     Sok sikert kívánok Önöknek a spanyol nyelv tanulásához! 

Yasmin Hondar Gómez
','Javított kiadás ISBN: 978-615-5110-30-6',NULL,1451382135,0);
INSERT INTO books VALUES('',0,'','GabeReal--Tudod_vannaK_azok_a_szavak--FD.jpg','','',1,1,0,2,'',1,1040,10,'','','',NULL,NULL,'',40,0,NULL,4,3,2010,278,'GabeReal the Great','Tudod, vannak azok a szavak','978-963-06-8817-8',2,'','3','A4',80,'0',1980,5,'#LA3','GabeReal','http://www.konyvesbolt.online/spd/978-963-06-8817-8/GabeReal-the-Great-Tudod-vannak-azok-a-szavak-Ad-L','','','','','','','',3,3,0,7,4,5,5,'Array-0-0','2010-3-4','Nagy Gábor Imre 70/452-2060  6000 Kecskemét, Pákozdi csata u. 1. IV/40.','gaberealthegreat@vipmail.hu','','Mit összegezzek itt hátul,
mitől nyolcvan lap feltárul,
miről ez egy mindent elárul?
 

Miféle kincset villantsak,
hogy a papírt lásd aranynak,
kincstárát puszta szavaknak?

Miféle nagyságot, urat
kérjek fel, hogy hazudja:
„E kötet remek munka!”?

Csupán ajánlom, őszintén.
A döntés, mint mindig, tiéd:
Érdekel, belülre mi fért?','120x200 mm',NULL,1463045028,0);
INSERT INTO books VALUES('',0,'','Kopor_Tihamer--Folyondar--FD.jpg',240,0,1,0,0,4,'',1,'',5,20,'',75,NULL,NULL,300,300,5,NULL,10,5,2010,279,'Kopor Tihamér','A Folyondár','978-963-9934-73-3',2,'','3','A5',180,'0',2290,2,'#LGI,LB3# T:G B:B','Kopor-Tihamer','http://www.konyvesbolt.online/spd/978-963-9934-73-3/Kopor-Tihamer-A-Folyondar-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-73-3/Kopor-Tihamer-A-Folyondar-Ad-Librum-2010','','','',3,3,0,7,4,5,5,'Array-0-0','2010-5-10','30/211-1963  2030 Érd, Talabor u. 42.','kate.kopor.tihu@gmail.com','Négy ember karmikusan meghatározott egymáshoz tartozása.','„Mindenkinek csak ajánlani tudom… Nagyon belterjes ez a történet. Mint egy görög dráma, amelynek hősei egy városban élnek generációk óta, sorsuk számtalan alkalommal összefonódott… A múltnak súlya van ebben a könyvben.”

Rigó Béla író, a Kincskereső folyóirat főszerkesztője
 

Eleve elrendeltetés, vagy szabad akarat? Ez a lebilincselő, érzelmileg megrázó alkotás, az örök emberi kérdéseket feszegeti. Amikor életünk keresztútjainál valamelyik irányba fordulunk, szabad akaratunk testesül-e meg, vagy végrehajtjuk transzcendens lényünknek még a születésünk előtt megalkotott élettervét?

A főhős élete utolsó hetében már nem kapaszkodik a mindegy milyen, de mégis csak élet, meglévő cafataiba. Már nem néz szűkölő félelemmel a hamarosan bekövetkező végre – sőt van ereje tréfálkozni is róla. Mert szabaddá vált a lelke. De vajon boldoggá is?

Ez a mű négy ember karmikusan meghatározott egymáshoz tartozásáról szól. Az utolsó napjait élő főhős, Kaszás Tamás és életét, sőt életeit meghatározó két nő bonyolult, az övéhez sorsszerűen kapcsolódó viszonyáról. Az egyik az életerejét akaratlanul is elszívó, gúzsba kötő feleség, a másik az örök, nagy szerelem, az izgalmasan szép, intelligens Gina.

Valamint a mellékszereplő ápolónővér is fontos ablakot nyit visszaemlékezésében, amelyen keresztül ráláthatunk Kaszás Tamás lényének arra az alapvonására, amelyik mindig is mozgatta tetteiben. Nem mellesleg megismerhetjük saját egyéni drámájának örökre titkolni akart sötét részletét is.

Kaszás Tamásnak adatott egy lehetőség, hogy egy életen belül, újra kezdhetik lelkének iker részével, az eltéphetetlen igazi nagy szerelemmel. De nem tud élni a lehetőséggel, eltékozolja az időt, a létet, a vágyat. Akár a legtöbb lottónyertes a főnyereményt. A döntés előli menekülést választja. Vagy a megoldást?

Lehet-e a halál happy end?

Erről szól ez a szívbe markoló, izgalmas lélektani regény.','kiajánlva!',NULL,1451300196,1);
INSERT INTO books VALUES('',3,'','Yasmin_Hondar_Gomez--Compartiendo--FD.jpg',159,0,1,2,0,31,'',0,'','','','','',NULL,NULL,'',100,0,NULL,15,8,2014,280,'Yasmín Hondar Gómez','Compartiendo sueños con mis amigos de Vento','978-615-5110-65-8',2,'','7','140x200 mm',120,'0',2978,1,'#LB5,LG8# spanyol nyelvű','','http://www.konyvesbolt.online/spd/978-615-5110-65-8/Yasmin-Hondar-Gomez-Compartiendo-suenos-con-mis-am','','','','http://www.konyvesbolt.online/spd/978-615-5110-65-8/Yasmin-Hondar-Gomez-Compartiendo-suenos-con-mis-am','','','',3,3,1,9,4,5,5,'2014-1-0','2014-8-15','','','','Esta sencilla novela describe la vida de los alumnos de la Escuela Vocacional de Vento en los años del 68 al 71 del siglo pasado. Este texto no solo es mío; es de todos aquellos que me ayudaron a reconstruir pedazos de nuestra juventud.
   No es una novela cronológica. Son recuerdos que me vinieron a la mente como relámpagos, sin saber qué año y lugar pasaron. Al principio quería reconstruirlos con la fantástica memoria de mi amigo Juan Batista, de mi hermana Yamilis Hondar  y de su esposo Raúl Alonso. Unos meses más tarde, con la ayuda de mi hermana, aparecieron Antonio Cuan Chang, Vivian Núñez, Rafael Guirola, Adolfo Pérez, Benito Sierra, Jorge Orlando Mitjans, Eva Sevillano, Siomara Martínez,  José Rodríguez Soria (el Chino), Carmen Colina, Miguel Asso, Ernesto Viera, Natividad Guerrero,  Ernesto Viera, Felipe Orestes Fragoso Concepción y otros más.
   Traté de escribirla con un lenguaje sencillo de adolescentes de aquella época para que no solo la entendieran mis amigos de Vento, sino también los alumnos de español de Hungría. Quiero que ellos conozcan un poco las bellas frases cubanas. 
   Los personajes y los sucesos son reales, pero están unidos con un poco de fantasía.','A szerző korábban felhalmozott részesedéséből finanszírozva.

100 példány:
10 pld. szerző
6 pld. köteles
8 pld. kubai nagykövetség
6 pld. kiadóban marad
70 pld. terjesztésre

A szerző kérésére Kubába postázott, de elveszett 12db kártérítésére 10.800 Ft-ot utalt a Magyar Posta (2015.07.24.) ',NULL,1451384675,0);
INSERT INTO books VALUES('',0,'','Janurik_Tamas--A_romani_nyelv_alapjai--FD.jpg',170,'',1,1,0,35,'',1,1208,10,'','','',NULL,NULL,'',50,0,NULL,24,2,2010,281,'Janurik Tamás','A romani nyelv alapjai','978-963-9934-75-7',2,'','3','200x140mm',136,'0',1990,5,'#LA5','Romani','http://www.konyvesbolt.online/spd/978-963-9934-75-7/Janurik-Tamas-A-romani-nyelv-alapjai-Ad-Librum-201','','','','','','','',3,3,1,9,4,5,5,'2010-2-0','2010-2-24','Dr. Janurik Tamás 20/316-1400  8000 Székesfehérvár, Ady Endre u. 22.','janurik.tamas@freemail.hu','','Dr. Janurik Tamás magyar és összehasonlító nyelvész, a Kecskeméti Főiskola professor emeritusa, a nyelvtudományok kandidátusa, különböző európai nyelvek kutatója. A romani nyelvet (illetve annak standardizált nyelvi változatát, a lovárit) évek óta tanítja a főiskolán.

  „A romani nyelv alapjai” a könyvpiacon fellelhető tankönyvekkel ellentétben nem nyelvkönyv, hanem a romani nyelv tanulásához kisegítő háttérismereteket nyújtó segédkönyv.

  A könyv a hangkészletről szóló fejezetben a romani hangállomány mellett a szavak ragozása során létrejövő hangváltozásokat is teljes, táblázatszerű formában mutatja be.

  A szókészleti rész a szótanuláshoz kíván hathatós segítséget nyújtani, a romani nyelv 1410 motiválatlan (azaz memoriterként megtanulandó) alapszavát szótározza, valamint az ezekből alkotható képzett és összetett származékszavak szóalkotási módjait is szótárszerűen tárgyalja, megkönnyítve ezzel az azonos szótípusba tartozó szóalakok jobb felismerését.

  A nyelvtani elemek című rész elsősorban azokra a nyelvi jelenségekre koncentrál, amelyek a rendkívül logikus romani nyelvtani rendszerben a nyelvet tanulók számára mégis némi nehézséget okozhatnak: ilyen a (hímnemű és nőnemű) főnevek többes számának alakulása, valamint az igék múlt idejű alakjainak rendkívül változatos    – azonban világos, jól áttekinthető logikai rendszert alkotó – időjelekkel való ellátása. A romani igék biztonságos használatának alapfeltétele a jelen idejű és múlt idejű igetövek alapos ismerete. A hatféle igetípust tovább rendszerező huszonnyolc igeragozási táblázat ennek elérését kívánja elősegíteni.

  Mert minden nyelvtudás alapja a biztos nyelvtani háttér!','megjelenéskor 10 pld-t kér (1208 Ft/db - 10% kedvezmény)
Új ára 2490.- 2017.02.28-tól
',NULL,1488536841,0);
INSERT INTO books VALUES('',0,'','','','',1,1,0,43,'',1,1970,10,'','','',NULL,NULL,'',301,0,NULL,29,8,2010,282,'Wiersumné dr. Gyöngyösi Erika','GCSE Mathematics I. For Bilingual Students','978-615-5014-49-9',2,'','3','A5',194,'0',3000,5,'#LGIV# a szerző értékesíti','GCSE-Mathematics','','','','','','','','',3,2,1,9,4,5,4,'2010-7-27','2010-8-29','Wiersumné dr. Gyöngyösi Erika, 70/5678-259, 3942 Sárazsadány, Kossuth Lajos u. 15.','gyerika@hotmail.com','','','Támogató: Sárospataki Református Kollégium Gimnáziuma és Általános Iskolája (3950 Sárospatak, Rákóczi u. 1.)',NULL,1460630464,0);
INSERT INTO books VALUES('',0,'','Komor_Zoltan--Mesek_Kaptarvarosbol--FD.jpg',281,'',1,1,0,4,'',1,1478,10,'','keménytábla','',NULL,NULL,'',30,0,NULL,19,3,2010,283,'Komor Zoltán','Mesék Kaptárvárosból (parabolaregény)','978-963-87741-9-4',2,'','3','140x200 mm',226,'0',1940,5,'#LA6 Nagy Zoltán','Komor-Zoltan','http://www.konyvesbolt.online/spd/978-963-87741-9-4/Komor-Zoltan-Mesek-Kaptarvarosbol-parabolaregeny-A','','','','','','','',3,3,1,9,4,5,4,'2010-2-10','2010-3-19','Nagy Zoltán, 06703965305, 4181 Nádudvar, Kádas u.2.','komorzoltan@gmail.com','','Ismét beköszönt az éjszaka, és a város tarka neonpillái felnyílnak: kezdetét veszi egy újabb rémálom a betondzsungelben. Tompa fényű méreg-jelmezbe bújnak a felhők. A sarkon álmos drogdílerek álmot árulnak. Mámorhártyákban tekeregnek a féregszajhák. Gyermekként fut a mocsok a város karjaiba.

Hét modern mese, hét, a nagyvárosi éjszakában játszódó élettörténet egymásutánja és egybefonódása (kirakós darabja) ez a regény. Szereplői korunk partravetettjei: egy jobb életről álmodó utcalány, aki egy különös betegség miatt esténként féreggé változik. Egy sarki drogárus, aki ismeri a bűntudat kitörlésének ősi és titkos szertartását. Egy hatalmaskodó, de fizikailag gyenge strici, akinek végül saját fizetett bérgyilkosával kell szembeszállnia. Egy, az eltartott háztartásbeli szerepbe beleunt feleség, aki önként lesz prostituált, csak hogy történjen végre valami. És mások, akik ideig-óráig a képzeletbeli megapolisz, Kaptárváros alvilági szövevényébe csavarodnak. De vajon létezik-e kiút a kiúttalanságból, menekvés erről a szörnyűséges helyről, vagy igaz a városiak közt terjengő szóbeszéd, miszerint a városon kívül nem is létezik semmi?

Komor Zoltán groteszk, szürreális elemekkel átszőtt történetfüzére lüktető lidércnyomás egy örök sötétségben tengődő világról, ahol bármi megtörténhet, semmi sem túl bizarr, vagy hihetetlen. A rémálmok irányát követő ív a pokol legmélyebb bugyrától egy tündöklő ébredésig kalauzolja az Olvasót.','Borka készíti
',NULL,1462954253,0);
INSERT INTO books VALUES(1000,0,'','Petrozsenyi_Nagy_Pal--Eletkepek--FD.jpg','',2,1,0,0,3,'',1,'',45,65,'','',NULL,NULL,'',30,0,NULL,9,4,2010,284,'Petrozsényi Nagy Pál','Életképek – Elbeszélések és egyéb kisprózai alkotások','978-963-9888-90-6',2,'','3','A5',250,'0',2990,1,'#LA6 T:G B:V','Nagy-Pal','http://www.konyvesbolt.online/spd/978-963-9888-90-6/Petrozsenyi-Nagy-Pal-Eletkepek-Elbeszelesek-es-egy','','','','http://www.konyvesbolt.online/spd/978-963-9888-90-6/Petrozsenyi-Nagy-Pal-Eletkepek-Elbeszelesek-es-egy','','','',3,3,1,7,4,5,3,'2010-2-0','2010-4-9','Nagy Pál, 06/76/41 30 35, Kecskemét, Puskás Tivadar 13.','gyanlap@hotmail.com','Társadalmi freskó a mai magyar valóságról.','Életképek? Igen, társadalmi freskó a mai magyar valóságról, melynek valamennyi képviselőjét megtaláljuk itt 250 oldalba sűrítve. A történetek egyik tipikus alakja a kisember, akit akárhányszor döngölnek a földbe, többnyire ott is marad sajnos. Van, aki lázad, verekszik, mint az Életképek „főhősei”. Hiába: mint a föl-földobott kő mindig visszahullnak a magasból - a társadalom uralkodó erőivel legfeljebb egy nagy ember szállhat szembe sikerrel. Szomorú, de az igazi valóság ez, amit az író dísztelen stílusban, mégis figyelemreméltó szuggesztivitással ábrázol. Az írások gerince az akció, ezért olvasmányosak is. Azonban minden cselekvésben ott bújkál a lélek és valamilyen eszmei mondanivaló, más szóval egyszerre voltaire-i, illetve maupassant-i és csehovi vonásokat mutatnak fel a kötet elbeszélései. A témák meglehetősen változatosak, színesek: a prófétaság elöl menekülő Tóth Jónás (Éli, éli… !), társkeresés az interneten (Internet avagy az igazi), ezotéria (Hatodik érzék), irodalomköri capriccio (Sic itur ad astra), elfojtott vágyak (A nagy ugrás) stb. Aki mindezeket elolvassa, garantáltan sokáig fog még emlékezni reájuk.','Új email: gyanlap@hotmail.com (2012-12-14, Régi: palnagy4@gmail.com)

Kötelespéldányt kell küldeni!

Kiajánlva


',NULL,1451299694,0);
INSERT INTO books VALUES('',0,'','Tarator--Mamuttampon--FD.jpg',333,0,1,0,0,11,'',1,'',40,65,'','',NULL,NULL,'',500,0,NULL,12,4,2010,285,'P. Tarator','Mamuttampon','978-963-9934-76-4',2,'','3','148x210 mm',252,'0',2500,1,'#LC2,LGI,LGIII,LGVI# B6  Olaszi Tamás; T:G B:V','Tarator','http://www.konyvesbolt.online/spd/978-963-9934-76-4/P--Tarator-Mamuttampon-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-76-4/P--Tarator-Mamuttampon-Ad-Librum-2010','','','',3,3,4,7,4,5,4,'2010-2-10','2010-4-12','Olaszi Tamás, 70/201-5846, 8230 Balatonfüred, Ibolya u. 5/C. I/3.','olaszi.tamas@gmail.com','Miután az újságíró a végére járt mind a kényes témának, mind Indiának, rá akarták venni, hogy soha ne írja meg a cikket. Sikerült is nekik.','„Csupán egy elhaló vakkantásra futotta tőlem, mielőtt egy felbőszült mongúz sebességével hátravetettem magam, hogy elkapjam az egyik távozni készülő csomagot. Robert észrevette a manőveremet a tükörből, és reflexszerűen fékezett egyet. A Scorpio hátsó ajtaja a hirtelen fékezés hatására utolért minket, és hatalmas döndüléssel csapódott a helyére, csupán milliméterekkel kerülve el az ujjaimat. 
Ahogy ott hasaltam, lábaimmal a hátsó üléssorba kapaszkodva, seggemet a plafonnak nyomva, derékig a csomagtartóban, éppen csak megmenekült ujjaimra meredve, átfutott az agyamon, hogy vajh van-e dicstelenebb halál, mint szétzúzott kézzel a csomagtartón át az indiai főútra hengerbucskázni, és ott felhergelt gyerekelefántok által pépes masszává tapostatni. Ha van is, akkor és ott nem jutott eszembe egy sem.”

Egy újságírót munkaadói elküldtek a benzinszagú és pálmaillatú Indiába. Azt kérték, hogy járjon utána egy kényes, ám igen érdekes esetnek, amiben a feszültség szó szerint kézzel fogható. Miután pedig a végére járt mind az esetnek, mind Indiának, rá akarták venni, hogy soha ne írja meg az ebből készült cikket.

Sikerült is nekik.

Némi nyomásgyakorlás hatására a történet végül nem jelent meg újságban, viszont így, évekkel az események után talán könyvben már kiadható. P. Tarator első regénye valós alapokon nyugszik, ám története nem ér véget a könyv borítójánál.','Régi lakcím: 1119 Budapest, Fehérvári út 105/A.',NULL,1451377044,0);
INSERT INTO books VALUES('',0,'','','',0,0,1,41,31,'',1,3910,'','','','',NULL,NULL,'',60,0,NULL,19,12,2013,286,'Pongrácz Pál','Malmok. A korai ipari építészet','',2,'','6','165x235',432,'0',4000,5,'Keménytábla','','','','','','','','','',4,3,1,9,4,4,3,'2013-11-27','2013-12-19','','','','Az Ybl-díjas szerző korábban megjelent kötete, a Régi malomépítészet műszaki-technika-történeti szemlélettel tekintette át a malmokkal kapcsolatos ismereteket. A kiadás óta eltelt több mint negyven esztendő alatt a tudomány és a kutatás újabb eredményei nyomán tovább bővült a szakirodalom, számos új értekezés jelent meg.

Az újabb műszaki felmérések és helyreállítások tervdokumentációi kibővítették az írott dokumentumok gyakran csupán az egyes malomtípusok bemutatására alkalmas vázlatos ismertetéseit, és a legújabb történeti, technikatörténeti kutatások is több korábbi álláspont revízióját igénylik. Mindez kikövetelte a korábbi, kizárólag a szél- és vízenergiát hasznosító malomtípusok építési és építészeti kérdéseire koncentráló tanulmány kiegészítését.','A megrendelő nem fogadta el az első adag példányt 2013. karácsonya előtt. Szerződésbontás. A régi ISBN (978-615-5110-65-8) egy spanyol nyelvű könyvre került.',NULL,1407487500,0);
INSERT INTO books VALUES('',0,'','Cserjes_Katalin--Hajnoczy--FD.jpg','',0,1,0,0,41,'',1,'',40,40,'','',NULL,NULL,'',80,0,NULL,0,2,2010,287,'Cserjés Katalin','„a lebegő orgonagyökér” - Egy Hajnóczy-prózakalauz első fejezetei','978-963-06-8571-9',1,'','2','',257,'0',3490,4,'#LB2#','','http://www.konyvesbolt.online/spd/978-963-06-8571-9/Cserjes-Katalin-a-lebego-orgonagyoker---Egy-Hajnoc','','','','http://www.konyvesbolt.online/spd/978-963-06-8571-9/Cserjes-Katalin-a-lebego-orgonagyoker---Egy-Hajnoc','','','',3,3,0,0,0,5,0,'Array-0-0','2010-2-0','Dr. Cserjés Katalin, 6800 Hódmezővásárhely, György u. 24.','vasskatalin@vnet.hu','','Munkám célja, hogy közelebb kerüljek Hajnóczy Péter sokrétű, kísérletező prózájának néhány jellegzetesnek tartott sajátosságához. (...)
Energikus, drámai szövegvilága folyamatosan újabb és újabb értelmező hozzáfordulásokat indukál. Élő, mozgékony organizmusnak látom Hajnóczy életművét, mely transz-avantgárd érzékenységről ad számot.','csak terjesztjük!
kiajánlva!',NULL,1451380782,0);
INSERT INTO books VALUES('',0,'','Varga_Attila--Biblia_es_biztonsagpolitika--FD.jpg','','',1,0,28,40,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,31,3,2010,288,'Varga Attila','Biblia és biztonságpolitika','978-963-06-8910-6',1,'','3','A5',250,'0',2490,1,'#LB4,LGIV, LGV?# B:B','Biblia-es-biztonsagpolitika','http://www.konyvesbolt.online/spd/978-963-06-8910-6/Varga-Attila-Biblia-es-biztonsagpolitika-2010','','','','','','','',3,3,1,7,4,5,2,'2010-2-23','2010-3-31','2440 Százhalombatta, Tavasz u. 5., Tel.: 20/543-3511','vargaattila8@digikabel.hu','Találhatunk-e biztonságpolitikai útmutatásokat, előrejelzéseket a Bibliában?','Találhatunk-e biztonságpolitikai útmutatásokat, előrejelzéseket a Bibliában? E mű szerzője szerint, igen. Sőt…

A könyv olvasása először megdöbbentő, antiszemita, rasszista, gyűlöletet keltő, valamint magyar és nemzetellenes, de ugyanakkor zsidóbarát érzelmeket is kelthet. Sokakat felháborodásra, míg másokat elgondolkodásra, további érdeklődésre és megértésre indíthat, hiszen az Üdvterv az emberiség teremtésének, létének, biztonságának, az elmúlt és eljövendő történelmének forgatókönyve. A könyv ezekre rávilágít.

Emberek, politikusok nem tudnak, még a globalizmus által sem „felebarátaik” részére biztonságot teremteni. Sőt ellenkezőleg, förtelmes diktatúrát valósítanak meg. S ebben a folyamatban a zsidóságnak igencsak kétértelmű szerepe van. Az áldásokat, de a büntetéseket is elsőként kapták és kapják meg a történelem viharaiban. A terv a zsidósággal kezdődött és velük együtt fejeződik be. Ma már Izraelbe való összegyűjtésük időszakát éljük.

A pogromok, a holokauszt ismerete tudatában minden nemzet örülhet, hogy a tervben nem ők lettek a főcsapás irányába rohamosztagként, főszereplőként bevetve.

Korunkban a mammon és a hatalom imádata, az emberiség nyomorba döntése, az igazságosság és szolidaritás mellőzése ítéletért kiált. Azonban, mindenki, a világ és egyéni kedvezőtlen sorsa ellenére is, saját döntése alapján megszerezheti a legfőbb, örökkön tartó biztonságot, az örök életet.','Új email: vargaattila8@digikabel.hu (2013.01.22.)

Új email: varga.attila8@t-online.hu (2011.03.03.), régi volt: varga.attila8@fibermail.hu

Borka: levlap tervezése',NULL,1474538664,0);
INSERT INTO books VALUES('',0,'','','',0,0,1,0,43,'',1,1750,10,'','','',NULL,NULL,'',70,0,NULL,20,2,2011,289,'Magyar Létesítménygazdálkodási Szövetség','Létesítménygazdálkodás 2009','',3,'Magyar Létesítménygazdálkodási Szövetség','4','A5',150,'0',5950,4,'Szerk. Czerny József; T&B:V','','','','','','','','','',4,3,2,4,3,1,0,'2010-2-0','2011-2-20','Czerny József, 21/2526259, 30/964-6454, Magyar Létesítménygazdálkodási Szövetség, 1021 Budapest, Hűvösvölgyi út 54.','jozsef.czerny@hfms.org.hu','','','ISBN 978-963-06-9013-3 felhasználva Sarlós Erzsébet 2. könyvére.',NULL,1415363394,0);
INSERT INTO books VALUES('',0,'','Raday_Martin_Bence--Az_utolso_valosagshow--FD.jpg','',0,1,1,13,11,'',1,2000,10,'','','',NULL,NULL,'',60,0,NULL,9,4,2010,290,'Ráday Martin Bence','Az Utolsó Valóságshow','978-963-06-8911-3',1,'','3','A4',407,'0',2990,5,'#B4 Markó András; T:G B:B','Raday-Martin-Bence','','','','','','','','',5,3,0,7,4,5,5,'Array-0-0','2010-4-9','Markó András 70/429-4861','andras.marko.jr@gmail.com','','Danil, a 28 éves, cinikus, pókerőrült, unalmas életet élő, budapesti bróker egy frissen megjelent képregényben rátalál múltjának rejtett titkaira. Ezidőtájt veszíti el állását, s olcsóbb albérletbe kell költöznie barátnőjével, az ex-modell, titokban drum ’n’ bass DJ Melisszával, aki csúcsingatlanos cégnél szenved, s arról álmodozik, hogy topmilliárdosok fejelcsavarója, s  a világ megmentője lesz…
Danil ráeszmél, hogy az irreálisan olcsó luxus-albérletben mindenki gyanús: Levi, a dúsgazdag anarchista, Zazie, a carpediemista ezo-lányka, a fiatal Hitlerre hasonlító Hailey, s Danil „véletlenül” felbukkanó gyerekkori barátai…
A gyanúsítottak sora végén mintha saját, ifjúkori énje állna… 
2010. tavasza. Vihar előtti csend. A közelgő vészkorszak még csak a hírekből kúszik mindennapjaikba… Danil nyomozni kezd, ám hiába jut el az Íjászig és a Rajzolóig, a lidércnyomássá erősödő valóságshow írója nem engedi felfedni magát, egészen addig, amíg hőseink rá nem ébrednek kiválasztott szerepükre.
2011.-2012. Az egymásba kuszálódó életű lakótársaknak a polgárháborúba és diktatúrába csúszó Magyarországon, a koncentrációs táborrá drótozott Angliában, s a pénzügyi spekulánsok által kirobbantott világháborúban már nehéz a kényelmesebb utat választaniuk…

A hátborzongató antiutópiát hálószoba-szigetek és miniatűr társadalmi alternatívák képeslapjai ellensúlyozzák, kemény munkához kötve minden szerelmi beteljesülést; az Utolsó Valóságshow így lesz rémálma és megváltása minden elkényelmesedett, önző és műproblémákon sajnálkozó nagyvárosi divatszinglinek és yuppie-nak…

A New York Times-nak is dolgozó Ráday Martin Bence nem keres felelőst, kik juttatták az összeomlás szélére a világot. Viszont megnevezi azokat, akik azonnal változtatni tudnak rajta.','Lezárva 2014.02.22. Összes példány kiadva, kifizetéshez később szla.',NULL,1393060278,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,13,11,'',1,'',8,20,'',90,NULL,NULL,500,500,5,NULL,13,4,2010,291,'Gabriel A. Dom','A végzet kezdete','978-963-9934-78-8',2,'','3','147x205 mm',334,'0',2990,2,'#C T:G B:V 438 g. Doma Gábor','Gabriel-Dom','http://www.konyvesbolt.online/spd/978-963-9934-78-8/Gabriel-A--Dom-A-vegzet-kezdete-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-78-8/Gabriel-A--Dom-A-vegzet-kezdete-Ad-Librum-2010','','','',3,3,1,7,4,5,1,'2010-2-22','2010-4-13','Doma Gábor, 42/480-408, 30/2793-022, Nyíregyháza, Kezdő út 28.','g.dom78@gmail.com','','Daren City – 2024. Minden megszűnt létezni, ami egykoron számított. Az épületek romosak, az utcákon hömpölygő szemét, a levegő dermedt, áporodott bűz terjeng, vérbe fagyott és oszlásnak indult tetemek hevernek szanaszét. Egy Akumba nevű vírus, melyet megváltóként emlegetnek, futótűzként söpört végig a földkerekségen, megsemmisítő csapást mérve szinte minden nemű életformára. Hirtelen csapott le, nem lehetett rákészülni… az emberi faj csaknem teljesen kipusztult, de még így is akadtak jó páran, akik egy, a város mélyén húzódó hosszú alagútrendszerben, jól védhető menedékhelyre találtak. A vezetőjük egy igen megtermett, középkorú, mackós külsejű férfi, Maxwell Tarkin, vagy ahogyan magát nevezte: Zeusz… különösen szeszélyes jelenség. Egyfelől remek katona és stratéga, bármikor tűzbe menne a híveiért, másfelől szerfelett titokzatos egyén. De mindenekelőtt halandó ember és mint ilyent, a gonosz egy nap őt is megtalálja egy Asska-Mor nevű titokzatos idegen képében, aki mindent megváltoztat. Zeusz halálos fertőzést kap, ezért végleg el kell hagynia a menedéket, de nem egyedül. Egy ötfős csapat indul el, hogy megtalálják a vírus ellenszerét és fényt derítsenek a rejtélyre, ám az útjuk nem oda vezet, ahová eltervezték. Egy idegen világbeli ördögi színjátékba csöppennek, ahol a nagybetűs SORS és maga a gonosz irányítják a bábukat. A küldetésből vesszőfutás lesz és immár nem az ellenszer felkutatása a cél, hanem az életben maradás…','',NULL,1451377220,0);
INSERT INTO books VALUES('',0,'','Szalayne_Halasz_Orsolya--Egy_szenvedelybeteg_eletutja--FD.jpg','','',1,1,0,36,'',1,1340,10,'','','',NULL,NULL,'',30,0,NULL,1,4,2010,292,'Dr. Szalayné Halász Orsolya','Egy szenvedélybeteg életútja','978-963-9934-77-1',2,'','3','A5',182,'0',2040,5,'#LB3 T&B:V','Szenvedelybetegseg','http://www.konyvesbolt.online/spd/978-963-9934-77-1/Dr--Szalayne-Halasz-Orsolya-Egy-szenvedelybeteg-el','','','','','','','',3,3,1,7,4,5,3,'2010-2-0','2010-4-1','70/610-3083, postacím: 8400 Ajka, Ifjúság út 7/b 2. em 7.; állandó: 3265 Vécs, Május 1 út 21. (a szerződésben fordítva van a két cím)','orsi80@ajkanet.hu','','Az alkoholizmus társadalmunk és korunk egyik legsúlyosabb problémája. Az emberiség számára egyre világosabbá vált, hogy egészségügyi, gazdasági, társadalmi, családi, munkaügyi és nem utolsósorban a személyiség vonatkoztatásában pusztító népbetegséggel állunk szemben.

A könyv címe: Egy szenvedélybeteg életútja. A karrier, életút mint szociológiai kifejezés részben fedi a viselkedést előtérbe állító dependencia szindrómát. Az alkoholista karriernek a kialakulását a társas kapcsolatok rendszerében helyeztem el. Ezen belül az alcímben utalok arra, hogy mennyiben volt szerepe a korai traumáknak és váratlan veszteségeknek, veszélyeztető családi hatásoknak, serdülőkori kockázati faktoroknak, kortárs csoportoknak, iskolai, munkahelyi veszélyeztető tényezőknek az alkoholista betegek karrierjének a kialakulásában. A könyvben bemutatásra kerül az alkoholbetegségek közös lélektani folyamatai és ezek különféle viselkedésbeli megnyilvánulásai.

Vannak olyan jelzések, amelyek arra hívják fel a figyelmet, hogy itt az ideje beavatkozni. Szükséges, hogy ezeket a veszélyeztető tüneteket éppúgy felismerje mindenki, mint bármilyen más betegség kezdeti tüneteit. Könyvem üzenete: Mi szakemberek fogjunk össze és állítsuk meg korunk pestis járványát, az ALKOHOLIZMUST!','',NULL,1463045151,0);
INSERT INTO books VALUES('',0,'','Tamas_Zoltan--Ferfi_lelekvandorlas--FD.jpg',237,0,1,0,0,20,'',1,'',40,60,'','',NULL,NULL,'',300,0,NULL,6,8,2013,293,'Tamás Zoltán','Férfi lélekvándorlás','978-963-87741-2-5',2,'','6','140x200 mm',192,'0',2990,1,'#LB2,LGV,LG19#','','http://www.konyvesbolt.online/spd/978-963-87741-2-5/Tamas-Zoltan-Ferfi-lelekvandorlas-Ad-Librum-2013','','','','http://www.konyvesbolt.online/spd/978-963-87741-2-5/Tamas-Zoltan-Ferfi-lelekvandorlas-Ad-Librum-2013','','','',3,3,4,7,4,5,3,'2013-5-0','2013-8-6','20/326-2757, 96/337-613; 9024 Győr, Babits M. u. 9.','tamas.zoltan2010@gmail.com','','A szerző saját bevallása szerint a korábbi könyvének nemzetközi sikere sarkalta ennek az újabb kötetnek a megírására. A Férfi lélekvándorlás is, miként a szerző minden műve két alapvető dologra épül: a humorra és a kételkedésre. Írásai egyszerre ironikusan filozofikusak és játékosak. Súlyosak és humorosak. Olyan témákról szólnak, mint az élet, a halál, a boldogság, a valóság és a misztikum kapcsolata. Új titkokat tudhatunk meg a lélekről és a szerelemről. A kötet éppen a színessége miatt kissé eklektikus – ami jelen esetben nem negatívum – hiszen a különböző írások különböző témákhoz kapcsolódnak. A nagyrészt humorral megtöltött rövid darabok egyvalamiben azonban hasonlítanak egymásra: gondolkodásra sarkallnak, még akkor is, ha nem mindegyikkel értünk egyet. 

Az olvasó, amikor kézbe veszi a könyvet még biztos abban, hogy helyes életet él, helyes a világnézete, ám amikor a végére ér, számára is kiderül, hogy mindvégig tévúton járt. A Férfi lélekvándorlás legfőbb tanulsága az, hogy nem mindig a megszokott racionális gondolkodásmód a legcélravezetőbb. Vannak olyan helyzetek, amikor alaposan felül kell vizsgálnunk értékítéleteinket. 

A könyvet ajánljuk mindazoknak, akik szeretnek elmélyedni a humor, a lélek, a szerelem és a bölcsességek világában.

Tomasso DAngelo','',NULL,1451301227,0);
INSERT INTO books VALUES('',0,'','Tamas_Zoltan--Mindenkeppen_kimeletlen--FD.jpg','','',1,0,0,3,'',1,'',40,60,'','',NULL,NULL,'',300,0,NULL,12,4,2010,294,'Tamás Zoltán','Mindenképpen kíméletlen','978-963-9934-79-5',2,'','3','',168,'0',2490,1,'#A6 T:G B:B','Tamas-Zoltan','','','','','','','','',3,3,2,7,4,5,4,'2010-3-2','2010-4-12','20/326-2757, 96/337-613; 9024 Győr, Babits M. u. 9.','tamas.zoltan2010@gmail.com','Ironikus, szórakoztató és halálosan komoly gondolatok.','A könyv zsúfolásig tele van ironikus, szórakoztató és halálosan komoly gondolatokkal. Egy isteni színjáték. Magam sem írhattam volna jobban.

Dante


Ez a mértéktartó humorral, az emberi természetről, társadalomról, vallásról, művészetekről, tudományról és az Univerzumról megírt könyv annyira jó, hogy, még nekem is tetszik. Ebből tanultam meg én is; legjobb leszedni az érett almát a fáról, még mielőtt a fejünkre esik.

Newton
 

A könyv sokat segített világnézetem fejlődésében. Először azt gondoltam, csak beleolvasok. Aztán élvezettel elolvastam az egészet és azóta tudom, hogy az internet forradalmából következhet a valódi demokrácia.

Platón

 
Kortól és nemtől függetlenül mindenkinek bátran ajánlom ezt a kellemes zamatú délutáni vagy kora esti könyvet, mely kissé fűszeres, néha enyhén csípős stílusával méltán képviseli a jövő mámorát.

Ámor','Az oldalszámbeli túllépés felével nő a végár.

kiajánlva!',NULL,1458819661,0);
INSERT INTO books VALUES(995,0,'<p>Mark Wander igényes és színvonalas krimijében kizárólag egyszerű és klasszikus elemekre építkezik. Művének mozgatórugója azonban nem a pénz, vagy a hatalom – ahogy azt a bűnügyi regényekben megszoktuk, hanem egy őszinte és mélyről fakadó ösztönös bosszúvágy. Keserű érzelmek által vezérelt karaktereivel és életszerű helyzeteivel hihető történetet tár elénk, melynek középpontjában végig a főhős áll. Fia­talos lendületének és újszerű írásmódjának köszönhe­tően könnyedén gyarapíthatja rajongótáborát.</p>
<p>Bán István forgatókönyvíró</p>','Mark_Wander--A_bosszu_kotelez--FD.jpg',163,3,1,0,0,11,'',1,'',0,0,'','',NULL,NULL,'',500,0,NULL,15,4,2010,295,'Mark Wander','A bosszú kötelez','978-963-9934-81-8',2,'','3','A5',219,'0',1990,3,'#LB7,LC1,LG23,LG25#  Csabai Márk T:G B:B','Mark-Wander','http://www.konyvesbolt.online/spd/978-963-9934-81-8/Mark-Wander-A-bosszu-kotelez-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-81-8/Mark-Wander-A-bosszu-kotelez-Ad-Librum-2010','','','',3,3,1,7,4,5,1,'2010-3-9','2010-4-15','Csabai Márk, 30/6408343, Göd Pesti út 93/b.','csabaimark@gmail.com','Nyomozás egy sorozatgyilkos után keserű érzelmek között.','A Jersey City-i nyomozó, Rendel McNail feleségét harminchárom késszúrással megölték. Sosem derült ki, hogy miért.

Évekkel később egy sorozatgyilkos tűnik fel a városban. Áldozataival harminchárom késszúrással végez.

Kézre kerítését Rendel McNail kapja feladatul.

A régi sebek felszakadnak, az igazságra lassan fény derül. A nyomozó szembesülni kényszerül a ténnyel, hogy a borzalmak kiváltója valójában ő maga.

Akire a gyilkos vadászik.','11-08-07: #RA1a 53 pld. (stimmel)

106x167 mm
20 borítót kér 100 Ft/pld. (és 5-10 ajándékba)

250 pld-t megvesz, cserébe nincs felvásárlási kötelezettség.',NULL,1451377380,0);
INSERT INTO books VALUES('',0,'','Toth_Laszlo_Pal--Felelmunknek_vegre_vege--FD.jpg','','',1,0,0,4,'',0,'',8,30,'',90,NULL,NULL,500,500,5,NULL,2,6,2010,296,'Tóth László Pál','Félelmünknek végre vége','978-963-9934-80-1',2,'','3','140x200 mm',232,'0',2390,2,'#LD#RF T:G B:B','Toth-Laszlo-Pal','http://www.konyvesbolt.online/spd/978-963-9934-80-1/Toth-Laszlo-Pal-Felelmunknek-vegre-vege-Ad-Librum-','','','','','','','',3,3,1,7,4,5,5,'2010-3-4','2010-6-2','Tóth Dénes (örökös), 36/314-678, 3300 Eger, Gólya u. P/4. I. 7.','tothdenes.3300.eger@gmail.com','Tanulságos állatmese – akár gyerekeknek is.','Tanulságos állatmese – akár gyerekeknek is.

Egy félreértés következtében az állatok elhiszik, hogy a farkas tud repülni. A róka és a talpnyalók segítségével a csodaerejűnek vélt farkas lassacskán az erdő ura lesz. Kialakul a rendszer, amelyben mindenki megfigyel és megfigyelt…','250 példányt megvesz a szerző az elején.

Kiajánlva!

',NULL,1483439042,0);
INSERT INTO books VALUES('',0,'','Szabo_Csaba--Fel_ev_Afganisztanban--FD.jpg',308,2,1,0,18,15,'',1,'',8,30,'',125,NULL,NULL,500,500,4,NULL,18,8,2010,297,'Szabó Csaba','Fél év Afganisztánban (Részletek egy katona naplójából)','978-963-9934-82-5',2,'','3','A5',234,'0',2490,2,'#LA4,LB7,LGI#  T&B:V','Afganisztanban','http://www.konyvesbolt.online/spd/978-963-9934-82-5/Szabo-Csaba-Fel-ev-Afganisztanban-Reszletek-egy-ka','','','','http://www.konyvesbolt.online/spd/978-963-9934-82-5/Szabo-Csaba-Fel-ev-Afganisztanban-Reszletek-egy-ka','','','',3,3,4,7,4,5,1,'Array-0-0','2010-8-18','30/303-3949, 6000 Kecskemét, Nagykőrösi utca 28/1.','csaba23@hotmail.com','Egy Afganisztánban szolgált magyar katona élményei.','Ki is egy katona valójában? Ez csak nézőpont kérdése. Persze a katona is ember, mint bárki más, létezése mégis mindenkinek mást jelent. Az ellenségnek félelmet, visszatartó erőt vagy halált; egy fiatal lánynak talán szerelmet; egy gyereknek az apát. Ugyanakkor a katona is gyermek, egy őt féltő anya gyermeke...

A történet egy magyar katonáról szól, aki Afganisztánban szolgált és döntéseket hozott. El tudja képzelni, hogy milyen érzés műveleti területen, az otthontól távol, teljesen egyedül, emberek élete fölött fegyverrel a kézben döntéseket hozni?','Vállalta, hogy 2011 folyamán 50 példányt elvisz az utánnyomásból. (A többire nem kellett már fogyási garanciát vállalnia.)

Megváltozott a postacíme:
6000 Kecskemét, Nagykőrösi utca 28/1.
és egyéni vállalkozó lett: asz. 73426637-1-51
2015.12.07-től:6000 Kecskemét, Kada Elek u. 13. 3/40.',NULL,1451377466,0);
INSERT INTO books VALUES('',0,'','','','',1,0,3,2,'',0,'',40,40,'','',NULL,NULL,'',120,0,NULL,9,4,2010,298,'Korponai István','Most és Mindörökké','978-963-9934-83-2',2,'','3','A5',70,'0',2290,1,'#LA3# A3 T&B:B','Korponai-Istvan','http://www.konyvesbolt.online/spd/978-963-9934-83-2/Korponai-Istvan-Most-es-Mindorokke-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,3,'2010-3-0','2010-4-9','Korponai István, 06308570221, 2314 Halásztelek, Ady Endre utca 39.','korpi01@citromail.hu','','Pacsirta

Pacsirta száll arany madár
mérhetetlen könnyű lelke
rásimul a végtelenre

Pacsirta száll arany madár
ég tetején énekelve
Istent látja, könnyes szemmel

Pacsirta száll mióta már
arany torka trillájára
hold fekszik az égaljára.','kiajánlva!',NULL,1467277462,1);
INSERT INTO books VALUES('',0,'','Meszaros_Tibor--Hiaba_minden_aldozat_I--FD.jpg','','',1,0,0,4,'',1,'',40,40,'','',NULL,NULL,'',120,0,NULL,28,5,2010,299,'Mészáros Tibor','Hiába minden áldozat? - Viharban, Pocsolya, Kéregető','978-963-9934-87-0',2,'','3','A5',900,'0',2990,1,'#LD# T:G B:B - 978-963-9934-86-3 Ö 204x142mm ','Meszaros-Tibor','http://www.konyvesbolt.online/spd/978-963-9934-87-0/Meszaros-Tibor-Hiaba-minden-aldozat---Viharban-Poc','','','','','','','',3,3,1,7,1,5,3,'2010-3-10','2010-5-28','Mészáros Tibor, 30/613-2153, 2120 Dunakeszi, Kagyló u. 49.','meszarostibor50@gmail.com','','Mégis

 

Az emberek esztelenek, következetlenek és magukba fordultak;

            mégis szeresd őket.

Ha jót teszel, megvádolnak, hogy önzés és hátsó gondolat vezérel;

            mégis tégy jót.

Ha sikeres vagy, hamis barátokat és igazi ellenségeket nyersz;

            mégis érj célt.

A jó, amit teszel, holnap már feledésbe merül;

            mégis tedd a jót.

A becsületesség és őszinteség sebezhetővé tesz;

            mégis légy becsületes és nyílt.

Amit évek alatt felépítesz, meglehet, lerombolhatják egy nap alatt;

            mégis építs.

Az embereknek szükségük van segítségre, de ha segítsz, támadás érhet;

            mégis segíts.

A legjobbat add a világnak abból, amid csak van,

és ha verést kapsz cserébe;

            mégis a legjobbat add a világnak, amid csak van.

 

Kalkuttai Teréz','978-963-9934-86-3 Ö
Viharban I. kötet - ISBN 978-963-9934-87-0
Pocsolya II. kötet - ISBN 978-963-9934-88-7
Kéregető III. kötet - ISBN 978-963-9934-89-4',NULL,1458818354,0);
INSERT INTO books VALUES('',0,'','Brigitte_Bear--VarazsloVer--FD.jpg',220,0,1,0,11,14,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,1,6,2010,300,'Brigitte Bear','VarázslóVér','978-963-9934-90-0',2,'','3','130x200 mm',196,'0',2290,1,'#LC2# B6 Medve Brigitta K:I T:G B:szerző','Brigitte-Bear','http://www.konyvesbolt.online/spd/978-963-9934-90-0/Brigitte-Bear-VarazsloVer-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-90-0/Brigitte-Bear-VarazsloVer-Ad-Librum-2010','','','',3,3,4,7,4,5,3,'2010-3-11','2010-6-1','Medve Brigitta, 20/540-5040, 1116 Budapest, Abádi tér 7.','medvebrigitta@freemail.hu','Tudtad, hogy Budapesten is élnek vámpírok? Mentettek meg már valaha a rémálmaid?','Tudtad, hogy Budapesten is élnek vámpírok?
Mentettek meg már valaha a rémálmaid?
Mert ebben a könyvben mindenre választ kapsz…
Ez a történet három, Londonban élő vámpír mindennapjaiba enged betekintést, akik egy szép tavaszi éjjelen megismerkednek egy turistaként odalátogató magyar vámpírkutatóval. Sok érdekességet mesél nekik, de igazán egy könyv az, ami felkelti az érdeklődésüket. Sebastian és Elizabeth, a két főhős, Budapestre utaznak, hogy a könyv nyomába eredjenek, amiről úgy hiszik, hogy megváltoztathatja az életüket, de mit sem sejtenek arról, hogy a magyar vámpír klán már várja őket. Nyomon követhetjük budapesti barangolásaikat és a könyv utáni nyomozás izgalmait, amire egy bűntett nyomja rá sötét bélyegét…','Sorozatcím: A Nod nyomában
(OSZK - nem kell közös isbn-szám)

Borítókészítő: Madaras Balázs

Kiajánlva!',NULL,1451378464,0);
INSERT INTO books VALUES('',0,'','Magyar_B_Attila--Viragszerda--FD.jpg','',0,1,1,0,4,'',1,1460,10,'','','',NULL,NULL,'',20,0,NULL,1,4,2010,301,'Magyar B. Attila','Virágszerda','978-963-9934-85-6',2,'','3','A5',220,'0',1650,5,'#LB4,LG7#   Balog Sándor','Magyar-B-Attila','http://www.konyvesbolt.online/spd/978-963-9934-85-6/Magyar-B--Attila-Viragszerda-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-85-6/Magyar-B--Attila-Viragszerda-Ad-Librum-2010','','','',3,3,0,9,4,5,5,'2010-3-17','2010-4-1','Balog Sándor T.: 20/423-68-23 Cím: 1155 Bp., Mézeskalács tér 15. II/2.','balogford2@mail.datanet.hu','Vidám hangvételű, kizárólag párbeszédeket tartalmazó kisregény.','A vidám hangvételű, kizárólag párbeszédeket tartalmazó kisregény cselekménye 2005 tavaszán játszódik. Szereplői nagy összegű fogadás kapcsán keresik a feleletet a csaknem kétezer éve megválaszolatlan kérdésre: Valóban három nappalt és három éjszakát volt a sírban Jézus, ahogy megjövendölte, vagy péntek délutántól vasárnap hajnalig? Miért, talán nem mindegy? – kérdezhetné bárki. A történetből kiderül, hogy egyáltalán nem az!','Változik a telefonszáma, most éppen: 30-9918-049. De a végleges: 20-423-68-23.',NULL,1451300122,0);
INSERT INTO books VALUES('',1,'','Attila_B_Magyar--Palm_Wednesday--FD.jpg','','',1,1,0,4,'',1,1364,10,'','','',NULL,NULL,'',20,0,NULL,1,4,2010,302,'Attila B. Magyar','Palm Wednesday','978-963-9934-84-9',2,'','3','A5',188,'0',1650,5,'','Magyar-B-Attila','http://www.konyvesbolt.online/spd/978-963-9934-84-9/Attila-B--Magyar-Palm-Wednesday-Ad-Librum','','','','','','','',3,3,1,9,4,5,5,'2010-3-17','2010-4-1','Balog Sándor T.: 20-423-68-23 Cím: 1155 Bp., Mézeskalács tér 15. II/2.','balogford2@mail.datanet.hu','An entertaining, short novel, consisting entirely of dialogues.','This entertaining, short novel, consisting entirely of dialogues, takes us back to the spring of 2005. The novel’s main protagonists, in order to win a large sum of money that has been wagered, try to find the answer to a question that has remained unanswered for almost 2,000 years: Did Jesus spend three days and three nights in the tomb, as he had foretold, or was he really only there from Friday afternoon until the early hours of Sunday morning? Some might think the question pointless and in their turn ask the question: Does it matter? After reading the story it will become clear to the reader that, yes, it really does matter!','Változik a telefonszáma, most éppen: 30-9918-049. De a végleges: 20-423-68-23.',NULL,1460370308,0);
INSERT INTO books VALUES('',0,'','Mickey_Miller--Kairoi_gyilkossagok--FD.jpg','',0,1,1,0,11,'',1,1380,10,'','','',NULL,NULL,'',60,0,NULL,10,5,2010,303,'Mickey Miller','Kairói gyilkosságok','978-963-9934-91-7',2,'','3','A5',195,'0',1800,5,'#LB6 T:G B:Szerző Molnár Miklós','Mickey-Miller','http://www.konyvesbolt.online/spd/978-963-9934-91-7/Mickey-Miller-Kairoi-gyilkossagok-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-91-7/Mickey-Miller-Kairoi-gyilkossagok-Ad-Librum-2010','','','',3,2,1,7,4,5,3,'2010-3-0','2010-5-10','Molnár Miklós, +36304732856, 1118 Bp., Kelenhegyi út 18., állandó: 9011 Győr, Pengős utca 1.','mmickey84@gmail.com','Klasszikus krimi Egyiptomban.','A történetet egy Egyiptomban töltött, két hetes országos körutazás ihlette. Ezért személyes tapasztalatok és élmények is beépültek a cselekménybe. Annak ellenére, hogy valós szituációk színesítik a művet, mind a történet, mind a helyszínül szolgáló szálloda fiktív, és a szereplők is egytől egyig kitalált alakok. A regény történelmi érdekességekkel, lélektannal és humorral fűszerezett.

Egy tizenkét főből álló brit turistacsoport Kairóban tölt el nyolc napot. Van, aki felejteni érkezett Egyiptomba. Van, aki ünnepelni. Van, aki csupán kísérőként. És természetesen olyan is akad, aki egész egyszerűen csak egy kis kikapcsolódásra, valamint az ókori műemlékek megtekintésére vágyott.
Ahogy telnek a napok, világossá válik, hogy az egymással összezárt utasok nem igazán találják meg a közös hangot. Sőt, olyannyira nem, hogy egyre inkább puskaporossá válik közöttük a levegő. Hiszen mind annyira különbözőek. Más életfelfogással rendelkeznek, más célokkal érkeztek.
Egy baljós hajnalon egyiküket holtan találják meg. Senki nem hagyhatja el a szálloda épületét. Az utasok jól tudják, hogy gyilkos van közöttük. De azt nem tudhatják, hogy vajon melyikük lesz a következő áldozat. A fényűző, pazar hotel egy veszélyes börtönné válik.
A helyi rendőrség 24 órán belül megoldja az ügyet, ám úgy tűnik, hogy még így sem haladnak elég gyorsan. Hiszen a nyomozás során tizenhárman keverednek gyanúba, és ahogy múlik az idő, egyre többen kerülnek elő holtan a brit csoport tagjai közül.','',NULL,1451377078,0);
INSERT INTO books VALUES('',0,'','','','',1,0,30,36,'',0,'',60,60,'','',NULL,NULL,'',120,0,NULL,21,4,2010,304,'Zágon Judit','Álmomban egy farkas… mit jelent? - (270 álom jelentése + álom-szótár)','978-963-9934-92-4',2,'','3','A5',380,'0',2990,1,' #A4 T&B:B Hivatalos lezárásra várva - a szerzőnél a maradék hivatalos példány.','Zagon-Judit','','','','','','','','',3,3,1,7,4,5,3,'2010-3-0','2010-4-21','Zágon Judit, 2013 Pomáz Tavasz utca 3., 06/203970611, 06/26329396','pszichoglass@t-online.hu','','Az álmok a külvilághoz, az életkörülményekhez való alkalmazkodásunkat biztosítják – sokféle módon. Elősegítik a helyes (etikus) és célravezető magatartásformák rögzítését, vagyis megerősítik („memorizálják”) a bevált viselkedés- és gondolatmintáinkat. Helytelen vagy téves stratégiáink megváltoztatására ösztönöznek, provokálják szemléletmódunk megváltoztatását, hogy összhangba kerüljünk a környezetünkkel és önmagunkkal. Hidat képeznek a tudatalattink és a racionális tudatunk között, megpróbálják a kettőt összehangolni. Ezeket a funkciókat az álmok jó esetben a rájuk való emlékezés és megfejtés nélkül is teljesítik. Az álmokra való emlékezés és az álomfejtés tanulható szellemi munka, mely az önismeretet, a tudatos megértést és fejlődést szolgálja.

Míg az éber életünkben a személyiségünknek csak egy kicsiny töredéke látható, addig az álmaink a végtelen tudattalan világunk megnyilvánulásai.

A könyv 270 elemzett álommal segíti az olvasó tájékozódását az álmok világában – a leggyakoribb és legegyszerűbb tipikus álmoktól az egyedi, misztikus álmokig. Az elemzések egyszerűek, világosak, lényegre törők és közérthetőek, nem igényelnek pszichológiai ismereteket. A könyv második részében található álomszótár nem hagyományokra és hiedelmekre épül, hanem a modern, mai európai, illetve magyar átlagember gondolkodásmódjára és lelki működésére. Az Álmomban egy farkas… mit jelent? kézikönyvként is használható. Ha értetlenül állunk egy álmunk előtt, ihletet meríthetünk belőle akár a szótárban, akár a megfejtett álmok között.

További info: http://www.almainkjelentese.hu','',NULL,1458818978,0);
INSERT INTO books VALUES('',0,'','Nanassy_Szabolcs--Kalandozasok_ket_kereken--FD.jpg',226,'',1,1,0,15,'',1,1334,10,'','','',NULL,NULL,'',60,0,NULL,9,4,2010,305,'Nánássy Szabolcs','Kalandozások két keréken - Erdély','978-963-06-9094-2',1,'','3','140x200 mm',178,'0',1992,5,'#LB2,LG16,LG31#  T&B:Szerző','Nanassy-Szabolcs','http://www.konyvesbolt.online/spd/978-963-06-9094-2/Nanassy-Szabolcs-Kalandozasok-ket-kereken---Erdely','','','','','','','',3,3,1,9,4,5,5,'Array-0-0','2010-4-9','Nánássy Szabolcs T: 20/578-6775 C: 2800 Tatabánya, Vadász u. 25.','snanassy@yahoo.com','Két motor, két motoros, és egy fantasztikus motoros kalandtúra!','Két motor, két motoros, és egy fantasztikus motoros kalandtúra! Nemrég két tatabányai fiatalember elhatározta, hogy egy motoros túra keretében bebarangolják Erdély vadregényes tájait.
Az út során rengeteg megpróbáltatásban volt részük: küzdöttek a romániai utakon uralkodó kaotikus útviszonyokkal, egymással, motort és
felszerelést egyaránt sújtó műszaki problémákkal. Jó néhányszor eltévedtek, és párszor életveszélyes közlekedési szituációkba keveredtek, melyek olykor majdnem tragédiába torkolltak.
A túra során alkalmuk nyílt megtapasztalni az erdélyi emberek szívélyességét, megcsodálni kézművességük gyönyörű alkotásait. Betekintést
nyertek Székelyföld lakóinak kulturális életébe, és megismerkedtek a közép-, és jelenkori magyar történelem jó néhány nevezetes eseményének
helyszínével.
A könyv ennek a túrának a történetét meséli el.
','2490-ről 20% árengedmény 2011.09.19-től.',NULL,1480927313,0);
INSERT INTO books VALUES(1990,0,'','Kakuk_Matyas--Oszet_nyelvi_peldatar--FD.jpg',423,3,1,1,0,35,'',0,1862,0,0,'','',NULL,NULL,'',50,0,NULL,29,7,2010,306,'Kakuk Mátyás','Oszét nyelvi példatár és szótár','978-963-9934-93-1',2,'','3','A5',354,'0',2490,5,'#LA5','Kakuk-Matyas','http://www.konyvesbolt.online/spd/978-963-9934-93-1/Kakuk-Matyas-Oszet-nyelvi-peldatar-es-szotar-Ad-Li','','','','http://www.konyvesbolt.online/spd/978-963-9934-93-1/Kakuk-Matyas-Oszet-nyelvi-peldatar-es-szotar-Ad-Li','','','',3,3,1,7,4,5,1,'Array-0-0','2010-7-29','T: 56/462-476 C: 5440 Kunszentmárton, Alsóköröspart 6/C.','kakukm@invitel.hu','','','Nincs jogdíj.',NULL,1456740139,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Orokke_fiatalon--FD.jpg','',0,1,0,0,12,'',1,'','','','','',NULL,NULL,'',70,0,NULL,25,7,2013,307,'P. Dobrossy Rita','Örökké fiatalon','978-963-87741-5-6',2,'','6','140x200 mm',120,'0',1990,5,'#LB3','','http://www.konyvesbolt.online/spd/978-963-87741-5-6/P--Dobrossy-Rita-Orokke-fiatalon-Ad-Librum-2013','','','','http://www.konyvesbolt.online/spd/978-963-87741-5-6/P--Dobrossy-Rita-Orokke-fiatalon-Ad-Librum-2013','','','',3,3,4,7,4,5,5,'2013-5-0','2013-7-25','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','Reggelenként kilovagoltam a házam melletti ösvényen keresztül egy erdei tisztásra, és mindig eszembe jutott, hogy valahol - talán - ott van Ági is, aki annyira örült volna, ha mindezt megérheti.
Tartoztam neki azzal, hogy valóra váljon az álmunk, hiszen mindketten így szerettük volna befejezni az életünket... A szívünk mélyén örökre fiatalon...','',NULL,1451377941,0);
INSERT INTO books VALUES('',0,'','Bratan_Erzsebet--Elni_vagy_olni--FD.jpg','','',1,0,0,4,'',0,1550,8,20,'',30,NULL,NULL,150,150,2,NULL,28,5,2010,308,'Brátán Erzsébet','Élni vagy ölni? Egy vérvonal hattyúdala','978-963-9934-95-5',2,'','3','',250,'0',1990,2,'#LA6# K:D T:G B:V','Bratan-Erzsebet','http://www.konyvesbolt.online/spd/978-963-9934-95-5/Bratan-Erzsebet-Elni-vagy-olni-Egy-vervonal-hattyu','','','','','','','',3,3,2,7,4,5,5,'2010-4-0','2010-5-28','Brátán Erzsébet, 06 20 807 77 26, ideiglenes/postacím: 2091 Etyek, Alsóhegy u. 38., állandó: 2051 Biatorbágy, Biai G. u. 43.','bratanerzsi@gmail.com','','"Az ezoterikus és alternatív gyógyászati írásokat jegyző szerzőt egy vidéki kastélymúzeumban tett látogatás inspirálta e regény megírására. Brátán Erzsébet ezért könyve elején egy kis történelemleckét tart tankönyvi idézettel, hogy behatárolja történetének időhatárait. A néhány oldalas idézetből megtudjuk: az 1848-as szabadságharc leverésétől az 1956-os forradalom leveréséig ágyazódik a történelem szövetébe a keresztnevükön szerepeltetett nagybirtokos báró család tagjainak sorsa. A fő szál József úrfi és a szolgálólány, Mária szerelme, ehhez kapcsolódnak a fantázia szülte, de valóságosnak ható szereplők. "Milyen volt az élet ezekben az időkben a fővárostól távol? A távoli uradalmakban, kisfalvakban és a tanyákon, a vérkeringéstől eldugott területeken?" - írja a szerzőnő elöljáróban."','Korr. ápr. 25-re.

Kiajánlva!

',NULL,1461228739,0);
