INSERT INTO books VALUES('',0,'','Csonka_Edit--Csillagok--FD.jpg','',0,1,1,16,2,'',0,2784,10,'','','',NULL,NULL,'',30,0,NULL,28,6,2010,311,'Csonka Edit','A csillagok mesélnek','978-963-06-9229-8',1,'','3','A4',52,'0',3290,5,'#A3 Weisz Edit T&B:B','Csonka-Edit','','','','','','','','',5,3,1,7,4,5,5,'2010-4-18','2010-6-28','Weisz Edit; 42/866-013,30/572-9631; 4231 Bököny, Dózsa Gy. u. 48/b.','weiszedit@citromail.hu','','Kedves gyerekek, kedves felnőttek!

Az élet számtalan területén megtapasztalhatjuk, hogy mennyire hiányzik és mennyire fontos a mindennapi életünkhöz a szeretet. Amit néha nem is olyan egyszerű megtalálni, hiszen olyan pici és furcsa dolgokban képes elrejtőzködni, amit meg se gondolnánk. Pedig ott lapul, és ha rátalálunk, ugyanúgy örül, mint a bújócskázó gyerekek.

Ennek a pár kis történetnek is ez a célja. Szeretetből szól hozzátok, kérem, fogadjátok szeretettel!

A szerző','A szerz.-ben szereplő árhoz képest 300 Ft-os emelés: 2990 helyett 3290 Ft.

weboldal kész (borító+hátszöveg hiányzik)

Régi email: wlili@citromail.hu (2012.10.03-ig).',NULL,1450692190,0);
INSERT INTO books VALUES('',0,'','Kollat_Gyula--Korok_az_ordogszantasok_foldjen--FD.jpg',298,'',1,1,6,31,'',1,2466,10,'','színes oldalak','',NULL,NULL,'',30,0,NULL,28,5,2010,312,'Kollát Gyula','Körök az ördögszántások földjén (Rendhagyó bükki túrakalauz és fotóalbum)','978-963-9934-96-2',2,'','3','140x200 mm','222 + 20','0',2990,5,'#LA6 T&B:V','Kollat-Gyula','http://www.konyvesbolt.online/spd/978-963-9934-96-2/Kollat-Gyula-Korok-az-ordogszantasok-foldjen-Rendh','','','','','','','',3,3,1,4,1,5,3,'2010-0-0','2010-5-28','Kollát Gyula, 70/585-5606, 6723 Szeged, Szamos utca 1/A.','kollat.gyula@gmail.com','','Egy-egy túraútvonal végigjárása minden esetben több, mint jobbra-balra kanyarodásokkal tarkított kilométer mennyiség megtétele. Útközben, és persze előtte és utána is történések részesei vagyunk. Találkozunk emberekkel, fákkal, virágokkal, sziklákkal és vízeséssel, na és persze mindenféle helyzetekkel. Ezek lehetnek mulatságosak, vagy szomorúak, akad közöttük meghökkentő és tanulságos is, de valamennyiben közös az, hogy élményt jelentenek számunkra, amik majd hazatérve egy idő után emlékeinkké szelídülnek. Összegyűjtöttem egy csokorra valót a túráimon velem megesett, szép magyar szóval, sztorikból, és ezt kívánom most nagy szeretettel átnyújtani.
Autós ember vagyok, ami annyit tesz, hogy ezzel a járművel közelítem meg túráim kiindulási pontjait. Hogy az autónak ne kelljen az erdőszélen éjszakáznia, nekem pedig valamilyen tömegközlekedési eszközzel a szállásra, majd másnap az autóhoz bumlizni, ezért körtúrákat terveztem, amelyek visszavezetnek az autóhoz. Próbáltam kimazsolázni a hegység legszebb természeti látnivalóit (csúcsok, barlangok, vízesések), történelmi emlékhelyeit (várak, kolostorromok), és azokat felfűzve kialakítani az útvonalakat.
Saját csetlés-botlásaim megismertetésével bátorítani kívánok mindenkit arra, hogy induljanak útnak, mert túrázni jó, és nem csak profiknak való mulatság. Én rabja lettem ennek az időtöltésnek, és legszívesebben főállású túrázó lennék, ha tehetném. Remélem, hogy kalandjaim megírásával sokakat sikerül „megmérgeznem”, és a hátizsák meg a túrabot örök útitársaikká lesznek.','',NULL,1462954903,0);
INSERT INTO books VALUES('',0,'','Windischgraetz--Dobay--Ok_is_hosok_voltak--FD.jpg',154,'',1,0,39,18,'',1,'',40,70,'','',NULL,NULL,'',500,0,NULL,14,7,2010,313,'herceg Windischgraetz Natália és Dr. Dobay Miklós','Ők is hősök voltak – Két fennmaradt egészségügyi dokumentum a Don menti harcok idejéből','978-963-9934-98-6',2,'','3','148x210 mm',104,'0',2490,1,'#LB4,LGV,LGVI#  T&B:B Dobay Pál a közreadó, T&B:B','Windischgraetz-Dobay','http://www.konyvesbolt.online/spd/978-615-5014-56-7/Hollai-Imre-Ut-az-Elnokseghez-Ad-Librum-2010','','','','','','','',3,3,4,7,4,5,4,'2010-5-0','2010-7-14','Dobay Pál, 33/316-642, 2500 Esztergom, Várfok u. 24., ','dobayne.hajnalka@gmail.com','Egy magyar ápolónő és vele együtt dolgozó tábori orvos naplója a második világháborúból.','A II. világháború vezéralakjai éppúgy „halhatatlanok” már, mint Mózes, Nagy Sándor vagy Néró. A rohamra hajszolt, lövészárokban megfagyó, fogságban sínylődő ismeretlen katonáról számtalan dokumentumregény és -film készült. Ám alig-alig esik szó e legnagyobb világégés önkéntes egészségügyi szereplőiről, akik a halál folytonos aratása ellenében szüntelenül az élet mellett álltak, a legeslegdrágábbat mentették az egyetemes öldöklésben és pusztulásban. Ezeknek állít emléket e könyv egy magyar ápolónő és vele együtt dolgozó tábori orvos fennmaradt naplója közreadásával. Íróik nem géppisztollyal vagy kézigránáttal harcoltak, hanem operáló szike, sebkötöző pólya meg injekciós tű volt a fegyverük. Ezekkel tették meg, ami tőlük telt, s így lettek hősök. Írásuk csaknem 70 év távolából is megdöbbentő és tanulságos, noha a háború ezer arcából csak egyetlen egyet, de a legszörnyűbbet villantják fel. Közreadó: Dobay Pál. A kötet nyolc színes képet tartalmaz abból a korból, amikor még a színes fényképezés ritkaságszámba ment.','(dossziéban: Dobay Pál)

',NULL,1480931924,0);
INSERT INTO books VALUES('',0,'','','',0,0,2,0,10,'',1,'','','','','',NULL,NULL,'',12,0,NULL,24,4,2013,314,'Ellen Adlon','A Csajkovszkij-projekt II. Szárnycsapások','(nincs ISBN)',1,'','6','140x200 mm',200,'0','',1,'','','','','','','','','','',5,3,4,7,4,5,5,'2013-3-25','2013-4-24','Asszisztens: katalin.kiss71@gmail.com 20/403-6971; Horváth Edit 1071 Damjanich u. 28/A. Fszt. 8.a. 70/201-5871','katalin.kiss71@gmail.com','','A sorozatgyilkos oszladozó testét kifogják Londonban a Temzéből. A Pyramide Balettegyüttes fellégezve készül a Hattyúk Tava bemutatójára. Ám váratlanul újabb gyilkosságok zavarják meg életüket. a rendőri nyomozás bizonyítja, hogy nem az igazi sorozatgyilkos halt meg, így a Pyramide minden tagja újra gyanús lesz. Ráadásul nem csak a pénz utáni hajsza, de szerelmi féltékenység is okozhatja az újabb gyilkosságokat. Akár nő is lehet a tettes...','',NULL,1366961003,0);
INSERT INTO books VALUES('',0,'','Enrico_Angelotti--Evszaktunderek--FD.jpg','','',1,1,0,16,'',1,2580,10,'','','',NULL,NULL,'',40,0,NULL,22,6,2010,315,'Enrico Angelotti','Évszaktündérek','978-963-9934-97-9',2,'','3','120x200 mm',261,'0',2990,5,'#LA4 Sörös László keménytábla T:G B:B','Angelotti','http://www.konyvesbolt.online/spd/978-963-9934-97-9/Enrico-Angelotti-Evszaktunderek-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,3,'2010-4-0','2010-6-22','Sörös László, 8109 Tés, Felszabadulás u. 65., 20/349-0965','laszlo.soros@freemail.hu','Sikerül-e a vándordiáknak kiszabadítani Arabella hercegkisasszonyt, aki az Ezerarcú Szellem fogságában raboskodik? Évszakmesék.','Tavasz után nyár, nyár után az ősz, majd a tél. Így változnak az évszakok örökös körforgásban, mióta világ a világ. Falevelek hullnak, hópelyhek szállingóznak, tavaszi virágok nyílnak, sárgán izzik a nyári nap. Minden évszaknak megvannak a maga sajátosságai, s a maga sajátos történetei.

Sikerül-e a némi varázserővel is rendelkező vándorló diáknak kiszabadítani Arabella hercegkisasszonyt, aki az Ezerarcú Szellem fogságában raboskodik? Odaér-e Frida időben a Havas Hegyek Birodalmába, egy titokzatos jégcsillagot követve?  Megtalálja-e Kristóf a zöld ruhás hölgyet, akiért a szíve dobog, vagy vajon megleli-e Roland király hőn áhított boldogságát? Kik azok az évszaktündérek, és miért segítenek hőseinknek?

Mindezekre a kérdésekre választ kapunk, ha végigkövetjük, miként alakul a könyv szereplőinek sorsa, s közben betekintést nyerhetünk a tündérek varázslatos, csodákkal teli világába is.','weboldal+shop kész',NULL,1460362518,0);
INSERT INTO books VALUES('',0,'','Kovacs_Laszlo--A_nyomozo--FD.jpg','','',1,0,0,4,'',1,'',40,65,'','',NULL,NULL,'',50,0,NULL,28,5,2010,316,'Kovács László','A nyomozó','978-963-9934-99-3',2,'','3','A5',90,'0',2100,1,'#A6 T:G B:V','Kovacs-Laszlo','http://www.konyvesbolt.online/spd/978-963-9934-99-3/Kovacs-Laszlo-A-nyomozo-Ad-Librum-2010','','','','','','','',3,2,1,7,4,5,3,'2010-4-0','2010-5-28','220-1413','laszlone.kovacs@chello.hu','','Az „elsőbálos” kisregényíró Kovács László művét elolvasva először azon gondolkodtam el, hogy miféle műfaj is a kisregény, pontosabban ez a kisregény. A szerző frappáns választ adott nekem. Szerinte „A tisztességbe, a közjóért és az értelmes rendért való cselekvésbe, valamint az igazság hazugság feletti győzelmébe vetett hitnek komikus, ironikus, olykor groteszk elemekkel átszőtt jelképes meséje.”

A szerző már bizonyította tehetségét két – nemrégiben kiadott – novellás kötetével. Az Éhes őrnagy és a Kártyások a tűzhányón c. művek készítették elő az utat a most kézben tartott kisregényhez, amelyben kiteljesedik az író világszemlélete: a groteszk.
A groteszk ábrázolásmód tökéletes „öntőforma” a zavaros, kibogozhatatlan, azaz MAI magyar társadalmi, politikai, gazdasági állapotunk megmutatására.
E műben a főhős látókörébe kerül az oktatás, az egészségügy, a közpénzek felhasználásának számos ellentmondásos problémája szinte az abszurditásig kihegyezett módon, az író jellegzetes ironikus – de mindig humánus – stílusában.
Összekuszálódott életünk kibogozására magunknak kell megtalálni a megoldást. Talán némi segítséget ad hozzá ez a könyv!
Sok sikert kívánok hozzá!
Csabai Ágnes, alias Berta von Bruneck

„Lupe helyeslőleg bólintott.
– Rendben van, kiálltad az elméleti próbát. De azért ne bízd el magad! A java ezután következik.
– Jöhet.
– Ugye ma szerda van?
– Az.
– Akkor ma, mi ketten, portyázni mehetnénk, csak úgy, az apostolok lován. Velem tartasz?
– Hát, ha mindenáron versenyezni akar a tömegközlekedéssel, én benne vagyok.”

(Részlet a műből)','Kiajánlva!',NULL,1458818755,0);
INSERT INTO books VALUES('',2,'','Kerekes_Gabor--Zwischen_Heldenplatz_und_Hosok_tere--FD.jpg','',0,1,1,0,41,'',1,'',40,40,'','',NULL,NULL,'',50,0,NULL,10,6,2010,317,'Gábor Kerekes','Zwischen Heldenplatz und Hősök tere - Studien zur österreichischen Literatur','978-963-9934-43-6',2,'','3','140x200 mm',105,'0',2990,1,'#LB5#  T:Szerző,B:V','Gabor-Kerekes','http://www.konyvesbolt.online/spd/978-963-9934-43-6/Gabor-Kerekes-Zwischen-Heldenplatz-und-Hosok-tere-','','','','http://www.konyvesbolt.online/spd/978-963-9934-43-6/Gabor-Kerekes-Zwischen-Heldenplatz-und-Hosok-tere-','','','',3,3,1,9,4,5,3,'Array-0-0','2010-6-10','Dr. Kerekes Gábor 06-26-331-695 Cím: 2085 Pilisvörösvár, Puskin köz 3.','kegahu@yahoo.de','','','',NULL,1451380657,0);
INSERT INTO books VALUES(NULL,0,'','',424,0,0,0,0,4,'',0,'',0,0,'',90,NULL,NULL,500,500,5,NULL,18,8,2010,318,'Varga M. János','Az ÉSZ Törvénye - Az életkor-szabályozás regénye','978-615-5014-00-0',2,'','3','A5',360,'0',1990,2,'LEZÁRVA! ->§454 K&T&B:A','Varga-M-Janos','','','','','','','','',5,3,4,7,4,5,0,'2010-6-0','2010-8-18','30/542-9395 Balatonfüred, Németh L. u. 1/A.','janosmvarga@gmail.com','Évente százmilliárdokat költünk szívműtétekre, dializátorokra, gyógyszerekre stb., mi történne, ha előre szabályoznánk az ember elérhető életkorát? Egy meghökkentő sci-fi (vagy jóslat?).','Részletek Az ÉSZ Kiáltványából: „Az emberi életkor meghosszabbítására irányuló törekvés jelenkorunk egyik legnagyobb problémája. Évente
százmilliárdokat költünk szívműtétekre, dializátorokra, gyógyszerekre, és az orvos-egészségügyi módszerek továbbfejlesztésére, hogy életünk kellemetlen, és biológiailag értelmetlen végét egyre tovább nyújtsuk. És mivel kollektív teherbírásunk véges, az emberi életvéggel kapcsolatos kiadásokat már csak egészséges életek rovására – a jövő generációk bankszámlájá-
ról – tudjuk fedezni. (...) Mint bőrünk színét, születésünkkel megöröklünk egy endotroponinnak és clothorinnak nevezett sorshormont, amelyek
mennyisége – ezek aránya – várható életkorunkat megszabja. Állatkísérleteink alapján bebizonyosodott, hogy ezen sorshormonok, vagy ezeket imitáló anyagok adagolásával kísérleti állatok élethossza mesterségesen beállítható. (...) Javaslom, hogy vegyük kezükbe önnön sorsunk intézését! Határozzuk meg, mi az az életkor, ami a társadalom teherbírását figyelembe véve elérhető. Állítsuk be az újszülöttek sorshormon-szintjét arra az értékre, amely a meghatározott életkor elérését biztosítja, és miután a célt megadtuk, a többit bízzuk életkor-szabályzó rendszerünk automata-pilótájára.” (...)

S.E.Kely szenátor véleménye az ÉSZ Kiáltványáról: „Őszintén meg kell mondanom, hogy McCato szenátor felhívása óta egy írás sem hozott ki annyira
a sodromból, mint az ön Kiáltványa. Véleményem szerint az ön írása felforgató szellemét tekintve vetekszik a Kommunista Kiáltvány és a Mein Kampf
szellemével – de szeretném remélni, hogy hatását tekintve majd elmarad mögöttük.”

A szerző a Római Magyar Akadémia ösztöndíjasa volt, a Berkeley, az Innsbrucki, a Stockholmi és a Yale Egyetemen tanított és kutatott. Tudományos közleményei mellett eddig főleg esszéket és aforizmákat (Aforizmák, Elmélkedések, Epifrázisok) publikált.
','',NULL,1325425126,0);
INSERT INTO books VALUES('',0,'<h4>zárkózott</h4>

<p>A zárkózott (introvertált) ember szótlanságával jelzi, hogy valami rejtegetnivalója van.</p>

<p>Az extrovertált bőbeszédűségével próbálja elterelni róla a figyelmet.</p>','Varga_M_Janos--Epifrazisok--FD.jpg','','',1,0,27,21,'',1,'',0,0,'','',NULL,NULL,'',150,0,NULL,28,6,2010,319,'Varga M. János','Epifrázisok','978-615-5014-01-7',2,'','3','98x135 mm',176,'0',990,1,'#LB4# K:I T&B:B','Varga-M-Janos','http://www.konyvesbolt.online/spd/978-615-5014-01-7/Varga-M--Janos-Epifrazisok-Ad-Librum-2010','','','','','','','',3,3,0,7,4,5,5,'Array-0-0','2010-6-28','30/542-9395 Balatonfüred, Németh L. u. 1/A.','janosmvarga@gmail.com','Szellemes szótár epigrammákkal.','','Formátum: A6

Kiajánlva! (weboldal+shop kész)
