INSERT INTO books VALUES('',0,'','Mester_Gyorgyi--Halali_jo_tortenetek--FD.jpg',260,'',1,0,0,3,'',1,'',40,70,'','',NULL,NULL,'',100,0,NULL,28,5,2010,320,'Mester Györgyi','Haláli (jó) történetek','978-963-87741-7-0',2,'','3','140x200 mm',200,'0',1500,1,'#LB5#','Mester-Gyorgyi','http://www.konyvesbolt.online/spd/978-963-87741-7-0/Mester-Gyorgyi-Halali-jo-tortenetek-Ad-Librum-2010','','','','','','','Ad_Librum--Mester_Gyorgyi--Halali_jo_tortenetek--Kulonnyomat.pdf',3,3,1,7,4,5,3,'2010-5-4','2010-5-28','','mestergyorgyi@freemail.hu','Szellemes novellák sora.','Azon az éjszakán teljes átéléssel viselt, erotikus álma volt. Évek óta először. Szinte megújult tőle, frissen, felajzottan ébredt. Pedig nem is a szőke nővel álmodott. Az álmában látott női test csupán fehér bársonnyal borított, ruganyos, kemény hús volt, melyben úgy merült el, mint légy a tejben. Élvezettel… de semmi több. Ettől ébredt jóllakottan, kielégülten. Az éjjel átélt élmény azontúl hatással volt a mindennapjaira is. Magában gyakran fohászkodott, legyen szerencséje, csak picurka szerencséje, hogy legalább egy pillantás erejéig, ismét láthassa az asszonyt. A látványt akarta magába szívni, elraktározni, hogy megéljen belőle a következő találkozásig. De vajon találkozásnak nevezhető az olyan együttlét, amelynek egyoldalúan, csupán ő a részese?!

Az a nő valójában még a létezéséről sem tud. Nem is sejti, hogy valaki felfigyelt rá, és az udvari séták alkalmával, ha teheti, lopva, folyamatosan szemmel tartja. Amíg kinn levegőznek, csak a sziluettjét látja, de odabenn, a zárka magányában lehetősége van rá, hogy elképzelje teljes testi valójában. Levetkőzteti, de jó értelemben. Csak a szürke kabáttól meg a fekete sapkától szabadítja meg, egyébként színes, testhez álló, csinos ruhába öltözteti, és lehunyt szemmel élvezi a látványt. Hogy milyen szép is az a nő! És illatos! Szinte orrában érzi a test bódítóan édes illatát, és méghozzá olyan intenzíven, mintha mellette állna. Csak a kezét kellene kinyújtania, és megérinthetné. Elönti a forróság. Soha ennyire nem akart férfias külsejűnek mutatkozni, jóképűnek, izmosnak, megkívánhatónak. Ettől a naptól fogva, minden reggel fekvőtámaszok tucatjait csinálta, a végén kinyomta már a százhúszat is. Jó erőnléten akart maradni, úgy szabadulni, hogy ha összeakad a nővel, esélye lehessen nála…','',NULL,1467279705,0);
