INSERT INTO books VALUES('',0,'','Kiss_Sarolta--Szelkabatban--FD.jpg','',0,1,0,2,16,'',1,'',40,60,'','',NULL,NULL,'',1000,0,NULL,3,12,2010,330,'Kiss Sarolta','Szélkabátban','978-963-08-0435-6',1,'','3','B5',68,'0',1990,1,'#LD3# T:Szerző, B:B','Kiss-Sarolta','http://www.konyvesbolt.online/spd/978-963-08-0435-6/Kiss-Sarolta-Szelkabatban-2010','','','','http://www.konyvesbolt.online/spd/978-963-08-0435-6/Kiss-Sarolta-Szelkabatban-2010','','','',3,3,1,9,4,5,3,'2010-11-15','2010-12-3','Kiss Sarolta, 20/240-1150, 1171 Budapest, Nemesbükk u. 62.','kiss.saci@gmail.com','Több évtizednyi óvodapedagógusi tapasztalat súgta Kiss Sarolta újabb gyerekverseit.','SZÉL KÓSZÁL

Csendes éjben szél kószál
