INSERT INTO books VALUES('',0,'','Szatmari_Zsuzsanna--Erzesek--FD.jpg','','',1,0,0,2,'',1,'',40,40,'','',NULL,NULL,'',120,0,NULL,8,12,2010,331,'Szatmári Zsuzsanna','Érzések és érzelmek','978-963-08-0457-8',1,'','3','120x200 mm',100,'0',1990,1,'#LA3#','Szatmari-Zsuzsanna','http://www.konyvesbolt.online/spd/978-963-08-0457-8/Szatmari-Zsuzsanna-Erzesek-es-erzelmek-2010','','','','','','','',3,3,1,7,4,5,5,'2010-11-0','2010-12-8','Szatmári Zsuzsanna, 70-63-56-204, 2030 Érd, Búvár utca 14/a.','zsuzsesz1982@citromail.hu','Többrétegű versek az érzelmek hullámzásáról.','E többrétegű kötet minden verse egy adott lelkiállapotot és érzést kísér végig. A versek – és a borító is – a költő végleteit tükrözi.

A szerző kifejezi köszönetét a családjának és a barátainak, akik mindig őszinte véleményt mondtak és új versek írására inspiráltak.','10e Ft plusz a korrektúrára.

Nyomdába adva 2010.11.22.',NULL,1458734306,0);
INSERT INTO books VALUES('',0,'','Janurik_Tamas--A_lovari_nyelv_torteneti_szotana--FD.jpg',138,'',1,1,0,35,'',1,'',40,60,'','',NULL,NULL,'',55,0,NULL,0,0,2008,332,'Janurik Tamás','A lovári nyelv történeti szótana','978-615-5014-29-1',2,'','3','A5',104,'0',1990,1,'#LA5 T: szerző, B:V','Romani','http://www.konyvesbolt.online/spd/978-615-5014-29-1/Janurik-Tamas-A-lovari-nyelv-torteneti-szotana-Ad-','','','','','','','',3,3,0,0,0,0,0,'2010-6-26','Array-0-0','Dr. Janurik Tamás, 20/316-14000','janurik.tamas@freemail.hu','','Dr. Janurik Tamás magyar és összehasonlító nyelvész, a Kecskeméti Főiskola professor emeritusa, a nyelvtudományok kandidátusa, különböző európai nyelvek kutatója. A romani nyelvet (illetve annak standardizált nyelvi változatát, a lovárit) évek óta tanítja a főiskolán.
"A lovári nyelv történeti szótana" Magyarországon először kisérli meg a lovári alapszókincs összevetését a legismertebb újind nyelv, India államnyelve, a hindí szókészletével, valamint annak feltárását, hogy az Indiából Magyarországig tartó hosszú, több évszázados vándorlás során a lovári nyelvváltozatot beszélő roma népesség nyelve milyen új szókészleti elemekkel gazdagodott a perzsa, kurd, örmény, görög, szláv (bolgár, szerb, szlovák) román, német és magyar nyelvekből átvett szavak révén.
+++','',NULL,1480590626,0);
INSERT INTO books VALUES('',0,'','Matthew_Vigo--Rejtelem_a_deltengeren--FD.jpg',226,'',1,0,0,10,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,18,8,2010,333,'Matthew Vigo','Rejtelem a déltengeren','978-615-5014-33-8',2,'','3','130x200 mm',200,'0',1990,1,'#LC,LGII#RA1a Száray Mátyás, 130x200 mm, B:B T:G','Vigo','http://www.konyvesbolt.online/spd/978-615-5014-33-8/Matthew-Vigo-Rejtelem-a-deltengeren-Ad-Librum-2010','','','','','','','',3,3,4,7,4,5,5,'2010-7-0','2010-8-18','Száray Mátyás, 30/857-4471, 1119 Budapest, Etele út 69. 8/77.','mszaray@yahoo.com','Ki ölte meg a pókerverseny győztesét? Klasszikus krimi egzotikus helyszínen.','Anthony Noir, az ismert detektív, lévén nem különben szenvedélyes kártyajátékos, lelkesen fogadja el a meghívást az apró, déltengeri szigeten megrendezésre kerülő pókerversenyre. 15 játékos érkezik, de csupán egy nyer...
Az összejövetel gyors lezajlása után a nemzetközi vendégsereg sietősen tovább állna, de egy váratlan trópusi vihar maradásra kényszeríti őket...
S mire az égzengés elvonul, a verseny újdonsült győztesét holtan találják...
Valaki végzett vele. Mégis ki? Az egyik vesztes. De vajon melyikük? A titokkal teli brazil özvegy, esetleg a rafinált magyar zenetudós, netán a hírhedt francia bűvész, vagy a szenvedélyes kolumbiai hazárdőr, a féltékeny angol színésznő, a filippínó énekesnő, de lehet a dörzsölt török kereskedő...
Sok indíték, még több lehetőség. De Anthony Noir ugyancsak precíz ember, addig nem tágít a szigetről, míg az ügy minden részét helyére nem teszi.','Második kifizetés kezdeményezve 2011.12.31. 42.453 Ft-ról.

11-08-07: #RA1a 106 pld.

Nyomdába 100727.

Végleges kézirat június végére.
',NULL,1474540194,0);
INSERT INTO books VALUES('',0,'','Nemes_Maria--Batyu_humor--FD.jpg',164,0,1,1,0,20,'',1,1208,10,'','','',NULL,NULL,'',160,0,NULL,14,7,2010,334,'Nemes Rózsa','Egy batyu humor','978-963-06-9564-0',1,'','3','A5',136,'0',1990,5,'A LÍRÁS FORGALOM A §386-OS SZÁMRA KERÜL! #LD1 Tatainé Nemes Mária Rózsa, T&B:B','Nemes-Rozsa','http://www.konyvesbolt.online/spd/978-963-06-9564-0/Nemes-Rozsa-Egy-batyu-humor-2010','','','','http://www.konyvesbolt.online/spd/978-963-06-9564-0/Nemes-Rozsa-Egy-batyu-humor-2010','','','',3,3,1,7,4,5,5,'2010-5-0','2010-7-14','Tatainé Nemes Mária Rózsa, 20/241-6543, 2534 Tát, Móra F. 5.','boszike@vipmail.hu','Az ízes vidéki nyelv.','Öreglegények

– Hát té Bözsi! Hogy ménnyi öreglegíny van manapság ebbe a faluba!
– Az, hallod! Hát az a Vencél fia is, az a Tomi gyerék, annak is, hogy hány nője vót má, oszt mind ott hatta!!
– Hát hallod, az úgy vót rígén is, hogy sok cipőt fő köllött próbányi ahhó, hogy mégtuggyuk mellik a kínyelmes, oszt csak aszt véttük még, amellik a legjobban passzót!...','150 példány kell a szerzőnek kiadáskor

