INSERT INTO books VALUES('',0,'','Wanderer_Janor--Akik_felett_mindig_kek_az_eg--FD.jpg','','',1,0,0,3,'',1,'',40,60,'','',NULL,NULL,'',300,0,NULL,6,10,2010,336,'Wanderer János','Akik felett mindig kék az ég','978-615-5014-35-2',2,'','3','130x200 mm',140,'0',1990,1,'#LD#  K:K,B:V,T:G','Wanderer-Janos','http://www.konyvesbolt.online/spd/978-615-5014-35-2/Wanderer-Janos-Akik-felett-mindig-kek-az-eg-Ad-Lib','','','','','','','',3,3,2,7,4,5,5,'2010-8-0','2010-10-6','Wanderer János, 30/217-1636, 1115 Budapest, Etele út 52/A. VIII/48.','csilimon@gmail.com','Sorsok, események a hatalmas óceánból, amely voltaképpen az élet.','Ha az írónak sikerül tér - és időkorlát nélkül észrevétlenül, ugyanakkor szórakoztatóan, gondolatokat ébresztve végigkalauzolnia  az általa kijelölt úton olvasóját, munkája eredményesnek bizonyul.

Amennyiben nekem megadatik, hogy megfoghassam kezed, már boldog vagyok, mert célom elérhettem: hiszen ez azt jelenti, hogy ott állhatok melletted!

Gyermekkorom Lajoskomárom ege alatt múlt el felettem, ma a fővárosban élek. Harmincnyolc évem során egyre inkább közelebb került hozzám az olvasás, később az írás. Érdekel az emberi lélek s tetteink valódi mozgatórugója, melyek minduntalan tetten érhetőek a felszín alatt. Ez a könyv  sorsokat, eseményeket ragad ki a hatalmas óceánból, mely voltaképpen maga az élet.','100723: A szerző telefonon visszajelzett a tördelésről, és hogy szeptember elején lesznek kész az illusztrációk.

100721: A tördelés küldése.

100719: Korrektúrára adva Katának

100713: Kézirat leadva. Esetleges alcím: Elbeszélések, novellák

A kézirat a nyár folyamán várható, az illusztrációk augusztus végén.
8 kép lesz a kötetben, 1 a borítón. A borítókészítés csak a borítóillusztráció érkezése után kezdődik.

70 pld-t visz el a szerző kiadáskor.

Betűméret mint a Szalóczy-kötetben.

Szerződéskötés 2010. június 17-én.',NULL,1463131217,0);
INSERT INTO books VALUES('',0,'','Matyas_Istvan--Zugsarok--FD.jpg',145,'',1,1,0,4,'',1,1160,10,'','','',NULL,NULL,'',30,0,NULL,29,7,2010,337,'Mátyás István','Zugsarok','978-615-5014-34-5',2,'','3','A5',120,'0',1160,5,'#LB6 T:G,B:B','Matyas-Istvan','http://www.konyvesbolt.online/spd/978-615-5014-34-5/Matyas-Istvan-Zugsarok-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,3,'2010-6-0','2010-7-29','Mátyás István, 2030 Érd Csér utca 28., 20/770-71-10','matyasistvan1977@gmail.com','','A napjainkban zajló események főszerepében egy testvérpár áll. Mike, az idősebb testvér, útban 6 éve nem látott öccséhez, összeismerkedik Cameronnal, a világjáró kalandorral. Közös utazásuk nem sokkal később véget egy közeli kisvárosban. Cameron egy csatlakozást igyekszik elérni, melynek köszönhetően kalandos útját északon folytathatná, míg Mike végre viszontlátja Petert. A testvérek első közösen eltöltött napjukat kezdik meg, mikor a városba érve, a társaságukhoz csapódik Cameron. A továbbutazási lehetőséget elszalasztó kalandor Peter felajánlására velük tart. Immáron hárman lakják az erdei házikót, melyben egy váratlan pillanatban egy különleges mondat hangzik el Mike szájából: „Úgy gondolom, az álmodás, nem más, mint az elméleti időutazás. Az álom az átjáró a párhuzamos világok között és a deja-vu, nos, az a párhuzamos univerzumok véletlen kereszteződése.”

Ezen felvetés hatással lesz hármójuk elkövetkezendő napjaira. Míg Mike egyre több gondolatát ossza meg társaival, Peter elején hitetlenkedő hozzáállását felváltja a kíváncsiskodó énje. Telnek a napok és csak gyűlnek az érdekes felvetések és a megvalósításért kiáltó ötletek. Egy különös eseménysorozatnak köszönhetően előkerülnek olyan tárgyak, melyek hatására az     elmúlt napokban elhangzottakra teljesen más megvilágításból látunk rá. Hirtelen az egyszerűnek vélt dolgok bonyolultak lesznek, amit fokoz még Cameron váratlan és indokolatlan eltűnése is. Az ő szemszögéből figyelhetjük tovább az események alakulását a végkifejletig, mely számára is tartogat meglepetéseket.','2 pld. kell neki

Árlevitel 1980 forintról 1160 forintra 2012.11.14-én.',NULL,1476957727,0);
INSERT INTO books VALUES('',0,'','Jankovich_Valeria--Eleteim-titkaim--FD.jpg','','',1,0,18,24,'',0,'',40,40,'','',NULL,NULL,'',120,0,NULL,13,10,2010,338,'Jankovich Valéria','Életeim-titkaim – Ungár Anikó élete','978-615-5014-36-9',2,'','3','A5',175,'0',2990,1,'#LB6 T&B:A, 29 ff és 13 sz. kép','Ungar-Aniko','http://www.konyvesbolt.online/spd/978-615-5014-36-9/Jankovich-Valeria-Eleteim-titkaim-Ungar-Aniko-elet','','','','','','','',5,3,1,7,4,5,5,'2010-6-30','2010-10-13','Jankovich Valéria, 20/548-3656, 1113 Budapest, Karolina út 5. II/2.','valeriajankovich2@gmail.com','Ungár Anikó színes élettörténete sok képpel.','Sas István (reklámfilmrendező) és felesége Irén
Anikó született intelligens. Ez a képesség és tapintat nem tanulható, otthonról hozta. Sokszor előfordult már társaságban is, hogy hallgat és figyel. Beszélgetéseknél nem hangoztatja szellemi fölényét, mert nem akar más rovására villogni. Sok mindent látott, tapasztalt utazásai során. Olyan, aki itta az élményeket, nem
csoda, ha kitágult a horizontja.

Sütő Enikő (ügyvéd, modell)
Ahogy az évek múlnak, ő nemhogy nem „romlik”, hanem szépül, nemesedik, de nemcsak külsőre, hanem lélekben is. Ez árulkodik magáról az emberről, hisz a test a lélek temploma. Lelkiállapotunk egy bizonyos életkor után különösen látványosan mutatja testünkön, mit raktároztunk el a lelkünkben. Van-e tartásunk, feszességünk, odafigyelünk-e a lényegre stb.

Rózsa György (a Magyar Televízió szerkesztőriportere, műsorvezetője)
Példás, ahogy előkészül egy előadásra. A kellékeket, s mindent, ami fontos a sikeres, zökkenőmentes előadáshoz, legalább hatszor leellenőriz. Itt nem lehet hiány! Az öltözőjét, akármilyen parányi is, pillanatok alatt átrendezi saját ízlése szerint. Néha elég, ha csak kipakolja a cuccait, máris sokkal barátságosabbá válik a környezet. Rugalmasan alkalmazkodik az adott helyzethez. Nincs fogas,
édes istenem, nem gond, megoldjuk pillanatok alatt. Ha belép a színpadra, csend támad. Mindenki rá figyel – ezt viselkedésével, belső tartásával, belső sugárzó aurájával éri el.

Mácsai Pál (színész, rendező, az Örkény Színház igazgatója)
Az igazat megvallva csak néhányszor láttam színpadon Anikót, de azt nem lehet elfelejteni. Az egész lényében van valami „dögös”. Ne értse félre, egyszerűen fantasztikus, hogy egy ilyen törékeny, kecses, szép nő saját védtelenségét meghazudtolóan, hogy képes ilyen mérhetetlen, mondhatni masculin, vagyis Mefisztói energiát és erőt sugározni a nézők felé. Semmi „zsabó, fodor, cicababa” mosoly, hanem elegáns fejtartás, koncentrálóképesség, visszafogottság és elbűvölő hatás, olyan, aki csacska női mosoly helyett bátran és nyíltan néz a szemedbe.
','PODPlusz
(166 x 400) + (9 x 6000) = 120.400 Ft -> 1003,33 Ft/pld.',NULL,1459841089,0);
INSERT INTO books VALUES('',0,'','',516,'',0,0,0,39,'',0,'',8,30,'',125,NULL,NULL,500,500,3,NULL,18,8,2010,339,'Hölbling Tamás','A honfoglalás forráskritikája II. A hazai kútfők','978-615-5014-39-0',2,'','3','A5',400,'0',2990,2,'folytatódik §516; T:szerző,B:B; -13 példánynak kellene lennie! és 15 példánynak Lajosnál!','Holbling-Tamas','','','','','','','','',5,3,1,9,4,5,5,'2010-7-1','2010-8-18','Hölbling Tamás, 20-340-4310, 7635 Pécs, Mandulás köz 2.','tamas.holbling@kollmax.hu','A honfoglalás eseménytörténetének új megvilágítása helyezése a források tudományos, kritikai újraértelmezése útján - 2. kötet','A Honfoglalás forráskritikája első, a külföldi kútfőkkel foglalkozó kötete három stratégiai következtetéssel zárult. (1) A Dzsajháni-hagyomány nem valamiféle őshazai magyarokról, hanem a 910 körül a Kárpát-medencében élő magyarokról szól. (2) A magyarok bejöveteléhez semmi köze a 895-896-os balkáni hadjáratnak, sőt utóbbit már a megtelepedett, a Kárpát-medencei bolgár állásokat felszámolt magyarok hajtották végre. Ez a honfoglalás eseménytörténetét és időpontját is új megvilágításba kell helyezze. (3) A DAI által emlegetett sabartoi asphaloi nevű nép nem a Volgán túlról érkező hétmagyarokkal, hanem az Anonymus és a krónikáink által említett Csaba-féle kunokkal azonosítható.

Ezen következtetések tökéletesen kisimítják a magyar krónikák és a korhű görög, arab vagy német források között látszólag feszülő ellentéteket, és megnyitják az utat a magyar krónikairodalom felhasználása előtt. Azt az utat, amit a magyar történelemtudomány azért reteszelt el több mint egy évszázada, mert a tévesen keltezett Dzsajháni-hagyomány és az abszolutizált és félreértett De Administrando Imperio alapján felvázolt torz történelmi képbe nem voltak beilleszthetők krónikáink állításai.

Míg előző kötetünkben csak utalások szintjén jelentek meg a magyar krónikák és Anonymus gesztája, a második kötet elemzései immáron
rájuk fókuszálnak.','',NULL,1460710980,0);
