INSERT INTO books VALUES('',0,'','Varga_Bela--Fulop_lovag_az_orvosolo--FD.jpg',331,0,1,0,0,4,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,23,3,2012,356,'Varga Béla','Fülöp lovag, az orvosölő','978-615-5110-47-4',2,'','5','130x200 mm',296,'0',1490,1,'#LC2,LGI#','','http://www.konyvesbolt.online/spd/978-615-5110-47-4/Varga-Bela-Fulop-lovag-az-orvosolo-Ad-Librum-2012','','','','http://www.konyvesbolt.online/spd/978-615-5110-47-4/Varga-Bela-Fulop-lovag-az-orvosolo-Ad-Librum-2012','','','',3,3,4,7,4,5,5,'2012-1-0','2012-3-23','1043 Bp. Kassai u. 9.  II./16., 30/429-6739','vargabela27@citromail.hu','','Képzeletbeli világ csap össze a valósággal, pontosabban az orvosokkal, az emberi méltóság nevében. Ebben az eszmerendszerben a boncolás és a szervátültetés egyenlő a kannibalizmussal, merénylet az emberi jogok, a szeretet és jóérzés ellen, gyalázat, amit meg kell szüntetni és művelőit meg kell büntetni. Egy költött nép, a b. nép, évszázados küzdelmének lényege ez a küzdelem, e körül forog egész történelme, ez adott és ad neki erkölcsi fölényt ellenségeivel szemben a valódi, végső győzelem esélye nélkül.

Két irányzat csap össze B. országban a múltban és jelenben: a békés izolációt és lassú térnyerést hirdető kollaboránsok és a megsértett emberi méltóság nevében bosszút, terrort hirdető intifádorok. Fülöp, a történet főhőse, egyszemélyes 21. századi intifádor, magával csalja barátait B. országból a kegyetlen és kíméletlen emberboncolók valóságába, hogy ott terve szerint vérengző bosszút álljon a sértett emberi méltóság nevében. Honfitársa és ellentétpárja, Cefizil úr, a kollaboráns emberjogi harcos ezenközben mindent megtesz, hogy terrortámadásukat megakadályozza.

Szépség és otrombaság, költészet és valóság, emberi méltóság és áldemokrácia tehát – az orvosok és a B. Birodalom csap össze ennek a meglehetősen elvont, ám finom helyzetkomikumokban gazdag kalandregénynek a lapjain, amelynek során az olvasó végül a prózából a líra magasságaiba menekülhet.','Szerződés módosítás a kiadó javára (2015.07.03)',NULL,1451299767,0);
INSERT INTO books VALUES('',0,'','Janurik_Tamas--A_lovari_nyelv_kiskateja--FD.jpg',86,'',1,1,0,35,'',1,'',40,60,'','',NULL,NULL,'',50,0,NULL,29,10,2010,357,'Janurik Tamás','A lovári nyelv kiskátéja','978-615-5014-54-3',2,'','3','',60,'0',1990,1,'#LA5# T:szerző,B:V','Romani','http://www.konyvesbolt.online/spd/978-615-5014-54-3/Janurik-Tamas-A-lovari-nyelv-kiskateja-Ad-Librum-2','','','','','','','',3,2,1,9,4,5,0,'2010-9-0','2010-10-29','Dr. Janurik Tamás, 20/316-1400, 8000 Székesfehérvár, Ady Endre u. 22.','janurik.tamas@freemail.hu','','Dr. Janurik Tamás magyar és összehasonlító nyel­vész, a Kecskeméti Főiskola professor emeri­tu­sa, a nyelvtudományok kandidátusa, különböző európai nyelvek kutatója. A romani nyelvet (illetve annak standardizált nyelvi változatát, a lovárit) évek óta tanítja a főiskolán. 
A lovári nyelv kiskátéja 500 kérdés–felelet formájában vezeti végig az olvasót a nyelvre jellemző sajátosságok feltárásában, szerepük, fontosságuk és működési módjuk megértésében. A nyelvi jellegre vonatkozó kérdéseket és válaszokat a hangrendszert és a legfontosabb hangváltozásokat bemutató kérdések és feleletek követik, a kiadvány azonban elsősorban az alaktani sajátosságokra koncentrál, részletesen tárgyalja a főnévragozást, rövidebben a melléknevek és számnevek jellemzőit, ismét részletesebben a különböző névmások használati szabályait, kitér az elöljárók és az igekötők ismertetésére, a legnagyobb terjedelmet mégis az igeragozás igen részletes tárgyalásának szenteli, a lovári nyelvtankönyvek hasonló fejezeteinél sokkal rendszerezettebb, részletesebb és áttekinthetőbb formában.
A kérdve kifejtő módszer egyúttal segít a különböző nyelvtani fogalmak (az élő és élettelen ragozás, az alapalakok és függő alakok, a névszóragozási esetek elnevezései és funkciói, a különböző névmásfajták és névmási határozószók osztályozása, az igetípusok, igeidők, igemódok stb.) megértetésében is. Az egyes nyelvtani fogalmak pontos ismerete nélkül azoknak a beszédfolyamatokban vagy írott formában való alkalmazása sem lehet sikeres vagy hibátlan. Általános tapasztalat ugyanis, hogy az idegen nyelvek tanulását az anyanyelvi nyelvtani ismeretek teljes hiánya vagy hiányos és sokszor félreértelmezett volta gátolja leginkább.
Az 500 kérdés tehát bevezet a lovári nyelv nyelvtani fogalmainak megismerésébe, a reájuk adott 500 válasz pedig a részletek, az egyes nyelvtani elemek elsajátítását teszi lehetővé.
','',NULL,1480592846,0);
INSERT INTO books VALUES('',0,'','Kerekes_Pal--Az_elektronikus_konyv--FD.jpg',177,'',1,0,33,43,'',0,'',10,20,'',30,NULL,NULL,300,300,2,NULL,6,10,2010,358,'Dr. Kerekes Pál PhD','Az elektronikus könyv: e-könyv, e-könyv-olvasó, e-könyv-kereskedelem','978-615-5014-58-1',2,'','3','140x200 mm',134,'0',1990,2,'#LB6# K:K,T&B:V','Kerekes-Pal','http://www.konyvesbolt.online/spd/978-615-5014-58-1/Dr--Kerekes-Pal-PhD-Az-elektronikus-konyv-e-konyv-','','','','','','','',3,3,4,7,4,5,5,'2010-9-0','2010-10-6','20/9557-826','kerekes.pal@t-online.hu','Az e-book és jövője.','Az elektronikus könyv új kultúrtechnikai komplexumokra téríti, kényszeríti az olvasókat. Az Internet és a különböző hozzáférési eszközök – mint a mobiltelefon, a notebook, az asztali számítógép, és természetesen az e-reader – összetett virtuális térbe helyezik a tudás és a műélvezet logisztikáját. A könyvespolcok ritkán érintett tárlókká válnak, hiszen a digitális készletek – azonnal elérhetően – kimeríthetetlen készletben állnak rendelkezésre.

A könyv felvázolja az e-könyv technikai, kereskedelmi struktúráját. Az e-book határterületeit is számba veszi: a hangos- és videokönyvet, a POD konstrukciót. A digitális könyvet a nyomtatott könyv folytatásaként, nem pedig megszüntetőjeként elemzi.

A könyv szerzője informatikus könyvtáros végzettségű. Doktori értekezését az elektronikus kultúra és az online közszolgálat összefüggéseiről írta. Dolgozott nagy informatikai multik partnereként, kommunikációs tanácsadója volt a hazai internet vállalkozások legnagyobbjainak. Rendszeresen publikál szaklapokban, elméleti folyóiratokban.','50 pld. a szerzőnek kiadás után.',NULL,1476869746,0);
INSERT INTO books VALUES('',0,'','Demeter_D_Zoltan--A_szabadsag_ara--FD.jpg','','',1,1,0,4,'',0,1284,10,'','','',NULL,NULL,'',130,0,NULL,28,9,2010,359,'Demeter D. Zoltán','A szabadság ára','978-615-5014-55-0',2,'','3','A5',128,'0',1600,5,'#LB3#  130x200 mm, K:K,T:G,B:V','Demeter-D-Zoltan','http://www.konyvesbolt.online/spd/978-615-5014-55-0/Demeter-D--Zoltan-A-szabadsag-ara-Ad-Librum-2010','','','','','','','',3,3,4,7,4,5,5,'2010-9-1','2010-9-28','Demeter D. Zoltán, 96/600-201, 9071 Gönyü, Kossuth L. 60-62.','demeter13@gmx.net','Egy kalandos szökés regénye Erdélyből a 80-as években.','Demeter D. Zoltán 1945-ben született Kolozsváron. A család politikai nézetei miatt menni kényszerült. Miután Magyarország nem fogadta be , a 80-as évek elején a családjával nyugatra szökött.

Ebbe a kalandregénybe sűrítette be, egy nem mindennapi szökés történetét, az örökké kínzó fájdalmat, amely a hontalansággal jár, és azt, hogyan őrölnek fel idegen nemzetek malmai egy igazi magyar családot.','100+1 pld. a szerzőnek

2010.11.26: ajánlat a hasonló méretű, de hozott nyomdai anyaggal készülendő 193.500 Ft-os áron.',NULL,1467282766,0);
INSERT INTO books VALUES('',0,'<h4>Merő Béla rendező véleménye</h4>

<p>Nagyon lendületes írás, magával ragadott, s egy ültő helyemben el is olvastam.</p>

<p>Gondolatiságával, világképével mélységesen egyetértek. (…) Kívülállóként és résztvevő/szenvedőként hasonlóan értékelem és szemlélem világunkat.</p>

<p>A történet is jó. Egy ember élete, szinte egy évszázadnyi történelem több aspektusból ábrázolva. Jó a `gúny és apoteózis` dialektikája, jó az, hogy nem kötelezi el magát egyetlen eszmével sem, s így lebegteti a kérdéseket, és ezáltal az olvasóval fogalmaztatja meg az igazságot.</p>','Halmos_Antal--Kolja--FD.jpg','','',1,1,8,1,'',1,1136,10,'','','',NULL,NULL,'','',0,NULL,6,10,2010,360,'Halmos Antal','Kolja, a nép ellenségének fia -  Filmnovella','978-615-5014-57-4',2,'','3','120x200 mm',78,'0',1490,5,'BIZOMÁNYOSI FORGALOM NEM IDE KERÜL! #B7 K:K,B:V,T:G','Tuckos','','','','','','','','',5,3,4,7,4,5,5,'2010-9-6','2010-10-6','Halmos Antal, tel.: 70/311-0172, levelezési cím: 1124 Budapest, Tamás köz 3/C.;','antal.halmos@gmail.com','','','40 pld. a szerzőnek

Lezárva 2012.09.14. A leltár szerinti példányok nem léteznek, a hiba nem derült ki. Korábban a szerzőnek adott 10 pld. mint eladás volt leltárazva, ezért a (már nem korrigálható) túlfizetés a jogdíjban.',NULL,1457615628,0);
INSERT INTO books VALUES('',0,'','Gary_Elijah--Visszajatszas_Az_alom--FD.jpg',102,'',1,0,0,4,'',1,60,40,'','','',NULL,NULL,'',500,0,NULL,19,11,2010,361,'Gary Elijah','Visszajátszás - Az álom','978-615-5014-60-4',2,'','3','130x200 mm',80,'0',1390,1,'## K:K,B:V,T:G','Gary','http://www.konyvesbolt.online/spd/978-615-5014-60-4/Gary-Elijah-Visszajatszas---Az-alom-Ad-Librum-2010','','','','','','','',3,2,3,7,4,5,3,'2010-9-9','2010-11-19','Kovács Gergő, 30/501-1323, 4564 Nyírmada Honvéd út 11/A.','.kovacsgergo@outlook.com','Elvarratlan szálak, nyitott kérdések, hátborzongató események. A könyv felkészít egy rejtélyes és titokzatos jövő eljövetelének a lehetőségére.','Elvarratlan szálak, nyitott kérdések, hátborzongató események. A kötet bevezet egy különös világba, felkészít egy rejtélyes és titokzatos jövő eljövetelének a lehetőségére. Egy fiatal srácról szól, aki nem mindennapi kalandokat él át, mégis amiken keresztül megy, az velünk is bárhol, bármikor megtörténhetnek. A mai katasztrófáktól, terroristacselekményektől sújtott korban eme könyv különleges képet ad.','gary-wk@hotmail.com; új címadatai vannak 2015.júliús',NULL,1472717878,0);
INSERT INTO books VALUES('',0,'','',216,'',0,0,0,8,'',1,'',8,20,'',100,NULL,NULL,500,500,5,NULL,3,11,2010,362,'Füst Antal','Koronás hegyek – A Zagyva-völgyi várak regénye','978-615-5014-61-1',2,'','3','130x200 mm',192,'0',2490,2,'LEZÁRT->§147, K:K,B:V,T:G','Fust-Antal','','','','','','','','',5,3,3,7,4,5,5,'2010-9-10','2010-11-3','Dr. Füst Antal, 30/353-2766, 1142 Budapest, Nezsider park 2.','antalfust@gmail.com','Történelmi rege a török idők várairól.','A Zagyva-völgyi várak megmaradt kövei ma is valami különleges erőt sugároznak. Ostromágyúk által szaggatott falaikkal, felhőkbe törő csonka lakótornyaikkal a magyarság nagy próbatételeit idézik, példát mutatnak az utókornak, vitézségből és helytállásból. A késői utódok borzongva mesélik a védők hőstetteit, menekülő alagutakról, nagy szerelmekről és még nagyobb tragédiákról suttognak. A kövek pedig továbbra is féltékenyen őrzik a titkokat.

A salgótarjáni születésű szerző a regényben olyan stílusban fűzi egybe a történelmet és a várak legendáit, mint amikor a nagyapó mesél az unokáinak.','Bar-mi',NULL,1460713857,0);
