INSERT INTO books VALUES('',0,'','Nemeth_Gyorgy-FD.jpg',124,0,1,0,12,4,'',1,'',40,60,'','',5,275,'','',0,'',30,11,2008,372,'Németh György Gábor','Ophelia virágai','978-963-9888-51-7',2,'','1','A5',96,'0',1990,1,'#LB6,LGI#  §95 folytatása','Nemeth-Gyorgy','http://www.konyvesbolt.online/spd/978-963-9888-51-7/Nemeth-Gyorgy-Gabor-Ophelia-viragai-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77329&type=22&_v=Nemeth_Gyorgy_Gabor_Ophelia_viragai','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/ophelia_viragai','http://www.konyvesbolt.online/spd/978-963-9888-51-7/Nemeth-Gyorgy-Gabor-Ophelia-viragai-Ad-Librum-2008','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-30','Dr. Németh György Gábor, 06-30-5023-222, ideiglenes: 1072 Budapest, Dob u. 46/a., állandó: 1121 Budapest, Árnyas út 14.','nemethgyo@freemail.hu','Mélyre hatoló pszichológiai regény.','„Az álmod éjjel játszódik, s te egyedül vagy a gyerekkori otthonodban. Az ágyban fekve arra riadsz fel, hogy valaki odakint járkál a kertben. Leszaladsz a földszintre, és kinézel az ablakon. Eleinte semmit nem látsz, csak a vaksötétet, majd hirtelen egy arc jelenik meg az üveg túloldalán. Egy szőrös férfiarc. A vonásai durvák, a képe sebhelyes, a tekintetéből kegyetlenség árad. Megpróbálja kinyitni az ablakot, de nem jár sikerrel, így hát továbbsiet, hogy keressen egy titkos helyet, ahol bejuthat. Megpróbálod megelőzni. Minden ajtót és ablakot be kell zárnod, mielőtt odaérne. Versenyt futtok egymással. 
De a konyhaajtó mindig utoljára marad, s mire odajutnál, ő már a házban van.” ','Bizományosi átvétel ingyenes kiadásból.',1224574565,1451299975,0);
INSERT INTO books VALUES('',0,'','Molnar_Hajnalka--Durcas_a_szamitogeped--FD.jpg',609,'',1,0,0,33,'',1,'',40,48,'','',NULL,NULL,'',1000,0,NULL,29,10,2010,373,'Molnár Hajnalka','Durcás a számítógéped? Informatikakönyv nőknek','978-963-08-0086-0',1,'','3','165x235',280,'0',3750,1,'#LC3,LGVI, LG régi salgók#   RB3 T:szerző,B:B, keménytábla','durcas','http://www.konyvesbolt.online/spd/978-963-08-0086-0/Molnar-Hajnalka-Durcas-a-szamitogeped-Informatikak','','','','','','','',3,3,1,9,4,5,3,'2010-9-23','2010-10-29','Molnár Hajnalka, 20/921-0593, 1037 Budapest, Jablonka út 140.','hajnim.molnar@gmail.com','Csajos könyv a számítógépek világáról.','Milyen a számítógépek lelkivilága? Hány kilobájt egy szép férfi szempár? Vajon ördöngös számítógépet szerelni? Milyen szuperek a szuperszámítógépek? Hogyan tanítanál meg táncolni egy robotot? Miről beszélgetnek a neten egymással a gépek? A te számítógéped hogyan gondolkodik? Miért durcás, amikor lefagy? Milyen egy számítógépes betörő? Miként préselődnek át egy vékonyka vezetéken a nyaralásról készített fotók? Eljönnél velem a processzor belsejébe? Mondd, volna kedved elolvasni ezt a könyvet?
Ez egy nőknek szóló informatikakönyv. Ajánlott olvasmány az informatikaórák és a számítógépes tanfolyamok hallgatóinak. Reménysugár az érettségire, vizsgára készülőknek. Kedves ajándék a barátnődnek. Remek időtöltés mosogatás helyett.','Email 2017-03-17-ig: hajnim@caesar.elte.hu

A webboltos jogdíj szerződés szerint 60%, de 20%-kal olcsóbban kínáljuk, így lett a teljes ár 48%-a.',NULL,1489742370,0);
INSERT INTO books VALUES('',0,'','Eitler_Tamas--Hatekony_szovegertes--FD.jpg','','',1,1,0,35,'',1,2170,10,'','','',NULL,NULL,'',50,0,NULL,22,9,2011,374,'Dr. Eitler Tamás','Hatékony szövegértés (Készségfejlesztő feladatgyűjtemény)','978-615-5014-63-5',2,'','4','180x250 mm',214,'0',2990,5,'T&B:V','Eitler-Tamas','http://www.konyvesbolt.online/spd/978-615-5014-63-5/Dr--Eitler-Tamas-Hatekony-szovegertes-Keszsegfejle','','','','','','','',3,3,1,7,4,5,4,'2010-9-23','2011-9-22','Dr. Eitler Tamás, 215-2789, 30/414-9579, 1096 Budapest, Haller u. 44.','eitler.tamas@btk.elte.hu','E hiánypótló könyv hatékonyan és élvezetesen fejleszti a szövegértési készséget.','E hiánypótló könyv hatékonyan és élvezetesen fejleszti a szövegértési készséget:

* érdekes, autentikus szövegeket tartalmaz;
* a feladatok motiválóak, változatosak;
* a megoldókulccsal gyorsan ellenőrizhetőek a válaszok;
* tanulási és értelmezési technikákat gyakoroltat, nem szájba rágósan;
* rávezetve, élvezetesen tanítja meg az értelmezési technikákat;
* segíti az autonóm tanulási stílus kialakítását;
* fejleszti a kooperatív, kommunikációs és projektszervezési készségeket.

A könyv elsősorban az érettségi szövegértési feladataira készít fel. A csoportos és egyéni felkészülésben egyaránt kiváló segítség. Ezen kívül az egyetemi hallgatók és a magyarul tanuló középhaladó és haladó szinten lévő külföldiek is haszonnal forgathatják.

A könvv szerzője:
Dr. Eitler Tamás az ELTE Angol Alkalmazott Nyelvészeti Tanszékének adjunktusa. Főbb oktatási és kutatási területei: szociolingvisztika, multimodális kommunikáció, kritikai diskurzuselemzés, angol pr és reklám szaknyelv.','A szerzőnek 22 példány kell kiadáskor.',NULL,1460112598,0);
INSERT INTO books VALUES('',0,'<p>Megkérdeztük a szerzőt, mennyiben tekintendő a regény életrajzi ihletésűnek?</p>
 
<p>"Ez a könyv a fantáziaterméke, nem életrajz, nem egyfajta emlékirat. Felhasználtam viszont tapasztalataimat és élményeimet, ahogy  másokét is, – amiért elnézést kérek tőlük – és szétosztottam mindezt a regény erre alkalmas, vagy alkalmas helyzetben lévő szereplői között. Így azután, noha valóban olvashatunk valahol másutt megesett történeteket, valahonnan ismerős figurákról, de azonosítható személyt nem találunk."</p>','Gati_Vilmos--Elfelejtett_legio--FD.jpg','','',1,0,0,8,'',0,'',40,60,'','',5,370,'',500,0,'',29,5,2009,375,'Gáti Vilmos','Az elfelejtett légió','978-963-9888-62-3',2,'','2','A5',278,'0',2990,1,'#LB2#  T:G 110. duplikátuma','Gati-Vilmos','http://www.konyvesbolt.online/spd/978-963-9888-62-3/Gati-Vilmos-Az-elfelejtett-legio-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81295&type=22&_v=Gati_Vilmos_Az_elfelejtett_legio','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/az_elfelejtett_legio','','','','',3,0,0,7,4,0,0,'Array-0-0','2009-5-29','','agenda.alapitvany@t-online.hu','Történet az 50-es évek Néphadseregéről.','Sem sarat dobálni, sem fényezni nem állt szándékomban, amikor elhatároztam, hogy leporolom annak a bizonyos régi hadseregnek az emlékét, amelyről ma még sokan őriznek személyes emlékeket, gyakran fájdalmasakat. Még többen vannak, akik csak mások tapasztalatai s véleménye alapján ítélkeznek, többnyire sommásan. Ez a sereg nem volt különleges. Jellemzői, tulajdonságai nem különböztethetők meg a kor társadalmának tulajdonságaitól és jellemvonásaitól. Ezt a sereget, még nem olyan régen, kevés kivétellel az egész magyar férfitársadalom megjárta.

A tisztek, tiszthelyettesek és a mindenkori besorozott és behívott nemzedékek a kettészakadt világban álltak fegyverben. Abban a világban, amelyben a vezérkarok térképeit befedték az atombombák és rakéták ellipszis alakú hatókörzetei,  azok a halálos ellipszisek, amelyek jelzik a területet, ahol a bomba vagy rakéta rombol és öl. A mi kis országunk térképén nem sok ilyen ábra fért el. Ezek a magyar fiatalok olyan seregben szolgáltak, amelyről szakszerűen kiszámították, hogy egy összecsapás első üteme során, vagyis napok alatt – ahogy a vezérkarban mondják – élőerőben hetven százalékos veszteséget fog szenvedni tisztekből, tiszthelyettesekből, sorkatonákból.

A kép, amit az elmúltakról alkotunk, mindig nagyon egyéni és minél bonyolultabb eseményekre emlékeztet, annál nehezebben ragadja meg a képzelet. A megélt történelmet is képesek vagyunk félreérteni. Ezért ne kárhoztassuk az utóbb születetteket, ha a járható utat keresve, elfogadják a történtekről a leegyszerűsített képet, különösen akkor, ha az a kor számukra már valóban távoli. A hősi korszakok nemzedéke, kivéve egy pár bitang árulót, csupa hősökből állt. Míg a szomorú időkre emlékezve csak gazembereket és szenvedő áldozatokat vélnek felismerni. 

Pedig a később kárhoztatott, sötétnek tartott korszakokban is az élvezték emberek a napsütést, átéltek örömöket, ismerték a barátságot, a szerelmet, az orgazmust. Mindez vonatkozik e könyv témájára és szereplőire egyaránt.  Ne taszítsuk el, és főként ne vessük meg őket, amiért rossz korban születtek.
','Fogyásit akkortól kell küldeni, amikor az ingyenesből elment az összes példány.
m.peredi@t-online/Peredi Mária örökös',1225885804,1459940690,0);
INSERT INTO books VALUES('',0,'','Szabo_Maria_Gizella-FD.jpg',251,'',1,0,0,12,'',1,'',40,75,'','','','','','',0,'',0,10,2008,376,'Szabó Mária Gizella','Szerelmi zsákutcák avagy száz békát megcsókoltam','978-963-06-5800-3',1,'','1','A5',204,'0',795,1,'#LB4#','Szabo-Maria-Gizella','http://www.konyvesbolt.online/spd/978-963-06-5800-3/Szabo-Maria-Gizella-Szerelmi-zsakutcak-avagy-szaz','http://bookline.hu/product/home!execute.action?id=75588&type=22&_v=Szabo_Maria_Gizella_Szerelmi_zsakutcak_avagy_szaz_bekat_megcsokoltam','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-10-0','Szentiné Szabó Mária Gizella, 70 2013392, 6900 Makó Baross u 8.','mariagizella@citromail.hu','Kiről szól ez a könyv? Rólad, rólam és mindazokról, akik kitartóan bíztak abban, hogy megtalálják a „királyfit”.','Kiről szól ez a könyv? Rólad, rólam és mindazokról, akik kitartóan bíztak abban, hogy megtalálják a „királyfit”. Tudjuk, az út rögös, de ezer tapasztalatot, szépséget és titkot rejt számunkra, mialatt megismerjük a párkapcsolatok rejtelmeit, és főleg saját magunkat. Márta, a főszereplő egy elvált, kétgyermekes, még mindig szép ex-vállalkozó, aki az eltűnő szépség árnyékában visszatekint szerelmi életére, de a történések most is változatlanul zajlanak körülötte. Keresi a választ, hogy a dolgok miért történtek így. Bejárhatjuk az utat Mártával, nevetve, sírva, remélve és csalódva, némi humorral és iróniával szemlélve a világot, miközben a saját kérdésünkre is megtalálhatjuk a választ.','2010. márciusától az ár 795 Ft',1218613294,1467197701,0);
