INSERT INTO books VALUES('',0,'','Galyas_Eva--Rolam_vagy_rolad--FD.jpg','','',1,0,0,2,'',1,'',40,60,'','',NULL,NULL,'',100,0,NULL,8,12,2010,378,'Galyas Éva','Rólam vagy rólad','978-615-5014-64-2',2,'','3','A5',80,'0',1500,1,'#LD# Galyas Klára Éva','Galyas-Eva','http://www.konyvesbolt.online/spd/978-615-5014-64-2/Galyas-Eva-Rolam-vagy-rolad-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,4,'2010-9-30','2010-12-8','Galyas Klára Éva, 1089 Budapest Práter u. 39. fszt. 2. - de valójában Floridában él.','eva.galyas@live.ca','','Igézve...

