INSERT INTO books VALUES('',0,'','Lady_Nairi--Verstar--FD.jpg',131,'',1,0,0,2,'',1,'',40,60,'','',NULL,NULL,'',100,0,NULL,24,11,2010,387,'Lady Nairi','Verstár','978-963-08-0396-0',1,'','3','140x200 mm',98,'0',1490,1,'#LA3,LGI#  Homonnai Rita','Nairi','http://www.konyvesbolt.online/spd/978-963-08-0396-0/Lady-Nairi-Verstar-2010','','','','','','','',3,3,1,7,4,5,4,'2010-10-25','2010-11-24','Homonnai Rita, 70/62-70-246, 4400 Nyíregyháza, Ferenc krt. 17. 4/14.','homonnai.rita@gmail.com','','„Nem vagyok a szavak embere, de tényleg szépek a versek, tükrözik az érzéseid!”
Béres Edit

„Nagyon nehéz helyzetben vagyok most, hiszen pár mondatban igen nehéz jól megfogalmazni, hogy miért is szeretem Lady Nairi verseit. Bátran mondhatom, hogy majdnem minden művét olvastam már, mielőtt e könyvbe kerültek volna, és mindig magával tudott ragadni a hangulat, a téma, a szimbólumok és a sorok közti üzenetek összhangja. Soha nem vettem észre rajta, hogy gondot okozna neki vers formájába önteni a mondanivalóját. Érzékeny lélek és gazdag fantázia jellemzi, ez visszaköszön a versekben is, a kedves olvasó maga is tapasztalni fogja. Bátran ajánlom mindenkinek ezt a verseskötetet, mert biztos vagyok benne, másnak is kellemes perceket szereznek a versek, csakúgy, mint nekem.”
Gabányi Ferenc

„Van, aki a vérét ontja fájdalmában, van, aki könnycseppeket hullajt, van, aki némán üvölt magában, Lady Nairi viszont, mint egy kiapadhatatlan forrás, ontja magából a verseket és a csodálatosan szép, őszinte szavakat! Őt termékennyé és alkotóvá teszi a fájdalom, és különleges képességével akkor is ad, amikor mások elvennének. Köszönjük, hogy vagy; csodálatos érzelmi mélységed minden embert lelke mélyéig megérint!”
M. Vincze Eszter

„E kötet gyönyörű szép, igényesen kidolgozott verseket tartalmaz, amelyből bárki erőt meríthet, újat tanulhat. Csak így tovább! Kívánok minden jót Neked, tiszta szívből, hiszen ilyen egy barát…”
Mester Ágnes Erika

„Lady Nairit, vagy Homonnai Ritát, a versein keresztül ismertem meg, egy ideig ugyanazon az íróoldalon voltunk mindketten tagok, ahol az ő versei nagyon is „megfogtak”.
Egy olyan fiatal nőt ismertem meg benne, aki annak ellenére, hogy a felnőttek életének a kezdetén van, a mindennapi életben mindkét lábával a valóságban él, megérti a mai élet kegyetlen törvényeit, a verseiben azonban egy hihetetlen könnyedséggel és magával ragadó tartalommal elvezeti az olvasót egy szebb, képzelt világba, és amikor e versét végig olvastad, úgy érzed magadat, mintha te is e csodálatos világnak egyik boldog tagja volnál.
A természet csodálatos képével elébünk varázsol egy mindenkitől kívánt és mindenkinek hiányzó valóságot.
A teljes örömömhöz, evvel a tehetséges fiatal költővel kapcsolatban még eddig az, ami legjobban hiányzik, hogy személyesen sohasem találkoztunk.”
Mucsi Antal','lady.nairi@gmail.com',NULL,1472717644,0);
INSERT INTO books VALUES('',0,'','Maria_M_Bosnyak--Baljos_sugallat--FD.jpg','',0,1,1,0,4,'',1,1170,10,'','','','','','',30,0,'',24,11,2010,388,'Mária M. Bosnyák','Baljós sugallat','978-963-87741-3-2',2,'','3','120x200 mm',80,'0',1990,5,'#LB3 B:B T:G','Maria-Bosnyak','http://www.konyvesbolt.online/spd/978-963-87741-3-2B/Maria-M--Bosnyak-Baljos-sugallat-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-87741-3-2B/Maria-M--Bosnyak-Baljos-sugallat-Ad-Librum-2010','','','',3,3,1,7,4,5,5,'2010-10-20','2010-11-24','Bosnyák Mária, 20/557-3769, 2800 Tatabánya ,Tatai út 9/1.','bosnyak.maria@freemail.hu','','','12 pld. kell a szerzőnek','',1451300085,0);
INSERT INTO books VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,6,31,'',1,'',20,40,'','','','','','',0,'',28,5,2010,389,'Kollát Gyula','Körök az ördögszántások földjén (Rendhagyó bükki túrakalauz)','978-615-5014-75-8',2,'','3','A5',240,'0',1495,6,'#A5','Kollat-Gyula','','','','','','','','',2,3,1,9,4,0,0,'2010-0-0','2010-5-28','Kollát Gyula, 70/585-5606, 6723 Szeged, Szamos utca 1/A.','kollat.gyula@gmail.com','','Egy-egy túraútvonal végigjárása minden esetben több, mint jobbra-balra kanyarodásokkal tarkított kilométer mennyiség megtétele. Útközben, és persze előtte és utána is történések részesei vagyunk. Találkozunk emberekkel, fákkal, virágokkal, sziklákkal és vízeséssel, na és persze mindenféle helyzetekkel. Ezek lehetnek mulatságosak, vagy szomorúak, akad közöttük meghökkentő és tanulságos is, de valamennyiben közös az, hogy élményt jelentenek számunkra, amik majd hazatérve egy idő után emlékeinkké szelídülnek. Összegyűjtöttem egy csokorra valót a túráimon velem megesett, szép magyar szóval, sztorikból, és ezt kívánom most nagy szeretettel átnyújtani.
Autós ember vagyok, ami annyit tesz, hogy ezzel a járművel közelítem meg túráim kiindulási pontjait. Hogy az autónak ne kelljen az erdőszélen éjszakáznia, nekem pedig valamilyen tömegközlekedési eszközzel a szállásra, majd másnap az autóhoz bumlizni, ezért körtúrákat terveztem, amelyek visszavezetnek az autóhoz. Próbáltam kimazsolázni a hegység legszebb természeti látnivalóit (csúcsok, barlangok, vízesések), történelmi emlékhelyeit (várak, kolostorromok), és azokat felfűzve kialakítani az útvonalakat.
Saját csetlés-botlásaim megismertetésével bátorítani kívánok mindenkit arra, hogy induljanak útnak, mert túrázni jó, és nem csak profiknak való mulatság. Én rabja lettem ennek az időtöltésnek, és legszívesebben főállású túrázó lennék, ha tehetném. Remélem, hogy kalandjaim megírásával sokakat sikerül „megmérgeznem”, és a hátizsák meg a túrabot örök útitársaikká lesznek.','','',1294666819,0);
INSERT INTO books VALUES('',0,'','Frideczky_Katalin--Jolan_gyereket_var--FD.jpg','',0,1,0,0,3,'',1,'',40,40,'','',NULL,NULL,'',120,0,NULL,24,11,2010,390,'Frideczky Katalin','Jolán gyereket vár','978-615-5014-73-4 ',2,'','3','125x180 mm',110,'0',1500,1,'#LB5# T:G B:V','Frideczky-Katalin','http://www.konyvesbolt.online/spd/978-615-5014-73-4_/Frideczky-Katalin-Jolan-gyereket-var-Ad-Librum-201','','','','http://www.konyvesbolt.online/spd/978-615-5014-73-4_/Frideczky-Katalin-Jolan-gyereket-var-Ad-Librum-201','','','',3,3,1,7,4,5,3,'2010-10-1','2010-11-24','Frideczky Katalin, 20/500-2131, 1105 Budapest, Gergely u. 1.','frid@freestart.hu','','„A sokféle téma és hang e mennyisége kirajzol egy írói karaktert, melyben a mai élet sokféle sutasága és a társadalmi meghatározottságok anomáliái groteszken és jellegzetesen női szempontból kerülnek ábrázolásra.” (Suhai Pál)

„Jó az írásaidban, hogy remekül őrzöd a feszültséget, sohasem lehet kitalálni a továbbmenetelt, megérkezést, s a fordulatok közt nem telik el hosszabb idő, mint amennyi még feszesen tartja a gondolat ritmusát.” (Hollós Máté)

„Ami számomra jó és izgalmas az írásaiban, az éppen a szociografikus megközelítésmód. Az egyén belső/külső konfliktushelyzetén keresztül társadalmi jelenségekre világít rá, s ez fontos…” (Handó Péter)

Frideczky Katalin 1950-ben született Budapesten. A  Liszt Ferenc Zeneakadémia zongora-tanszakán diplomázott 1974-ben, majd két évig a leningrádi Rimszkij-Korszakov Konzervatórium gyakornoka volt. 1984 óta a Bartók Béla Konzervatórium zongoratanára, korrepetítora. 1997 óta rendszeresen koncertezik állandó kamarapartnerével, Büki Mátyás hegedűművésszel.
Büki Mátyás és Frideczky Katalin hegedű-zongora duója 1997 óta aktív szereplője a hangversenyéletnek. Repertoárjuk a zeneirodalom valamennyi korszakát felöleli Bachtól napjainkig.
A tanítás és koncertezés mellett szépirodalmi tevékenységet is folytat. 2009-ben lépett először a nyilvánosság elé. Azóta több novellája megjelent különböző folyóiratokban (SZÍN, IPM-magazin, Palócföld, Ezredvég, Budapest Bristol online), valamint a Littera Nova Kiadó "Menedékjog 2010" c. antológiájában. Jelen kötet több év elbeszéléseiből válogat.','',NULL,1451299433,0);
INSERT INTO books VALUES('',0,'','Halmos_Antal--Het_ev_Indiaban--FD.jpg','',0,1,1,0,15,'',1,3584,10,'','','',NULL,NULL,'',60,0,NULL,17,12,2010,391,'Halmos Antal','7 év a csodálatos Indiában és két nepáli túra','978-615-5014-74-1',2,'','3','140x200 mm','428 ff + 20 sz.','0',3990,5,'#B7','Tuckos','','','','','','','','',5,3,1,7,4,5,5,'2010-10-22','2010-12-17','Halmos Antal','antal.halmos@gmail.com','7 év élményei az indiai szubkontinensen.','7 év élményei az indiai szubkontinensen, betekintés a gyökeresen más világlátásba, a barátságos indiaiak életébe, India vallásainak, kultúrájának alapos leírása. A varázslatosan szép indiai építészeti emlékek ismertetése kiváló magyar és professzionális indiai fotósok képeit tartalmazó CD-vel kísérve.','50 példány kell a szerzőnek.

Hirdetés a Könyvhét karácsonyi számában.

Lezárva 2012.09.14.',NULL,1347700007,0);
INSERT INTO books VALUES('',0,'','Eiben_Tamas--Jelszo_hatekonysag--FD.jpg',410,'',1,0,0,34,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,29,11,2010,392,'Eiben Tamás','A jelszó: hatékonyság – Menedzsment útmutató az eredményes üzlethez','978-615-5014-72-7',2,'','3','170x240 mm',236,'0',3990,1,'#LE4,LG27,28# T:G B:V','Eiben-Tamas','http://www.konyvesbolt.online/spd/978-615-5014-72-7/Eiben-Tamas-A-jelszo-hatekonysag-Menedzsment-utmut','','','','','','','',3,3,3,7,4,5,4,'2010-10-25','2010-11-29','Aachen International Kft., Eiben Tamás Endre, 1086 Budapest, Szerdahelyi u. 4-8. 5/5.','tamas.eiben@yahoo.de','Végre egy valóban hasznos, a helyi viszonyokról szóló menedzsment-szakkönyv, melynek gyakorlati tanácsaival elébe mehet főnöke elvárásainak és egy csapásra eredményes vezető lehet.','- Hogyan érjük el, hogy a munkatársak felelősséget vállaljanak, és mindent megtegyenek az üzleti sikerért?
- Hogyan csökkenthetjük jelentősen a helyiségekkel kapcsolatos költségeinket?
- Hogy készítsünk költségvetést, ha nem vagyunk pénzügyi szakemberek?
- Hogyan javítsuk a marketing eredményre gyakorolt hatását?

Ez a könyv gyakorlati vezetési kézikönyv. Nem gyárt elméleteket, ám megoldókulcsot ad a vállalat nevű komplexumhoz, a működés minden lényeges területén. Bemutatja, hogyan építhetjük fel, és irányíthatjuk részlegünket, telephelyünket vagy cégünket a hatékonyságot mint alapelvet szem előtt tartva.

Aki elolvassa a könyvet, átfogó eszköztárat szerez a mindennapos menedzsment-problémák megoldásához.

A szerző nemzetközi környezetben tett szert évtizedes menedzsment-tapasztalatára, specialistájává vált a létrehozó és átalakítási projekteknek. MBA diplomáját általános menedzsmentből szerezte Ausztriában. Jelenleg üzleti hatékonysági tanácsadással foglalkozik.','',NULL,1467724044,0);
INSERT INTO books VALUES('',0,'','Eric_Asvak-FD.jpg',332,0,1,0,0,13,'',1,'',5,30,'','',5,543,'','',0,'',9,2,2009,393,'Eric Asvak','Vér/vonal - Harc a létezésért','978-963-9888-72-2',2,'','2','140x200 mm',269,'0',2700,1,'#LD,LGII,LGV# BIZOMÁNYOS Sepsikné Erika','Eric-Asvak','http://www.konyvesbolt.online/spd/978-963-9888-72-2/Eric-Asvak-Ver-vonal---Harc-a-letezesert-Ad-Librum','','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/vervonal_harc_a_letezesert','http://www.konyvesbolt.online/spd/978-963-9888-72-2/Eric-Asvak-Ver-vonal---Harc-a-letezesert-Ad-Librum','','','',3,3,1,9,4,5,0,'2008-12-6','2009-2-9','Sepsik Istvánné, 06–48/411–515; 06–30/502–4994, 3700 Kazincbarcika, Rózsa út 10/b.','furafiu@citromail.hu','Évszázadokkal ezelőtt egy puccskísérlet után a vagyonától megfosztott Collins-dinasztia megmaradt harcosai a Birodalom határán kívül lévő, független bolygóra menekültek...','Évszázadokkal ezelőtt egy puccskísérlet után a vagyonától megfosztott Collins-dinasztia megmaradt harcosai a Birodalom határán kívül lévő, független bolygóra menekültek. Utódaik alapították meg a Vadászok Rendjét, és az idő múlásával békésebb módszerrel hozzájutottak a császári trónhoz is. 
A legbefolyásosabb Nagy Ház azonban történetünk kezdetén már csak három emberből áll...

Ronald Parker, a vadászok Vezére vágyai nyomán és Rendje érdekében kizsarol a Birodalom uralkodónőjétől egy trónörököst. Egy peremvidéki származású vadászát társítja a nagy múltú dinasztia leszármazottjához, s ezzel akaratlanul is az események olyan láncolatát indítja el, amelybe beleremeg a Vadászok Rendje.

Ideiglenes szövetségek, érdekbarátságok, titkok, csapdák, szerelmek kusza hálója – kegyetlen játszma két kíméletlen és kiszámíthatatlan ember között.
Harc egymással - egymásért.
Az életük a tét.
Az ellenfél a jutalom.','',1228815755,1451302299,0);
INSERT INTO books VALUES('',0,'','Lengyel-Kuba--Holtak_vilaga--FD.jpg',296,0,1,0,0,11,'',0,'',15,30,'',50,NULL,NULL,500,500,2,NULL,31,1,2011,394,'Lengyel Dávid és Kuba Richárd','Holtak világa - A jóslat','978-615-5014-99-4',2,'','4','130x200 mm',252,'0',2290,2,'#LGV# B:B,T:G,K:K','Holtak-vilaga','','','','','','','','',5,3,4,7,4,5,5,'2010-11-20','2011-1-31','Lengyel Dávid, 30/586-3530, 6200 Kiskőrös, Madách Imre u. 28., davis-lengyi@freemail.hu; Kuba Richárd, 20/241-4760','holtakvilaga@gmail.com','A zombik támadnak Kiskőrösön.','Egy csapat katona érkezik a Kiskőrös mellett lévő egykori katonai laktanyához. A létesítmény területéről segélykérést észleltek. Azonban, mire odaérnek, nem találnak mást, csupán egy maroknyi túlélőt, hatalmas pusztítást, és élőholtak tömegét.

Egy katona, Andrássy Bálint tizedes az egyik szobában rábukkan egy kis könyvre, Kozma András naplójára. Miközben olvassa, egyre inkább bepillantást nyer ennek a húszas évei elején járó fiatalnak a küzdelmekkel teli életébe. Ez idő alatt arra is rájön, hogy egy nostradamusi jóslatnak köszönhetően ez a fiú már régóta számított rá, hogy egy napon a holtak életre kelnek...','373.000 leütés
Nem kérnek digitális kiadást.
Szerzői ár: 916 Ft.',NULL,1423136336,0);
INSERT INTO books VALUES('',0,'','Csodacsalad--Professzionalis_kigyermekellatas--FD.jpg','',0,1,0,0,43,'',0,'','','','','',NULL,NULL,'',300,0,NULL,20,1,2011,395,'Csodacsalád Egyesület','Professzionális kisgyermekellátás a gyakorlatban - Szakmai kézikönyv','978-963-08-0395-3',3,'Csodacsalád Egyesület','4','A5',240,'0',9000,4,'#LB4# T&B:A','Csodacsalad','http://www.konyvesbolt.online/spd/978-963-08-0395-3/Csodacsalad-Egyesulet-Professzionalis-kisgyermekel','','','','http://www.konyvesbolt.online/spd/978-963-08-0395-3/Csodacsalad-Egyesulet-Professzionalis-kisgyermekel','','','',3,3,1,7,4,5,5,'2010-11-30','2011-1-20','Csodacsalád Egyesület, Dr. Nagy Ágnes, 6421 Kisszállás, Marx u. 9. Képviseli: Dr. Nagy Ágnes, 20/529-1143','agnes.nagy.decse@gmail.com','Egységes óvoda-bölcsődében dolgozó pedagógusoknak szóló tanfolyam anyaga.','Egységes óvoda-bölcsődében dolgozó pedagógusoknak szóló tanfolyam anyaga CD melléklettel!

KIKNEK SZÓL:
