INSERT INTO books VALUES('',1,'','Hajdu_Laszlo--Non-tectonic_systems--FD.jpg','',0,1,1,0,43,'',1,1570,10,'','','',NULL,NULL,'',70,0,NULL,7,2,2011,436,'László Hajdú','Non-tectonic Systems. A universal approach to the unavoidable future building industrialization','978-615-5110-02-3',2,'','4','140x200 mm',100,'0',2500,5,'Sanicont Kft. #LA5','Hajdu-Laszlo','http://www.konyvesbolt.online/spd/978-615-5110-02-3/Laszlo-Hajdu-Non-tectonic-Systems--A-universal-app','','','','http://www.konyvesbolt.online/spd/978-615-5110-02-3/Laszlo-Hajdu-Non-tectonic-Systems--A-universal-app','','','',3,3,1,9,4,5,5,'2011-1-0','2011-2-7','Sanicont Kft. / Dr. Hajdú László, 20/9352-199, 1125 Budapest, Sárospatak út 36/b.','hajdu.laszlodr@t-online.hu','','','',NULL,1451381121,0);
INSERT INTO books VALUES('',0,'','Vasas_Judit--Mah-ree_Nok--FD.jpg',340,0,1,0,22,11,'',1,'',5,20,'','','','','','',0,'',7,12,2009,437,'Vasas Judit','Mah-ree Nok - Misztikus kalandregény','978-963-9934-33-7',2,'','2','A5',280,'0',2990,1,'#LB2,LGIII,LG30#  ->§206','Vasas-Judit','http://www.konyvesbolt.online/spd/978-963-9934-33-7/Vasas-Judit-Mah-ree-Nok---Misztikus-kalandregeny-A','http://bookline.hu/product/home!execute.action?id=85509&type=22&_v=Vasas_Judit_Mah_ree_Nok','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/mah_ree_nok','http://www.konyvesbolt.online/spd/978-963-9934-33-7/Vasas-Judit-Mah-ree-Nok---Misztikus-kalandregeny-A','','Vasas-Judit','',3,3,0,7,4,5,5,'Array-0-0','2009-12-7','6721 Szeged, Füredi u. 9/B. T.: 20/442-7354','szamira15@gmail.com','Történet egy nagyon régi, mágikus könyvről, ami valójában nem is létezik. Vagy mégis?','A Mah-ree Nok csak egy legenda: történet egy nagyon régi, mágikus könyvről, ami valójában nem is létezik. Vagy mégis? Erre a kérdésre keresi a választ az ifjú Duncan Scott, és meg is találja – legalábbis azt hiszi, mígnem kénytelen lesz rájönni, hogy olyan erőkkel játszadozik, amikre aligha van befolyása. Csakhogy addigra már – hála neki – a barátai is nyakig ülnek a pácban… Vajon képesek lesznek együtt helyrehozni a dolgokat, vagy viselniük kell Duncan kíváncsiságának következményeit egészen életük végéig (ami talán nincs is olyan messze…)?','344 g: 90 pld. = 31 kg = 2 csomag

11-08-07: #RA1b 13 pld. (összesen 18, stimmel)','',1451376912,0);
INSERT INTO books VALUES('',0,'','Pasztor_Peter--Koca_es_az_ismeretlen--FD.jpg',112,'',1,0,0,16,'',1,'',40,40,'','','','','',1000,0,'',5,11,2009,438,'Pásztor Péter','Kóca és az ismeretlen','978-963-9934-44-3',2,'','2','120x200 mm',100,'0',1490,1,'#LB4,LGIII#  Judák Tamás, ingyenesből: ->§219','Pasztor-Peter','http://www.konyvesbolt.online/spd/978-963-9934-44-3/Pasztor-Peter-Koca-es-az-ismeretlen-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=84671&type=22&_v=Pasztor_Peter_Koca_es_az_ismeretlen','','http://www.fo.hu/hu/konyv/szepirodalom/ifjusagi_irodalom/regenyek/koca_es_az_ismeretlen','','','','',3,3,0,7,4,5,0,'2009-9-28','2009-11-5','Judák Tamás, 2347 Bugyi, Alsóvány-puszta 47., T.: 70/568-6796;06-29-348-137','bobitaskoca@gmail.com','Négy fiatal manó kalandjai.','Négy fiatal manó, kik egy fában élnek, kíváncsiságuk miatt mind távolságban, mind saját múltjukban olyan messzire keverednek, mit maguk sem sejtettek. Kócát szárnyai alá veszi a vén könyvtáros, Fátyolka ajándékba kap egy szivárványpillangót, találkoznak a vízisárkányok népével, és mindeközben egy különös idegen után kezdenek kutatni, akitől azt remélik, hogy választ ad megannyi kérdésükre...','','',1458641789,0);
INSERT INTO books VALUES('',0,'','Vago_Zoltan--Kalandok_Kapitany_bacsival--FD.jpg','','',1,0,0,16,'',1,'',10,20,'',30,NULL,NULL,300,300,2,NULL,21,3,2011,439,'Vágó Zoltán','Kalandok Kapitány Bácsival','978-615-5110-03-0',2,'','4','130x200 mm',140,'0',1990,2,'#LB6, LGVI,LGsalgó#  T&B:B','Vago-Zoltan','http://www.konyvesbolt.online/spd/978-615-5110-03-0/Vago-Zoltan-Kalandok-Kapitany-Bacsival-Ad-Librum-2','','','','','','','',3,3,4,7,4,5,5,'2011-1-18','2011-3-21','Vágó Zoltán, 70/317-1575, 2120 Dunakeszi, Jósika u. 29.','zoltan.vago@gmail.com','Látogasd meg a Tündérek falvát, repülj vendégszárnyakon!','Te mit tennél, ha megtámadna egy szőrös óriáspók? Találkoztál már hetvenhetes ikrekkel? Neveltél fel csokievő sárkányt? Most mindezt átélheted! Látogasd meg a Tündérek falvát, repülj vendégszárnyakon! Fedezd fel, hogy a fantáziádnál nincs erősebb varázslat!

Egy kisfiú Meseországba csöppen. Barátságot köt a vitorlás hajón lakó Kapitány családdal, Bóbitával, a tündérlánnyal és eljut a hihetetlen Égigérő Állatkertbe. Szembeszáll a gonosz Pöffeteg Gorommal, aki sárkányokkal és ármánnyal támad ellenük.

Zoli autót épít, rakétát tervez, mellyel a csillagokig röppen. Számíthat a találékonyságára, a bátorságára, és természetesen a barátaira.
Tarts vele Meseországba! Éld át a kalandokat, és Te is örök barátokra lelsz!','',NULL,1467282116,0);
INSERT INTO books VALUES('',0,'','Varga_Geza--Menj_biztosra--FD.jpg',186,'',1,0,26,34,'http://books.google.hu/books?printsec=frontcover&id=4-P_YKwFY7YC#v=onepage&q=&f=false',1,'',40,40,'','',5,160,'','',0,'',30,4,2009,440,'Varga Géza','Menj biztosra! (Olvasókönyv biztosítósoknak és ügyfeleiknek)','978-963-9888-30-2',2,'','2','148x210 mm',128,'0',2490,1,'#LB4, LGrégi salgó az ajtónál# §163 folytatása','Menj-biztosra','http://www.konyvesbolt.online/spd/978-963-9888-30-2/Varga-Geza-Menj-biztosra-Olvasokonyv-biztositosokn','http://bookline.hu/product/home!execute.action?id=80373&type=22&_v=Varga_Geza_Menj_biztosra_Olvasokonyv_biztositosoknak_es_ugyfeleiknek','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/menj_biztosra_olvasokonyv_biztositosoknak_es_ugyfeleiknek','','','Varga-Geza--Menj_biztosra','',3,3,1,7,4,5,1,'2009-4-24','2009-4-30','Dr. Varga Géza, 70/454-7741, 3580 Tiszaújváros, Babits M. u. 2.','menjbiztosra@gmail.com','Hasznos ismeretek és tanácsok ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről.','A könyv szerzője - közgazdász képzettségű biztosítási üzletkötő - átvilágította a biztosítások világát, és bemutatja, hogy hogyan látja azt egyszerre belülről és kívülről is. Hasznos ismereteket és tanácsokat ad ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről. Rávilágít néhány, a biztosítók működésével és a biztosítások értékesítésével kapcsolatos hatékonysági problémára, és megértő empátiával firtatja a potenciális ügyfelek különböző attitűdjeit és annak okait. A szakmailag igényes tartalmat néhány színes, érzelemben gazdag olvasmány egészíti ki.

A tartalomból:

    * az élet mint szerencsejáték;
    * a biztosítások fajtái és jellegzetességei;
    * kapitalizmus és marketizmus;
    * a befektetések időzítése;
      a biztosítások értékesítésének módjai;
    * az öngondoskodás filozófiája.
','Szerződés módosítás a kiadó javára (2015.07.03)','',1467282440,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,15,'',1,'',15,30,'',50,NULL,NULL,500,500,2,NULL,16,3,2011,441,'Kollár László','Londoni ébredés – A város, ahogyan még sosem láttad – I. rész','978-615-5110-00-9',2,'','4','148x210 mm',432,'0',3390,2,'#LG5# (maradék példányok)','Kollar-Laszlo','','','','','','','','',5,3,4,7,4,5,4,'2011-1-21','2011-3-16','30-600-10-57, 3711 Szirmabesenyő, Alkotmány út 3.','l.kollar86@gmail.com','','„Belegondolni se merek, hogy vajon hány ember él abból, amit szeret. Hogy vajon hány ember válhatott azzá, amivé szeretett volna. Hogy milyen életet él a kenyérkeresők minden bizonnyal fájdalmasan túlnyomó többsége…

És sajnos, ha jobban belegondolok, az átlag, dolgozó ember élete leginkább az egyik klasszikus westernfilmhez hasonlít. Hisz miből áll az ilyen ember élete?

Szabadnap, munkanap és fizetésnap… Vagyis… A jó, a rossz és a csúf…”


London… Egyeseknek csupán a brit főváros… De nekünk… sokkal több annál… Remény, esély, lehetőség… Hol élmény, hol gyötrelem… Hol megnyugvás, hol kihívás…

Ez a könyv a saját, igaz történetemet meséli el arról, hogyan hagytam hátra mindent azért, hogy két barátommal együtt, új életet kezdjek Londonban… Kalandunk során felfedeztük a jól ismert nevezetességek mögött megbújó sokszínű, és sok veszélyt rejtő világot…

Elgondolkodtató tanmese a boldogulásról, avagy hazudj a túlélésért, dolgozz a megbecsülésért, és küzdj az álmaidért…

Az akadály, mi utadba kerül, akármilyen nagy… a legnagyobb akadály te magad vagy…','Lezárva 2014. május.',NULL,1423048746,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,4,'',1,'',40,40,'','','','','','',0,'',3,11,2009,442,'Liz Bet','Végre az enyém...','978-963-9934-39-9',2,'','2','A5',80,'0',1690,1,'§211-ből, Kiss-Hegyi Erzsébet','Liz-Bet','','http://bookline.hu/product/home!execute.action?id=84491&type=22&_v=Bet_Liz_Vegre_az_enyem_','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/vegre_az_enyem','','','','',3,3,0,7,4,5,1,'2009-9-0','2009-11-3','Kiss-Hegyi Erzsébet, 30/463-5482, 3300 Eger, Vízimolnár u. 8. 3/9.','lisandra@freemail.hu','','Mary, a csinos ingatlanközvetítő mélységesen csalódott férjében. A válás után egyedül él, nem is akar hallani férfiakról. Barátnője unszolására végül mégis felad egy hirdetést egy társkereső irodánál.

Túl sok reményt nem fűz a dologhoz, és úgy látszik, igaza is lesz… De éppen amikor végleg feladni készül, olyan levél érkezik, melynek írója felkelti érdeklődését. A jóképű, titokzatos Ronald, aki, amilyen hirtelen feltűnik, olyan váratlanul el is tűnik…','Postai feladó okmány van, átvételi semmi. Fedezné a leltárhiányt.','',1455266893,0);
