INSERT INTO books VALUES('',0,'','Pusztai_Marianna--Az_ido_fogsagaban--FD.jpg',162,2,1,0,0,2,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,6,6,2011,459,'Pusztai Marianna','Az idő fogságában','978-615-5110-08-5',2,'','4','140x210 mm',134,'0',1990,1,'#LA3# T:G B:B ','Pusztai-Marianna','http://www.konyvesbolt.online/spd/978-615-5110-08-5/Pusztai-Marianna-Az-ido-fogsagaban-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-08-5/Pusztai-Marianna-Az-ido-fogsagaban-Ad-Librum-2011','','','',3,3,1,7,4,5,5,'2011-4-6','2011-6-6','Jaczina Marianna, Fogarasi út 29/A. III/13., 383-0512, 30/431-9065, férj: 30/445-7525','net923@t-online.hu','Érzékeny és erősen gondolati tartalmú líra.','\\\"Pusztai Marianna lírája érzékeny és erősen gondolati tartalmú. Értéke az intellektus és az értelmező ábrázolás szerves egysége...\\\"
(Losonci Miklós)

DERÜLT ÉGBŐL

Kinn fagy zabál, benn féltések,
sorjáznak egyre a kérdések,
szokatlan a színdarab,
torlódnak a házfalak,
derült égből eső locsog,
mennyi kátyú? – elsápadok.
Szélborzolta lebernyegek
vérszegényen tüsszentenek.
Romterület. Szamárkórón lábunk,
múmiákat szerteszét dobálunk,
terepszínre vált a som,
meggörnyed az alkalom.
 

VÁLASZÚTON

Mint föld gyomrát csikarja
a szűkre szabott forma,
úgy füstölög a pulykaméreg, –
mi kéne ha volna?
szamár ordít, a komondor
idegen önmagának,
nyitja-csukja száját a föld,
válaszúton a testek kémiája,
kétujjnyi vajúdás,
a piros most sem ád zöld utat,
szemek nyirkos cikkanásán
felbugyborog
a fene-nagy öntudat,
pöfékeli fojtó füstjét
a szusszanó
vaskalapos gondolat,
eszeveszett riadót fúj a vágy,
kárvallottan nyeldekeli 
a csókokat,
a mérték és arány
nem találja megfelelő helyét,
s a szellem tekintélye most
a boldogsággal kérne cserét.','Nyomda 0518',NULL,1451296108,0);
INSERT INTO books VALUES('',0,'','Susy_Cat_Lee--Forro_csoki_és_Mona_Lisa--FD.jpg','',2,1,0,0,16,'',1,'',40,60,'','',NULL,NULL,'',1000,0,NULL,24,6,2011,460,'Susy Cat Lee','Forró csoki és Mona Lisa','978-615-5110-11-5',2,'','4','120x200 mm',220,'0',1990,1,'#LE4,LGIV #RA1 T:G B:B K:K','Susy-Cat-Lee','http://www.konyvesbolt.online/spd/978-615-5110-11-5/Susy-Cat-Lee-Forro-csoki-es-Mona-Lisa-Ad-Librum-20','','','','http://www.konyvesbolt.online/spd/978-615-5110-11-5/Susy-Cat-Lee-Forro-csoki-es-Mona-Lisa-Ad-Librum-20','','','',3,3,2,7,4,5,3,'2011-4-20','2011-6-24','Ivicsics Mátyásné, 30/3284099, 1163 Budapest, Lándzsa u. 21/C.','ivicsics.zsuzsi@gmail.com','Ha unod a sulit és tele van a gálatopánod mindennel, ha
legszívesebben köddé válnál, vagy csak jól esne egy kis nevetés...','Ha unod a sulit és tele van a gálatopánod mindennel, ha
legszívesebben köddé válnál, vagy csak jól esne egy kis ne-
vetés...

Végy egy gimit, adj hozzá diákokat, fűszerezd meg folyosón ordibálással, várban bujkálással, komisz macskával, bohókás
öreg Lorddal, férfias kakaskodással, gyönyörű ruhákkal, végül egy éjkék szempárral.

Hevítsd a helyzetet forrás pontig több ízben. Az így elkészült étket (eme könyvet) fogyaszthatod reggelire, ebédre, csak úgy nassolásként, szívfájdalomra, vagy gyomorrontás esetén orvosságként...

Csak ne felejts el elegendő forró csokit és egy jó meleg takarót magadhoz venni olvasás előtt!','Nyomdába 2011.06.03.',NULL,1451378725,0);
INSERT INTO books VALUES('',0,'','Aimen_Klimmeron--Kama_Pura--FD.jpg',622,'',1,0,22,12,'http://books.google.hu/books?printsec=frontcover&id=c9pXcGlpyt8C#v=onepage&q=&f=false',1,'',40,40,'','',5,650,'','',0,'',4,6,2009,461,'Aimen Klimmeron','Káma Púra - A gyönyörök városa','978-963-9888-94-4',2,'','2','A5',476,'0',3990,1,'#LB5# T:G Csibi István Levente','Kama-Pura','http://www.konyvesbolt.online/Aimen-Klimmeron-Kama-Pura--A-gyonyorok-varosa','http://bookline.hu/product/home!execute.action?id=81300&type=22&_v=Klimmeron_Aimen_Kama_Pura_A_gyonyorok_varosa','','','','','','',3,3,1,7,4,1,1,'2008-12-0','2009-6-4','Csibi István Levente, Sf. Georghe, jud. Covasna, Str. Várady József, nr. 72A, Bl. 1, ap. 14, Románia','klimmeron@yahoo.co.uk','Regény művészetről, szerelemről, szexualitásról, két – egy jellegzetesen női és egy jellegzetesen férfi – szemszögből. Ezoterika és erotika.','Regény művészetről, szerelemről, szexualitásról, két – egy jellegzetesen női és egy jellegzetesen férfi – szemszögből. Egy svéd zenészfiú és egy francia táncoslány párhuzamosan meséli kalandjait, szerelmi életének fontos állomásait, a gyerekkori nemi vágy első rezdüléseitől kezdve a tantrikus szerelem mély, szakrális dimenzióinak feltárulásáig.  Életútjuk, amely Közép-Kelet-Európában keresztezi egymást, külső és belső utazás is egyben: kemény megpróbáltatások egész sora, amely révén a két főhős saját lelkivilágának árnyoldalaival találja szemben magát, ugyanakkor olyan tapasztalatokban részesül, amelyek az élet dolgainak mélyebb megértéséhez vezetik őket.
Aimen Klimmeron, jórészt valóságelemekre épülő regénye, Európa legnagyobb Tantra-jóga iskolájának rejtélyes és vitatott világába enged bepillantani, a beavatott szemén keresztül.  Szól mindazokhoz, akiket foglalkoztat a szerelem, a szexualitás, és szeretnének erről “szép”-irodalmi megjelenítésben olvasni, vagyis egy felemelő kicsengésű, olvasmányos, ugyanakkor mély bölcsességgel átitatott írást venni a kezükbe.','Lezárva 2014. május 4.','',1483440155,0);
INSERT INTO books VALUES('',0,'','Razso_Laura--A_kohercegno--FD.jpg',38,0,1,0,0,16,'',1,'',40,60,'','',NULL,NULL,'',500,0,NULL,7,7,2011,462,'Rázsó Laura','A kőhercegnő','978-615-5110-12-2',2,'','4','100x140 mm',48,'0',1490,1,'#LB4#  T:G B:B K:K','Razso-Laura','http://www.konyvesbolt.online/spd/978-615-5110-12-2/Razso-Laura-A-kohercegno-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-12-2/Razso-Laura-A-kohercegno-Ad-Librum-2011','','','',3,3,2,7,4,5,3,'2011-4-0','2011-7-7','5081 Szajol, József A. út 34. nincs mo-i telefonszáma','laramedios@hotmail.co.uk','Két elgondolkodtató mese, A kohercegnő és A mágikus kulcs.','Két elgondolkodtató mese, A kohercegnő és A mágikus kulcs.
','',NULL,1451378818,0);
INSERT INTO books VALUES('',0,'','Belteki_Katalin--Setet_ejurunk_segits_rajtunk--FD.jpg',467,0,1,1,0,14,'',1,2100,10,'','','',NULL,NULL,'',30,0,NULL,14,7,2011,463,'Bélteki Katalin','Setét Éjurunk, segélj rajtunk…','978-615-5110-15-3',2,'','4','140x200 mm',400,'0',2490,5,' #LA3 T:G B:B K:K ','Belteki-Katalin','http://www.konyvesbolt.online/spd/978-615-5110-15-3/Belteki-Katalin-Setet-Ejurunk-segelj-rajtunk-Ad-Li','','','','http://www.konyvesbolt.online/spd/978-615-5110-15-3/Belteki-Katalin-Setet-Ejurunk-segelj-rajtunk-Ad-Li','','','',3,3,2,7,4,5,5,'2011-4-29','2011-7-14','1118 Budapest, Torbágy u. 3. IV/13., 30/990-7133','roomi@freemail.hu','Egy dark fantasy regény uralkodói tervekről, fekete mágiáról, hitről és vallásról, testvéri szeretetről, szerelemről és a bennünk lakozó démonról.','1535-ben háború dúl az emberek és vérivók között. Az égbolton bőrszárnyakon repülő, karmos szörnyek cikáznak, a földön óriási farkasok tizedelik a keresztes lovagok seregét. A vérfarkasok és vámpírok szövetsége azonban gyengül, vesztésre állnak. Utolsó reménységük a vámpír uralkodónő fia, Szelviel, akit tetszhalottként kristálykoporsóban menekítenek. A szerencse azonban elpártol a szörnyektől, és az ifjú nem a háború végén, népe új rejtekén ébred, hanem ötszáz évvel később – napjainkban, egy kisváros mellett...
Egy dark fantasy regény uralkodói tervekről, fekete mágiáról, kitartásról és kudarcról, hitről és vallásról, testvéri szeretetről, szerelemről és a bennünk lakozó démonról.','Régi email cím: belteki.katalin@ick.hu (2014.09.19.)

A szerzőnek 20 példány kell.
Nyomdában 2011.07.01.',NULL,1451378497,0);
INSERT INTO books VALUES('',0,'','Yasmin_Hondar_Gomez--Mosolyogva_spanyolul_II--FD.jpg',473,'',1,0,0,35,'',1,'',40,60,'','','','','',300,0,'',17,6,2011,464,'Yasmín Hondar Gómez','Mosolyogva spanyolul - Második kötet','978-615-5110-13-9',2,'','4','A4',175,'0',3500,1,'#LC,LGI#  T&B:Szerző 6 oldal színes','Mosolyogva-spanyolul','http://www.konyvesbolt.online/spd/978-615-5110-13-9/Yasmin-Hondar-Gomez-Mosolyogva-spanyolul---Masodik','','','','','','','',3,3,1,9,3,5,3,'2010-5-27','2011-6-17','Jakab Istvánné, 3529 Miskolc, Szentgyörgy u.74. 3/5, 0630/743-79-47','yasminh@t-online.hu','Spanyol nyelvkönyv.','Ez a könyv magyarul beszélő, 14. életévüket betöltött nyelvtanulók számára készült, akik már átvették az első könyvemet, vagy azok részére, akik már tanulták a kijelentő mód jelen idejét, az egyszerű jövő, továbbá a közel-, a befejezett, a folyamatos és a folyamatos régmúlt időket. Elsajátították továbbá a határozói igenév és a melléknévi igenév témakörét, valamint a személyes névmás tárgy-, és részeshatározós esetét és a felszólító mód használatát.

A második kötet különlegessége az, hogy összefoglalva tartalmazza a 2010. október 28-án elfogadott új helyesírási szabályokat, továbbá figyelembe veszi a Spanyol Királyi Akadémia és a Spanyol Nyelv Akadémiai Szövetsége által  2009-ben közösen kiadott „Új Spanyol Nyelvtan” című kötetben szereplő nyelvtani előírásokat is.

Ebből a kiadványból a tanulók megismerhetik a személyes névmások tárgy- és részeshatározós esetének együttes használatát, a  melléknév fokozását, továbbá a kötőmód jelen idejét, folyamatos múltját, a közel- és a régmúlt időket. Elsajátíthatják továbbá a feltételes mód jelen és múlt idejét, a feltételes mondatok, a befejezett jövő, illetve a függő beszéd használatát, a főnévi igenév alakjait, az igék szenvedő alakját, a vonatkozó, a személyes névmásokat, a célhatározói, az okhatározói, a megengedő, a következtető mondatokat és az új helyesírás és hangsúlyozás általános szabályait.

Remélem, hogy ezzel a könyvvel a  nyelvtanulás élvezetesebb és gyorsabb lesz azok számára is, akik a spanyol nyelvvel eddig nehezebben boldogultak.

Sok sikert kívánok Önöknek a spanyol nyelv tanulásához!

A szerző


A könyvhöz tartozó CD megrendelheto a kiadótól az info@adlibrum.hu címen 1700 Ft-os áron.','Nyomdába 2011.06.02.','',1485162643,0);
INSERT INTO books VALUES('',0,'','Reczey_Kata--Orvenykonyv--FD.jpg',191,'',1,0,12,15,'',1,'',40,40,'','','','','',120,0,'',3,6,2011,465,'Réczey Kata','Örvénykönyv – Arno anno','978-615-5110-14-6',2,'','4','140x200 mm',148,'0',1990,1,'#LA4,LGVI#  PODplusz T:G B:B K:K','Reczey-Kata','http://www.konyvesbolt.online/spd/978-615-5110-14-6/Reczey-Kata-Orvenykonyv-Arno-anno-Ad-Librum-2011','','','','','','','',3,3,4,7,4,5,5,'2011-4-28','2011-6-3','06-30-370-9250','71kathy@citromail.hu','Firenzei párhuzamos történetek 200 év különbséggel.','Egy történet, amely az 1800-as évekhez kötődik. Egy másik történet,
amely napjaink lapjaira tartozik. A szereplők az idők folyamán (talán)
változnak. A főszereplő azonban változatlan... Firenze.
','Nem szabad feltölteni a Google Books-ba.',1220002279,1480931634,0);
INSERT INTO books VALUES('',0,'','Tabacsik_Ferenc--Az_ejszaka_szulotte--FD.jpg','','',1,0,0,14,'',1,'',40,40,'','',5,419,'','',0,'',23,4,2009,466,'Tabacsik Ferenc','Az éjszaka szülötte','978-963-9888-95-1',2,'','2','A5',160,'0',2190,1,'#LD#  A §134 bizományos folytatása.','Frank-Bauer','http://www.konyvesbolt.online/spd/978-963-9888-95-1/Tabacsik-Ferenc-Az-ejszaka-szulotte-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=80219&type=22&_v=Tabacsik_Ferenc_Az_ejszaka_szulotte','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/az_ejszaka_szulotte','','','Tabacsik_Ferenc','',3,3,1,7,4,1,1,'2009-1-0','2009-4-23','Tabacsik Ferenc, 2475 Kápolnásnyék, Balassa u. 4.; tel:20/538-8945','tabacsikferenc@citromail.hu','Frank Bauer küzdelme a túlvilági alakváltó lények ellen.','Létezik egy világ, amelyről csak kevesen tudnak az emberek közül. Ez a világ itt van körülöttünk, de mégsem látjuk. Csak az igaz szívvel és tiszta tudattal rendelkező teremtmények előtt tárja fel kapuit. Egy másik dimenzió. 	

Ebben a világban a jó és a rossz, a fény és az árnyék vívja szakadatlan küzdelmét, és itt minden létező megmutatja valódi arcát. A Földön ma elhatalmasodott a bűn, és a sötétség az úr. Az egyensúly visszaállása nem létező álom csupán. De él közöttünk egy bátor hős, kinek van mersze úszni az árral szemben. Életét a gonosz elleni küzdelemre tette fel. Egy a maroknyi igaz közül, ki a becsületért küzd. Ez a férfi Frank Bauer, a különleges képességekkel bíró magánnyomozó.


Tabacsik Ferenc sajátos stílusban, kellő misztikával fűszerezve megteremtette Frank Bauer, a zseniális magánnyomozó alakját. A mai gonoszsággal és sötétséggel teli korban ez a példaértékű hős újra visszahozza az igazság és a becsület ízét a tévúton járó emberiség számára. Ebben a két történetben Frank Bauer nyomozásai során lenyűgöző mély értelmével és rendkívüli intelligenciájával – amellett, hogy az aktuális bűnügyek felderítésén fáradozik – még arra is törekszik, hogy a nemes lélek megvilágosító felismerései felé vezesse az olvasót.
','','',1486636199,0);
INSERT INTO books VALUES('',0,'','Bastiat--A_Torveny--FD.jpg',154,'',1,0,0,42,'',1,'',40,60,'','',NULL,NULL,'',1500,0,NULL,24,8,2011,467,'Frédéric Bastiat','A törvény – Ami látható s ami nem látható','978-615-5110-17-7',2,'','4','130x200 mm',128,'0',1890,1,'#LD#  Global Education Kft. (Kész Zoltán) T:G B:B K:K','Bastiat','http://www.konyvesbolt.online/spd/978-615-5110-17-7/Frederic-Bastiat-A-torveny-Ami-lathato-s-ami-nem-l','','','','','','','',3,3,4,7,4,5,3,'2011-5-0','2011-8-24','Global Education Kft. (képviseli:  Kész Zoltán), Telefon: 30/9523-697, 8200 Veszprém, Kinizsi u. 7.','kesz.zoltan@gmail.com','A Hayek által méltatott francia gondolkodó elmélkedései az államról és piacról.','Ha a gazdaságpolitikát csak az előre látható hatások alapján elemezzük, nemcsak egy megvalósítható rendre teszünk szert, hanem kioltjuk a szabadságot, s megakadályozzuk, hogy további jó származzon a döntések miatt. A szabadság pedig fontos az egyének számára, hogy a csak általuk ismert körülményekből a legjobbat kihozzák. Tehát soha nem tudhatjuk, hogy milyen pozitív cselekvést akadályozunk meg azáltal, hogy korlátozzuk az egyén szabadságát, hogy az általuk jónak ítélt módon szolgálják embertársaikat. Azonban mindenfajta beavatkozás korlátozással jár. Minden korlátozásnak természetesen van valami meghatározott célja. Minden egyes esetben látni fogjuk, hogy a kormány döntéseinek közvetlen és látható eredményeit kiegyensúlyozhatják olyan egyéni döntések, amelyeket megakadályoztak. Következésképp, ha az emberek nem dönthetnek szabadon, mert döntéseikben a kormány megakadályozza őket, nem beszélhetünk szabadságról. Bastiat-nak igaza volt abban, hogy a döntés szabadságát erkölcsi alapnak tartotta, amelyet semmi esetre sem szabad az opportunizmus oltárán feláldozni. Valószínűleg azért, mert a szabadságnak nincs olyan eleme, amit ne törölnének el, ha csak akkor vennénk őket figyelembe, amikor rámutathatunk a konkrét kárra, amit az eltörlés okozhat.
Friedrich von Hayek','',NULL,1483438459,0);
INSERT INTO books VALUES('',0,'','Gondor_Otto_gyilkoszenek--Gitart_karokkal--FD.jpg',100,'',1,1,28,22,'',1,0,0,'','','',NULL,NULL,'',50,0,NULL,29,6,2011,468,'gyilkoszenek.com','Gitárt karokkal, avagy a tékozló rocker hazatér','978-615-5110-23-8',2,'','4','120x200 mm',100,'0',1200,5,'#LB6#  Göndör Ottó T:G B:B,','Gitart-karokkal','','','','','','','','',5,3,4,7,4,5,5,'2011-5-11','2011-6-29','Göndör Ottó; 1108 Bp, Harmat u. 129.; 06/20-563-0870;','otto.gondor@elmu.hu','Megdöbbentő pálfordulatok a kemény rock közismert arcai között.','A gyilkoszenek.com válogatáskötete megdöbbentő pálfordulatokat ír le a kemény rock közismert arcainak soraiból, a bibliai „Tékozló Fiú” története alapján. Hasonló utat jártak be ugyanis a könyv főhősei Alice Coopertől Nico McBrainen (Iron Maiden) át, Nina Hagenig közel kéttucatnyian…

„Még a legnagyobb sztárokról is, akikről azt hisszük, hogy elégedetté teszi őket a siker, kiderül, hogy valami hiányzik az életükből. Jó szembesülni azzal, hogy a könyvben szereplő emberek megtalálták az igazi boldogság forrását.”  Fejes Zoltán gitár virtuóz (ex-Classica, Cornerstone Club)','Szerzői ár 1200 Ft.',NULL,1467455565,0);
INSERT INTO books VALUES('',0,'','Bekes_Vera--Trauma_es_narrativa--FD.jpg',319,'',1,1,36,39,'',1,2060,10,'','','',NULL,NULL,'',30,0,NULL,20,2,2012,469,'Békés A. Vera','Trauma és narratíva – A Holokauszt trauma reprezentációja','978-615-5110-16-0',2,'','5','170x240 mm',250,'0',2490,5,'#LA4 T:G B:V K:K','Bekes-Vera','http://www.konyvesbolt.online/spd/978-615-5110-16-0/Bekes-A--Vera-Trauma-es-narrativa-A-Holokauszt-tra','','','','','','','',3,3,1,7,4,5,5,'2011-2-0','2012-2-20','1136 Bp. Tátra u. 26., levelezés: 1112 Bp. Eper u. 63.,20/2117359','bekesavera@gmail.com','A holokausztról szóló személyes elbeszélések pszichológiai elemzése.','Békés A. Vera könyve a holokausztról szóló személyes elbeszélések pszichológiai sajátosságait kutatja, abból a szempontból, hogy a traumatikus események felidézésének és narratívummá alakításának módjai miként változnak az idő múlásával.  A kutatás alapjául szolgáló szövegbázisok három különböző szövegbázisból származnak: a Deportáltakat Gondozó Országos Bizottság (DEGOB) által 1945-46-ban készített jegyzőkönyvekből, az 1980-as években készült második generációs mélyinterjúkból, valamint  a 2000-es évek elején a Közép-Európai Kutatási és Dokumentációs Központ Centropa) keretében holokauszt-túlélőkkel készített interjúkból. A nemzetközi szakirodalomban is egyedülálló kutatás tudományos eredményei  módszertani és elméleti szempontból  egyaránt figyelemreméltóak.  A könyv fontos hozzájárulás a holokauszt-trauma és általában a negatív életesemények  hatásának és feldolgozásának megértéséhez, éppen ezért pszichoterapeuták, pszichológusok  és más segítő foglalkozásúak éppúgy érdeklődéssel olvashatják, mint a holokauszt kutatásával foglalkozó társadalomtudósok.
Erős Ferenc','A szerzőnek 10+1 példány kell.',NULL,1480674695,0);
INSERT INTO books VALUES('',0,'','Mason_Murray--Lelekcsapda--FD.jpg','',1,0,0,0,11,'',1,'',15,30,'',50,NULL,NULL,500,500,2,NULL,30,9,2011,470,'Mason Murray','Lélekcsapda','978-615-5110-18-4',2,'','4','140x200 mm',300,'0',2990,2,'#LGV# T:G B:B K:K Zibriczki Zoltán, misztikus thriller','Mason-Murray','','','','','','','','',5,3,4,7,4,5,5,'2011-5-0','2011-9-30','Zibriczki Zoltán, 3530  Miskolc, Corvin u. 9. 3/2., 30/466-8201','zoltan.zibriczki@gmail.com','A nagy sikerű Elátkozottak városa szerzője ezúttal is bőven adagolja a feszültséget és újra biztos kézzel vezeti olvasóit a borzongató rejtélyek hosszú során.','Mason Murray visszatért! A nagy sikerű Elátkozottak városa szerzője ezúttal is bőven adagolja a feszültséget és újra biztos kézzel vezeti olvasóit a borzongató rejtélyek hosszú során.

Mark Moore, az ex-FBI ügynök egy szép nyári reggelen arra ébred, hogy kényszerűségből valaki más életét kell tovább élnie. A tükörből egy vadidegen arc bámul vissza rá. Mit tehet valaki, ha megfosztják a legfontosabb tulajdonától, a saját életétől? Veszítenivaló híján elindul, hogy visszaszerezze.

Segítségül csak egykori szerelmére számíthat, aki egyetlenként fogadja el őt másnak, mint amit a látszat sugall, vagyis saját magának. Útjuk akadályok végeláthatatlan sorozata, vesztükre tör az arctalan hatalom az állam érdekeit védelmezve, felbukkannak profi bérgyilkosok és csak akkor van esélyük a sikerre, ha megtalálják azt az embert, aki felelős a lelkek csapdába csalásáért. Őt viszont a föld nyelte el…

A sok humorral átszőtt történet megpróbál segíteni, hogy megtaláljuk a választ az egyik legfontosabb kérdésre: mik vagyunk mi valójában?','A könyv augusztus 20-a után kerül nyomdába, a webboltból szeptember 1-jétől lesz rendelhető, és legkésőbb szeptember közepén lesz a boltokban is, meg a webboltból is postázzuk.

Alternatív email cím: zibriczkiz@indamail.hu

Elszámolás után a bérraktárból, nem árusítjuk+1db selejt',NULL,1424165188,0);
INSERT INTO books VALUES('',0,'','Mester_Gyorgyi--Vizio--FD.jpg',255,'',1,0,0,3,'',1,'',40,70,'','','','','',100,0,'',10,6,2011,471,'Mester Györgyi','Vízió - Novellák','978-615-5110-19-1',2,'','4','140x200 mm',208,'0',1500,1,'#LB5#  &C3 T:G B:B','Mester-Gyorgyi','http://www.konyvesbolt.online/spd/978-615-5110-19-1/Mester-Gyorgyi-Vizio---Novellak-Ad-Librum-2011','','','','','','','Ad_Librum--Mester_Gyorgyi--Halali_jo_tortenetek--Kulonnyomat.pdf',3,3,1,7,4,5,4,'2011-5-13','2011-6-10','','mestergyorgyi@freemail.hu','','Először csak permetszerű ködként szitált, szemerkélt az eső. Mivel az ég szeplőtelen volt, ráadásul a nap is sütött, valaki megjegyezte, amit ilyenkor szokás, „veri az ördög a feleségét”.
Másnap azonban, szinte percre pontosan ugyanabban az időben, beborult az ég, és nagy cseppekben esni kezdett. Hullt az égi áldás, kopogva, hangosan dobolt a bádog ablakpárkányokon. Áldás volt, mert rég nem esett már eső, jót tett a sarjadó vetésnek, tisztára, fényeszöldre mosdatta a fák leveleit, elverte az út porát. Késő délutánra kiderült. Kéken, mosolygósan feszült a föld fölé az égi palást, s a felfrissült levegőt örömmel lélegezték be a táguló tüdők.
Harmadnap, a már ismerős időpontban, ismét esni kezdett. Az ég haragosan elfeketült, fényes rést csupán a cikázó villámok nyitottak rajta, félelmes dörgések kíséretében. Zuhogott, szakadt, mintha dézsából öntötték volna. Reggelre nagy tócsákban állott a víz, a fák leveleit helyenként cafatosra szaggatta a fergeteges szélvihar, mely az előző napi felhőszakadás velejárója volt. Hegyes sarkú körömcipők, fényesre dörgölt férficipők, apró tipegők kerülgették a járdák, az utca gödreiben megülő esőlét. Itt-ott fojtott szitkozódás hallatszott: ez nem is pocsolya, ez már valóságos sártenger. Pedig a java még hátravolt…
Háromnapos eső nem ritkaság. Ezzel nem is lett volna baj, hiszen eddig, a csapadékos délutánokat követően, estére mindig kitisztult az idő, egyre tovább maradt világos, és néha még a nap is kisütött. 
Csütörtökön azonban, a hét negyedik esős napján, valami megváltozott. Először csak beborult az ég, majd egyik percről a másikra, orkánszerű szél támadt. Nyűtte, szinte földig hajlította a vékonyabb fák törzsét, s oly lendülettel kergette végig az utcán a szemetet, mintha legalább is, a célba elsőként való beérés lenne az őrült futam tétje. Aztán megnyílt az ég gyászfekete kárpitja, s az eső úgy szakadt le, mintha hatalmas, végtelenített dézsából, folyamatosan öntenék. Hamarosan megteltek az árkok, az utakon hömpölygött a víz. A csatornák eldugultak, nem tudták elnyelni a hatalmas mennyiséget. Éjszakára kicsit szelídült ugyan a vihar, de az eső, az nem állt el… ','Vastagabb papírra, az összes példány Budakeszire.','',1467279746,0);
INSERT INTO books VALUES('',1,'','Anna_White--The_Change--FD.jpg',448,2,0,0,0,4,'',1,'',40,60,'','',NULL,NULL,'',1000,0,NULL,23,1,2012,472,'Anna Y. White','The Change','',2,'','4','130x200 mm',388,'0',2990,1,'#LB6  #L Anna Yatsevich / Zerno Kft.','White','','','','','','','','',4,3,1,7,4,4,4,'2011-5-0','2012-1-23','Zerno Kft. 30/489-3033','annutika@gmail.com','The adventures of the nineteen-year-old Natalya in Budapest.','Big city...
Boys...
Clubs...
Fun...

Or not that fun after all?

Starting afresh for nineteen-year-old Natalya Orlova doesn’t seem as exciting as she has imagined it the minute she is literally alone, with nobody around, in foreign Budapest.

But luckily, Natalya meets Veronica, a ‘pink’ girl, who also came to Budapest to study. What seems to become a best-friends-forever soon
turns out to be the bitterest rivalry imaginable.

So who will stay and who will go from that one small dorm room the girls share?','',NULL,1412844981,0);
INSERT INTO books VALUES('',0,'','Zagonyi_Monika--Versiras_konnyeden--FD.jpg','',0,1,0,0,31,'',1,1140,10,'','','',NULL,NULL,'',50,0,NULL,20,7,2011,473,'Zágonyi Mónika','Versírás könnyedén','978-615-5110-22-1',2,'','4','120x200 mm',60,'0',2300,5,'#LA3 T:G B:B K:K','Zagonyi-Monika','http://www.konyvesbolt.online/spd/978-615-5110-22-1/Zagonyi-Monika-Versiras-konnyeden-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-22-1/Zagonyi-Monika-Versiras-konnyeden-Ad-Librum-2011','','','',3,3,2,7,4,5,5,'2011-5-0','2011-7-20','1038 Budapest, Zsirai M. u. 6. VI/18., 06-70-394-5992','thetawords@gmail.com','A költészet alapvető fogalmai és technikái egyszerűen, könnyen érthető formában.','A versírás mesterség, a művészet pedig a lélekben rejlik; az első ismerete, és a második jelenléte teremti a költőt.
A szerző – aki maga is elismert alkotó – célja ezzel a könyvvel az,
hogy egyszerűen, könnyen érthető formában mutassa be a költészet alapvető fogalmait, technikáit.
','A kötelespéldányokat még számlázni kell a szerzőnek.',NULL,1451384700,0);
INSERT INTO books VALUES('',0,'','GyA--Miert--FD.jpg',254,0,1,0,0,22,'',1,'',40,60,'','',NULL,NULL,'',1000,0,NULL,5,11,2011,474,'Gy.A.','Miért?','978-963-08-1639-7',1,'','4','130x200 mm',148,'0',1990,1,'#LB3# Rraklap Gyurcsik Antal és Gyurcsik Attila T:G B:B K:K','GyA','http://www.konyvesbolt.online/spd/978-963-08-1639-7/Gy-A--Miert-2011','','','','http://www.konyvesbolt.online/spd/978-963-08-1639-7/Gy-A--Miert-2011','','','',3,3,2,9,4,5,4,'2011-5-0','2011-11-5','1122 Budapest, Városmajor u. 7. II/2. 30/9608-841','gyantal@vipmail.hu','Ez a könyv az élet nagy miértjeire és egyéb kérdésekre ad választ.','Ha meg akarod érteni a világot,hogy mi miért van, hogy miért történnek és miért úgy történnek az események, ahogy történnek, miért élünk, miért van betegség és halál, miért vannak az életben jó és rossz dolgok, akkor most megértheted. Ez a könyv a miértekre és egyéb kérdésekre ad választ.

A könyvben szereplő kérdések közül néhány: Mi van a halál után? Mit kell annak tenni, aki a tökéletességet el akarja érni? Miért teremtett Isten, talán unatkozott? Vannak ufók? Ha állat szeretnék lenni, lehetek? Miért kell megöregedni? Mia véleményed az Indiában található ősi pálmalevelekről, amiről ma élő emberek sorsa olvasható. Mi a különbség a buddhizmusban említett karma, a szabad akarat és a te elméleted között? És így tovább...
','Készpénzben fizetett 2. részlet. A bélyegzést végül nem számoltam fel.

Szerződés módosítva 2011.10.10-én.

A szerző ott volt a nyomdai munkálatok indulásánál.',NULL,1451380035,0);
INSERT INTO books VALUES('',0,'','','',0,0,0,0,14,'',0,'',40,40,'','',5,350,'','',0,'',31,3,2009,475,'Mary Morgan','Selina, a vámpírboszorkány','978-963-9888-87-6',2,'','2','A5',320,'0',2990,1,'->§142 #A6 425 gr. Balogh Orsolya','Mary-Morgan','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','','http://www.fo.hu/hu/konyv/szepirodalom/ifjusagi_irodalom/regenyek/selina_a_vampirboszorkany','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','Mary_Morgan--Selina','Mary_Morgan--Selina',3,3,1,7,4,1,1,'2008-12-0','2009-3-31','BALOGH ORSOLYA, 30/522-53-21, állandó: 1221 Budapest, Leányka u. 32. IX/58.; ideiglenes: 1225 BUDAPEST AKÓ U. 26.','morgan333@freemail.hu','','Biztos hogy csak ember vagy? 
Egy lány, aki tizennyolc éves koráig csak ember volt... majd egyszerre lett vámpír és boszorkány. Soha vissza nem térő alkalom a Mágiába és a Vámpírok a Birodalmába való belépéshez. Ahol megismerkedik a szerelem és a vér ízével. Démonok és Angyalok szüntelen harca. 
De a kettős életnek ára van. Nem lehet egyszerre két oldalon állni. A Halál örökké elkíséri.
Döntsd el, Te melyik oldalon állsz?
','12nov: 11 pld. #A6','',1451378402,0);
INSERT INTO books VALUES('',0,'','Jakabfi_Zsolt--Csak_egy_tanc_volt--FD.jpg',275,0,1,0,4,12,'',1,1560,10,'','','',NULL,NULL,'',30,0,NULL,5,10,2011,476,'Jakabfi Zsolt','Csak egy tánc volt...','978-615-5110-21-4',2,'','4','140x200 mm',220,'0',2290,5,'T:G B:B K:K','Jakabfi-Zsolt','','','','','','','','',5,3,4,7,4,5,5,'2011-5-27','2011-10-5','1141 Budapest, Fischer István utca 142/B. 20/571-76-40','zsoltziu9@freemail.hu','A szerelmes történet visszarepít 1976-ba, a nosztalgikus múltba.','Szerelmes regényt tart a kezében a kedves Olvasó. Sőt, több ennél! A történet visszarepít 1976-ba, a nosztalgikus múltba. Az első szerelem feledhetetlen, nincs ez másképp Bartók Anna életében sem, akiről szól ez a történet. Ez az a nyár, amely gyökerestül megváltoztatja a lány életét, s talán ekkor lép át a kamaszkorból a felnőttbe. Az első szerelem emléke örökre megmarad...','Lezárva 2013.03.18-án.

10+1 pld. a szerzőnek.

110707: nyomat megérkezett, várhatóan 25-30 napot fogja olvasni...',NULL,1363594978,0);
INSERT INTO books VALUES('',0,'','Stephanie_Ford--Veres_labnyomok_a_levegoben--FD.jpg',512,0,1,0,0,10,'',0,40,40,'','','','','','','',0,'',8,2,2010,477,'Stephanie Ford','Véres lábnyomok a levegőben','978-963-9934-58-0',2,'','3','148x210 mm',400,'0',2990,1,'#LC3,LGI#  §238-ból, Guth István Károlyné (Lovasi Tünde)','Stephanie-Ford','http://www.konyvesbolt.online/spd/978-963-9934-58-0/Stephanie-Ford-Veres-labnyomok-a-levegoben-Ad-Libr','','','','http://www.konyvesbolt.online/spd/978-963-9934-58-0/Stephanie-Ford-Veres-labnyomok-a-levegoben-Ad-Libr','','','',3,3,0,7,4,5,5,'2009-11-0','2010-2-8','Guth István Károlyné (Lovasi Tünde) T.: 29/350-033 C.: 2220 Vecsés, Major u. 7/a.','lovasitunde@gmail.com','Vajon sikerül-e felgöngyölíteni a levegőben lebegő véres lábnyomok és a gyilkosságok rejtélyét két botcsinálta nyomozónak?','Jackie Simonnal madarat lehetne fogatni, mikor megtudja, hogy egy rendőrcsere-program keretén belül elutazhat Rockswoodba nyomozói tapasztalatot szerezni. Kicsit csodálkozik ugyan, minthogy ő nem nyomozó, ám a lehetőségnek azért örül. Fogalma sincs, hogy úti céljának legfőbb nevezetessége – ha van ilyen egyáltalán –, hogy szinte egyáltalán nem történnek bűnügyek, mint ahogyan arról sem, hogy leendő főnöke rendőr ugyan, ám jelenlegi pozícióját egyféle felfelé buktatásnak köszönheti. Mindössze egyetlen közös vonásuk van: a tapasztalat hiánya. Épp ezért éri sokként a friss társakat, hogy nem sokkal Jackie megérkezése után furcsa gyilkosság történik: egy helybéli, gazdag család villájában rábukkannak a látogatóba érkező rokon kamaszlány holttestére, amely körül szemmel láthatóan nincs minden rendben… És ezzel elindul a lavina: több haláleset követi egymást, amelyeknek van egy igen különös közös mozzanata. Ráadásul az álmos vidéki városban felbukkanó filmes stábnak köszönhetően hirtelen igencsak felpezsdül az élet – alaposan megnehezítve botcsinálta nyomozópárosunk dolgát. Vajon sikerül-e felgöngyölíteni a levegőben lebegő véres lábnyomok és a gyilkosságok rejtélyét főhőseinknek, vagy Rockswood immár az örökre megoldatlan, misztikus halálesetekről lesz híres-hírhedt?','','',1451380368,0);
INSERT INTO books VALUES('',0,'<p>További információ és kapcsolat a szerzővel <a href=\\\"https://www.facebook.com/pages/Gondolatok-a-konyhában/120345524738092\\\" target=\\\"_blank\\\">a könyv Facebook-oldalán</a>.</p>

<p><a href=\\\"http://www.youtube.com/watch?v=0i3p7ytitPQ\\\" target=\\\"_blank\\\">A szerző videóüzenete az olvasókhoz.</a></p>','Horvath_Karoly--Gondolatok_a_konyhaban--FD.jpg',280,'',1,1,0,30,'',1,1750,10,'','','',NULL,NULL,'',60,0,NULL,20,10,2011,478,'Gy. Horváth Károly','Gondolatok a konyhában','978-615-5110-37-5',2,'','4','130x200 mm',250,'0',1990,5,'#LA4 Horváth Károly B:B T:G K:K','Horvath-Karoly','http://www.konyvesbolt.online/spd/978-615-5110-37-5/Gy--Horvath-Karoly-Gondolatok-a-konyhaban-Ad-Libru','','','','','','','',3,3,2,7,4,5,5,'2011-8-0','2011-10-20','Horváth Károly, 8900 Zalaegerszeg, Csapási u. 4., 30/5620-129, 92/815-040','gyhkaroly@gmail.com','Elköltöztél otthonról és elfogyott a szendvics? Egy gasztronómiai stand up comedy.','Elköltöztél otthonról és elfogyott a szendvics? Unalmas a szakácskönyved? Elhadarta a tévészakács a rántást, és neked összecsomósodik? Nincs meg a szellemi táplálék receptje? Nem ettél még olyan kínai kaját, amilyent még a kínaiak sem? Nem tudod mi a teendő, ha eltörted egy kurugla nyelét? Nem bírod eldönteni nokedlit főzzél-e vagy galuskát? Kíváncsi vagy min agyal a konyha magányában egy lányos apa? És mért nem jutnak az eszébe épelméjű gondolatok?

Két műfaji meghatározása született ennek az írásnak. Van, aki szerint gasztronómiai novellagyűjtemény, mások szerint gasztronómiai stand up comedy. Főzünk, iszogatunk, elmélkedünk. Az életről és az ételről beszélgetünk. Közben csomómentesre keverjük a rántást. És jól érezzük magunkat, ahogy egy rendes konyhában illik.','Régi telefonszám: 30/400-7769',NULL,1480678253,0);
INSERT INTO books VALUES('',0,'','Bardosi_Attila--Valami_szur--FD.jpg','',0,1,0,0,2,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,16,9,2011,479,'Bárdosi Attila','Valami szúr','978-615-5110-24-5',2,'','4','120x200 mm',92,'0',1990,1,'#LA2#  keménytábla,  84 ff. + 8 színes','Bardosi-Attila','http://www.konyvesbolt.online/spd/978-615-5110-24-5/Bardosi-Attila-Valami-szur-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-24-5/Bardosi-Attila-Valami-szur-Ad-Librum-2011','','','',3,3,4,7,4,5,4,'2011-6-15','2011-9-16','Appenrode 5 37130 Göttingen BRD, 004915142418295','abardosi@web.de','A Németországban élő költő 2010-2011-es versei.','Ha a festő egy képet megfestett, a zeneszerző egy szimfóniát megkomponált, ez nem jelenti rögtön azt, hogy egy műalkotás született. Ez csak akkor történhet meg, ha a képet megtekinti, a zeneművet meghallgatja valaki. Így van ez a vers esetében is: valakinek el kell olvasnia az írott költeményt.

Egy műnek csak akkor van esélye a műalkotás szintjét elérni, ha valaki
magáévá teszi, szellemileg és érzelmileg azonosul vele, tartalmát saját gondolataival, érzéseivel kiegészíti; más szóval: a festményt, a szobrot, a zenét, a szavakat saját életének tükrében újra és újra életre kelti. Egy mű halhatatlanságát egyedül az dönti el, hogy ez a párbeszéd képes-e bennünk azokat a reflexiókat kiváltani, amelyek az alkotó szándékában voltak. Ennek megfelelően, nem csak a művész tekinthető a műalkotás szerves részének, hanem mi magunk is. Egy új műnek magában kell hordoznia minden korábbi műalkotás szellemét.

Ellenkező esetben elkerülhetetlenül és végérvényesen megszakítjuk kulturális evolúciónk fejlődési folyamatát, amely létfontosságú az emberi faj fennmaradásának szempontjából. Létünk így nem ágyazódik be az idő dinamikus áramlásába, hanem összefüggések nélküli epizódokra esik szét. Ez a kulturális dezintegráció csak akkor kerülhető el, ha sikerül történelmi hagyományainkat a jelen igényeivel összehangolni, ami feltétele annak, hogy esztétikai fejlődésünk
a következő generációk életében is töretlenül tovább tudjon folytatódni.

Egy műalkotás tartalma, jelentése megváltozik annak tükrében, hogy aktuálisan milyen térben létezik, kinek az érzékszervével kerül kapcsolatba, tartalmát kinek az agya interpretálja, és végül, de nem utolsósorban, hangulata mondanivalója kinek a lelkét érinti meg.

Egy alkotási folyamat nem más, mint az idővel való állandó küzdelmünk. Sikerül maradandót alkotnunk, akkor esélyünk nyílhat arra, hogy megnyerjük ezt a csatát.','',NULL,1451297685,0);
