INSERT INTO books VALUES('',0,'','Gabriel_Dom--A_vegzet_kezdete--FD.jpg',444,'',1,0,13,11,'',1,'',40,40,'','','','','','',0,'',13,4,2010,481,'Gabriel A. Dom','A végzet kezdete','978-963-9934-78-8',2,'','3','147x205 mm',334,'0',2990,1,'#LE4,LGII,LGV,LGrégi salgó#  C T:G B:V 438 g. Doma Gábor','Gabriel-Dom','http://www.konyvesbolt.online/spd/978-963-9934-78-8/Gabriel-A--Dom-A-vegzet-kezdete-Ad-Librum-2010','','','','','','','',3,3,1,7,4,5,1,'2010-2-22','2010-4-13','Doma Gábor, 42/480-408, 30/2793-022, Nyíregyháza, Kezdő út 28.','g.dom78@gmail.com','Daren City – 2024. Minden megszűnt létezni, ami egykoron számított.','Daren City – 2024. Minden megszűnt létezni, ami egykoron számított. Az épületek romosak, az utcákon hömpölygő szemét, a levegő dermedt, áporodott bűz terjeng, vérbe fagyott és oszlásnak indult tetemek hevernek szanaszét. Egy Akumba nevű vírus, melyet megváltóként emlegetnek, futótűzként söpört végig a földkerekségen, megsemmisítő csapást mérve szinte minden nemű életformára. Hirtelen csapott le, nem lehetett rákészülni… az emberi faj csaknem teljesen kipusztult, de még így is akadtak jó páran, akik egy, a város mélyén húzódó hosszú alagútrendszerben, jól védhető menedékhelyre találtak. A vezetőjük egy igen megtermett, középkorú, mackós külsejű férfi, Maxwell Tarkin, vagy ahogyan magát nevezte: Zeusz… különösen szeszélyes jelenség. Egyfelől remek katona és stratéga, bármikor tűzbe menne a híveiért, másfelől szerfelett titokzatos egyén. De mindenekelőtt halandó ember és mint ilyent, a gonosz egy nap őt is megtalálja egy Asska-Mor nevű titokzatos idegen képében, aki mindent megváltoztat. Zeusz halálos fertőzést kap, ezért végleg el kell hagynia a menedéket, de nem egyedül. Egy ötfős csapat indul el, hogy megtalálják a vírus ellenszerét és fényt derítsenek a rejtélyre, ám az útjuk nem oda vezet, ahová eltervezték. Egy idegen világbeli ördögi színjátékba csöppennek, ahol a nagybetűs SORS és maga a gonosz irányítják a bábukat. A küldetésből vesszőfutás lesz és immár nem az ellenszer felkutatása a cél, hanem az életben maradás…','','',1458636877,0);
INSERT INTO books VALUES('',0,'','Tamas_Zoltan--Mindenkeppen_kimeletlen--FD.jpg',221,'',1,0,0,3,'',1,'',40,60,'','','','','',300,0,'',12,4,2010,482,'Tamás Zoltán','Mindenképpen kíméletlen','978-963-9934-79-5',2,'','3','140x200 mm',168,'0',498,1,'->§294 leértékelése #LA6,LGIV#   RB1c T:G B:B','Tamas-Zoltan','http://www.konyvesbolt.online/spd/978-963-9934-79-5/Tamas-Zoltan-Mindenkeppen-kimeletlen-Ad-Librum-201','','','','','','','',3,3,2,7,4,5,4,'2010-3-2','2010-4-12','20/326-2757, 96/337-613; 9024 Győr, Babits M. u. 9.','tamas.zoltan2010@gmail.com','','A könyv zsúfolásig tele van ironikus, szórakoztató és halálosan komoly gondolatokkal. Egy isteni színjáték. Magam sem írhattam volna jobban.

Dante


Ez a mértéktartó humorral, az emberi természetről, társadalomról, vallásról, művészetekről, tudományról és az Univerzumról megírt könyv annyira jó, hogy, még nekem is tetszik. Ebből tanultam meg én is; legjobb leszedni az érett almát a fáról, még mielőtt a fejünkre esik.

Newton
 

A könyv sokat segített világnézetem fejlődésében. Először azt gondoltam, csak beleolvasok. Aztán élvezettel elolvastam az egészet és azóta tudom, hogy az internet forradalmából következhet a valódi demokrácia.

Platón

 
Kortól és nemtől függetlenül mindenkinek bátran ajánlom ezt a kellemes zamatú délutáni vagy kora esti könyvet, mely kissé fűszeres, néha enyhén csípős stílusával méltán képviseli a jövő mámorát.

Ámor','110713: 79 pld. raktár','',1458637068,0);
INSERT INTO books VALUES('',0,'','Prudent_Man--A_hulladeklebonto--FD.jpg','',0,1,1,0,13,'',1,1080,10,'','','',NULL,NULL,'',30,0,NULL,20,7,2011,483,'Prudent Man','A Hulladéklebontó','978-615-5110-25-2',2,'','4','120x200 mm',60,'0',1680,5,'#LB3 Tóth Tamás','Prudent-Man','http://www.konyvesbolt.online/spd/978-615-5110-25-2/Prudent-Man-A-Hulladeklebonto-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-25-2/Prudent-Man-A-Hulladeklebonto-Ad-Librum-2011','','','',3,3,2,7,4,5,5,'2011-6-0','2011-7-20','Tóth Tamás; (30)533-3388; 8089 Vértesacsa Rózsadomb u. 9.','toth.tamas985@citromail.hu','Létrehozzák azt a mutáns élőlényt, amely képes megemészteni a hulladékokat. De az események nem várt fordulatot vesznek.','Template City városában az emberek zavartalanul élik mindennapjaikat. A városban azonban egyre nagyobb problémát okoz a kommunális, és egyéb hulladékok kezelése.
William Mckbray környezetvédelmi megbízottnak egy nap zseniális (vagy őrült?) ötlete támad a felhalmozódott hatalmas mennyiségű szemét eltüntetésére.
Néhány befolyásos ember támogatásával az Evil vállalat épülete alatt egy titkos laboratóriumot alakítanak ki, ahol létrehozzák azt a mutáns élőlényt, amely képes megemészteni a hulladékokat.
Ezután azonban nem várt események sorozata következik be, és a városban elszabadul a pokol...','5 pld. a szerzőnek
Korábbi email cím: hatalmastamas@citromail.hu (2012.05.05.)',NULL,1451302087,0);
