INSERT INTO books VALUES(990,0,'','Dobrossy_Rita--Vandorok--FD.jpg','',0,1,1,0,4,'',1,'','','','','','','','',70,0,'',17,8,2011,485,'P. Dobrossy Rita','Vándorok','978-615-5110-28-3',2,'','4','140x200 mm',300,'0',2490,5,'#LB3','Dobrossy-Rita','http://www.konyvesbolt.online/spd/978-615-5110-28-3/P--Dobrossy-Rita-Vandorok-Ad-Librum-2011','','','','http://www.konyvesbolt.online/spd/978-615-5110-28-3/P--Dobrossy-Rita-Vandorok-Ad-Librum-2011','','','',3,3,4,7,4,5,5,'2010-7-7','2011-8-17','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1., 45/421-051','dobrozsirita@freemail.hu','Három különböző nő életének egy-egy szakasza.','Ez a könyv három különböző nő életének egy-egy szakaszát mutatja be.
Az első kisregény a fiatal lányt, a második a kisgyermekes anyát, a harmadik pedig egy középkorú hölgyet ismertet meg az olvasókkal.
Ami közös bennük: kitartóak, bátrak, erősek, - és mint minden nő -,tele vannak érzelmekkel, elfojtott indulatokkal. Más-más módon, de kitartóan keresik a boldogságot, és a megfelelő társat.
Mindhárman cipelik magukkal létük gondjait és örömeit.
Élik koránt sem egyhangú életüket, amelynek fő mozgatórugói: az őszinte szerelem, és az igazi otthon megtalása utáni vágy...','Szerzői ár: 1900 Ft, jogdíj nincs.','',1451300746,0);
