INSERT INTO books VALUES('',0,'','','',0,0,2,0,18,'',0,'',0,0,'','','','','',15,0,'',2,9,2013,513,'C. Simian','Lököttek között II.','978-963-87741-4-9',1,'','6','140x200 mm',128,'0','',1,'Kiss Elemér T:G B:B','C-Simian','','','','','','','','',3,3,4,7,4,5,5,'2013-6-19','2013-9-2','Kiss Elemér 20/801-8818 - 2645 Nagyoroszi, Bajcsy u. 55.','','','„Ejh ezek a rohadt ócska lábak,ez a tökéletlen test, olyan gyomor kéne, mint a kutyának, három szív akár a polipnak és olyan potencia, mint a gibraltári makákónak. Az állatok nem ismerik a bűn fogalmát és bűntudatuk sincsen, sokszor jó volna cserélni velük!”
Ekkor elgáncsolta magát,vagy meglökték,tény,hogy kiesett az útra. Fék sivított és hatalmas ütést érzett.
A Nemzet a földön volt és elveszítette az öntudatát, fényt látott és Csaba királyfi jött a vitézeivel a csillagösvényen, éppen ideje!','','',1378102976,0);
