INSERT INTO books VALUES('',0,'','','',0,0,2,0,10,'',1,'','','','','','','','',12,0,'',25,9,2013,518,'Ellen Adlon','A Csajkovszkij-projekt III. Az ügynöknő halála','(nincs ISBN)',1,'','6','140x200 mm',200,'0','',1,'Horváth Edit','','','','','','','','','',5,3,3,7,4,5,3,'2013-8-9','2013-9-25','Asszisztens: katalin.kiss71@gmail.com 20/403-6971; Horváth Edit 1071 Damjanich u. 28/A. Fszt. 8.a. 70/201-5871','katalin.kiss71@gmail.com','','A sorozatgyilkos, aki már két köteten át macska-egér harcot folytatott a rendőrséggel, ezúttal le akar számolni a nőkkel is, ha nem úgy táncolnak, ahogy ő fütyül.
Kié lesz az óriás befektetői összeg? Megkapja-e a bank, mint jogos tulajdonos, vagy annak a személynek kerül a kezébe, aki mindenkit kijátszva megcélozta?','','',1381649615,0);
INSERT INTO books VALUES('',0,'','Bardosi_Attila--Pathetique--FD.jpg','',0,1,0,0,2,'',1,'',40,40,'','','','','',500,0,'',18,11,2013,519,'Bárdosi Attila','Pathétique','978-615-5110-20-7',2,'','6','140x200 mm',256,'0',1990,1,'#LA2# keménytábla','Bardosi-Attila','http://www.konyvesbolt.online/spd/978-615-5110-20-7/Bardosi-Attila-Pathetique-Ad-Librum-2013','','','','http://www.konyvesbolt.online/spd/978-615-5110-20-7/Bardosi-Attila-Pathetique-Ad-Librum-2013','','','',3,3,4,7,4,5,3,'2013-9-4','2013-11-18','Appenrode 5 37130 Göttingen BRD, 004915142418295','abardosi@web.de','A Németországban élő költő 2013-as versei.','„Bárdosi Attila versei a harminckét zongoraszonáta meghallgatásának, átélésének hatására, az inspiráció erejével születtek. A költő lelkében élő, szüntelenül munkálkodó gondolatok és asszociációk találkoznak a zeneszerző kompozícióiból áradó szellemiséggel, így mi – bármilyen furcsának is tűnhet – egy párbeszédhez hasonló műfajban találjuk magunkat. Megérezhetjük, hogy milyen lehet megmártózni a zsenialitás titkos tavában. Milyen fényszög világíthatja meg testi-lelki fejlődésünk különböző állomásait? Vajon tényleg érzékeljük-e őket?“
Klukon Edit - zongoraművész

„Nahát! Már megint micsoda merész kísérletre vállalkozott a „fiatal költő”! – csettintettem elismerően, először csak a címet és a kézirat mennyiségét látva, amikor kézbe vettem Bárdosi Attila újabb versciklusát…..! De a ciklus alcímét olvasva már kissé összevontam a szemöldökömet: lírai asszociációk Beethoven 32 szonátájára? Olyasféle parnasszista szonettekre gyanakodtam, úgyhogy átugorva a többoldalas prózai bevezetőn, mindjárt a versek olvasásába kezdtem. Hála Isten, semmi jele annak, amire gyanakodtam! Bárdosi Attila új versciklusa a lírikus legszemélyesebb érzéseit rögzíti, amelyekhez csupán „sorvezetők” Beethoven szonátái. Ezek után lapoztam vissza a költő prózai bevezetőjéhez. Pontos zenetörténeti, zeneelméleti kiselőadás! Szinte röstelkedem a magam zenei analfabetizmusa miatt. Mit akarok én itt megmagyarázni? Tessék elolvasni a kötetet! Figyelmesen, elejétől a végéig!”
Sumonyi Zoltán - költő','','',1451297737,0);
INSERT INTO books VALUES('',0,'','Vasi_Szabo_Janos--Levegokovacs--FD.jpg','',2,1,1,3,13,'',1,1360,10,'','','','','','',16,0,'',25,10,2013,520,'Vasi Szabó János','Levegőkovács','978-615-5014-74-1',2,'','6','140x200 mm',124,'0',1690,5,'#LB5#','Vasi-Szabo-Janos','http://www.konyvesbolt.online/spd/978-615-5014-74-1/Vasi-Szabo-Janos-Levegokovacs-Ad-Librum-2013','','','','http://www.konyvesbolt.online/spd/978-615-5014-74-1/Vasi-Szabo-Janos-Levegokovacs-Ad-Librum-2013','','','',3,0,4,7,4,5,4,'2013-9-10','2013-10-25','9762 Tanakajd, Kossuth L. u. 26. Tel.: 94/711-108','vasi.szabo.janos@gmail.com','','Különös világokba vezet minket ez a könyv. Világokba – mondom –, hiszen sokan talán csak tudat alatt érezzük, de megfogalmazni nem tudjuk, hogy immár nem egyetlen világban élünk, hanem legalább kettőben, az egyik, amelyet a Biblia szerint az Úr teremtett, a másik, amelyet az ember hozott létre a maga szeretetével és kegyetlenségével. E kettő vagy több(?) világ között vajon hol vannak az átjárók? Ha nincs vezetőnk nem érzékeljük őket, s éppen ebből fakad Vasi Szabó János alkotói módszere. A sokat megélt és tapasztalt író vezet minket e bonyolult élet útvesztőiben. Miközben őrzi a prózaírás hagyományait, meg is újítja azokat. „Mágikus realizmus”. Vasi Szabó János alkotó stílusát jelöli e kifejezés, nem az én találmányom, hanem egyik kritikusáé, de magam is találónak érzem. Van azonban egy nagyon fontos jellemzője is: még a legdrámaibb, legtragikusabb történetnek is van feloldása, jövőt sejtető katarzisa. Az igazi, népéért felelősséget érző író használni akar. E könyv haszna is kétségtelen, ezért bízvást ajánlhatom az olvasók szíves figyelmébe.
Varga Tibor','10 példány a szerzőnek 1000Ft+124old*3Ft-os áron.','',1451301658,0);
INSERT INTO books VALUES('',0,'','Bardosi-Reglodi--Valaszok_a_valaszokra--FD.jpg',432,0,1,0,0,2,'',1,'',40,40,'','','','','',500,0,'',14,3,2014,521,'Bárdosi Attila és Reglődi Dóra','Válaszok a válaszokra. Versek 2013-2014','978-963-87819-6-3',2,'','7','140x200 mm',228,'0',1990,1,'#LA2# védőborítós keménytábla #Artúr','Bardosi-Attila','http://www.konyvesbolt.online/spd/978-963-87819-6-3/Bardosi-Attila-es-Reglodi-Dora-Valaszok-a-valaszok','','','','http://www.konyvesbolt.online/spd/978-963-87819-6-3/Bardosi-Attila-es-Reglodi-Dora-Valaszok-a-valaszok','','','',3,3,4,7,4,5,3,'2014-1-29','2014-3-14','Appenrode 5 37130 Göttingen BRD, 004915142418295','abardosi@web.de','A hivatásuk révén élet és halál mezsgyéjén mozgó két szerző egymást több síkon inspirálva ír elmúlásról és mindennapi örömökről. ','A kötetben szereplő versek, grafikák két tartalmilag teljesen különböző, de érzelmileg hasonló múltú életvonal egy pontban történő kereszteződésének eredménye. Két nem mindennapi hivatás, egy anatómus és egy patológus találkozott egy keskeny ösvényen az élet és a halál mezsgyéjén, ahol mindkettő ugyanazzal a dologgal foglalkozik – bár másként hangzik –, de mégis ugyanarra a kérdésre keresik mindketten a választ: az anatómus „Miért élünk?”, a patológus „Miért halunk meg?”. Ebből kifolyólag látószögünk, egymásba ötvöződve gyakran és néha meglepő formában különbözik a megszokottól, a mindennapitól. Foglalkozásunk következtében értékrendszerünk valószínűleg sok téren eltér az általánostól. Talán érzékenyebben reagálunk olyan dolgokra, amelyek az elmúlással kapcsolatosak, talán jobban odafigyelünk a mindennapi kis örömökre, amik fölött sokan könnyelműen elsiklanak, és azok értéke csak életük egy váratlan, gyakran tragikus időszakában tudatosul bennük ismét. Mégsem gondoljuk azt, hogy a versek hangulatukkal kizárólag azokat az élményeket tükrözik, amelyek bennünket hivatásunk révén, akaratunktól függetlenül naponta érintenek, és a laikusok képzeletében negatív érzelmeket ébresztenek. Talán sikerül verseinkkel ezeket a köztudatban kialakult, torzult képeket más tartalommal, más színekkel újrafesteni, hiszen ez a valóság, hiszen ezek mind hozzánk, emberekhez tartoznak, hiszen mind ezekből vagyunk.
A versek nem két különböző nézőpontot tárnak fel, ellenkezőleg, egymást kiegészítve, egymást több síkon inspirálva összeadódott két élet, amelyeknek végeredménye több lett mint pusztán a kettő összege.','','',1451297882,0);
INSERT INTO books VALUES('',0,'','Joba_Katalin--Cinegemese--FD.jpg',31,'',1,0,0,16,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,7,5,2014,522,'Jóba Katalin','Cinegemese','978-963-87819-5-6 ',2,'','7','130x200 mm',8,'0',1200,1,'#LB6# T&B:B Nyomda: Empire Media','','http://www.konyvesbolt.online/spd/978-963-87819-5-6_/Joba-Katalin-Cinegemese-Ad-Librum-2014','','','','','','','',3,3,4,7,4,5,4,'2014-2-3','2014-5-7','1024 Budapest Keleti Károly u. 46. I/4. 30/313-6750','joba.katalin@gmail.com','','Kedves történet, bájos mese – ami akár igaz is lehetne. Gyereknek és felnőttnek is szól ez a vers: egy cinkéről és a megmentőjéről, barátságról és szerelemről, elválásról és egymásra találásról. Aki eddig elolvasta, mosolygott közben és örömmel vette kézbe újra.','',NULL,1480929120,0);
INSERT INTO books VALUES('',0,'','Diviki_Emma--Gacsari_Kronika--FD.jpg',325,0,1,1,0,31,'',1,1636,10,'','','',NULL,NULL,'',30,0,NULL,11,3,2014,523,'N. Diviki Emma','175 éves a füzesgyarmati Gacsári Krónika','978-963-87819-7-0',1,'','7','148x210 mm',212,'0',2900,5,'#LB2','Gacsari','http://www.konyvesbolt.online/spd/978-963-87819-7-0/N--Diviki-Emma-175-eves-a-fuzesgyarmati-Gacsari-Kr','','','','http://www.konyvesbolt.online/spd/978-963-87819-7-0/N--Diviki-Emma-175-eves-a-fuzesgyarmati-Gacsari-Kr','','','',3,3,1,9,4,5,5,'2014-2-0','2014-3-11','Nagyné Diviki Emma, Budapest 1171 Földeák u. 25., 258-8423','ammeikivid@gmail.com','','Jelen gyűjteményes mű magába foglalja „A Füzes Gyarmati Helvéziai Hitvallású Szent Ekklézsiának Krónikája” című művet és az íróját, Gacsári Istvánt méltató írásokat és idézeteket, valamint először közöli,  175 éves Krónika teljes, eredeti szövegét.
   Cél: Méltón emlékezni a 175 éves Krónikáról, s egyben lehetővé tenni, hogy végre, bárki hozzáférhessen, olvashassa.
   Gacsári István hitvallása; szülőföldje múltjának, őseinek megismerése, minden hazafi számára elengedhetetlen. A nemzet felemelkedésének záloga, a múlt ismerete. Krónikájával ehhez akart hathatós segítséget nyújtani. 
   Helytörténeti írása nemcsak Füzesgyarmat és a környező települések, hanem a nemzet számára is pótolhatatlan értéket képvisel. Munkásságán keresztül bepillantást enged az ország történetébe és népe életébe.
   Családkutatáshoz is jelentős forrásanyagot hozott létre. Gacsári István Krónikája egyedülálló a maga nemében. Lelkipásztori hivatása révén, személy szerint ismerte szülőföldje népét. Krónikájában név szerint felsorolta valamennyi hivatalt betöltő nevét és a szolgálatuk évét. Mintegy 176 családot sorol fel, származási helyük megnevezésével. Ezzel nagy segítséget ad, nemcsak a helyben lakók, hanem az elszármazottak, akik ma már az ország egész területén megtalálhatók, vagy az ország trianoni határán kívül rekedtek számára, hogy őseikre rátaláljanak.    
   Magatartásával példát mutatott Krónikájával minden magyarnak üzent. Ismerjük meg üzenetét!','Utánnyomás 2014.06.17.:
22 példány x 1636 Ft x 90% = 32393 Ft
6 kötelespéldány x 1636 Ft x 50% = 4908 Ft
Összesen 37.301 Ft
Szállítási költség 2000 Ft
A kötetek kiszállítását a lakására: 1171 Bp. Földeák u. 25.

24 pld. utánrendelése a Print Shop Prótól 2014.06.17.',NULL,1452510748,0);
INSERT INTO books VALUES('',0,'','Tarator--Szellel_szemben--FD.jpg',317,1,1,0,0,10,'',1,'',40,40,'','','','','',300,0,'',28,5,2014,524,'P. Tarator','Széllel szemben','978-615-5110-66-5',2,'','7','148x210 mm',246,'0',2800,1,'#LC3,LGVI#  A5 Olaszi Tamás; T:G B:V','Tarator','http://www.konyvesbolt.online/spd/978-615-5110-66-5/P--Tarator-Szellel-szemben-Ad-Librum-2014','','','','http://www.konyvesbolt.online/spd/978-615-5110-66-5/P--Tarator-Szellel-szemben-Ad-Librum-2014','','','',3,3,4,7,4,5,4,'2014-2-25','2014-5-28','Olaszi Tamás, 70/201-5846, 8230 Balatonfüred, Ibolya u. 5/C. I/3.','olaszi.tamas@gmail.com','Minden egy apró szívességgel kezdődik, de főhősünk hamarosan Írország szél szaggatta vidékein találja magát egy összeesküvés nyomában. Sarkában pedig üldözők járnak, akik nem ismernek félelmet, fájdalmat, vagy olyan régi bölcsességeket, hogy soha ne szívózz az írekkel.','Írország, 2008. Választás előtt áll az ország. A legtöbben sör mellett döntenek.
Egy népszavazás, ami átírhatja Európa történelmét. Egy kis ország, ami egy kontinens jövőjét határozhatja meg. Egy határozott és céltudatos ember, aki mindig eléri célját. 
Leszerelt katonák, akik nem csak a felmosórongyhoz értenek. Csempészek, akik távolra tudnak köpni, és habozás nélkül meg is teszik. Egy nagyformátumú nő. És ami a legijesztőbb: kockás inges, kordbársony nadrágos, zoknival viselt szandálos mérnökök. 
Egy újságíró találkozik egy régi baráttal, és akinek ilyen barátja van, annak már nincs szüksége ellenségre. Minden egy apró szívességgel kezdődik, de hamarosan Írország szél szaggatta vidékein találja magát egy összeesküvés nyomában, amelynek szálai messze túlmutatnak az ország határain. Sarkában pedig üldözők vannak, akik nem ismernek félelmet, fájdalmat, vagy olyan régi bölcsességeket, hogy soha ne szívózz az írekkel.

„– Sláinte – emelte poharát Finian, amiből arra következettem, hogy ez az egészségedre helyi változata.
– Sláinte – mondta Orlagh is, és én is mondtam valami hasonlót, ami után elnéző mosollyal hozzákoccintották poharukat az enyémhez.
– Látjátok azt a szikár embert a pultnál újságot olvasni? – kérdezte Finian.
– A kitaposott cipőben? – kérdeztem.
– Igen. Ő amolyan helyi híresség. Költő és drámaíró. Mármint hogy íróból van itten sok, mert telente az ember vagy drámát csinál vagy gyereket, de ő olyan, akinek ki is adták az írásait.
– Olvashattam tőle valamit?
– Nem hiszem, mert gaelic nyelven ír. De igen termékeny író. Kilenc gyereke van és hét drámája.”','Rossz nyomás és hibás elválasztások: újranyomás 2014. június.','',1451380407,0);
INSERT INTO books VALUES('',0,'','Karsten_es_Beckman--Tul_a_demokracian--FD.jpg',131,'',1,0,0,40,'',1,1400,10,'','','',NULL,NULL,'',30,0,NULL,16,4,2014,525,'Frank Karsten és Karel Beckman','Túl a demokrácián','978-963-08-8813-4',1,'','7','140x200 mm',100,'0',2000,5,'#LB3 Váradi István','','http://www.konyvesbolt.online/spd/978-963-08-8813-4/Frank-Karsten-es-Karel-Beckman-Tul-a-demokracian-A','','','','','','','',3,3,1,9,4,5,5,'2014-2-0','2014-4-16','Váradi István, 1174 Budapest, Kisfaludy u. 13., 30-334-6892','ivaradi@gmail.com','A szerzők egyszerű, közérthető érvekkel mutatják be, hogy a közhiedelemmel ellentétben a demokrácia nem a szabadság, a civilizáció, a jólét, a béke és a törvényesség záloga, hanem éppen ellenkezőleg: az egyéni szabadságjogok csorbulásának, a társadalmi konfliktusok erősödésének, az állami kiadások egekig szökésének és az életszínvonal csökkenésének az oka.','A szerzők szerint a demokráciát az emberek túlnyomó többsége a lehető legjobb politikai rendszernek tartja. Nem túlzás azt állítani, hogy a demokrácia egyfajta világi vallássá, a Föld legnagyobb politikai hitévé vált. Könnyen a civilizált társadalom ellenségének nyilváníthatják azt, aki kritizálja a demokráciát. 

Azonban mégis ez az a feladat, amire Karel Beckman és Frank Karsten vállalkozott. Rendkívül olvasmányos, provokatív könyvükben vitába szállnak az utolsó fennmaradt politikai tabuval, miszerint üdvösségünk kulcsa a demokrácia.

Egyszerű, közérthető érvekkel mutatják be, hogy a közhiedelemmel ellentétben a demokrácia nem a szabadság, a civilizáció, a jólét, a béke és a törvényesség záloga, hanem éppen ellenkezőleg: az egyéni szabadságjogok csorbulásának, a társadalmi konfliktusok erősödésének, az állami kiadások egekig szökésének és az életszínvonal csökkenésének az oka.

Megcáfolnak 13 olyan mítoszt, amellyel általában védeni szokták a demokrácia intézményét. Emellett vonzó alternatívát is kínálnak: az egyéni szabadságjogokon és az önkéntes társadalmi kapcsolatokon alapuló társadalmi berendezkedést.

Nem érti, miért nő egyre inkább az állam mérete, miért emelkedik az államadósság, miközben a szabadságjogai és a jóléte egyre inkább veszélybe kerül? A könyv elolvasása eloszlat minden kétséget, tudni fogja mindez miért történik, és hogy mi a megoldás.

A Túl a demokrácián rendkívül érdekes, úttörő munka mindazok számára, akik jobban meg kívánják érteni a jelenleg tapasztalható társadalmi problémák és a gazdasági válság okait.','10 pld. a megbízónak kiadáskor.',NULL,1481799035,0);
INSERT INTO books VALUES('',2,'','Gabor_Kerekes--Literatur_diesseits_und_jenseits_des_Rennweg--FD.jpg','',0,0,2,0,41,'',0,'',0,0,'','','','','',50,0,'',14,5,2014,526,'Gábor Kerekes','Literatur diesseits und jenseits des Rennweg. Studien zur österreichischen Literatur','978-963-87819-8-7',2,'','6','140x200 mm',128,'0','',1,'#LB5#  T:szerző','','','','','','','','','',3,3,1,9,4,5,5,'2014-3-3','2014-5-14','Dr. Kerekes Gábor 06-26-331-695 Cím: 2085 Pilisvörösvár, Puskin köz 3.','kegahu@yahoo.de','','','','',1421316784,0);
INSERT INTO books VALUES('',0,'','SolutionSurfers--Brief_Coaching--FD.jpg','',0,1,0,0,34,'',0,'',40,70,'','','','','',500,0,'',19,5,2014,527,'Chris Iveson, Evan George, Harvey Ratner','Brief Coaching. Megoldásközpontú megközelítés','978-963-08-9075-5',3,'SolutionSurfers Magyarország Kft.','7','135x200 mm',224,'0','',1,'#B2 SolutionSurfers B&T:B','Coaching','','','','','','','','',3,3,1,9,4,5,4,'2014-3-31','2014-5-19','SolutionSurfers Magyarország Kft., 1222 Budapest, Lőcsey u. 6/A., 20/421-8300, +41 79 432 2108','info@handlungsspielraeume.com','','„A coaching eleganciájáról és szépségéről írt talán legforradalmibb jelenleg kapható könyv. A szerzők mintegy 30 év tapasztalatát sűrítették a könyvbe, az olvasó kezébe helyezve a coaching esszenciáját. Könnyed és kellemes olvasmány, ugyan akkor elgondolkodtató és egyben gyakorlatias. Az olvasó könnyen azon kaphatja magát, hogy a javasolt kérdéseket, megfogalmazásokat akár már a következő coachingbeszélgetésében is alkalmazza, hiszen vonzók és zseniálisak. Ráadásul lenyűgöző, hogy egészen rövid idő alatt milyen tartós változásokat eredményeznek. Hihetetlen? Olvassa el, és tanuljon a legjobbaktól! Hasznos olvasást!”
Peter Szabó MCC , a „Coaching Plain and Simple” társszerzője, a Solutionsurfers egyik alapító tagja

A megoldásközpontú megközelítés olyan új szemléletet ajánl, amely arra
fókuszál, hogy miből fogja tudni az ügyfél, hogy céljait elérte, és mit tesz már most is, ami segíƟ majd, hogy ezt megtegye. A megoldásközpontú coach a megoldás felé tereli ahelyett, hogy a problémától távolítaná az ügyfelet. Így a probléma nem is kap a beszélgetéseken központi szerepet, helyette a coach és az ügyfél a remélt jövő felé dolgozik.

A könyv coachingeseteket dolgoz fel, és coachingbeszélgetések részleteit elemezve kínál útmutatást arra, hogyan lehet:
• az erőforrásokat megtalálni a hibák helyett,
• felfedezni a lehetséges és remélt jövő képét,
• megvizsgálni, hogy mi járul már jelenleg is az elképzelt jövőhöz,
• ügyfeleinket életük összes területének szakértőjeként kezelni.

Chris Iveson , Evan George és Harvey Ratner a BRIEF független tréning,
terápia és tanácsadó cég alapító tagjai, és megoldásközpontú brief terápiával dolgoznak.','A papír 100 grammos Niveus Print/Mondi.','',1405159163,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Mindhalálig--FD.jpg','',0,1,0,0,12,'',1,'',0,0,'','','','','',50,0,'',3,6,2014,528,'P. Dobrossy Rita','Mindhalálig','978-615-5110-68-9',2,'','7','140x200 mm',240,'0',2490,5,'#LB3','','http://www.konyvesbolt.online/spd/978-615-5110-68-9/P--Dobrossy-Rita-Mindhalalig-Ad-Librum-2014','','','','http://www.konyvesbolt.online/spd/978-615-5110-68-9/P--Dobrossy-Rita-Mindhalalig-Ad-Librum-2014','','','',3,3,2,1,2,5,4,'2014-3-25','2014-6-3','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051, férj: 30/292-2034','dobrozsirita@freemail.hu','','A könyv két kisregényt tartalmaz, ahol a második írásom, az első folytatása. 
Elgondolkodtató tartalom jellemzi mindkét részt, hiszen két középkorú barátnő először megpróbálja egy időre újra felidézni elmúlt ifjúságának minden boldogságát, minden szerelmes percét, de egyikük tragikus végkimenetelű esete ráébreszti a másikat: életmódot kell változtatniuk, mert ez már nem az ő világuk! Bele kell törődniük az idő múlásába...
Második könyvemben, az eddigi női főszereplő teljes életmódváltáson esik át, mert úgy érzi így KELL élnie... Egy vidéki házba költözve, - még mutatósan, csinosan -, mégis teljesen egyedül várja az öregedés minden fázisát, noha teste-lelke tiltakozni kezd ez ellen, mikor megismerkedik a tőle majdnem két évtizeddel fiatalabb zenésszel és nem tud parancsolni érzéseinek...
 
        "jöjj hát, és hazudd azt, hogy nincsen veszve még,
         Amíg a régi tűz szívedben ég
         Amíg egy régi daltól könnyes lesz szemünk
         Ez a tűz, ez a dal, ez az édes életünk..."
                                                                                      Bródy János','40 pld. a szerzőnek','',1451377970,0);
INSERT INTO books VALUES('',1,'','Kontschan_Jeno--Uropodina_mites_of_Transylvania--FD.jpg',181,0,1,1,0,43,'',1,1548,'','','','','','','',40,0,'',8,7,2014,529,'Kontschán Jenő','Uropodina mites (Acari: Mesostigmata) of Transylvania (Romania)','978-615-5110-67-2',2,'','7','140x200 mm',140,'0',2500,5,'#LB2','','http://www.konyvesbolt.online/spd/978-615-5110-67-2/Kontschan-Jeno-Uropodina-mites-Acari-Mesostigmata-','','','','http://www.konyvesbolt.online/spd/978-615-5110-67-2/Kontschan-Jeno-Uropodina-mites-Acari-Mesostigmata-','','','',3,3,1,7,4,5,0,'2014-4-0','2014-7-8','Dr. Kontschán Jenő, 30/768-6927, ideiglenes lakcím: 1215 Budapest, Árpád u. 12/C. 2/62.; állandó: 2840 Oroszlány, Takács I. u. 3.','jkontschan@gmail.com','A könyv Erdély korongatka faunáját mutatja be.','','','',1451383444,0);
INSERT INTO books VALUES('',0,'','Thomas_Z_Marshall--Egek_fele--FD.jpg',265,'',1,0,10,9,'',1,'',40,40,'','',NULL,NULL,'',300,0,NULL,29,10,2014,530,'Thomas Z Marshall','Egek felé','978-615-5110-69-6',2,'','7','140x200 mm',128,'0',2900,1,'#LB4,LGVI#Tamás Zoltán keménytábla, ragasztott belív','','http://www.konyvesbolt.online/spd/978-615-5110-69-6/Thomas-Z-Marshall-Egek-fele-Ad-Librum-2014','','','','','','','',3,3,4,7,4,5,5,'2014-5-10','2014-10-29','Tamás Zoltán, 9024 Győr, Babits M. u. 9., 20/326-2757, 96/337-613','tamas.zoltan2010@gmail.com','A regény főhőse kidolgoz egy, az internet forradalmára épülő elméletet és hozzá kapcsolódó számítógépes programot, amely a társadalmi döntés hatalmát és szabadságát az uralkodó kaszt kezéből átadja a közösségnek. Ezzel elindul a kálváriája.','Az „Egek felé” fordulatokkal teli, mozgalmas, kiszámíthatatlan, kifejezetten szórakoztató, egyúttal mélyen elgondolkodtató kisregény. Stílusa mesterien tömör, és feszültségekkel teli. Egy XXI századi szerelmi - és karriertörténet, amely bemutatja, hogy a társadalmi illúzióknak hinni akaró átlagpolgár miként lesz játékszere a politika intrikáinak.

A regény főhőse boldog, kiegyensúlyozott szerelmi házasságban éli a középosztály mindennapi életét, mégis abban különbözik a legtöbb sorstárától, hogy komolyan veszi a demokrácia, és a szabadság, egyenlőség, testvériség eszményét. Kidolgoz egy, az internet forradalmára épülő elméletet és hozzá kapcsolódó számítógépes programot, amely a társadalmi döntés hatalmát és szabadságát az uralkodó kaszt kezéből átadja a közösségnek. Munkája eredményét szeretné a gyakorlatban megvalósítani, ezért felveszi a kapcsolatot a politikai és pénzügyi hatalom tagjaival. Azzal, hogy a főhős komolyan elhiszi a minden ember egyenlő ígéretét, elindul a kálváriája.','50%-os leárazást kért minden kiadványára 16.12.15.',NULL,1481876120,0);
INSERT INTO books VALUES('',0,'','Bardosi_Attila--Allati_tukorkepek--FD.jpg',257,0,1,0,0,2,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,7,11,2014,531,'Bárdosi Attila','Állati tükörképek','978-615-5110-70-2',2,'','7','140x200 mm',98,'0',1990,1,'#LA3,LB7#; 94 ff + 4 színes oldal','','http://www.konyvesbolt.online/spd/978-615-5110-70-2/Bardosi-Attila-Allati-tukorkepek-Ad-Librum-2014','','','','http://www.konyvesbolt.online/spd/978-615-5110-70-2/Bardosi-Attila-Allati-tukorkepek-Ad-Librum-2014','','','',3,3,4,7,4,5,5,'2014-9-16','2014-11-7','Appenrode 5 37130 Göttingen BRD, 004915142418295','abardosi@web.de','','Aesopus, La Fontaine fabulái, meséi, Nagy Lajos ironikus, prózai jellemképei, Romhányi József nyelvi zsonglőrmutatványai; ki ne ismerné ezeket a páratlan alkotásokat, amelyeknek közös jellemvonása, hogy főszereplői állatok. A kézben tartott verseskötet - hangulatilag más jellegű megközelítéssel - ezek közé sorolható be, Nem példálózva, úgymond a „mutatóujjat“ fölemelve, hanem az emberi agyban tükröződő, valóságként fölfogott klisék, téveszmék, és az állatok által reflektált emberi tükörképek révén tart elénk (görbe)tükröt, feltárva ezzel azt az alapvető hibát, amelyet mi ismételten, újra és újra a környezetünkben élőkkel szemben csökönyösen elkövetünk: Mindent a saját szemszögünkből magyarázunk, mindent a saját tapasztalataink szerint, a saját erkölcsi normáinknak keretén belül, határtalan arroganciával ítélünk meg. Ez ugyanúgy érvényes egy állatfaj teljesítményének minőségi (le)értékelésére, mint azok intelligenciájára, szociális, valamint érzelmi viselkedésére. Ezzel szemben sokkal logikusabb és ésszerűbb lenne, ha mindent és mindenkit saját adott környezetének, életkörülményeinek határain belül bírálnánk el és minősítenénk. Ha ezt tennénk, hamar világossá válna, hogy az úgynevezett felsőbbrendűségünkbe vetett hitünk megalapozatlan. Az evolúció szemszögéből nézve; senki és semmi sem fejlettebb vagy fejletlenebb a másiknál, feltéve, ha saját mércéjével és saját környezetén, életterén belül mérettetik meg.

Jóllehet a rejtvényszerű versek elején nem szerepel a cím, biztosak lehetünk abban, hogy néhány sor után nem csak a versekben szereplő állatokra, hanem önmagunkra is ráismerünk majd.','',NULL,1451297800,0);
