INSERT INTO books VALUES('',0,'','Bardos_Erika--Az_onismeret_a_harmonikus_elet_kulcsa--FD.jpg',324,'',1,0,0,28,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,23,11,2016,536,'Bárdos Erika','Az önismeret a harmonikus élet kulcsa','978-615-5686-44-3',2,'','9','130x200 mm',260,'0',3490,1,'#LE,LGVI#','','http://www.konyvesbolt.online/Bardos-Erika-Az-onismeret-a-harmonikus-elet-kulcsa','','','','','','','',3,3,4,7,4,5,3,'2016-10-19','2016-11-23','2151 Fót, Mézeskalács u. 17.; 30/332-0550','ebardos47@gmail.com','','A horoszkóp, az univerzum köre, életünk kerete adott. Születésünk pillanatában megérkezünk a magunk választotta pontjára, valamilyen céllal, megoldandó feladattal. Ez a sorsunk, a karmánk, ezt kell megcselekednünk. A jövőnk kulcsa, a megoldás abban rejlik, hogy felismerjük-e a karmánk szabta feladatot, és hogy azt hogyan teljesítjük.
Az asztrológia nem jóslás, hanem a sorsfeladatunk tudatosításáról és elfogadásáról szól.
Ez az asztrológiai kézikönyv a lehető legegyszerűbb alapokon nyugszik: elegendő ismerni a Szaturnusz, a Jupiter, valamint a Nap jegy és az uralkodó bolygójának elhelyezkedését a horoszkópban jegyek és házak szerint.
A könyv elsősorban azoknak szól, akik alapvető asztrológiai ismeretekkel rendelkeznek, és szeretnének könnyen eligazodni, esetleg másoknak is tanácsot adni, hogy miként ismerhetik fel a nekik rendelt utat.','Bankszámlaszám: 10205000-08960661 (K&H).',NULL,1483438656,0);
INSERT INTO books VALUES('',0,'','Barczikay_Lilla--Batyam_konnyei--FD.jpg',404,'',1,0,11,16,'',1,'',15,15,'','',NULL,NULL,'',400,0,NULL,3,6,2016,537,'Barczikay Lilla','Bátyám könnyei',' 978-615-5110-82-5',2,'','9','145x205 mm',280,'0',3290,1,'#LD#','','http://www.konyvesbolt.online/Barczikay-Lilla-Batyam-konnyei','','','','','','','',3,3,1,7,4,5,1,'2016-4-0','2016-6-3','Barczikay Lilla, 1022 Budapest Vadrózsa u. 03. II/3., 70/492-7182','barczikaylilla@gmail.com','Nita és csapata mindent maguk mögött hagyva útra kelnek halottnak hitt testvérük felé. Az Anyám teremtményei folytatása.','Nita és csapata mindent maguk mögött hagyva útra kelnek halottnak hitt testvérük felé. Aprócska buszukban összezsúfolódva próbálnak megküzdeni az életüket meghatározó kitaszítottsággal és üldözöttséggel. Korábbi győzelmükre fájdalmas homály borul, megmaradt ellenségeik elől pedig nincs hová elbújni. A hárpiák semmit sem kímélnek, hatalmas a bosszúvágyuk, hogy az egész csapatot eltöröljék a föld színéről. Titkok, családok, szerelmek… már semmi nincs biztonságban! Nitáék mégsem adják fel, szemük előtt pedig egyetlen mondat lebeg: „Ő jobbat érdemel!”.
Az Anyám teremtményei folytatása.','',NULL,1479893581,0);
INSERT INTO books VALUES('',0,'','Zsiros_Andras--Tarajosvilag--FD.jpg',337,'',1,0,0,43,'',1,'',0,0,'','',NULL,NULL,'',500,0,NULL,7,6,2016,538,'Zsiros András','Tarajosvilág. Hányféleképpen hajthat hasznot a sokszínű baromfiudvar?','978-615-5110-84-9',5,'','9','148x210 mm',200,'0',3990,3,'#LD,LGrégi salgó# 8 színes oldal, X ff és 16 színes kép','','http://www.konyvesbolt.online/Zsiros-Andras-Tarajosvilag','','','','','','','',3,3,4,7,4,5,1,'2016-3-0','2016-6-7','30/256-7046, 2200 Monor Munkácsy u 16','amon29@citromail.hu','Kézikönyv a baromfitartás iránt érdeklődőknek. Válaszok a fajtaválasztás, takarmányozás, keltetés és hasonló alapkérdésekre. 
8 oldal színes kép;','Ez a könyv mindazoknak szól, akik érdeklődnek a baromfitartás iránt és egyetlen helyen szeretnének utánanézni felmerülő kérdéseiknek. A témában jártas szakértő szerző úgy állította össze írását, hogy azok is találjanak benne hasznos tanácsokat, akik csak most kezdenek bele a háztáji állattartásba, de azok is haszonnal forgathassák, akik régóta foglalkoznak baromfitenyésztéssel. A Tarajosvilág igyekszik minden fontos kérdést tárgyalni: az állatok kiválasztását, élőhelyük kialakítását és táplálásukat éppúgy, mint a keltetés, a tenyésztés és a versenyeztetés mesterfogásait. A kötet kuriózuma az összesen 60 baromfifajtát bemutató részletes ismertető.
A szerző, aki az Ad Librum Kiadó Hobbinyúltenyésztés című könyvének is szerzője, szívesen válaszol az olvasók kérdéseire a kisallattenyesztes.hu weboldalon.','',NULL,1472544085,0);
INSERT INTO books VALUES('',0,'','','','',1,0,31,26,'',1,'',10,10,'','',NULL,NULL,'',1000,0,NULL,15,6,2017,539,'Mikos Ákos','Esküvő Tour – Így éld meg jól az esküvődet!','978-615-5686-67-2',5,'','10','130x200 mm',160,'0',2490,3,'T Aktív Szerző','','','','','','','','','',2,3,2,1,1,1,1,'2017-4-1','2017-6-15','70/250-4028','mikosa@radio88.hu; mikos.akos87@gmail.com','','Most szervezed az esküvőtöket?
Fejtörést okoz, hogy kit hívjatok meg?
Mit illik és mit nem?
Mitől tartasz a legjobban?
Egyáltalán hogyan készülj?
Izgulsz? 
             Esküvő Tour - Az izguló jegyespárok végső menhelye
Ceremóniamesterként már sok mindent megéltem, vallástudományi tanulmányaim alatt sok mindent megértettem.
Öt éve töltöm a hétvégéimet boldog párokkal, lelkes násznéppel és odaadó segítőkkel. 
Ugyanúgy izgulnak és ugyanúgy aggódnak, mint most te és a párod.
Kulcsot adok nektek ahhoz, hogy élményekben gazdagon, gondtalanul éljék meg ezt a napot.
Ez a könyv sok tippet és trükköt ad, de a legjobb, hogy az eredményt együtt fogjuk elérni, átélni.
Együtt tudom, menni fog, mert oltári jók vagytok!','Egyéni vállalkozóként szerződött.
Kézirat leadása 2017. április 01-ig.
Megjelenik a Könyvhét előtt.',NULL,1487711083,0);
