INSERT INTO books VALUES('',0,'','Solti_Gabriella--Elet-enek--FD.jpg','','',1,0,0,2,'',1,'',30,30,'','',NULL,NULL,'','',0,NULL,24,3,2017,548,'Solti Gabriella','Élet-Ének','978-615-5686-73-3',2,'','10','120x200 mm',72,'0',1990,1,'','','http://www.konyvesbolt.online/Solti-Gabriella-Elet-Enek','','','','','','','',2,3,4,8,3,4,3,'2017-2-7','2017-3-24','2040 Budaörs, Rezeda u. 38.; tel:30/210-2576','gabcso@hotmail.dom','','Harminckét év gyöngyszemeit gyűjtöttem egybe Önnek nagy szeretettel:
szenvedélyből és fájdalomból született verseket, rajongással készült műfordításokat a csodálatos orosz irodalom kincsesládájából, és kalandos életem tapasztalatait összegző aforizmákat.
Egy pesti lány vagyok, aki „megjárta a Don-kanyart” (a voronyezsi egyetem bölcsészkarán végeztem), de aki jól ismeri Párizs és Brüsszel sokszínűségét is (összesen öt évet éltem ezekben a városokban). E két oly különböző világ megismerése az elvágyódást mély és igaz szeretetté nemesítette bennem minden és mindenki iránt,
amit és akiket egykor itthagytam.
Teljes szívvel remélem, hogy a verseimmel és aforizmáimmal átadhatom azt a boldogságot, amit a készülésükkor éreztem.','Szerző szállítja a nyomdai fájlokat.
Ny: Érd.',NULL,1489384832,0);
