INSERT INTO books VALUES('',0,'','Kovacs_Gyorgy--A_kereszteny_vallas_megszuletesenek_tortenete--FD.jpg',412,'',1,0,39,28,'',1,'',40,40,'','',NULL,NULL,'',500,0,NULL,12,12,2014,555,'Kovács György','A keresztény vallás megszületésének története','978-615-5110-71-9',2,'','7','165x235 mm',120,'0',3890,1,'#LC4,5, LGV# ragasztott keménytábla, 4 színes oldal','','http://www.konyvesbolt.online/spd/978-615-5110-71-9/Kovacs-Gyorgy-A-kereszteny-vallas-megszuletesenek-','','','','','','','',3,3,4,7,4,5,5,'2014-9-24','2014-12-12','Kovács György, 30/677 03 06, állandó: 5600 Békéscsaba,  Kodály Zoltán u. 10.','gyorgy.kovacs-strabag-jc@strabag.com','Ez a könyv megkísérli értelmezni azt, hogy történeti szempontból mely események vezettek el a keresztény vallás megszületéséhez, nagy vonalakban végigkíséri, hogyan vált a keresztény vallás világvallássá. Keménytáblás, 4 színes oldallal.','A keresztény vallás történetét a történetiség szempontjából kutató elemzések kevés figyelmet fordítanak annak az értelmezésére, hogy mely események bekövetkezése indította útjára a keresztény vallást, illetve hogy miért Jézus vált a Krisztussá a keresztény emberek szemében. Az eseményeknek ilyen célú történeti megközelítése azonban tudományos szempontból megkerülhetetlen.
Ez a könyv megkísérli értelmezni azt, hogy történeti szempontból mely események vezettek el a keresztény vallás megszületéséhez és Jézus kiválasztottá válásához. Megoldást keres arra, hogy ezek az események és az Újszövetségi kor eseményei milyen időpontokban következtek be a keresztény időszámítás szerint. Ezen kívül nagy vonalakban végigkíséri, hogyan vált a keresztény vallás világvallássá.','keresztenysegszuletese.adlibrum.hu',NULL,1472636512,0);
