INSERT INTO books VALUES('',0,'','Sarlos_Erzsebet--Az_eltitkoltak_eneke--FD.jpg',120,'',1,1,0,2,'',0,1640,0,34,'',30,5,292,120,120,1,'',27,11,2014,558,'Sarlós Erzsébet','Az eltitkoltak éneke','978-963-06-9013-3',2,'','7','140x200 mm',88,'0',2490,2,'#LB5#','Sarlos-Erzsebet','http://www.konyvesbolt.online/spd/978-963-06-9013-3/Sarlos-Erzsebet-Az-eltitkoltak-eneke-Ad-Librum-201','','','','','','','',3,3,4,9,4,5,1,'2014-11-6','2014-11-27','30-2512-111, 70-6273-756, 2071 Páty, Kossuth u. 55.','gingiber65@gmail.com','','','számlázási cím: 2071 Páty, Töki u. 26.',1223455703,1478081850,0);
INSERT INTO books VALUES('',0,'','Jim_Butcher--Pusztito_vihar--FD.jpg',315,'',1,0,0,13,'',1,'',0,0,'','','','','',2000,0,'',23,11,2011,559,'Jim Butcher','Pusztító vihar','978-615-5110-38-2',2,'','4','130x190 mm',300,'0',2690,3,'#LB4,LGVI# Kácsor Péter, Wizard Books','Dresden','http://www.konyvesbolt.online/spd/978-615-5110-38-2/Jim-Butcher-Pusztito-vihar-Ad-Librum-2011','','','','','','','',3,3,1,7,4,5,5,'2011-10-2','2011-11-23','Wizard-Books Kft., Kácsor Péter, 2097 Pilisborosjenő, Bécsi út 7., 20-490-0944','kacsor.peter@wizard-books.hu','Ha mágikus dolgokat kell kinyomozni, vegyünk egy varázslót, hogy elkapjunk egy… - akármit. A megfilmesített, milliós eladásokkal büszkélkedő, 16 részes krimi-fantasy sorozat első magyarul megjelenő kötete.','HARRY DRESDEN – VARÁZSLÓ
ELVESZETT TÁRGYAK FELKUTATÁSA. PARANORMÁLIS NYOMOZÁS.
KONZULTÁCIÓ. TANÁCSADÁS. MÉLTÁNYOS ÁRAK.
SZERELMI BÁJITALOKKAL, FENEKETLEN ERSZÉNYEKKEL, PARTIKKAL ÉS EGYÉB SZÓRAKOZTATÓ TEVÉKENYSÉGGEL NEM FOGLALKOZOM!

Harry Dresden a legjobb abban, amit csinál. Nos, technikailag ő az egyedüli, aki ezt csinálja. Így amikor a Chicago-i rendőrség olyan üggyel találja szemben magát, ami felülmúlja az emberi kreativitást és képességeket, nála keresik a válaszokat. A „mindennapi” világ tele van furcsa és mágikus dolgokkal – és legtöbbjük nem kedvez az embereknek. Itt jön a képbe Harry. Vegyünk egy varázslót, hogy elkapjunk egy… - akármit.

Csak egy gond van. Az üzlet finoman szólva is bűzlik. Tehát amikor a rendőrség megbízza konzulensként egy hátborzongató kettős gyilkossági ügyben, amit fekete mágiával követtek el, Harry pénzt lát a dologban. De ahol sötét varázslat van, ott egy sötét varázsló van a dolog mögött. És most az a varázsló tudja Harry nevét. És itt kezdenek a dolgok… érdekessé válni.

Mágia. Könnyen halálos lehet.','Előfinanszírozottból saját kockázatra átvett példányok.

Jim Butcher: Dresden-akták
1. Pusztító vihar ISBN 978-615-5110-38-2
2. Bolond hold ISBN 978-615-5110-39-9','',1474536085,0);
INSERT INTO books VALUES('',0,'','Matthew_Vigo--A_vegzetes_bestseller--FD.jpg',209,'',1,0,0,10,'',1,'',40,40,'','','','','',500,0,'',3,6,2015,560,'Matthew Vigo','A végzetes bestseller','978-615-5110-73-3',2,'','8','130x200 mm',188,'0',1990,1,'#LC,LGV,LGVI# Száray Mátyás, 130x200 mm, B:B T:G','Vigo','http://www.konyvesbolt.online/spd/978-615-5110-73-3/Matthew-Vigo-A-vegzetes-bestseller-Ad-Librum-2015','','','','','','','',3,3,4,7,4,5,3,'2015-2-1','2015-6-3','Száray Mátyás, 30/857-4471, 1119 Budapest, Etele út 69. 8/77.','mszaray@yahoo.com','Fagyossá válik a légkör, miután születésnapi partiján férjének rejtélyes módon nyoma vész, s mindenki szemében az írónő az első számú gyanúsított.','A híres írónő, Crystal Montague jó ideje alkotói válsággal küzd, s kiadója hiába várja tőle a következő bestsellert. Férjével ugyancsak megromlott a viszonya egy argentin szépfiú megjelenése óta.
Így visszavonul spanyolországi villájába új ihlet reményében, de – legutóbbi könyvének címéhez illően – a hőség ellenére társasága mégis dermesztőnek érzi a hangulatot a napos Trafalgar-fok közelében. Végül valóban fagyossá válik a légkör, miután születésnapi partiján férjének rejtélyes módon nyoma vész, s mindenki szemében az írónő az első számú gyanúsított.
Húga balsejtelme tehát beigazolódni látszik, mivel korábban az ismert magánnyomozó, Anthony Noir segítségét kérte. A polinéziai detektív számára többek között az írónő regényének jegyzete jelent majd segítséget a rendkívüli ügy megoldásában.','120x200 vagy 130x200 mm ???','',1472639557,0);
