INSERT INTO books VALUES('',0,'','Matthew_Vigo--Rejtveny_fekete-feherben--FD.jpg',309,'',1,0,0,10,'',1,'','','','','',NULL,NULL,'',500,0,NULL,2,11,2016,608,'Matthew Vigo','Rejtvény fekete-fehérben','978-615-5686-25-2',2,'','9','130x200 mm',240,'0',1990,1,'Száray Mátyás #LE# ','','http://www.konyvesbolt.online/Matthew-Vigo-Rejtveny-fekete-feherben-Ad-Librum-20','','','','','','','',3,3,4,7,4,5,3,'Array-0-0','2016-11-2','Száray Mátyás, 1119 Bp. Etele út 69. 8/77., tel: 30/857-4471','mszaray@yahoo.com','','A színészből lett detektív, Anthony Noir levelet kap Kaliforniából, melyben egy idős hölgy arra kéri, nyomozzon egy réges-régi ügyben. 1929 szilveszter éjszakáján az egyik híres hollywoodi filmsztár autóbalesetben elhunyt. A rejtélyes megbízó állítja, valójában kitervelt gyilkosság történt. Anthony Noir a nem szokványos eset minden fellelhető részletét megismeri, de nagy utazást kell megtennie, míg a filmcsillag titkára fényt derít...','',NULL,1489049507,0);
