INSERT INTO books VALUES('',0,'','','','',0,0,0,3,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,25,9,2016,611,'Rinyai László','Lakodalom az állatkertben','978-615-5686-15-3  ',2,'','9','',100,'0',990,6,'','','','','','','','','','',3,1,0,0,0,0,0,'Array-0-0','2016-9-25','Oberding Lászlóné, 1112 Budapest, Igmándi u. 11. I/2., 20/9437-047','oberding.laszlone@chello.hu','','A közelmúltban elhunyt Rinyai László (polgári nevén Oberding László) 
1973 novemberében kezdett bele hatalmas tervébe, hogy  valós történeteken keresztül megírja a 20. század második felének irodalmi tükrét egy olyan keretes elbeszélés-gyűjtemény formájában, amely a reneszánsz hagyományokat követi. Ennek egyes részei megjelentek az Irodalom visszavág című folyóiratban, illetve 2009-ben önálló kötet formájában egy kis rész Tetrameron I. Ízelítő címmel. 2011-ben jelent meg második kötete, a Különleges házasság, amelynek címadó novellája
nagyszülei - tényleg különös körülmények között, háborúban létrejött - házasságáról szól.
Rinyai László 1967-től Budapesten élt, 1982-től családjával az Igmándi utcában. E kötetet felesége, szellemi hagyatékának gondozója rendezte sajtó alá.','ISBN eredetileg Robin O`Wrightley-ra, de annak e-kiadására nincs szerződésünk.',NULL,1474832990,0);
INSERT INTO books VALUES('',0,'','','','',0,0,11,3,'',1,'','','','','',NULL,NULL,'','',0,NULL,25,9,2016,612,'Wanderer János','Az ősfák fiainak lombjai alatt','978-615-5686-18-4',2,'','9','',140,'0',1290,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-9-25','Wanderer János, 30/217-1636, 1115 Budapest, Etele út 52/A. VIII/48.','csilimon@gmail.com','Az elvándorlásból haza érkezők valamennyien megtapasztalhatták, mit jelent távoli vidéken élni s a lelkük mélyén valós-tisztán érzik: minél többet járom a világot, annál jobban szeretem a szülőfalumat.','Valaha az 1800-as évek kezdetén földesúri felhívás nyomán néhány tucat család kezdte lerakni a falu alapjait. Az első években jócskán érkeztek még szerencsét próbálni, de néhányan, kiknek elképzelt vágyaik valamiképp nem teljesültek, tovább is álltak.
    Mint mindenhol, az élet itt is hozott szebb, majd nyomorúságosabb időszakokat váltakozva. Sokan egész életüket itt élték le, de a nehezebb periódusok e tájról is vittek el embereket külföldre, főként Amerikába, majd a világháborúk rángatták el messze frontokra a férfiakat. Közülük akadt, aki visszatért - vagy, mert az Újvilág nem bírta örökös maradásra, vagy a harctér golyózáporában a gondviselés kézen fogta. Mások tanulni, dolgozni mentek el hosszabb-rövidebb időre, de végül itt értek révbe.
    Ők - a haza érkezők - valamennyien megtapasztalhatták, mit jelent távoli vidéken élni s a lelkük mélyén valós-tisztán érzik: minél többet járom a világot, annál jobban szeretem a szülőfalumat.','',NULL,1474832967,0);
INSERT INTO books VALUES('',0,'','','','',0,0,0,3,'',1,'','','','','',NULL,NULL,'','',0,NULL,25,9,2016,613,'Mester Györgyi','A hatodik. Novellák','978-615-5686-16-0',2,'','9','',196,'0',950,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-9-25','2092 Budakeszi, Ifjúság u. 2., 23/451-617','mestergyorgyi@freemail.hu','Mester Györgyi legújabb novellái és mesés történetei.','„Tagadhatatlan, odavagyok a könyvekért. Szeretek olvasni,a legjobb kikapcsolódás számomra egy nívós könyv. Több kedvenc olvasmányom is van, de a legkedvesebb mind közül a „Boszorkányok pedig nincsenek” című. Persze, a tartalomnak köze nincs Könyves Kálmán királyunk híres mondásához, mégis, a legnagyobb hatással ez a könyv volt az életemre...
Kezdhetném azzal, hogy ez a legkedvesebb könyvem egyszer csak
szőrén-szálán eltűnt. Hogy hová lett, máig nem derült ki. Fiatalabb
koromban ugyan többször is lakhelyet változtattam, a költözés
pedig tudottan nagy felfordulással jár, amikor is megeshet, hogy
elmarad tőlünk egy és más. Persze az is lehet, nem így keveredett
el, csupán valamelyik haverom nem adta vissza a kölcsönbe kért
könyvemet.
Egyszóval, komoly lelki traumaként éltem meg, amikor kerestem,
de nem találtam a kedvencemet. A helyzetet csak súlyosbította,
hogy régóta nem adták ki, és még a könyvtárakban sem akadtam rá,
hogy újraolvashattam volna. Elkeseredésemben úgy gondoltam,
ettől az élvezettől egyszer és mindenkorra megfosztott a sors.
Ezért is ért szinte sokként, amikor egyik könyvesbolti nézelődésem
során, a mustrára kitett, új kiadású könyvek között megláttam egy
példányt belőle. ..','',NULL,1474832944,0);
