INSERT INTO books VALUES('',0,'','','','',0,0,0,4,'',1,'','','','','',NULL,NULL,'','',0,NULL,25,9,2016,617,'Varga Béla','Túlélni állati erény','978-615-5686-19-1',2,'','9','',140,'0',995,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-9-25','1043 Bp. Kassai u. 9.  II./16., 30/429-6739','vargabela27@citromail.hu','A Fülöplovag, az orvosölő című mű folytatása, befejezése ez a könyv, párbeszédekből felépülő, versikékkel tarkított alkotás. Mese, a megismert előzmény mitologikus befejezése és egy világrend újra hangoztatott apológiája.','A Fülöplovag, az orvosölő című mű folytatása, befejezése ez a könyv, a megismert szereplők ismét útra kelnek biztonságos és idillikus országukból, hogy akarva-akaratlanul konfliktusba keveredjenek az orvosok uralta Valóság erőszakszervezeteivel az elesettek védelmében. Összecsapásuk végzetesnek bizonyul számukra.
Vajon mi az az erő, ami a harmonikus nyugalom világából a durvaság, káosz és boncolás jellemezte külső dimenzióba kényszeríti azokat, akik odahaza különben méltóságban élhetnének? Erre nem kap egyenes választ az olvasó. Ezúttal nincs ígéret a felemelkedésre sem, a füzetnyi könyvecske lapjainak derűből szomorúságba vezető vonala és a pesszimista záróakkord nem nyújt megnyugvást. Nem is igazi regény ez: főként párbeszédekből felépülő, versikékkel tarkított alkotás, mese, a megismert előzmény mitologikus befejezése és egy világrend újra hangoztatott apológiája.','',NULL,1474832837,0);
