INSERT INTO books VALUES('',0,'','Sajter_Gizella--Tudatelegtelenseg--FD.jpg',200,'',1,0,0,2,'',1,'',30,30,'','',NULL,NULL,'',100,0,NULL,11,11,2016,645,'Sajter Gizella','Tudatelégtelenség','978-615-5686-42-9',2,'','9','120x200 mm',64,'0',990,1,'#LE, LGVI# keménytábla','','http://www.konyvesbolt.online/Sajter-Gizella-Tudatelegtelenseg-Ad-Librum-2016','','','','','','','',3,3,4,7,4,5,5,'2016-10-14','2016-11-11','Via G. Matteotti 7., Pozzuoli(NA) 80078 IT; 1117 Bp. Fehérvári út 15. 2//3.; 06/39-329-833-2589','xd2332@gmail.com','','Közben éltem is.
Mégis az álmaim tűntek valóságosabbnak.
Néha szerettem.
Mégis mindig csalódtam magamban.
Mindig harcoltam.
Mégsem tudtam legyőzni önmagam.
Egy nap mindent elveszítettem.
Mégis volt mit elvesztenem másnap.','',NULL,1479893267,0);
