INSERT INTO books VALUES('',0,'','Mester_Gyorgyi--Felnottmesek_kifestokonyv--FD.jpg',210,'',1,0,0,24,'',1,'',40,40,'','',NULL,NULL,'',50,0,NULL,0,12,2016,649,'Mester Györgyi','Felnőttmesék. Kifestőkönyv','978-615-5686-46-7',2,'','9','B5',104,'0',1200,1,'','','http://www.konyvesbolt.online/Mester-Gyorgyi-Felnottmesek-Kifestokonyv-Ad-Librum','','','','','','','',3,3,0,0,0,0,0,'2016-11-30','2016-12-0','','mestergyorgyi@freemail.hu','','Felnőtt kifestőkönyv.','',NULL,1484154269,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Elmenni_messze--FD.jpg','','',0,0,0,4,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,650,'P. Dobrossy Rita','Elmenni messze..',' 978-615-5686-47-4 ',2,'','5','',361,'0',990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','A könyv négy kisregényt tartalmaz, amelyek címéhez - éppen úgy, mint az első kisregényhez – a Kormorán zenekar dalai adták az ihletet. A „Ha messze méssz…” című kisregény egy művészeti kolónia mindennapjait mutatja be. A két főszereplő egyike a világtól megcsömörlött híres zenész, aki terápiás céllal költözött társaihoz. Közte, és a fájdalmas múltú, szép festőnő között kialakuló, sodró lendületű szerelem vezérfonalán keresztül jutunk el a meglepő befejezésig.

Koltay Gergely csodaszép dalának felidézésével ajánlom még három - másodszorra kiadott - kisregényemet, melyek mindegyikében egy-egy újrakezdett élet nehézségeit, viszontagságát, és tünékeny boldogságát találja meg az olvasó. A dalrészlet - őszintén remélem - megtalálja helyét lelkekben, és szívekben egyaránt...  de tartalma alapján, minden esetben föl kellett adni a biztosat a bizonytalanért, és
 
ELMENNI MESSZE
 
Elmenni messze
magasra felrepülni
csapódni kőhöz
üvegként összetörni.
Veled, mégis egyedül
állni, csak állni szótlan,
végleg összeforrva
az életen túl egy csókban.','Nincs jogdíj.',NULL,1481271757,0);
