INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Mindhalálig--FD.jpg','','',0,0,0,12,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,652,'P. Dobrossy Rita','Mindhalálig',' 978-615-5686-48-1  ',2,'','7','',240,'0',1250,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051, férj: 30/292-2034','dobrozsirita@freemail.hu','','A könyv két kisregényt tartalmaz, ahol a második írásom, az első folytatása. 
Elgondolkodtató tartalom jellemzi mindkét részt, hiszen két középkorú barátnő először megpróbálja egy időre újra felidézni elmúlt ifjúságának minden boldogságát, minden szerelmes percét, de egyikük tragikus végkimenetelű esete ráébreszti a másikat: életmódot kell változtatniuk, mert ez már nem az ő világuk! Bele kell törődniük az idő múlásába...
Második könyvemben, az eddigi női főszereplő teljes életmódváltáson esik át, mert úgy érzi így KELL élnie... Egy vidéki házba költözve, - még mutatósan, csinosan -, mégis teljesen egyedül várja az öregedés minden fázisát, noha teste-lelke tiltakozni kezd ez ellen, mikor megismerkedik a tőle majdnem két évtizeddel fiatalabb zenésszel és nem tud parancsolni érzéseinek...
 
        "jöjj hát, és hazudd azt, hogy nincsen veszve még,
         Amíg a régi tűz szívedben ég
         Amíg egy régi daltól könnyes lesz szemünk
         Ez a tűz, ez a dal, ez az édes életünk..."
                                                                                      Bródy János','',NULL,1481274614,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Ne_hagyjatok_beken--FD.jpg','','',0,0,0,4,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,653,'P. Dobrossy Rita','Ne hagyjatok békén!',' 978-615-5686-49-8  ',2,'','2','',160,'0',990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 45/421-051, 4600 Kisvárda, Rétalja út 1.','dobrozsirita@freemail.hu','','Szeretném megismerni az IGAZI szerelmet.

Egy nevelőintézetből kikerült csinos, fiatal lány pincérnőként helyezkedik el egy night-clubban. Az éjszakai élet szexuális kihívásairól semmit sem tud. Egyedül van. Megismerkedik egy dúsgazdag vállalkozóval, aki rengeteg pénzt kínál föl, ha vele tölt egy éjszakát. A lánynak nagyon megtetszik a fiatal, jóképű férfi. Szerelmes lesz belé. A férfit is mélyen megérinti a lány szépsége, bája. Ám kiderül, hogy a férfi AIDS betegségben szenved, ezért számára ez az utolsó szerelem lehetősége…','',NULL,1481274569,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Vandorok--FD.jpg','','',0,0,0,4,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,654,'P. Dobrossy Rita','Vándorok',' 978-615-5686-50-4',2,'','4','',300,'0',1250,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1., 45/421-051','dobrozsirita@freemail.hu','Három különböző nő életének egy-egy szakasza.','Ez a könyv három különböző nő életének egy-egy szakaszát mutatja be.
Az első kisregény a fiatal lányt, a második a kisgyermekes anyát, a harmadik pedig egy középkorú hölgyet ismertet meg az olvasókkal.
Ami közös bennük: kitartóak, bátrak, erősek, - és mint minden nő -,tele vannak érzelmekkel, elfojtott indulatokkal. Más-más módon, de kitartóan keresik a boldogságot, és a megfelelő társat.
Mindhárman cipelik magukkal létük gondjait és örömeit.
Élik koránt sem egyhangú életüket, amelynek fő mozgatórugói: az őszinte szerelem, és az igazi otthon megtalása utáni vágy...','',NULL,1481274830,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Orokke_fiatalon--FD.jpg','','',0,0,0,12,'',1,'','','','','',NULL,NULL,'','',0,NULL,0,0,2008,655,'P. Dobrossy Rita','Örökké fiatalon','978-615-5686-51-1',2,'','6','',120,'0',990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','Reggelenként kilovagoltam a házam melletti ösvényen keresztül egy erdei tisztásra, és mindig eszembe jutott, hogy valahol - talán - ott van Ági is, aki annyira örült volna, ha mindezt megérheti.
Tartoztam neki azzal, hogy valóra váljon az álmunk, hiszen mindketten így szerettük volna befejezni az életünket... A szívünk mélyén örökre fiatalon...','',NULL,1481275122,0);
INSERT INTO books VALUES('',0,'','Dobrossy_Rita--Uveg-folyo--FD.jpg','','',0,0,0,4,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,656,'P. Dobrossy Rita','Üveg-folyó','978-615-5686-52-8',2,'','4','',284,'0',990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 45/421-051, 4600 Kisvárda, Rétalja út 1.','dobrozsirita@freemail.hu','A novellák és kisregények kegyetlen sorsokat, értelmetlen életeket, a függőség mindennapjait mutatják be.','Ez a könyv – novellák és kisregények formájában – kegyetlen sorsokat, értelmetlen életeket, a függőség mindennapjait, reális, mégis elérhetetlen emberi kívánságokat, feltétel nélküli szeretetet, és
a békesség utáni vágyat mutatja be.
A könyvet elolvasva talán kicsit leértékelődnek az általunk legfontosabbnak tartott gondok...
Kívánom: Úgy legyen!
P. Dobrossy Rita','',NULL,1481275431,0);
INSERT INTO books VALUES('',0,'','Takacs_Hajnal--Bantalmazottak_igazsaga--FD.jpg',222,'',1,0,26,31,'',1,2093,10,10,'','',NULL,NULL,'',1000,0,NULL,15,2,2017,657,'Takács Hajnal','Bántalmazottak igazsága','978-615-5686-55-9',2,'','10','130x200',180,'0',2990,3,'#LE, LGraklap#  T Aktív Szerző','','http://www.konyvesbolt.online/Takacs-Hajnal-Bantalmazottak-igazsaga','','','','','','','',3,3,4,7,4,5,1,'2016-12-0','2017-2-15','1151 Bp. Fő út 36.; tel:30/555-1639','takacs.hajnal@gmail.com','','Takács Hajnal kapcsolati erőszak túlélő könyve.

"Őszinte, mélyen átgondolt és átérzett írás. A könyv bátorságra késztet, és tisztázza mindazt, ami zavaros. Senki sem érdemel erőszakot." Feldmár András pszichológus és pszichoterapeuta
"Különleges alkalom, hogy valaki egyszerre ír könyvet a téma érintettjeként és szakértőjeként. Izgalmas lett a könyv, főleg a személyes, vallomásos részek mennek mélyre." Dr. Gyurkó Szilvia jogász, gyerekjogi aktivista
"Ez a könyv az alapja mindennek, amit a bántalmazásról tudni és elmondani kell. Hiszek abban, hogy ez a könyv sok mindenki számára a lezáró gondolatokat fogja elhozni." Demcsák Zsuzsa televíziós műsorvezető, A másik életem szerzője
"Ez az egyik legfontosabb írás, amit valaha ajánlhattam. Mindenki segíthet a családon belüli erőszak áldozatainak azzal, hogy megérti, mi, miért és hogyan történik velük." Bombera Krisztina televíziós újságíró','T:G,B:Egyed,K:Szilvia
NY: Galantusz
szerzői ár: 2.093.-',NULL,1489489126,0);
