INSERT INTO books VALUES('',0,'','','','',0,0,0,0,'',1,'','','','','',NULL,NULL,'','',0,NULL,15,2,2017,660,'Takács Hajnal','Bántalmazottak igazsága','978-615-5686-56-6',2,'','10','',180,'0',1990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2017-2-15','1151 Bp. Fő út 36.; tel:30/555-1639','takacs.hajnal@gmail.com','','Takács Hajnal kapcsolati erőszak túlélő könyve. „Őszinte, mélyen átgondolt és átérzett írás. A könyv bátorságra késztet, és tisztázza mindazt, ami zavaros. Senki sem érdemel erőszakot.” Feldmár András pszichológus és pszichoterapeuta „Különleges alkalom, hogy valaki egyszerre ír könyvet a téma érintettjeként és szakértőjeként. Izgalmas lett a könyv, főleg a személyes, vallomásos részek mennek mélyre.” Dr. Gyurkó Szilvia jogász, gyerekjogi aktivista „Ez a könyv az alapja mindennek, amit a bántalmazásról tudni és elmondani kell. Hiszek abban, hogy ez a könyv sok mindenki számára a lezáró gondolatokat fogja elhozni.” Demcsák Zsuzsa televíziós műsorvezető, A másik életem szerzője „Ez az egyik legfontosabb írás, amit valaha ajánlhattam. Mindenki segíthet a családon belüli erőszak áldozatainak azzal, hogy megérti, mi, miért és hogyan történik velük.” Bombera Krisztina televíziós újságíró','',NULL,1487770997,0);
