INSERT INTO books VALUES('',0,'','Varga_Bela--Lelkunk_parancsa--FD.jpg','','',1,0,0,4,'',1,1800,10,'','','',NULL,NULL,'',8,0,NULL,20,3,2017,673,'Varga Béla','Lelkünk parancsa','978-615-5686-65-8',2,'','10','130x200',158,'0',1990,5,'','','http://www.konyvesbolt.online/Varga-Bela-Lelkunk-parancsa','','','','','','','',2,2,3,1,1,4,5,'2017-1-0','2017-3-20','1043 Bp. Kassai u. 9.  II./16., 30/429-6739','vargabela27@citromail.hu','','A boncolás:
- Az emberi méltóság megsértése
- Rosszabb a gyilkosságnál mert a gyilkos az életet, az orvos a méltóságot veszi el
- Kegyeletsértés: akit felboncolnak, azt nem lehet megsiratni mivel meggyalázták, érte csak bosszút állni lehet
- Életvesztő: egy olyan világban ahol boncolás létezik, ott sem szülni, sem szeretni nem lehet
- Erőszak, méghozzá a legelvetemültebb erőszak, ami elkövethető
- A gonosz földi hatalmának legnyilvánvalóbb megtestesülése
- Csak kevesen mernek tiltakozni ellene.','K:Szilvi
T:G
