INSERT INTO books VALUES('',0,'','Bohonyey_Marta--Toth_Melinda--Mira--FD.jpg','','',1,0,0,26,'',1,'',10,10,'','',NULL,NULL,'',1000,0,NULL,27,3,2017,677,'Böhönyey Márta – Tóth Melinda','Mira. Így váltsd meg a világod!','978-615-5686-77-1',5,'','10','135x200',272,'0',3490,3,'T Aktív Szerző','','http://www.konyvesbolt.online/Bohonyey-Marta-Toth-Melinda-Mira-Igy-valtsd-meg-a','','','','','','','',2,3,0,0,0,4,1,'2017-2-6','2017-3-27','Böhönyey Márta 1115 Bp.Forrás u.6., tel:30/4104; Tóth Melinda 1061Bp.Paulay E. u. 15.II/10., tel:30/471-1074, toth.melinda@pszichorendeles.hu','info@pszichorendeles.hu','','Éld át és értsd meg a terápiát! - Pszichorendelés könyvben! 

Mira rejtélyes csomagot kap, ezzel különös egybeesések sora veszi kezdetét…

Mi köze a halsütöde logójának a hányattatott szerelmi élethez?
És a kis hableánynak a manipulatív főnökhöz?
Hogy válhat egy bársonyboleró megsemmisítő fegyverré egy szülő kezében?
Hogy vértez fel egy jó barát egy krokodillal, és a még ennél is rettenetesebb üveggolyókkal szemben?

A népszerű pszichológusduó első, formabontó könyvében Mira regényes életét nyomon követve bepillantást nyerünk a terápia hagyományosan zárt ajtaja mögé, hogy aztán a regényben olvasottak tudományos hátterére is fény derüljön. 

A kapott támpontok alapján saját életünkben is beazonosíthatjuk azokat a sokszor észrevétlen önsorsrontó beidegződéseket, amelyek miatt újra meg újra hasonló nehézségekbe ütközünk. A mű nem csak abban segít, hogy jobban megértsük magunkat, hanem abban is, hogy a gyakorlati útmutatót követve megszakítsuk ördögi köreinket.

Ha tetszett a könyv, látogass el az előadásokra!
Ha tetszettek az előadások, olvasd el a könyvet!','T:Egyed
B:külső',NULL,1489394658,0);
