INSERT INTO books VALUES('',0,'','','','',0,0,0,4,'',1,'',10,10,'','',NULL,NULL,'',1000,0,NULL,15,4,2017,680,'Pauer Emánuel','Magamon kívül','978-615-5686-75-7',2,'','10','120x200 mm',100,'0',1990,3,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2017-4-15','1071 Bp. Damjanich u. 32. 4/2.; tel: 20/224-2187','pauere@gmail.com','','Mindennapi szorongásainkat add meg nekünk ma… Egy ember a kitörés előtti utolsó pillanatokban, innen indulunk. Magunkon kívülre… Csak ott lehetünk szabadok. 
Nincs ebben semmi szomorú. 

Nehéz elmondanom, hogy minek írtam ezt a könyvet. Nem rólam szól, és mégis. Benne vagyok, ahogy te. Ahogy ők. Fullasztó bennrekedtség…
Csak az fogja érteni, aki érezte már, másként elolvasni sem érdemes.
Egy kétségbeesett, kapkodó, görcsökbe ránduló, esetlen szabadulási kísérlet a teljesség felé.
Szét akartam a felszínt szaggatni, a tartalmat darabjaira akartam törni, hogy megtaláljam a lényeg hiányzó, ismeretlen részét. Nem sikerült. A semmit nem lehet megtalálni. De tovább kell keresni.

Öngyilkosság a halál nélkül, ez a főhős útja. ','',NULL,1487710133,0);
